#include <cuda_runtime.h>
#include <cstddef>
#include <cstdint>

namespace {

// The hot step kernel operates on 32 packed cells at a time.
// The prompt explicitly allows internal data transformations inside run_game_of_life,
// so we convert the caller's byte-per-cell bool grid into a 1-bit-per-cell layout,
// run the actual Life update there, then expand back to bool.
using word_t = unsigned int;

constexpr int kWordBits  = 32;
constexpr int kWordShift = 5;

// Transform kernels: simple, bandwidth-bound, warp-centric.
// One warp packs or unpacks one 32-cell group with fully coalesced byte accesses
// using ballot/shuffle. 256 threads = 8 warps per block.
constexpr int kTransformWarpsPerBlock = 8;
constexpr int kTransformThreads       = kTransformWarpsPerBlock * kWordBits;
constexpr int kTransformBlocksPerSM   = 8;

// Step kernel geometry.
// x is exactly one warp (32 packed words) so each warp covers a contiguous horizontal span.
// y is 16 rows, giving 512-thread blocks: good halo amortization without going to 1024 threads.
// Because grid_dimensions is a power of two > 512, all legal sizes divide these tile sizes exactly.
constexpr int kStepBlockWords = kWordBits;
constexpr int kStepBlockRows  = 16;

constexpr unsigned kFullWarpMask = 0xFFFFFFFFu;

static_assert(sizeof(word_t) == 4, "word_t must be 32 bits");
static_assert(kTransformThreads % kWordBits == 0, "Transform block size must be a whole number of warps");
static_assert(kStepBlockWords == kWordBits, "Step kernel assumes exactly one warp in x");

// Align the west neighbor of each bit to the current cell's bit position.
// For bit i, result bit i becomes original bit i-1; bit 0 is filled from the previous word's MSB.
// NVCC generally lowers this idiom to a single SHF instruction on modern GPUs.
__device__ __forceinline__ word_t shift_from_left(word_t center, word_t left_word) {
    return (center << 1) | (left_word >> (kWordBits - 1));
}

// Align the east neighbor of each bit to the current cell's bit position.
// For bit i, result bit i becomes original bit i+1; bit 31 is filled from the next word's LSB.
__device__ __forceinline__ word_t shift_from_right(word_t center, word_t right_word) {
    return (center >> 1) | (right_word << (kWordBits - 1));
}

__device__ __forceinline__ void half_adder(word_t a, word_t b, word_t& sum, word_t& carry) {
    sum   = a ^ b;
    carry = a & b;
}

__device__ __forceinline__ void full_adder(word_t a, word_t b, word_t c, word_t& sum, word_t& carry) {
    const word_t axb = a ^ b;
    sum   = axb ^ c;
    carry = (a & b) | (c & axb);
}

// Compute one packed Life update for 32 cells in parallel.
//
// The eight neighbor masks are bitboards: bit i in each mask corresponds to neighbor presence
// for cell i.  We count neighbors with a carry-save adder tree:
//
//   8 one-bit inputs -> binary count bits for each lane
//
// We do not materialize the full 4-bit count explicitly because the Life rule only needs
// to distinguish:
//   - count == 2
//   - count == 3
//   - count >= 4
//
// After the final half-adder:
//   bit0         = count's 1s bit
//   bit1         = count's 2s bit
//   (e2 | d2)    = count >= 4
//
// Life rule:
//   next = (count in {2,3}) && (alive || count == 3)
//        = bit1 && !(count >= 4) && (alive || bit0)
__device__ __forceinline__ word_t life_word(
    word_t alive,
    word_t nw, word_t n, word_t ne,
    word_t w,              word_t e,
    word_t sw, word_t s, word_t se)
{
    word_t s1, c1;
    word_t s2, c2;
    word_t s3, c3;
    full_adder(nw, n, ne, s1, c1);
    full_adder(w,  e, sw, s2, c2);
    half_adder(s, se, s3, c3);

    word_t bit0, d1;
    full_adder(s1, s2, s3, bit0, d1);

    word_t t2, d2;
    full_adder(c1, c2, c3, t2, d2);

    word_t bit1, e2;
    half_adder(t2, d1, bit1, e2);

    const word_t two_or_three = bit1 & ~(e2 | d2);
    return two_or_three & (bit0 | alive);
}

// Pack 32 consecutive bool cells into one 32-bit word.
//
// Because every row length is a multiple of 32, the flat bool array can be partitioned into
// 32-cell groups without ever crossing a row boundary.  That means the transform kernels can
// ignore 2D indexing entirely and just operate on a linear array of packed words.
__global__ __launch_bounds__(kTransformThreads)
void pack_bool_to_words_kernel(const bool* __restrict__ input,
                               word_t* __restrict__ packed,
                               int total_words)
{
    const int lane        = static_cast<int>(threadIdx.x) & (kWordBits - 1);
    const int warp_in_blk = static_cast<int>(threadIdx.x) >> kWordShift;
    const int warp_idx    = static_cast<int>(blockIdx.x) * kTransformWarpsPerBlock + warp_in_blk;
    const int warp_stride = static_cast<int>(gridDim.x) * kTransformWarpsPerBlock;

    for (int linear_word = warp_idx; linear_word < total_words; linear_word += warp_stride) {
        const std::size_t cell_base = static_cast<std::size_t>(linear_word) << kWordShift;
        const word_t bits = __ballot_sync(kFullWarpMask, input[cell_base + lane]);
        if (lane == 0) {
            packed[linear_word] = bits;
        }
    }
}

// Unpack one 32-bit word back into 32 bool cells.
// Lane 0 loads the packed word once, then broadcasts it to the warp with shuffle.
__global__ __launch_bounds__(kTransformThreads)
void unpack_words_to_bool_kernel(const word_t* __restrict__ packed,
                                 bool* __restrict__ output,
                                 int total_words)
{
    const int lane        = static_cast<int>(threadIdx.x) & (kWordBits - 1);
    const int warp_in_blk = static_cast<int>(threadIdx.x) >> kWordShift;
    const int warp_idx    = static_cast<int>(blockIdx.x) * kTransformWarpsPerBlock + warp_in_blk;
    const int warp_stride = static_cast<int>(gridDim.x) * kTransformWarpsPerBlock;

    for (int linear_word = warp_idx; linear_word < total_words; linear_word += warp_stride) {
        word_t bits = 0;
        if (lane == 0) {
            bits = packed[linear_word];
        }
        bits = __shfl_sync(kFullWarpMask, bits, 0);

        const std::size_t cell_base = static_cast<std::size_t>(linear_word) << kWordShift;
        output[cell_base + lane] = ((bits >> lane) & 1u) != 0u;
    }
}

// Actual measured hot kernel.
//
// Each thread updates one packed 32-cell word.
// A 32x16 block stages an 18x34 shared-memory tile:
//   (block_rows + 2 halo) x (block_words + 2 halo)
//
// This cuts global traffic dramatically: neighboring packed words and neighboring rows
// are reused from shared memory rather than reloaded per output word.  Dead-outside-grid
// semantics are handled by zero-filling the halo at global boundaries.
__global__ __launch_bounds__(kStepBlockWords * kStepBlockRows)
void gol_step_packed_kernel(const word_t* __restrict__ in,
                            word_t* __restrict__ out,
                            int words_per_row)
{
    __shared__ word_t tile[kStepBlockRows + 2][kStepBlockWords + 2];

    const int bx = static_cast<int>(blockIdx.x);
    const int by = static_cast<int>(blockIdx.y);
    const int tx = static_cast<int>(threadIdx.x);
    const int ty = static_cast<int>(threadIdx.y);

    const int wx  = bx * kStepBlockWords + tx;
    const int row = by * kStepBlockRows  + ty;
    const int idx = row * words_per_row + wx;

    const int sx = tx + 1;
    const int sy = ty + 1;

    const bool has_left_block   = (bx != 0);
    const bool has_right_block  = (bx + 1 != static_cast<int>(gridDim.x));
    const bool has_top_block    = (by != 0);
    const bool has_bottom_block = (by + 1 != static_cast<int>(gridDim.y));

    // Center of the tile: always valid because the problem guarantees exact divisibility
    // by the chosen block shape.
    tile[sy][sx] = in[idx];

    // Left/right halo words.
    if (tx == 0) {
        tile[sy][0] = has_left_block ? in[idx - 1] : 0u;
    }
    if (tx == kStepBlockWords - 1) {
        tile[sy][kStepBlockWords + 1] = has_right_block ? in[idx + 1] : 0u;
    }

    // Top/bottom halo rows.
    if (ty == 0) {
        tile[0][sx] = has_top_block ? in[idx - words_per_row] : 0u;
    }
    if (ty == kStepBlockRows - 1) {
        tile[kStepBlockRows + 1][sx] = has_bottom_block ? in[idx + words_per_row] : 0u;
    }

    // Four corners of the halo.
    if (tx == 0 && ty == 0) {
        tile[0][0] = (has_left_block && has_top_block) ? in[idx - words_per_row - 1] : 0u;
    }
    if (tx == kStepBlockWords - 1 && ty == 0) {
        tile[0][kStepBlockWords + 1] =
            (has_right_block && has_top_block) ? in[idx - words_per_row + 1] : 0u;
    }
    if (tx == 0 && ty == kStepBlockRows - 1) {
        tile[kStepBlockRows + 1][0] =
            (has_left_block && has_bottom_block) ? in[idx + words_per_row - 1] : 0u;
    }
    if (tx == kStepBlockWords - 1 && ty == kStepBlockRows - 1) {
        tile[kStepBlockRows + 1][kStepBlockWords + 1] =
            (has_right_block && has_bottom_block) ? in[idx + words_per_row + 1] : 0u;
    }

    __syncthreads();

    const word_t north = tile[sy - 1][sx];
    const word_t self  = tile[sy][sx];
    const word_t south = tile[sy + 1][sx];

    const word_t nw = shift_from_left (north, tile[sy - 1][sx - 1]);
    const word_t n  = north;
    const word_t ne = shift_from_right(north, tile[sy - 1][sx + 1]);

    const word_t w  = shift_from_left (self,  tile[sy][sx - 1]);
    const word_t e  = shift_from_right(self,  tile[sy][sx + 1]);

    const word_t sw = shift_from_left (south, tile[sy + 1][sx - 1]);
    const word_t s  = south;
    const word_t se = shift_from_right(south, tile[sy + 1][sx + 1]);

    out[idx] = life_word(self, nw, n, ne, w, e, sw, s, se);
}

} // namespace

void run_game_of_life(const bool* input, bool* output, int grid_dimensions)
{
    // The caller owns synchronization.  This function therefore stays fully asynchronous and
    // uses stream-ordered allocation/free on the default stream rather than any synchronizing path.
    cudaStream_t stream = 0;

    // Packed row length in 32-bit words.  Since grid_dimensions is a power of two > 512,
    // this is also a power of two and at least 32.
    const int words_per_row = grid_dimensions >> kWordShift;
    const int total_words   = grid_dimensions * words_per_row;
    const std::size_t packed_bytes = static_cast<std::size_t>(total_words) * sizeof(word_t);

    // One contiguous temp allocation holds both packed input and packed output.
    word_t* packed_storage = nullptr;
    cudaMallocAsync(&packed_storage, packed_bytes * 2, stream);

    word_t* packed_input  = packed_storage;
    word_t* packed_output = packed_storage + total_words;

    // Transform kernels are simple and bandwidth-bound.  A modest number of blocks per SM
    // is enough to saturate memory while avoiding silly launch geometry for huge boards.
    int device   = 0;
    int sm_count = 0;
    cudaGetDevice(&device);
    cudaDeviceGetAttribute(&sm_count, cudaDevAttrMultiProcessorCount, device);

    const int max_useful_transform_blocks =
        (total_words + kTransformWarpsPerBlock - 1) / kTransformWarpsPerBlock;

    int transform_blocks = sm_count * kTransformBlocksPerSM;
    if (transform_blocks > max_useful_transform_blocks) transform_blocks = max_useful_transform_blocks;
    if (transform_blocks < 1) transform_blocks = 1;

    // bool -> packed bits
    pack_bool_to_words_kernel<<<transform_blocks, kTransformThreads, 0, stream>>>(
        input, packed_input, total_words);

    // Packed Life step
    const dim3 step_block(kStepBlockWords, kStepBlockRows);
    const dim3 step_grid(
        static_cast<unsigned>(words_per_row / kStepBlockWords),
        static_cast<unsigned>(grid_dimensions / kStepBlockRows));

    gol_step_packed_kernel<<<step_grid, step_block, 0, stream>>>(
        packed_input, packed_output, words_per_row);

    // packed bits -> bool
    unpack_words_to_bool_kernel<<<transform_blocks, kTransformThreads, 0, stream>>>(
        packed_output, output, total_words);

    // Safe without synchronization because the free is ordered after all prior work in the stream.
    cudaFreeAsync(packed_storage, stream);
}

#include <cuda_runtime.h>
#include <cstddef>

namespace {

// This implementation intentionally exploits two prompt-specific facts:
//
// 1) grid_dimensions is always a power of two and > 512.
//    That means the grid is exactly divisible by 32, 256, 8, and 4, so all
//    kernel launch shapes tile the domain perfectly with no per-thread bounds
//    checks in the hot path.
//
// 2) Data transformations inside run_game_of_life are explicitly allowed and
//    are not measured.
//    We therefore pack the bool grid into 32-bit words (one bit per cell),
//    run the actual Game-of-Life step in that packed form, then unpack back to
//    bool. The packed step updates 32 cells per thread using only bitwise
//    logic, which is substantially faster than processing one byte per cell.
//
// Cells outside the grid are dead; the packed step injects zero-valued halo
// words/rows at the global boundaries.

using u32 = unsigned int;
static_assert(sizeof(u32) == 4, "This implementation relies on 32-bit words.");

constexpr u32 kWarpSize = 32u;
constexpr u32 kWordBits = 32u;
constexpr u32 kFullMask = 0xFFFFFFFFu;
constexpr u32 kLastLane = kWarpSize - 1u;

// Pack/unpack:
// - block = 256 x 4 = 1024 threads
// - one warp packs/unpacks one 32-cell word
// - each block covers 8 packed words across x and 4 rows across y
constexpr u32 kPackBlockX = 256u;
constexpr u32 kPackBlockY = 4u;
constexpr u32 kPackWordsPerBlockX = kPackBlockX / kWarpSize;

// Packed Life step:
// - block = 32 x 8 = 256 threads
// - one thread updates one packed word = 32 cells
// - each warp therefore updates one 1024-cell row segment
// - each block covers 32 packed words across x and 8 rows across y
constexpr u32 kStepBlockX = 32u;
constexpr u32 kStepBlockY = 8u;
constexpr u32 kStepWordsPerBlockX = kStepBlockX;

static_assert(kPackBlockX % kWarpSize == 0u, "Pack/unpack block must contain whole warps.");
static_assert(kStepBlockX == kWarpSize, "Step kernel assumes blockDim.x == warpSize.");
static_assert(kWordBits == kWarpSize, "Ballot packing assumes 32-bit words and 32-lane warps.");

struct PackedBufferCache {
    u32* a = nullptr;
    u32* b = nullptr;
    std::size_t capacity_words = 0;
};

// Per-host-thread cache so steady-state execution avoids cudaMalloc/cudaFree.
// Plain cudaMalloc/cudaFree are used instead of stream-ordered allocation
// because run_game_of_life has no stream parameter; this keeps behavior correct
// under both legacy and per-thread default-stream modes.
thread_local PackedBufferCache g_cache;

inline void ensure_packed_capacity(const std::size_t required_words) {
    if (g_cache.capacity_words >= required_words) {
        return;
    }

    if (g_cache.a != nullptr) {
        (void)cudaFree(g_cache.a);
        g_cache.a = nullptr;
    }
    if (g_cache.b != nullptr) {
        (void)cudaFree(g_cache.b);
        g_cache.b = nullptr;
    }
    g_cache.capacity_words = 0;

    (void)cudaMalloc(reinterpret_cast<void**>(&g_cache.a), required_words * sizeof(u32));
    (void)cudaMalloc(reinterpret_cast<void**>(&g_cache.b), required_words * sizeof(u32));
    g_cache.capacity_words = required_words;
}

// Adds one 1-bit neighbor mask into a four-bit per-cell counter represented as
// parallel bitplanes (ones/twos/fours/eights). Overflow beyond the eights plane
// is impossible because each Life neighborhood contains exactly eight cells.
__device__ __forceinline__ void add_mask_to_counter(
    const u32 v,
    u32& ones,
    u32& twos,
    u32& fours,
    u32& eights)
{
    u32 x = v;

    u32 carry = ones & x;
    ones ^= x;

    x = carry;
    carry = twos & x;
    twos ^= x;

    x = carry;
    carry = fours & x;
    fours ^= x;

    eights ^= carry;
}

// These shift/or forms map to SHF-style funnel shifts on modern NVIDIA GPUs.
__device__ __forceinline__ u32 shift_west(const u32 word, const u32 left_word) {
    return (word << 1) | (left_word >> 31);
}

__device__ __forceinline__ u32 shift_east(const u32 word, const u32 right_word) {
    return (word >> 1) | (right_word << 31);
}

__global__ __launch_bounds__(1024)
void pack_bool_grid_kernel(const unsigned char* __restrict__ input,
                           u32* __restrict__ packed) {
    const u32 lane = threadIdx.x & kLastLane;
    const u32 word_in_block = threadIdx.x / kWarpSize;
    const u32 word_x = static_cast<u32>(blockIdx.x) * kPackWordsPerBlockX + word_in_block;
    const u32 y = static_cast<u32>(blockIdx.y) * kPackBlockY + threadIdx.y;

    const u32 words_per_row = static_cast<u32>(gridDim.x) * kPackWordsPerBlockX;
    const u32 n = words_per_row * kWordBits;

    const std::size_t row_base = static_cast<std::size_t>(y) * static_cast<std::size_t>(n);
    const std::size_t cell_x =
        static_cast<std::size_t>(blockIdx.x) * static_cast<std::size_t>(kPackBlockX) +
        static_cast<std::size_t>(threadIdx.x);
    const std::size_t cell_index = row_base + cell_x;

    const u32 mask = __ballot_sync(kFullMask, input[cell_index] != 0u);

    if (lane == 0u) {
        const u32 packed_row_base = y * words_per_row;
        packed[packed_row_base + word_x] = mask;
    }
}

__global__ __launch_bounds__(1024)
void unpack_bool_grid_kernel(const u32* __restrict__ packed,
                             unsigned char* __restrict__ output) {
    const u32 lane = threadIdx.x & kLastLane;
    const u32 word_in_block = threadIdx.x / kWarpSize;
    const u32 word_x = static_cast<u32>(blockIdx.x) * kPackWordsPerBlockX + word_in_block;
    const u32 y = static_cast<u32>(blockIdx.y) * kPackBlockY + threadIdx.y;

    const u32 words_per_row = static_cast<u32>(gridDim.x) * kPackWordsPerBlockX;
    const u32 n = words_per_row * kWordBits;

    const u32 packed_row_base = y * words_per_row;

    // One packed-word load per warp, then broadcast to all lanes.
    u32 word = 0u;
    if (lane == 0u) {
        word = __ldg(packed + packed_row_base + word_x);
    }
    word = __shfl_sync(kFullMask, word, 0);

    const std::size_t row_base = static_cast<std::size_t>(y) * static_cast<std::size_t>(n);
    const std::size_t cell_x =
        static_cast<std::size_t>(blockIdx.x) * static_cast<std::size_t>(kPackBlockX) +
        static_cast<std::size_t>(threadIdx.x);
    const std::size_t cell_index = row_base + cell_x;

    output[cell_index] = static_cast<unsigned char>((word >> lane) & 1u);
}

__global__ __launch_bounds__(256)
void life_step_packed_kernel(const u32* __restrict__ input,
                             u32* __restrict__ output) {
    const u32 lane = threadIdx.x;  // blockDim.x is exactly one warp
    const u32 word_x =
        static_cast<u32>(blockIdx.x) * kStepWordsPerBlockX + lane;
    const u32 y =
        static_cast<u32>(blockIdx.y) * kStepBlockY + threadIdx.y;

    // Packed-row indices fit in 32 bits for the targeted A100/H100 memory
    // sizes, while the original bool-grid indices may not. The hot packed step
    // therefore stays on 32-bit addressing.
    const u32 words_per_row = static_cast<u32>(gridDim.x) * kStepWordsPerBlockX;
    const u32 row_base = y * words_per_row;

    const bool has_north = (blockIdx.y != 0u) || (threadIdx.y != 0u);
    const bool has_south = (blockIdx.y + 1u != gridDim.y) || (threadIdx.y + 1u != kStepBlockY);
    const bool has_left_block = (blockIdx.x != 0u);
    const bool has_right_block = (blockIdx.x + 1u != gridDim.x);

    const u32* row_c = input + row_base;
    const u32* row_n = has_north ? (row_c - words_per_row) : nullptr;
    const u32* row_s = has_south ? (row_c + words_per_row) : nullptr;

    // Three 32-bit loads update 32 cells; adjacent-row reuse is expected to hit
    // in L1/L2 because neighboring warps process consecutive rows.
    const u32 north = has_north ? __ldg(row_n + word_x) : 0u;
    const u32 current = __ldg(row_c + word_x);
    const u32 south = has_south ? __ldg(row_s + word_x) : 0u;

    // Neighboring packed words inside the warp come from shuffle exchange.
    // Only the two warp-edge lanes issue extra global loads for the horizontal halo.
    u32 north_left_word = __shfl_up_sync(kFullMask, north, 1);
    u32 current_left_word = __shfl_up_sync(kFullMask, current, 1);
    u32 south_left_word = __shfl_up_sync(kFullMask, south, 1);

    u32 north_right_word = __shfl_down_sync(kFullMask, north, 1);
    u32 current_right_word = __shfl_down_sync(kFullMask, current, 1);
    u32 south_right_word = __shfl_down_sync(kFullMask, south, 1);

    if (lane == 0u) {
        if (has_left_block) {
            const u32 left_word_x = word_x - 1u;
            north_left_word = has_north ? __ldg(row_n + left_word_x) : 0u;
            current_left_word = __ldg(row_c + left_word_x);
            south_left_word = has_south ? __ldg(row_s + left_word_x) : 0u;
        } else {
            north_left_word = 0u;
            current_left_word = 0u;
            south_left_word = 0u;
        }
    } else if (lane == kLastLane) {
        if (has_right_block) {
            const u32 right_word_x = word_x + 1u;
            north_right_word = has_north ? __ldg(row_n + right_word_x) : 0u;
            current_right_word = __ldg(row_c + right_word_x);
            south_right_word = has_south ? __ldg(row_s + right_word_x) : 0u;
        } else {
            north_right_word = 0u;
            current_right_word = 0u;
            south_right_word = 0u;
        }
    }

    // Align the three rows' west/east neighbors onto the current bit positions.
    const u32 north_west = shift_west(north, north_left_word);
    const u32 north_east = shift_east(north, north_right_word);
    const u32 west = shift_west(current, current_left_word);
    const u32 east = shift_east(current, current_right_word);
    const u32 south_west = shift_west(south, south_left_word);
    const u32 south_east = shift_east(south, south_right_word);

    // Sum the eight neighbors as parallel 4-bit counters.
    u32 ones = 0u;
    u32 twos = 0u;
    u32 fours = 0u;
    u32 eights = 0u;

    add_mask_to_counter(north_west, ones, twos, fours, eights);
    add_mask_to_counter(north,      ones, twos, fours, eights);
    add_mask_to_counter(north_east, ones, twos, fours, eights);
    add_mask_to_counter(west,       ones, twos, fours, eights);
    add_mask_to_counter(east,       ones, twos, fours, eights);
    add_mask_to_counter(south_west, ones, twos, fours, eights);
    add_mask_to_counter(south,      ones, twos, fours, eights);
    add_mask_to_counter(south_east, ones, twos, fours, eights);

    // Life rule in packed form:
    // - exactly 3 neighbors -> alive
    // - exactly 2 neighbors -> keep current state
    // Counts >= 4 are filtered by ~(fours | eights).
    const u32 next = (twos & ~(fours | eights)) & (ones | current);
    output[row_base + word_x] = next;
}

}  // namespace

extern "C" void run_game_of_life(const bool* input, bool* output, int grid_dimensions) {
    // The prompt guarantees:
    // - square grid
    // - power-of-two dimensions
    // - dimensions > 512
    //
    // Therefore:
    // - words_per_row is an integer,
    // - pack/unpack tiles divide the grid exactly,
    // - the packed step tile (1024 cells in x, 8 rows in y) also divides exactly.

    const u32 n = static_cast<u32>(grid_dimensions);
    const u32 words_per_row = n / kWordBits;
    const std::size_t packed_word_count =
        static_cast<std::size_t>(n) * static_cast<std::size_t>(words_per_row);

    ensure_packed_capacity(packed_word_count);

    const auto* input_bytes = reinterpret_cast<const unsigned char*>(input);
    auto* output_bytes = reinterpret_cast<unsigned char*>(output);

    const dim3 pack_block(kPackBlockX, kPackBlockY, 1u);
    const dim3 pack_grid(words_per_row / kPackWordsPerBlockX, n / kPackBlockY, 1u);

    const dim3 step_block(kStepBlockX, kStepBlockY, 1u);
    const dim3 step_grid(words_per_row / kStepWordsPerBlockX, n / kStepBlockY, 1u);

    // In steady state this function is just three launches:
    // pack -> packed Life step -> unpack.
    // No synchronization is performed here; the caller owns synchronization.
    pack_bool_grid_kernel<<<pack_grid, pack_block>>>(input_bytes, g_cache.a);
    life_step_packed_kernel<<<step_grid, step_block>>>(g_cache.a, g_cache.b);
    unpack_bool_grid_kernel<<<pack_grid, pack_block>>>(g_cache.b, output_bytes);
}

#include <cuda_runtime.h>
#include <cstddef>
#include <cstdint>

// CUDA device-side bool storage is 1 byte. Reinterpreting the buffers as bytes avoids
// repeated bool<->integer conversions in the hot path and still preserves 0/1 semantics.
static_assert(sizeof(bool) == 1, "This implementation assumes 1-byte bool storage.");

namespace {

using cell_t = unsigned char;
using u32 = std::uint32_t;

// One warp owns one 32-cell span along X. This lets us fetch left/right neighbors with
// warp shuffles instead of shared memory. Each warp then rolls through several consecutive
// rows, keeping the vertical 3-row stencil window entirely in registers.
//
// The grid size is guaranteed to be a power of two and > 512, so all chosen strip heights
// divide the problem exactly. That means:
//   - no partially active warps/blocks,
//   - no bounds checks on the output domain itself,
//   - only true grid-edge halo handling remains.
constexpr int kWarpWidth      = 32;
constexpr int kWarpsPerBlock  = 4;
constexpr u32 kFullWarpMask   = 0xFFFFFFFFu;

template <int TILE_ROWS>
__global__ __launch_bounds__(kWarpWidth * kWarpsPerBlock)
void game_of_life_step_kernel(const cell_t* __restrict__ input,
                              cell_t* __restrict__ output,
                              int dim) {
    constexpr int kRowsPerBlock = TILE_ROWS * kWarpsPerBlock;

    const int lane = threadIdx.x;  // 0..31
    const int warp = threadIdx.y;  // 0..kWarpsPerBlock-1

    const bool is_lane0     = (lane == 0);
    const bool is_lane_last = (lane == (kWarpWidth - 1));

    const int x  = (static_cast<int>(blockIdx.x) << 5) + lane;
    const int y0 = static_cast<int>(blockIdx.y) * kRowsPerBlock + warp * TILE_ROWS;

    const bool top_segment    = (y0 == 0);
    const bool bottom_segment = (y0 + TILE_ROWS == dim);

    // Block-level X-edge information. Only lane 0 / lane 31 ever need these halos.
    const bool has_left_halo  = (blockIdx.x != 0u);
    const bool has_right_halo = (blockIdx.x + 1u < gridDim.x);

    const std::size_t stride    = static_cast<std::size_t>(dim);
    const std::size_t start_idx = static_cast<std::size_t>(y0) * stride + static_cast<std::size_t>(x);

    // Vertical rolling window for the center column of this lane.
    u32 above = top_segment ? 0u : static_cast<u32>(input[start_idx - stride]);
    u32 curr  = static_cast<u32>(input[start_idx]);
    // Valid for all launched TILE_ROWS (8/16/32), because every strip starts at y0 <= dim - TILE_ROWS.
    u32 below = static_cast<u32>(input[start_idx + stride]);

    // Rolling halo state for the two boundary lanes of the warp.
    u32 above_w = 0u, curr_w = 0u, below_w = 0u;
    if (is_lane0 && has_left_halo) {
        const std::size_t left_idx = start_idx - 1u;
        above_w = top_segment ? 0u : static_cast<u32>(input[left_idx - stride]);
        curr_w  = static_cast<u32>(input[left_idx]);
        below_w = static_cast<u32>(input[left_idx + stride]);
    }

    u32 above_e = 0u, curr_e = 0u, below_e = 0u;
    if (is_lane_last && has_right_halo) {
        const std::size_t right_idx = start_idx + 1u;
        above_e = top_segment ? 0u : static_cast<u32>(input[right_idx - stride]);
        curr_e  = static_cast<u32>(input[right_idx]);
        below_e = static_cast<u32>(input[right_idx + stride]);
    }

    std::size_t out_idx  = start_idx;
    std::size_t next_idx = start_idx + (stride << 1);  // row y0 + 2

#pragma unroll
    for (int row = 0; row < TILE_ROWS; ++row) {
        // Horizontal neighbors inside the warp come from shuffles.
        u32 aw = __shfl_up_sync(kFullWarpMask, above, 1);
        u32 cw = __shfl_up_sync(kFullWarpMask, curr,  1);
        u32 bw = __shfl_up_sync(kFullWarpMask, below, 1);

        u32 ae = __shfl_down_sync(kFullWarpMask, above, 1);
        u32 ce = __shfl_down_sync(kFullWarpMask, curr,  1);
        u32 be = __shfl_down_sync(kFullWarpMask, below, 1);

        // Replace undefined shuffle results at the two warp edges with real halo values.
        aw = is_lane0     ? above_w : aw;
        cw = is_lane0     ? curr_w  : cw;
        bw = is_lane0     ? below_w : bw;

        ae = is_lane_last ? above_e : ae;
        ce = is_lane_last ? curr_e  : ce;
        be = is_lane_last ? below_e : be;

        const u32 neighbors = aw + above + ae +
                              cw        + ce +
                              bw + below + be;

        // Conway rule:
        //   live if exactly 3 neighbors, or if currently alive and exactly 2 neighbors.
        output[out_idx] = static_cast<cell_t>((neighbors == 3u) | ((neighbors == 2u) & curr));

        if (row + 1 < TILE_ROWS) {
            out_idx += stride;

            // Roll the center-column window.
            above = curr;
            curr  = below;

            // Only the very last strip touching the bottom border needs zero-padding.
            const bool next_valid = !bottom_segment || (row + 2 < TILE_ROWS);
            below = next_valid ? static_cast<u32>(input[next_idx]) : 0u;

            // Roll the warp-edge halo state in lockstep.
            if (is_lane0) {
                above_w = curr_w;
                curr_w  = below_w;
                below_w = (has_left_halo && next_valid) ? static_cast<u32>(input[next_idx - 1u]) : 0u;
            }

            if (is_lane_last) {
                above_e = curr_e;
                curr_e  = below_e;
                below_e = (has_right_halo && next_valid) ? static_cast<u32>(input[next_idx + 1u]) : 0u;
            }

            next_idx += stride;
        }
    }
}

template <int TILE_ROWS>
inline void launch_game_of_life(const cell_t* input, cell_t* output, int dim) {
    constexpr int kRowsPerBlock = TILE_ROWS * kWarpsPerBlock;

    const dim3 block(kWarpWidth, kWarpsPerBlock);
    const dim3 grid(static_cast<unsigned int>(dim / kWarpWidth),
                    static_cast<unsigned int>(dim / kRowsPerBlock));

    game_of_life_step_kernel<TILE_ROWS><<<grid, block>>>(input, output, dim);
}

}  // namespace

extern "C" void run_game_of_life(const bool* input, bool* output, int grid_dimensions) {
    // The caller guarantees power-of-two dimensions > 512.
    // No synchronization here; the caller explicitly handles it.
    const cell_t* in  = reinterpret_cast<const cell_t*>(input);
    cell_t* out       = reinterpret_cast<cell_t*>(output);

    // Strip-height selection balances two effects:
    //   1) larger strips reduce top/bottom halo overhead,
    //   2) smaller strips create more total warps on the smallest legal boards.
    //
    // For 1024^2, TILE_ROWS=8 keeps enough independent warps in flight.
    // For larger boards, taller strips reduce memory traffic.
    if (grid_dimensions <= 1024) {
        launch_game_of_life<8>(in, out, grid_dimensions);
    } else if (grid_dimensions <= 2048) {
        launch_game_of_life<16>(in, out, grid_dimensions);
    } else {
        launch_game_of_life<32>(in, out, grid_dimensions);
    }
}

#include <cuda_runtime.h>
#include <cstdint>

/*
 * Optimized CUDA Conway's Game of Life for square, power-of-two boards allocated with cudaMalloc.
 *
 * Design choices tuned for modern data-center GPUs (A100/H100 class):
 *
 * 1) No shared memory:
 *    Each warp owns a horizontal stripe and walks multiple rows, keeping the 3-row rolling window
 *    in registers. Horizontal neighbors come from warp shuffles, so each input row is loaded once
 *    per tile and then reused directly from registers.
 *
 * 2) Explicit dead halo:
 *    Cells outside the grid are defined as dead. Top/bottom halos are represented by nullptr row
 *    pointers (uniform across the warp); left/right halos are explicit scalars carried only by the
 *    first/last lane of the warp.
 *
 * 3) Two kernels:
 *    - 32-wide, 1-cell-per-lane kernel: used only for the smallest legal board (1024x1024) so the
 *      GPU sees more independent warps.
 *    - 64-wide, 2-cells-per-lane kernel: used for larger boards. It halves shuffle/store overhead
 *      per output cell and uses aligned 16-bit loads/stores for adjacent cells.
 *
 * 4) 64-bit addressing:
 *    Even though grid_dimensions is an int, dim*dim can exceed 2^31 for large boards that still
 *    fit in GPU memory, so all row-stride arithmetic uses size_t.
 *
 * Assumptions intentionally exploited on the hot path:
 * - grid_dimensions is a power of 2 and > 512, so every tile dimension used here divides the board
 *   exactly and no partial-tile handling is needed.
 * - bool storage is byte-sized in CUDA device memory; values written are always 0 or 1.
 */

namespace {

using u8  = unsigned char;
using u16 = std::uint16_t;

static_assert(sizeof(bool) == 1, "This implementation assumes byte-sized bool storage.");

constexpr int      kWarpLanes            = 32;
constexpr int      kLastLane             = kWarpLanes - 1;
constexpr int      kRowsPerWarp          = 16;          // Vertical rolling window depth per warp.
constexpr int      kRowsPerWarpShift     = 4;           // log2(16)
constexpr int      kWarpsPerBlock        = 4;           // 128-thread blocks.
constexpr int      kBlockThreads         = kWarpLanes * kWarpsPerBlock;
constexpr int      kTileHeight           = kRowsPerWarp * kWarpsPerBlock;  // 64 rows per block.
constexpr int      kTileHeightShift      = 6;           // log2(64)
constexpr int      kScalarTileXShift     = 5;           // 32 columns per scalar-kernel block.
constexpr int      kPairedTileXShift     = 6;           // 64 columns per paired-kernel block.
constexpr int      kPairedKernelMinDim   = 2048;        // 1024x1024 uses the scalar kernel.
constexpr int      kMinBlocksPerSM       = 4;
constexpr unsigned kFullMask             = 0xffffffffu;

__device__ __forceinline__ u8 apply_life_rule(const int self, const int neighbors) {
    // self is already 0/1; branchless rule evaluation keeps the inner loop compact.
    return static_cast<u8>((neighbors == 3) | (self & (neighbors == 2)));
}

__device__ __forceinline__ u16 pack_two_bytes(const u8 lo, const u8 hi) {
    // NVIDIA GPUs are little-endian, so low/high byte order maps directly to cells [x, x+1].
    return static_cast<u16>(lo) | (static_cast<u16>(hi) << 8);
}

__device__ __forceinline__ u16 load_u16_aligned(const u8* ptr) {
    // The paired kernel always calls this with 2-byte aligned addresses:
    // - x is even by construction
    // - row stride is even because grid_dimensions is a power of two (> 512)
    u16 value;
    asm volatile("ld.global.u16 %0, [%1];" : "=h"(value) : "l"(ptr));
    return value;
}

__device__ __forceinline__ void store_u16_aligned(u8* ptr, const u16 value) {
    asm volatile("st.global.u16 [%0], %1;" :: "l"(ptr), "h"(value));
}

__device__ __forceinline__ void load_scalar_row(
    const u8* row,
    const int x,
    const bool has_left,
    const bool has_right,
    const bool first_lane,
    const bool last_lane,
    int& center,
    int& left_halo,
    int& right_halo)
{
    center = 0;
    left_halo = 0;
    right_halo = 0;

    if (row != nullptr) {
        center = static_cast<int>(row[x]);
        if (first_lane && has_left) {
            left_halo = static_cast<int>(row[x - 1]);
        }
        if (last_lane && has_right) {
            right_halo = static_cast<int>(row[x + 1]);
        }
    }
}

__device__ __forceinline__ void load_paired_row(
    const u8* row,
    const int x0,
    const bool has_left,
    const bool has_right,
    const bool first_lane,
    const bool last_lane,
    int& a,
    int& b,
    int& left_halo,
    int& right_halo)
{
    a = 0;
    b = 0;
    left_halo = 0;
    right_halo = 0;

    if (row != nullptr) {
        const u16 pair = load_u16_aligned(row + x0);
        a = static_cast<int>(pair & 0x00ffu);
        b = static_cast<int>(pair >> 8);

        if (first_lane && has_left) {
            left_halo = static_cast<int>(row[x0 - 1]);
        }
        if (last_lane && has_right) {
            right_halo = static_cast<int>(row[x0 + 2]);
        }
    }
}

/*
 * Narrow kernel:
 * - One warp covers 32 columns x 16 rows.
 * - One block covers 32 columns x 64 rows.
 * - Chosen only for 1024x1024 so the GPU sees twice as many independent warps as the paired kernel.
 */
__global__ __launch_bounds__(kBlockThreads, kMinBlocksPerSM)
void game_of_life_kernel_scalar(const bool* __restrict__ input,
                                bool* __restrict__ output,
                                int dim)
{
    const u8* __restrict__ in  = reinterpret_cast<const u8*>(input);
    u8* __restrict__ out       = reinterpret_cast<u8*>(output);

    const int lane = static_cast<int>(threadIdx.x);  // 0..31, intentionally one full warp in X.
    const int warp = static_cast<int>(threadIdx.y);  // 0..3
    const bool first_lane = (lane == 0);
    const bool last_lane  = (lane == kLastLane);

    // Power-of-two dimensions let the compiler emit shifts for these tile coordinates.
    const int x      = (static_cast<int>(blockIdx.x) << kScalarTileXShift) + lane;
    const int y_base = (static_cast<int>(blockIdx.y) << kTileHeightShift) + (warp << kRowsPerWarpShift);

    const bool has_left  = (blockIdx.x != 0u);
    const bool has_right = (blockIdx.x + 1u != gridDim.x);

    const size_t stride = static_cast<size_t>(dim);  // 64-bit because dim*dim can exceed 2^31.
    const size_t base   = static_cast<size_t>(y_base) * stride;

    const u8* center_row = in + base;
    const u8* north_row  = (y_base != 0) ? (center_row - stride) : nullptr;
    const u8* south_row  = center_row + stride;  // Valid under the stated tile divisibility constraints.

    int n, nl, nr;
    int c, cl, cr;
    int s, sl, sr;

    load_scalar_row(north_row,  x, has_left, has_right, first_lane, last_lane, n, nl, nr);
    load_scalar_row(center_row, x, has_left, has_right, first_lane, last_lane, c, cl, cr);
    load_scalar_row(south_row,  x, has_left, has_right, first_lane, last_lane, s, sl, sr);

    u8* out_ptr = out + base + static_cast<size_t>(x);
    int next_south_y = y_base + 2;

    #pragma unroll
    for (int i = 0; i < kRowsPerWarp; ++i) {
        int nL = __shfl_up_sync  (kFullMask, n, 1);
        int nR = __shfl_down_sync(kFullMask, n, 1);
        int cL = __shfl_up_sync  (kFullMask, c, 1);
        int cR = __shfl_down_sync(kFullMask, c, 1);
        int sL = __shfl_up_sync  (kFullMask, s, 1);
        int sR = __shfl_down_sync(kFullMask, s, 1);

        if (first_lane) {
            nL = nl;
            cL = cl;
            sL = sl;
        }
        if (last_lane) {
            nR = nr;
            cR = cr;
            sR = sr;
        }

        const int north3    = nL + n + nR;
        const int south3    = sL + s + sR;
        const int center_lr = cL + cR;
        const int neighbors = north3 + south3 + center_lr;

        *out_ptr = apply_life_rule(c, neighbors);
        out_ptr += stride;

        if (i + 1 < kRowsPerWarp) {
            n  = c;  nl = cl;  nr = cr;
            c  = s;  cl = sl;  cr = sr;

            if (next_south_y < dim) {
                south_row += stride;
            } else {
                south_row = nullptr;
            }

            load_scalar_row(south_row, x, has_left, has_right, first_lane, last_lane, s, sl, sr);
            ++next_south_y;
        }
    }
}

/*
 * Wide kernel:
 * - One warp covers 64 columns x 16 rows.
 * - Each lane updates two horizontally adjacent cells per row.
 * - One block covers 64 columns x 64 rows.
 * - Used for >= 2048x2048 because it cuts shuffle/store overhead per output cell while keeping
 *   enough block-level parallelism on large boards.
 */
__global__ __launch_bounds__(kBlockThreads, kMinBlocksPerSM)
void game_of_life_kernel_paired(const bool* __restrict__ input,
                                bool* __restrict__ output,
                                int dim)
{
    const u8* __restrict__ in  = reinterpret_cast<const u8*>(input);
    u8* __restrict__ out       = reinterpret_cast<u8*>(output);

    const int lane = static_cast<int>(threadIdx.x);  // 0..31
    const int warp = static_cast<int>(threadIdx.y);  // 0..3
    const bool first_lane = (lane == 0);
    const bool last_lane  = (lane == kLastLane);

    // x0 is always even; each lane owns cells [x0, x0 + 1].
    const int x0     = (static_cast<int>(blockIdx.x) << kPairedTileXShift) + (lane << 1);
    const int y_base = (static_cast<int>(blockIdx.y) << kTileHeightShift) + (warp << kRowsPerWarpShift);

    const bool has_left  = (blockIdx.x != 0u);
    const bool has_right = (blockIdx.x + 1u != gridDim.x);

    const size_t stride = static_cast<size_t>(dim);
    const size_t base   = static_cast<size_t>(y_base) * stride;

    const u8* center_row = in + base;
    const u8* north_row  = (y_base != 0) ? (center_row - stride) : nullptr;
    const u8* south_row  = center_row + stride;

    int na, nb, nl, nr;
    int ca, cb, cl, cr;
    int sa, sb, sl, sr;

    load_paired_row(north_row,  x0, has_left, has_right, first_lane, last_lane, na, nb, nl, nr);
    load_paired_row(center_row, x0, has_left, has_right, first_lane, last_lane, ca, cb, cl, cr);
    load_paired_row(south_row,  x0, has_left, has_right, first_lane, last_lane, sa, sb, sl, sr);

    u8* out_ptr = out + base + static_cast<size_t>(x0);
    int next_south_y = y_base + 2;

    #pragma unroll
    for (int i = 0; i < kRowsPerWarp; ++i) {
        // For a pair [a, b], the only cross-lane horizontal dependencies are:
        // - previous lane's b (left neighbor of a)
        // - next lane's a     (right neighbor of b)
        int n_prev_b = __shfl_up_sync  (kFullMask, nb, 1);
        int n_next_a = __shfl_down_sync(kFullMask, na, 1);
        int c_prev_b = __shfl_up_sync  (kFullMask, cb, 1);
        int c_next_a = __shfl_down_sync(kFullMask, ca, 1);
        int s_prev_b = __shfl_up_sync  (kFullMask, sb, 1);
        int s_next_a = __shfl_down_sync(kFullMask, sa, 1);

        if (first_lane) {
            n_prev_b = nl;
            c_prev_b = cl;
            s_prev_b = sl;
        }
        if (last_lane) {
            n_next_a = nr;
            c_next_a = cr;
            s_next_a = sr;
        }

        // Two outputs share most of their north/south contributions.
        const int north_pair = na + nb;
        const int south_pair = sa + sb;
        const int shared_ns  = north_pair + south_pair;

        const int center_for_a = c_prev_b + cb;
        const int center_for_b = ca + c_next_a;

        const int neighbors_a = shared_ns + center_for_a + n_prev_b + s_prev_b;
        const int neighbors_b = shared_ns + center_for_b + n_next_a + s_next_a;

        const u8 next_a = apply_life_rule(ca, neighbors_a);
        const u8 next_b = apply_life_rule(cb, neighbors_b);

        store_u16_aligned(out_ptr, pack_two_bytes(next_a, next_b));
        out_ptr += stride;

        if (i + 1 < kRowsPerWarp) {
            na = ca;  nb = cb;  nl = cl;  nr = cr;
            ca = sa;  cb = sb;  cl = sl;  cr = sr;

            if (next_south_y < dim) {
                south_row += stride;
            } else {
                south_row = nullptr;
            }

            load_paired_row(south_row, x0, has_left, has_right, first_lane, last_lane, sa, sb, sl, sr);
            ++next_south_y;
        }
    }
}

}  // namespace

void run_game_of_life(const bool* input, bool* output, int grid_dimensions) {
    // The caller requested pure performance and handles synchronization externally.
    // Kernel launches therefore remain fully asynchronous.

    const dim3 block(kWarpLanes, kWarpsPerBlock, 1);

    // The problem guarantees a power-of-two side length > 512, so all launches tile the domain
    // exactly with shifts rather than ceil-divisions.
    if (grid_dimensions >= kPairedKernelMinDim) {
        const dim3 grid(static_cast<unsigned>(grid_dimensions >> kPairedTileXShift),
                        static_cast<unsigned>(grid_dimensions >> kTileHeightShift),
                        1);
        game_of_life_kernel_paired<<<grid, block>>>(input, output, grid_dimensions);
    } else {
        const dim3 grid(static_cast<unsigned>(grid_dimensions >> kScalarTileXShift),
                        static_cast<unsigned>(grid_dimensions >> kTileHeightShift),
                        1);
        game_of_life_kernel_scalar<<<grid, block>>>(input, output, grid_dimensions);
    }
}

#include <cuda_runtime.h>
#include <cstddef>
#include <cstdint>

namespace {

// Fast path overview:
// - The public API uses one byte per cell (`bool`), but the hot simulation kernel is far faster
//   when the grid is bit-packed.
// - We therefore pack 32 horizontal cells into one uint32_t. Each thread updates one packed word,
//   i.e. 32 cells at once via pure bitwise logic.
// - One warp spans 32 packed words (1024 cells in X). Horizontal neighbor exchange uses warp
//   shuffles; only lane 0 / lane 31 touch cross-segment halo words.
// - Each warp computes two consecutive output rows using rolling row registers. That cuts the
//   average number of packed-row loads from 3/row to 2/row without using shared memory.
// - Neighbor counts are accumulated with a carry-save adder tree, so every logical instruction
//   updates 32 independent cells in parallel.
//
// The problem statement explicitly allows internal data transformations inside run_game_of_life.
// We keep those transformations outside the hot kernel so the simulation step itself is optimized.
//
// A small tiled bool fallback kernel is also provided for robustness:
// - if the caller passes an unsupported tiny grid (< 1024), or
// - if a temporary packed workspace cannot be reserved.
// The packed kernel remains the intended fast path.

constexpr unsigned kFullMask = 0xFFFFFFFFu;

constexpr int kPackThreads         = 256;
constexpr int kPackWarpsPerBlock   = kPackThreads / 32;

constexpr int kRowsPerWarp         = 2;

constexpr int kFallbackBlockX      = 32;
constexpr int kFallbackBlockY      = 8;

// Thread-local cached workspace.
// The API does not expose a stream, so thread-local state is the safest way to reuse temporary
// storage without introducing cross-thread races. Reuse also avoids paying allocator overhead on
// steady-state repeated calls.
struct Workspace {
    uint32_t* data = nullptr;   // actual allocation size is 2 * capacity_words uint32_t's
    size_t    capacity_words = 0;
    int       device = -1;
};

thread_local Workspace g_workspace;
thread_local int g_sm_count = 0;
thread_local int g_sm_device = -1;

__host__ inline int log2_power_of_two(unsigned x) {
    // grid_dimensions is guaranteed to be a power of two, so this exact integer log2 is cheap.
    int r = 0;
    while (x > 1u) {
        x >>= 1;
        ++r;
    }
    return r;
}

__host__ inline int get_sm_count(int current_device) {
    if (g_sm_device != current_device) {
        cudaDeviceGetAttribute(&g_sm_count, cudaDevAttrMultiProcessorCount, current_device);
        g_sm_device = current_device;
    }
    return g_sm_count;
}

__host__ inline bool ensure_workspace(size_t total_words, int current_device) {
    // Device switching is not the hot path, but correctness matters if the host thread changes
    // devices between calls.
    if (g_workspace.device != current_device) {
        if (g_workspace.data != nullptr && g_workspace.device >= 0) {
            const int old_device = g_workspace.device;
            cudaSetDevice(old_device);
            cudaFreeAsync(g_workspace.data, 0);
            cudaSetDevice(current_device);
        }
        g_workspace.data = nullptr;
        g_workspace.capacity_words = 0;
        g_workspace.device = current_device;
    }

    if (g_workspace.capacity_words < total_words) {
        if (g_workspace.data != nullptr) {
            cudaFreeAsync(g_workspace.data, 0);
            g_workspace.data = nullptr;
            g_workspace.capacity_words = 0;
        }

        if (cudaMallocAsync(reinterpret_cast<void**>(&g_workspace.data),
                            2 * total_words * sizeof(uint32_t),
                            0) != cudaSuccess) {
            g_workspace.data = nullptr;
            g_workspace.capacity_words = 0;
            return false;
        }

        g_workspace.capacity_words = total_words;
    }

    return g_workspace.data != nullptr;
}

__device__ __forceinline__ uint32_t load_packed_word(
    const uint32_t* __restrict__ grid,
    int row,
    int x_word,
    int n,
    int words_shift)
{
    // Packed row stride is a power of two, so row addressing is a shift, not a multiply.
    return (static_cast<unsigned>(row) < static_cast<unsigned>(n))
               ? __ldg(grid + ((static_cast<size_t>(row) << words_shift) +
                               static_cast<size_t>(x_word)))
               : 0u;
}

__device__ __forceinline__ unsigned char load_bool_cell(
    const bool* __restrict__ grid,
    int y,
    int x,
    int n)
{
    return (static_cast<unsigned>(y) < static_cast<unsigned>(n) &&
            static_cast<unsigned>(x) < static_cast<unsigned>(n))
               ? static_cast<unsigned char>(grid[static_cast<size_t>(y) * static_cast<size_t>(n) +
                                               static_cast<size_t>(x)])
               : 0u;
}

__device__ __forceinline__ void half_add(
    uint32_t a,
    uint32_t b,
    uint32_t& sum,
    uint32_t& carry)
{
    sum   = a ^ b;
    carry = a & b;
}

__device__ __forceinline__ void full_add(
    uint32_t a,
    uint32_t b,
    uint32_t c,
    uint32_t& sum,
    uint32_t& carry)
{
    // sum   = a ^ b ^ c
    // carry = majority(a, b, c)
    // Written in a form that current NVCC lowers well to LOP3-based code on Ampere/Hopper.
    const uint32_t axb = a ^ b;
    sum   = axb ^ c;
    carry = (a & b) | (axb & c);
}

__device__ __forceinline__ uint32_t evolve_word(
    uint32_t top,
    uint32_t mid,
    uint32_t bot,
    uint32_t top_left_halo,
    uint32_t top_right_halo,
    uint32_t mid_left_halo,
    uint32_t mid_right_halo,
    uint32_t bot_left_halo,
    uint32_t bot_right_halo,
    int lane)
{
    // Each input register holds 32 cells from one row.
    // Bit i corresponds to x = base_x + i. Ballot packing preserves exactly this layout.

    // Neighboring packed words in X come from warp shuffles.
    // Only the two warp-edge lanes substitute cross-segment halo words.
    uint32_t top_left_word  = __shfl_up_sync  (kFullMask, top, 1);
    uint32_t top_right_word = __shfl_down_sync(kFullMask, top, 1);
    uint32_t mid_left_word  = __shfl_up_sync  (kFullMask, mid, 1);
    uint32_t mid_right_word = __shfl_down_sync(kFullMask, mid, 1);
    uint32_t bot_left_word  = __shfl_up_sync  (kFullMask, bot, 1);
    uint32_t bot_right_word = __shfl_down_sync(kFullMask, bot, 1);

    if (lane == 0) {
        top_left_word = top_left_halo;
        mid_left_word = mid_left_halo;
        bot_left_word = bot_left_halo;
    }
    if (lane == 31) {
        top_right_word = top_right_halo;
        mid_right_word = mid_right_halo;
        bot_right_word = bot_right_halo;
    }

    // Construct the 8 aligned neighbor bitboards for all 32 cells in parallel.
    const uint32_t nw = (top << 1) | (top_left_word >> 31);
    const uint32_t nn = top;
    const uint32_t ne = (top >> 1) | (top_right_word << 31);

    const uint32_t ww = (mid << 1) | (mid_left_word >> 31);
    const uint32_t ee = (mid >> 1) | (mid_right_word << 31);

    const uint32_t sw = (bot << 1) | (bot_left_word >> 31);
    const uint32_t ss = bot;
    const uint32_t se = (bot >> 1) | (bot_right_word << 31);

    // Carry-save adder tree for eight 1-bit inputs:
    // count = ones + 2*twos + 4*fours + 8*eights
    uint32_t s0, c0, s1, c1, s2, c2;
    full_add(nw, nn, ne, s0, c0);
    full_add(ww, ee, sw, s1, c1);
    half_add(ss, se, s2, c2);

    uint32_t ones, c3;
    full_add(s0, s1, s2, ones, c3);

    uint32_t twos_partial, fours_partial;
    full_add(c0, c1, c2, twos_partial, fours_partial);

    uint32_t twos, carry_to_fours;
    half_add(twos_partial, c3, twos, carry_to_fours);

    uint32_t fours, eights;
    half_add(carry_to_fours, fours_partial, fours, eights);

    // Conway rule:
    // - survive on count == 2 if currently alive
    // - born on count == 3
    //
    // counts 2 and 3 are exactly the states where:
    //   twos == 1 and fours/eights == 0
    // Then `ones` distinguishes 3 from 2.
    const uint32_t can_live = twos & ~(fours | eights);
    return can_live & (ones | mid);
}

__global__ void pack_bool_to_words(
    const bool* __restrict__ input,
    uint32_t* __restrict__ output,
    int grid_shift,
    int words_shift,
    int words_mask,
    size_t total_words)
{
    // Grid-stride over packed words.
    // One warp packs one output uint32_t from 32 consecutive bool cells.
    const int lane = threadIdx.x & 31;
    const int warp = threadIdx.x >> 5;

    const size_t global_warp = static_cast<size_t>(blockIdx.x) * kPackWarpsPerBlock +
                               static_cast<size_t>(warp);
    const size_t total_warps = static_cast<size_t>(gridDim.x) * kPackWarpsPerBlock;

    for (size_t word_idx = global_warp; word_idx < total_words; word_idx += total_warps) {
        // Because words_per_row is a power of two, row decomposition is shift+mask.
        const int row  = static_cast<int>(word_idx >> words_shift);
        const int word = static_cast<int>(word_idx & static_cast<size_t>(words_mask));

        const size_t base = (static_cast<size_t>(row)  << grid_shift) +
                            (static_cast<size_t>(word) << 5);

        const bool alive = input[base + static_cast<size_t>(lane)];
        const uint32_t packed = __ballot_sync(kFullMask, alive);

        if (lane == 0) {
            output[word_idx] = packed;
        }
    }
}

__global__ void unpack_words_to_bool(
    const uint32_t* __restrict__ input,
    bool* __restrict__ output,
    int grid_shift,
    int words_shift,
    int words_mask,
    size_t total_words)
{
    // Inverse of pack_bool_to_words.
    // Lane 0 loads one packed word, broadcasts it across the warp, and each lane writes one bool.
    const int lane = threadIdx.x & 31;
    const int warp = threadIdx.x >> 5;

    const size_t global_warp = static_cast<size_t>(blockIdx.x) * kPackWarpsPerBlock +
                               static_cast<size_t>(warp);
    const size_t total_warps = static_cast<size_t>(gridDim.x) * kPackWarpsPerBlock;

    for (size_t word_idx = global_warp; word_idx < total_words; word_idx += total_warps) {
        uint32_t packed = 0;
        if (lane == 0) {
            packed = __ldg(input + word_idx);
        }
        packed = __shfl_sync(kFullMask, packed, 0);

        const int row  = static_cast<int>(word_idx >> words_shift);
        const int word = static_cast<int>(word_idx & static_cast<size_t>(words_mask));

        const size_t base = (static_cast<size_t>(row)  << grid_shift) +
                            (static_cast<size_t>(word) << 5);

        output[base + static_cast<size_t>(lane)] = ((packed >> lane) & 1u) != 0;
    }
}

__global__ void game_of_life_packed_kernel(
    const uint32_t* __restrict__ input,
    uint32_t* __restrict__ output,
    int n,
    int words_shift)
{
    // blockDim.x is always 32, so each warp is one contiguous X-segment of 32 packed words.
    // That is 32 * 32 = 1024 cells in X.
    const int segment = static_cast<int>(blockIdx.x);
    const int lane    = threadIdx.x;
    const int warp_y  = threadIdx.y;

    const int x_word = (segment << 5) + lane;
    const int y0     = ((static_cast<int>(blockIdx.y) * static_cast<int>(blockDim.y)) + warp_y)
                       << 1; // two rows per warp

    if (y0 >= n) {
        return;
    }

    const bool has_left_segment  = (segment != 0);
    const bool has_right_segment = (segment + 1 < static_cast<int>(gridDim.x));

    // Initial rolling window for rows y0-1, y0, y0+1.
    uint32_t top = load_packed_word(input, y0 - 1, x_word, n, words_shift);
    uint32_t mid = load_packed_word(input, y0 + 0, x_word, n, words_shift);
    uint32_t bot = load_packed_word(input, y0 + 1, x_word, n, words_shift);

    // Only edge lanes need true halo words from adjacent 32-word segments.
    uint32_t top_left_halo  = 0;
    uint32_t mid_left_halo  = 0;
    uint32_t bot_left_halo  = 0;
    uint32_t top_right_halo = 0;
    uint32_t mid_right_halo = 0;
    uint32_t bot_right_halo = 0;

    if (lane == 0 && has_left_segment) {
        top_left_halo = load_packed_word(input, y0 - 1, x_word - 1, n, words_shift);
        mid_left_halo = load_packed_word(input, y0 + 0, x_word - 1, n, words_shift);
        bot_left_halo = load_packed_word(input, y0 + 1, x_word - 1, n, words_shift);
    }

    if (lane == 31 && has_right_segment) {
        top_right_halo = load_packed_word(input, y0 - 1, x_word + 1, n, words_shift);
        mid_right_halo = load_packed_word(input, y0 + 0, x_word + 1, n, words_shift);
        bot_right_halo = load_packed_word(input, y0 + 1, x_word + 1, n, words_shift);
    }

    const size_t row_stride = static_cast<size_t>(1) << words_shift;
    const size_t out0 = (static_cast<size_t>(y0) << words_shift) + static_cast<size_t>(x_word);

    output[out0] = evolve_word(
        top, mid, bot,
        top_left_halo, top_right_halo,
        mid_left_halo, mid_right_halo,
        bot_left_halo, bot_right_halo,
        lane);

    // Roll the three-row window once to compute the next output row in the same warp.
    if (y0 + 1 < n) {
        top = mid;
        mid = bot;
        bot = load_packed_word(input, y0 + 2, x_word, n, words_shift);

        if (lane == 0) {
            top_left_halo = mid_left_halo;
            mid_left_halo = bot_left_halo;
            bot_left_halo = has_left_segment
                                ? load_packed_word(input, y0 + 2, x_word - 1, n, words_shift)
                                : 0u;
        }

        if (lane == 31) {
            top_right_halo = mid_right_halo;
            mid_right_halo = bot_right_halo;
            bot_right_halo = has_right_segment
                                 ? load_packed_word(input, y0 + 2, x_word + 1, n, words_shift)
                                 : 0u;
        }

        output[out0 + row_stride] = evolve_word(
            top, mid, bot,
            top_left_halo, top_right_halo,
            mid_left_halo, mid_right_halo,
            bot_left_halo, bot_right_halo,
            lane);
    }
}

__global__ void game_of_life_bool_fallback_kernel(
    const bool* __restrict__ input,
    bool* __restrict__ output,
    int n)
{
    // Robust fallback path only. The packed kernel above is the performance path.
    __shared__ unsigned char tile[kFallbackBlockY + 2][kFallbackBlockX + 2];

    const int tx = threadIdx.x;
    const int ty = threadIdx.y;

    const int x = static_cast<int>(blockIdx.x) * kFallbackBlockX + tx;
    const int y = static_cast<int>(blockIdx.y) * kFallbackBlockY + ty;

    const int sx = tx + 1;
    const int sy = ty + 1;

    tile[sy][sx] = load_bool_cell(input, y, x, n);

    if (tx == 0) {
        tile[sy][0] = load_bool_cell(input, y, x - 1, n);
    }
    if (tx == kFallbackBlockX - 1) {
        tile[sy][kFallbackBlockX + 1] = load_bool_cell(input, y, x + 1, n);
    }

    if (ty == 0) {
        tile[0][sx] = load_bool_cell(input, y - 1, x, n);
    }
    if (ty == kFallbackBlockY - 1) {
        tile[kFallbackBlockY + 1][sx] = load_bool_cell(input, y + 1, x, n);
    }

    if (tx == 0 && ty == 0) {
        tile[0][0] = load_bool_cell(input, y - 1, x - 1, n);
    }
    if (tx == kFallbackBlockX - 1 && ty == 0) {
        tile[0][kFallbackBlockX + 1] = load_bool_cell(input, y - 1, x + 1, n);
    }
    if (tx == 0 && ty == kFallbackBlockY - 1) {
        tile[kFallbackBlockY + 1][0] = load_bool_cell(input, y + 1, x - 1, n);
    }
    if (tx == kFallbackBlockX - 1 && ty == kFallbackBlockY - 1) {
        tile[kFallbackBlockY + 1][kFallbackBlockX + 1] =
            load_bool_cell(input, y + 1, x + 1, n);
    }

    __syncthreads();

    if (x < n && y < n) {
        const unsigned sum =
            tile[sy - 1][sx - 1] + tile[sy - 1][sx] + tile[sy - 1][sx + 1] +
            tile[sy    ][sx - 1]                    + tile[sy    ][sx + 1] +
            tile[sy + 1][sx - 1] + tile[sy + 1][sx] + tile[sy + 1][sx + 1];

        const bool alive = tile[sy][sx] != 0;
        output[static_cast<size_t>(y) * static_cast<size_t>(n) + static_cast<size_t>(x)] =
            (sum == 3u) || (alive && sum == 2u);
    }
}

} // anonymous namespace

void run_game_of_life(const bool* input, bool* output, int grid_dimensions) {
    if (input == nullptr || output == nullptr || grid_dimensions <= 0) {
        return;
    }

    const int n = grid_dimensions;

    // The fast packed path assumes at least one full warp of packed words per row.
    // The prompt guarantees n > 512 and power-of-two, so n >= 1024 in the measured path.
    const bool use_fast_path = (n >= 1024);

    const int current_device = []() {
        int d = 0;
        cudaGetDevice(&d);
        return d;
    }();

    if (!use_fast_path) {
        dim3 block(kFallbackBlockX, kFallbackBlockY, 1);
        dim3 grid(static_cast<unsigned>((n + kFallbackBlockX - 1) / kFallbackBlockX),
                  static_cast<unsigned>((n + kFallbackBlockY - 1) / kFallbackBlockY),
                  1);
        game_of_life_bool_fallback_kernel<<<grid, block, 0, 0>>>(input, output, n);
        return;
    }

    // All addressing in the packed path is derived from shifts because n is a power of two.
    const int grid_shift   = log2_power_of_two(static_cast<unsigned>(n));
    const int words_shift  = grid_shift - 5;          // divide row length by 32 cells/word
    const int words_per_row = 1 << words_shift;
    const int words_mask    = words_per_row - 1;
    const int segments_per_row = words_per_row >> 5;  // 32 packed words per warp segment

    const size_t total_words = static_cast<size_t>(n) << words_shift;

    if (!ensure_workspace(total_words, current_device)) {
        // If temporary storage cannot be reserved, fall back to the direct bool kernel.
        dim3 block(kFallbackBlockX, kFallbackBlockY, 1);
        dim3 grid(static_cast<unsigned>((n + kFallbackBlockX - 1) / kFallbackBlockX),
                  static_cast<unsigned>((n + kFallbackBlockY - 1) / kFallbackBlockY),
                  1);
        game_of_life_bool_fallback_kernel<<<grid, block, 0, 0>>>(input, output, n);
        return;
    }

    // Touch only the compact 2*total_words region even if the cached buffer is larger.
    uint32_t* const packed_input  = g_workspace.data;
    uint32_t* const packed_output = g_workspace.data + total_words;

    // Pack/unpack are not the measured hot path, but they are still launched with enough work
    // to saturate the device. A modest block cap keeps launch overhead reasonable.
    const int sms = get_sm_count(current_device);
    const size_t blocks_needed = (total_words + kPackWarpsPerBlock - 1) / kPackWarpsPerBlock;
    const size_t blocks_cap = static_cast<size_t>((sms > 0) ? (sms * 8) : 1);
    int pack_blocks = static_cast<int>((blocks_needed < blocks_cap) ? blocks_needed : blocks_cap);
    if (pack_blocks < 1) {
        pack_blocks = 1;
    }

    pack_bool_to_words<<<pack_blocks, kPackThreads, 0, 0>>>(
        input,
        packed_input,
        grid_shift,
        words_shift,
        words_mask,
        total_words);

    // For the smallest measured grid (1024x1024), there is only one X-segment per row, so we use
    // fewer warps/block to keep the block count high enough to fill the GPU. Larger grids get
    // 8 warps/block for slightly better efficiency.
    const int warps_per_block = (segments_per_row == 1) ? 4 : 8;
    const int rows_per_block  = warps_per_block * kRowsPerWarp;

    dim3 hot_block(32, static_cast<unsigned>(warps_per_block), 1);
    dim3 hot_grid(static_cast<unsigned>(segments_per_row),
                  static_cast<unsigned>((n + rows_per_block - 1) / rows_per_block),
                  1);

    game_of_life_packed_kernel<<<hot_grid, hot_block, 0, 0>>>(
        packed_input,
        packed_output,
        n,
        words_shift);

    unpack_words_to_bool<<<pack_blocks, kPackThreads, 0, 0>>>(
        packed_output,
        output,
        grid_shift,
        words_shift,
        words_mask,
        total_words);

    // Intentionally no synchronization and no host-side error polling here:
    // the caller owns synchronization, and the task explicitly prioritizes kernel performance.
}

#include <cuda_runtime.h>
#include <cstddef>
#include <cstdint>

namespace detail {

// Optimized CUDA Game of Life step for the exact API given.
//
// Rationale for this design:
// - The public API exposes bool grids in device memory, i.e. the natural external format is 1 byte/cell.
//   Repacking to a bit-compressed internal format can be worthwhile for multi-step simulations that stay
//   packed across generations, but for a single public step it adds extra kernels and extra global traffic.
//   This implementation therefore stays in the API-native byte layout.
// - The update is a 3x3 stencil and is memory-bandwidth bound. The kernel minimizes global traffic by
//   staging a tile in shared memory, doing one aligned 4-byte vector load/store per thread in X,
//   and computing two output rows per thread to amortize halo overhead in Y.
// - Cells outside the grid are dead. Edge blocks materialize this exactly by zero-filling halo rows/columns
//   in shared memory, so the hot update path has no per-cell bounds checks.
//
// Targeted for modern datacenter NVIDIA GPUs (A100/H100 class).

using byte = unsigned char;

static_assert(sizeof(bool) == 1, "This implementation relies on 1-byte bool storage.");

constexpr int kThreadsX = 32;
constexpr int kThreadsY = 8;

// Each thread updates 4 horizontally adjacent cells.
constexpr int kCellsPerThreadXShift = 2;
constexpr int kCellsPerThreadX      = 1 << kCellsPerThreadXShift;  // 4

// Each thread updates 2 rows, separated by kThreadsY.
constexpr int kRowsPerThreadY = 2;

// A block covers 128x16 output cells:
//   32 threads in X * 4 cells/thread = 128 cells
//    8 threads in Y * 2 rows/thread  = 16 cells
constexpr int kTileXShift = 7;  // 128
constexpr int kTileYShift = 4;  // 16
constexpr int kTileX      = 1 << kTileXShift;
constexpr int kTileY      = 1 << kTileYShift;

static_assert(kTileX == kThreadsX * kCellsPerThreadX, "Tile/thread X mapping mismatch.");
static_assert(kTileY == kThreadsY * kRowsPerThreadY,  "Tile/thread Y mapping mismatch.");

// Shared-memory row layout (136 bytes total):
//   [0..2]     unused padding
//   [3]        left halo
//   [4..131]   128 in-tile cells
//   [132]      right halo
//   [133..135] unused padding
//
// Starting the tile body at offset 4 means each thread's 4-cell chunk is 4-byte aligned, which enables
// aligned uchar4 vector loads/stores and also gives warp accesses a bank-friendly 4-byte stride.
constexpr int kSharedXOffset = 4;
constexpr int kSharedStride  = kTileX + (2 * kSharedXOffset);  // 136 bytes
constexpr int kSharedRows    = kTileY + 2;                     // + top and bottom halo rows

static_assert((kSharedStride & 3) == 0, "Shared stride must stay 4-byte aligned.");

__device__ __forceinline__ uchar4 load_u8x4(const byte* p) {
    return *reinterpret_cast<const uchar4*>(p);
}

__device__ __forceinline__ void store_u8x4(byte* p, const uchar4 v) {
    *reinterpret_cast<uchar4*>(p) = v;
}

__device__ __forceinline__ uchar4 zero_u8x4() {
    return make_uchar4(0, 0, 0, 0);
}

// Compute 4 horizontally adjacent outputs from 3 shared-memory rows.
// A 6-column sliding window is cheaper than recomputing all 8 neighbors independently for each cell.
__device__ __forceinline__ uchar4 evolve4(const byte* __restrict__ up,
                                          const byte* __restrict__ mid,
                                          const byte* __restrict__ dn) {
    const uint32_t c0 = static_cast<uint32_t>(up[0]) + static_cast<uint32_t>(mid[0]) + static_cast<uint32_t>(dn[0]);
    const uint32_t c1 = static_cast<uint32_t>(up[1]) + static_cast<uint32_t>(mid[1]) + static_cast<uint32_t>(dn[1]);
    const uint32_t c2 = static_cast<uint32_t>(up[2]) + static_cast<uint32_t>(mid[2]) + static_cast<uint32_t>(dn[2]);
    const uint32_t c3 = static_cast<uint32_t>(up[3]) + static_cast<uint32_t>(mid[3]) + static_cast<uint32_t>(dn[3]);
    const uint32_t c4 = static_cast<uint32_t>(up[4]) + static_cast<uint32_t>(mid[4]) + static_cast<uint32_t>(dn[4]);
    const uint32_t c5 = static_cast<uint32_t>(up[5]) + static_cast<uint32_t>(mid[5]) + static_cast<uint32_t>(dn[5]);

    const uint32_t w0 = c0 + c1 + c2;
    const uint32_t w1 = w0 - c0 + c3;
    const uint32_t w2 = w1 - c1 + c4;
    const uint32_t w3 = w2 - c2 + c5;

    const uint32_t self0 = static_cast<uint32_t>(mid[1]);
    const uint32_t self1 = static_cast<uint32_t>(mid[2]);
    const uint32_t self2 = static_cast<uint32_t>(mid[3]);
    const uint32_t self3 = static_cast<uint32_t>(mid[4]);

    const uint32_t n0 = w0 - self0;
    const uint32_t n1 = w1 - self1;
    const uint32_t n2 = w2 - self2;
    const uint32_t n3 = w3 - self3;

    // Branchless Game of Life rule:
    // next = (neighbors == 3) || (alive && neighbors == 2)
    const unsigned char o0 = static_cast<unsigned char>((n0 == 3u) | ((self0 != 0u) & (n0 == 2u)));
    const unsigned char o1 = static_cast<unsigned char>((n1 == 3u) | ((self1 != 0u) & (n1 == 2u)));
    const unsigned char o2 = static_cast<unsigned char>((n2 == 3u) | ((self2 != 0u) & (n2 == 2u)));
    const unsigned char o3 = static_cast<unsigned char>((n3 == 3u) | ((self3 != 0u) & (n3 == 2u)));

    return make_uchar4(o0, o1, o2, o3);
}

__global__ __launch_bounds__(kThreadsX * kThreadsY)
void game_of_life_step_kernel(const byte* __restrict__ in,
                              byte* __restrict__ out,
                              int n) {
    __shared__ __align__(16) byte tile[kSharedRows * kSharedStride];

    const int tx = static_cast<int>(threadIdx.x);
    const int ty = static_cast<int>(threadIdx.y);
    const int bx = static_cast<int>(blockIdx.x);
    const int by = static_cast<int>(blockIdx.y);

    const int last_bx = static_cast<int>(gridDim.x) - 1;
    const int last_by = static_cast<int>(gridDim.y) - 1;

    // Exact shifts are valid because the problem guarantees power-of-two dimensions and we choose power-of-two tiles.
    const int gx0 = (bx << kTileXShift) + (tx << kCellsPerThreadXShift);
    const int gy0 = (by << kTileYShift) + ty;

    const int shx      = kSharedXOffset + (tx << kCellsPerThreadXShift);
    const int sh_left  = shx - 1;
    const int sh_right = shx + kCellsPerThreadX;

    // Shared rows owned by this thread:
    //   sy0 in [1..8]   -> first  8 output rows of the block
    //   sy1 in [9..16]  -> second 8 output rows of the block
    // Shared row 0  is the top halo, row 17 is the bottom halo.
    const int sy0 = ty + 1;
    const int sy1 = sy0 + kThreadsY;

    const bool has_left   = (bx != 0);
    const bool has_right  = (bx != last_bx);
    const bool has_top    = (by != 0);
    const bool has_bottom = (by != last_by);

    const size_t n64 = static_cast<size_t>(n);
    const size_t g0  = static_cast<size_t>(gy0) * n64 + static_cast<size_t>(gx0);
    const size_t g1  = g0 + static_cast<size_t>(kThreadsY) * n64;  // second row handled by this thread

    byte* const s0 = tile + sy0 * kSharedStride;
    byte* const s1 = tile + sy1 * kSharedStride;

    // Load the two center rows handled by this thread.
    store_u8x4(s0 + shx, load_u8x4(in + g0));
    store_u8x4(s1 + shx, load_u8x4(in + g1));

    // Load left/right halo bytes for both rows.
    if (tx == 0) {
        s0[sh_left] = has_left ? in[g0 - 1] : 0;
        s1[sh_left] = has_left ? in[g1 - 1] : 0;
    }
    if (tx == kThreadsX - 1) {
        s0[sh_right] = has_right ? in[g0 + kCellsPerThreadX] : 0;
        s1[sh_right] = has_right ? in[g1 + kCellsPerThreadX] : 0;
    }

    // Top halo row: only the ty==0 warp needs to load it.
    if (ty == 0) {
        byte* const s_top = tile;
        if (has_top) {
            const size_t g_top = g0 - n64;
            store_u8x4(s_top + shx, load_u8x4(in + g_top));
            if (tx == 0) {
                s_top[sh_left] = has_left ? in[g_top - 1] : 0;
            }
            if (tx == kThreadsX - 1) {
                s_top[sh_right] = has_right ? in[g_top + kCellsPerThreadX] : 0;
            }
        } else {
            store_u8x4(s_top + shx, zero_u8x4());
            if (tx == 0) {
                s_top[sh_left] = 0;
            }
            if (tx == kThreadsX - 1) {
                s_top[sh_right] = 0;
            }
        }
    }

    // Bottom halo row: only the ty==7 warp needs to load it.
    if (ty == kThreadsY - 1) {
        byte* const s_bottom = tile + (kTileY + 1) * kSharedStride;
        if (has_bottom) {
            const size_t g_bottom = g1 + n64;
            store_u8x4(s_bottom + shx, load_u8x4(in + g_bottom));
            if (tx == 0) {
                s_bottom[sh_left] = has_left ? in[g_bottom - 1] : 0;
            }
            if (tx == kThreadsX - 1) {
                s_bottom[sh_right] = has_right ? in[g_bottom + kCellsPerThreadX] : 0;
            }
        } else {
            store_u8x4(s_bottom + shx, zero_u8x4());
            if (tx == 0) {
                s_bottom[sh_left] = 0;
            }
            if (tx == kThreadsX - 1) {
                s_bottom[sh_right] = 0;
            }
        }
    }

    __syncthreads();

    // All boundary handling is now encoded in the halo bytes, so the update path below is the same for
    // interior and edge cells: no per-cell bounds checks, just stencil arithmetic on shared memory.
    const byte* const up0  = tile + (sy0 - 1) * kSharedStride + sh_left;
    const byte* const mid0 = up0 + kSharedStride;
    const byte* const dn0  = mid0 + kSharedStride;

    const byte* const up1  = tile + (sy1 - 1) * kSharedStride + sh_left;
    const byte* const mid1 = up1 + kSharedStride;
    const byte* const dn1  = mid1 + kSharedStride;

    store_u8x4(out + g0, evolve4(up0, mid0, dn0));
    store_u8x4(out + g1, evolve4(up1, mid1, dn1));
}

}  // namespace detail

void run_game_of_life(const bool* input, bool* output, int grid_dimensions) {
    // Problem guarantees:
    // - square grid
    // - power-of-two dimensions
    // - dimensions > 512
    //
    // Therefore grid_dimensions is always divisible by both 128 and 16, so this launch covers the
    // full grid exactly with no partial blocks. The caller manages synchronization, so this function
    // only enqueues the kernel and performs no extra sync/error-checking work on the hot path.
    const dim3 block(detail::kThreadsX, detail::kThreadsY);
    const dim3 grid(static_cast<unsigned int>(grid_dimensions) >> detail::kTileXShift,
                    static_cast<unsigned int>(grid_dimensions) >> detail::kTileYShift);

    detail::game_of_life_step_kernel<<<grid, block>>>(
        reinterpret_cast<const detail::byte*>(input),
        reinterpret_cast<detail::byte*>(output),
        grid_dimensions);
}

#include <cuda_runtime.h>

namespace {

/*
  Optimized one-step Conway's Game of Life for large square grids on modern NVIDIA GPUs.

  Performance-oriented design:
  - Split the problem into a large interior and a tiny boundary. The boundary is O(n),
    so it is handled by a separate simple kernel to keep the hot interior path free of
    per-cell boundary checks.
  - The interior kernel is warp-centric:
      * each warp covers 32 consecutive x positions,
      * horizontal neighbors are exchanged with warp shuffles,
      * each thread walks a short strip of rows in y and keeps a 3-row rolling window
        entirely in registers.
    This keeps global memory traffic close to the minimum while avoiding shared-memory
    tiling for byte cells (which would otherwise either bank-conflict or force a 4x
    expansion to 32-bit storage).
  - grid.y is capped and processed with a grid-stride loop, so very large grids do not
    launch millions of tiny blocks.

  Storage note:
  - The caller supplies bool buffers in device memory. CUDA device bool storage is 1 byte,
    so the buffers are safely aliased as bytes here and the kernels write canonical 0/1.
*/

static_assert(sizeof(bool) == 1, "This implementation assumes 1-byte bool storage.");

using cell_t = unsigned char;

constexpr int      kWarpSize        = 32;
constexpr int      kWarpsPerBlock   = 4;    // 128 threads/block keeps enough blocks even at 1024x1024.
constexpr int      kInteriorThreads = kWarpSize * kWarpsPerBlock;
constexpr int      kRowsPerStrip    = 16;   // Good reuse/occupancy balance on A100/H100 class GPUs.
constexpr int      kBoundaryThreads = 256;
constexpr int      kMaxGridY        = 128;  // Cap grid.y; the interior kernel grid-strides in y.
constexpr unsigned kFullMask        = 0xffffffffu;

__device__ __forceinline__ cell_t apply_life_rule(unsigned int neighbors, unsigned int self) {
    // neighbors excludes self and self is stored as 0/1.
    return static_cast<cell_t>((neighbors == 3u) | (self & (neighbors == 2u)));
}

__launch_bounds__(kInteriorThreads)
__global__ void life_interior_strip_kernel(const cell_t* __restrict__ in,
                                           cell_t* __restrict__ out,
                                           int n) {
    // Legal widths are powers of two > 512, so kInteriorThreads=128 divides every legal n.
    const int tid      = static_cast<int>(threadIdx.x);
    const int lane     = tid & (kWarpSize - 1);
    const bool lane0   = (lane == 0);
    const bool lane31  = (lane == (kWarpSize - 1));

    const int x        = static_cast<int>(blockIdx.x) * kInteriorThreads + tid;
    const int last     = n - 1;

    // Most threads are interior cells; only the global left/right border lanes suppress stores.
    const bool write_cell = (x > 0) && (x < last);

    // Only warp edge lanes need cross-warp halo columns from global memory.
    const bool need_left  = lane0  && (x > 0);
    const bool need_right = lane31 && (x < last);

    const size_t pitch    = static_cast<size_t>(n);
    const size_t x64      = static_cast<size_t>(x);
    const int    stride   = n;
    const int    stride2  = n + n;
    const int    y_stride = static_cast<int>(gridDim.y) * kRowsPerStrip;

    for (int y0 = static_cast<int>(blockIdx.y) * kRowsPerStrip + 1; y0 < last; y0 += y_stride) {
        const int remaining  = last - y0;
        const int valid_rows = (remaining < kRowsPerStrip) ? remaining : kRowsPerStrip;

        const size_t base = static_cast<size_t>(y0 - 1) * pitch + x64;

        // p points at row (y-1), current x. q points at output row y, current x.
        const cell_t* p = in  + base;
        cell_t*       q = out + base + pitch;

        // Rolling 3-row window in registers.
        unsigned int r0 = static_cast<unsigned int>(p[0]);
        unsigned int r1 = static_cast<unsigned int>(p[stride]);
        unsigned int r2 = static_cast<unsigned int>(p[stride2]);

        // Cached cross-warp halos for lane 0 / lane 31. They stay zero on the true grid borders.
        const cell_t* lp = nullptr;
        const cell_t* rp = nullptr;
        unsigned int  l0 = 0, l1 = 0, l2 = 0;
        unsigned int rr0 = 0, rr1 = 0, rr2 = 0;

        if (need_left) {
            lp = p - 1;
            l0 = static_cast<unsigned int>(lp[0]);
            l1 = static_cast<unsigned int>(lp[stride]);
            l2 = static_cast<unsigned int>(lp[stride2]);
        }
        if (need_right) {
            rp  = p + 1;
            rr0 = static_cast<unsigned int>(rp[0]);
            rr1 = static_cast<unsigned int>(rp[stride]);
            rr2 = static_cast<unsigned int>(rp[stride2]);
        }

        #pragma unroll
        for (int i = 0; i < kRowsPerStrip; ++i) {
            if (i < valid_rows) {
                // Horizontal neighbors come from the warp. Only the two warp-edge lanes override
                // with the cached cross-warp halo values loaded above.
                unsigned int up_l  = __shfl_up_sync  (kFullMask, r0, 1);
                unsigned int up_r  = __shfl_down_sync(kFullMask, r0, 1);
                unsigned int mid_l = __shfl_up_sync  (kFullMask, r1, 1);
                unsigned int mid_r = __shfl_down_sync(kFullMask, r1, 1);
                unsigned int dn_l  = __shfl_up_sync  (kFullMask, r2, 1);
                unsigned int dn_r  = __shfl_down_sync(kFullMask, r2, 1);

                if (lane0) {
                    up_l  = l0;
                    mid_l = l1;
                    dn_l  = l2;
                }
                if (lane31) {
                    up_r  = rr0;
                    mid_r = rr1;
                    dn_r  = rr2;
                }

                if (write_cell) {
                    const unsigned int neighbors =
                        (up_l + r0 + up_r) +
                        (mid_l + mid_r) +
                        (dn_l + r2 + dn_r);

                    q[0] = apply_life_rule(neighbors, r1);
                }
            }

            // Advance the rolling window when another valid row remains in this strip.
            if ((i + 1) < kRowsPerStrip && (i + 1) < valid_rows) {
                p += stride;
                q += stride;

                r0 = r1;
                r1 = r2;
                r2 = static_cast<unsigned int>(p[stride2]);

                if (need_left) {
                    lp += stride;
                    l0  = l1;
                    l1  = l2;
                    l2  = static_cast<unsigned int>(lp[stride2]);
                }
                if (need_right) {
                    rp  += stride;
                    rr0 = rr1;
                    rr1 = rr2;
                    rr2 = static_cast<unsigned int>(rp[stride2]);
                }
            }
        }
    }
}

__global__ void life_boundary_kernel(const cell_t* __restrict__ in,
                                     cell_t* __restrict__ out,
                                     int n) {
    // One thread per boundary cell. This is O(n), so simplicity is preferred over further tuning.
    const int t            = static_cast<int>(blockIdx.x) * kBoundaryThreads + static_cast<int>(threadIdx.x);
    const int border_count = (n << 2) - 4;
    if (t >= border_count) {
        return;
    }

    const int last            = n - 1;
    const int two_n           = n << 1;
    const int three_n_minus_2 = two_n + n - 2;

    int x, y;
    if (t < n) {
        x = t;
        y = 0;
    } else if (t < two_n) {
        x = t - n;
        y = last;
    } else if (t < three_n_minus_2) {
        x = 0;
        y = t - two_n + 1;   // Left column, excluding corners.
    } else {
        x = last;
        y = t - three_n_minus_2 + 1; // Right column, excluding corners.
    }

    const size_t pitch = static_cast<size_t>(n);
    const size_t idx   = static_cast<size_t>(y) * pitch + static_cast<size_t>(x);
    const int    stride = n;

    const cell_t* p = in + idx;

    const bool has_left  = (x > 0);
    const bool has_right = (x < last);
    const bool has_up    = (y > 0);
    const bool has_down  = (y < last);

    unsigned int neighbors = 0;

    if (has_up) {
        const cell_t* pu = p - stride;
        if (has_left)  neighbors += static_cast<unsigned int>(pu[-1]);
        neighbors += static_cast<unsigned int>(pu[0]);
        if (has_right) neighbors += static_cast<unsigned int>(pu[1]);
    }

    if (has_left)  neighbors += static_cast<unsigned int>(p[-1]);
    if (has_right) neighbors += static_cast<unsigned int>(p[1]);

    if (has_down) {
        const cell_t* pd = p + stride;
        if (has_left)  neighbors += static_cast<unsigned int>(pd[-1]);
        neighbors += static_cast<unsigned int>(pd[0]);
        if (has_right) neighbors += static_cast<unsigned int>(pd[1]);
    }

    out[idx] = apply_life_rule(neighbors, static_cast<unsigned int>(p[0]));
}

} // anonymous namespace

void run_game_of_life(const bool* input, bool* output, int grid_dimensions) {
    // Standard double-buffered semantics are assumed: input and output must not alias.
    // The caller owns all synchronization; this function intentionally performs no sync
    // and does not inject host-side launch/error checks into the hot path.

    const cell_t* in  = reinterpret_cast<const cell_t*>(input);
    cell_t*       out = reinterpret_cast<cell_t*>(output);

    const int x_blocks = grid_dimensions / kInteriorThreads;

    // The interior kernel grid-strides in y, so grid.y is capped to avoid excessive block count
    // on very large grids while still keeping plenty of concurrency on A100/H100 class devices.
    const int total_strips = (grid_dimensions - 2 + kRowsPerStrip - 1) / kRowsPerStrip;
    const int y_blocks     = (total_strips < kMaxGridY) ? total_strips : kMaxGridY;

    life_interior_strip_kernel<<<dim3(static_cast<unsigned>(x_blocks), static_cast<unsigned>(y_blocks), 1),
                                 dim3(static_cast<unsigned>(kInteriorThreads), 1, 1)>>>(in, out, grid_dimensions);

    const int border_count   = (grid_dimensions << 2) - 4;
    const int boundary_blocks = (border_count + kBoundaryThreads - 1) / kBoundaryThreads;

    life_boundary_kernel<<<boundary_blocks, kBoundaryThreads>>>(in, out, grid_dimensions);
}

#include <cuda_runtime.h>
#include <cstddef>
#include <cstdint>

namespace {

// High-performance single-step Conway's Game of Life for square power-of-two grids.
//
// Design choices tuned for modern datacenter GPUs (A100/H100 class):
// - 32x16 thread blocks:
//   * blockDim.x == 32 means each warp owns exactly one tile row.
//   * this lets horizontal neighbors come from warp shuffles instead of shared memory.
// - Shared memory stores 32-bit values, not bytes:
//   * the input/output grid is byte-sized (bool), but 8-bit shared-memory accesses create
//     severe bank conflicts. Staging cells as uint32_t avoids that.
// - Interior blocks use a fast path with no per-load bounds checks.
//   Only the outermost ring of blocks executes boundary-safe zero-padding logic.
// - Linear indexing uses 64 bits because n*n can exceed 2^31 even when both grids still fit
//   in GPU memory on large devices.

constexpr int BLOCK_X = 32;
constexpr int BLOCK_Y = 16;
constexpr int BLOCK_X_LOG2 = 5;
constexpr int BLOCK_Y_LOG2 = 4;
constexpr int TILE_W = BLOCK_X + 2;
constexpr int TILE_H = BLOCK_Y + 2;
constexpr unsigned FULL_MASK = 0xFFFFFFFFu;

static_assert(BLOCK_X == 32, "This kernel assumes one warp per block row.");
static_assert(sizeof(bool) == 1, "CUDA bool is expected to be byte-sized.");

__device__ __forceinline__ uint32_t load_cell(const uint8_t* ptr) {
    // Input bools are represented as bytes in device memory; reading through uint8_t is valid
    // and keeps the hot path simple.
    return static_cast<uint32_t>(*ptr);
}

// 32x16 = 512 threads/block. launch_bounds encourages the compiler to stay within a register
// footprint that still allows 4 such blocks/SM on A100/H100-class GPUs.
__global__ __launch_bounds__(BLOCK_X * BLOCK_Y, 4)
void game_of_life_kernel(const uint8_t* __restrict__ input,
                         bool* __restrict__ output,
                         int n) {
    __shared__ uint32_t tile[TILE_H][TILE_W];

    const int tx = threadIdx.x;
    const int ty = threadIdx.y;
    const int bx = static_cast<int>(blockIdx.x);
    const int by = static_cast<int>(blockIdx.y);

    const int gx = (bx << BLOCK_X_LOG2) + tx;
    const int gy = (by << BLOCK_Y_LOG2) + ty;

    const ptrdiff_t pitch = static_cast<ptrdiff_t>(n);
    const size_t idx = static_cast<size_t>(gy) * static_cast<size_t>(pitch) + static_cast<size_t>(gx);
    const uint8_t* const in_ptr = input + idx;

    // Keep the current cell in a register for the entire kernel; neighbors in y come from shared
    // memory, neighbors in x come from warp shuffles.
    const uint32_t self = load_cell(in_ptr);
    tile[ty + 1][tx + 1] = self;

    // Uniform (block-wide) branch: only the outermost ring of blocks needs boundary handling.
    const bool interior_block =
        (bx > 0) &
        (by > 0) &
        (bx + 1 < static_cast<int>(gridDim.x)) &
        (by + 1 < static_cast<int>(gridDim.y));

    if (interior_block) {
        // Fast path: all halo loads are in-bounds.
        if (tx == 0) {
            tile[ty + 1][0] = load_cell(in_ptr - 1);
        }
        if (tx == BLOCK_X - 1) {
            tile[ty + 1][BLOCK_X + 1] = load_cell(in_ptr + 1);
        }
        if (ty == 0) {
            tile[0][tx + 1] = load_cell(in_ptr - pitch);
        }
        if (ty == BLOCK_Y - 1) {
            tile[BLOCK_Y + 1][tx + 1] = load_cell(in_ptr + pitch);
        }
        if (tx == 0 && ty == 0) {
            tile[0][0] = load_cell(in_ptr - pitch - 1);
        }
        if (tx == BLOCK_X - 1 && ty == 0) {
            tile[0][BLOCK_X + 1] = load_cell(in_ptr - pitch + 1);
        }
        if (tx == 0 && ty == BLOCK_Y - 1) {
            tile[BLOCK_Y + 1][0] = load_cell(in_ptr + pitch - 1);
        }
        if (tx == BLOCK_X - 1 && ty == BLOCK_Y - 1) {
            tile[BLOCK_Y + 1][BLOCK_X + 1] = load_cell(in_ptr + pitch + 1);
        }
    } else {
        // Boundary-safe path: outside-the-grid cells are treated as dead (0).
        if (tx == 0) {
            tile[ty + 1][0] = (gx > 0) ? load_cell(in_ptr - 1) : 0u;
        }
        if (tx == BLOCK_X - 1) {
            tile[ty + 1][BLOCK_X + 1] = (gx + 1 < n) ? load_cell(in_ptr + 1) : 0u;
        }
        if (ty == 0) {
            tile[0][tx + 1] = (gy > 0) ? load_cell(in_ptr - pitch) : 0u;
        }
        if (ty == BLOCK_Y - 1) {
            tile[BLOCK_Y + 1][tx + 1] = (gy + 1 < n) ? load_cell(in_ptr + pitch) : 0u;
        }
        if (tx == 0 && ty == 0) {
            tile[0][0] = (gx > 0 && gy > 0) ? load_cell(in_ptr - pitch - 1) : 0u;
        }
        if (tx == BLOCK_X - 1 && ty == 0) {
            tile[0][BLOCK_X + 1] = (gx + 1 < n && gy > 0) ? load_cell(in_ptr - pitch + 1) : 0u;
        }
        if (tx == 0 && ty == BLOCK_Y - 1) {
            tile[BLOCK_Y + 1][0] = (gx > 0 && gy + 1 < n) ? load_cell(in_ptr + pitch - 1) : 0u;
        }
        if (tx == BLOCK_X - 1 && ty == BLOCK_Y - 1) {
            tile[BLOCK_Y + 1][BLOCK_X + 1] =
                (gx + 1 < n && gy + 1 < n) ? load_cell(in_ptr + pitch + 1) : 0u;
        }
    }

    __syncthreads();

    // After staging:
    // - north/south center-column values come from shared memory
    // - left/right neighbors come from warp shuffles
    // - the current cell stays in the 'self' register
    const uint32_t north = tile[ty][tx + 1];
    const uint32_t south = tile[ty + 2][tx + 1];

    uint32_t north_l = __shfl_up_sync(FULL_MASK, north, 1);
    uint32_t north_r = __shfl_down_sync(FULL_MASK, north, 1);
    uint32_t self_l  = __shfl_up_sync(FULL_MASK, self, 1);
    uint32_t self_r  = __shfl_down_sync(FULL_MASK, self, 1);
    uint32_t south_l = __shfl_up_sync(FULL_MASK, south, 1);
    uint32_t south_r = __shfl_down_sync(FULL_MASK, south, 1);

    // Warp edges pull horizontal halo values from shared memory.
    if (tx == 0) {
        north_l = tile[ty][0];
        self_l  = tile[ty + 1][0];
        south_l = tile[ty + 2][0];
    }
    if (tx == BLOCK_X - 1) {
        north_r = tile[ty][BLOCK_X + 1];
        self_r  = tile[ty + 1][BLOCK_X + 1];
        south_r = tile[ty + 2][BLOCK_X + 1];
    }

    const int neighbor_count = static_cast<int>(
        north_l + north + north_r +
        self_l            + self_r +
        south_l + south + south_r);

    // Branch-free Game of Life rule evaluation:
    // next = (neighbors == 3) || (self && neighbors == 2)
    const uint32_t next =
        static_cast<uint32_t>(neighbor_count == 3) |
        (static_cast<uint32_t>(neighbor_count == 2) & self);

    output[idx] = static_cast<bool>(next);
}

}  // namespace

void run_game_of_life(const bool* input, bool* output, int grid_dimensions) {
    // The problem guarantees a power-of-two square board with dimension > 512.
    // Therefore these 32x16 tiles divide the board exactly: no partial blocks are needed.
    const dim3 block(BLOCK_X, BLOCK_Y);
    const dim3 grid(static_cast<unsigned int>(grid_dimensions >> BLOCK_X_LOG2),
                    static_cast<unsigned int>(grid_dimensions >> BLOCK_Y_LOG2));

    const auto* const input_bytes = reinterpret_cast<const uint8_t*>(input);

    // Intentionally no synchronization and no error-checking here; the caller owns both.
    game_of_life_kernel<<<grid, block>>>(input_bytes, output, grid_dimensions);
}

#include <cuda_runtime.h>
#include <cstdint>

namespace {

using u32 = std::uint32_t;
using u64 = std::uint64_t;

static_assert(sizeof(bool) == 1, "This implementation assumes 1-byte bool storage.");

constexpr u32 kFullWarpMask         = 0xFFFFFFFFu;
constexpr int kWarpWidthLog2        = 5;
constexpr int kWarpWidth            = 1 << kWarpWidthLog2;   // 32 cells, exactly one warp wide.
constexpr int kRowsPerWarpLog2      = 1;
constexpr int kRowsPerWarp          = 1 << kRowsPerWarpLog2; // 2 output rows per warp.
constexpr int kWarpsPerBlockLog2    = 4;
constexpr int kWarpsPerBlock        = 1 << kWarpsPerBlockLog2; // 16 warps/block.
constexpr int kTileRowsLog2         = kRowsPerWarpLog2 + kWarpsPerBlockLog2;
constexpr int kTileRows             = 1 << kTileRowsLog2;    // 32 rows/block.
constexpr u64 kMax32BitElementCount = u64{1} << 32;

// Adds a 1-bit mask into a bit-sliced 4-bit counter.
// For every bit position/cell independently, (b3:b2:b1:b0) stores the current
// neighbor count in binary. One call updates 32 counters in parallel.
__device__ __forceinline__ void add_mask_to_counter(
    const u32 x,
    u32& b0,
    u32& b1,
    u32& b2,
    u32& b3)
{
    const u32 c0 = b0 & x;
    b0 ^= x;
    const u32 c1 = b1 & c0;
    b1 ^= c0;
    const u32 c2 = b2 & c1;
    b2 ^= c1;
    b3 ^= c2;
}

// Computes the next-state bitmask for 32 cells at once.
//
// north/center/south are the packed 32-bit rows.
// *_lr packs the single horizontal halo bits for the corresponding row:
//   bit 0 -> cell immediately left  of the 32-cell segment
//   bit 1 -> cell immediately right of the 32-cell segment
//
// Outside-the-grid cells are represented by zero halo bits / zero halo rows.
__device__ __forceinline__ u32 compute_next_mask(
    const u32 north,
    const u32 center,
    const u32 south,
    const u32 north_lr,
    const u32 center_lr,
    const u32 south_lr)
{
    const u32 nw = (north << 1) | (north_lr & 1u);
    const u32 nn = north;
    const u32 ne = (north >> 1) | ((north_lr & 2u) << 30);

    const u32 ww = (center << 1) | (center_lr & 1u);
    const u32 ee = (center >> 1) | ((center_lr & 2u) << 30);

    const u32 sw = (south << 1) | (south_lr & 1u);
    const u32 ss = south;
    const u32 se = (south >> 1) | ((south_lr & 2u) << 30);

    u32 b0 = 0;
    u32 b1 = 0;
    u32 b2 = 0;
    u32 b3 = 0;

    add_mask_to_counter(nw, b0, b1, b2, b3);
    add_mask_to_counter(nn, b0, b1, b2, b3);
    add_mask_to_counter(ne, b0, b1, b2, b3);
    add_mask_to_counter(ww, b0, b1, b2, b3);
    add_mask_to_counter(ee, b0, b1, b2, b3);
    add_mask_to_counter(sw, b0, b1, b2, b3);
    add_mask_to_counter(ss, b0, b1, b2, b3);
    add_mask_to_counter(se, b0, b1, b2, b3);

    // Counts 2 and 3 share: b1 = 1 and b2 = b3 = 0.
    // Within that subset, b0 distinguishes:
    //   b0 = 0 -> count == 2  => survives only if currently alive
    //   b0 = 1 -> count == 3  => next state is alive regardless
    const u32 common_2_or_3 = (~(b2 | b3)) & b1;
    return common_2_or_3 & (center | b0);
}

// grid_dimensions is guaranteed to be a power of two, so log2 is trivial and
// computed once on the host. This is intentionally kept out of the hot kernel.
inline int log2_pow2(int x)
{
    unsigned int v = static_cast<unsigned int>(x);
    int l = 0;
    while (v > 1u) {
        v >>= 1;
        ++l;
    }
    return l;
}

// High-throughput single-step Game of Life kernel.
//
// Mapping:
// - blockDim = (32, 16)
// - blockDim.x is exactly one warp, so each threadIdx.y slice is a full warp.
// - Each warp loads two consecutive 32-cell row segments and turns them into two
//   32-bit masks with __ballot_sync.
// - 16 warps/block x 2 rows/warp = one 32x32 cell tile per block.
// - Shared memory holds packed row masks for the tile plus one halo row above
//   and below; horizontal halo cells are packed into 2-bit row_halo values.
// - The Life rule is evaluated with bit-sliced counters, so integer bitwise ops
//   update 32 cells at a time.
//
// The public API is bool-based, but the input is read as raw bytes. This keeps
// input loads on simple byte accesses while accepting any non-zero true encoding.
// Output is written as bool for full type correctness.
template <typename IndexT>
__global__ __launch_bounds__(kWarpWidth * kWarpsPerBlock)
void life_step_kernel(
    const unsigned char* __restrict__ input,
    bool* __restrict__ output,
    int dim_log2)
{
    __shared__ u32 row_masks[kTileRows + 2];
    __shared__ u32 row_halo[kTileRows + 2]; // bit0 = left halo, bit1 = right halo

    const int lane          = threadIdx.x; // 0..31
    const int warp_row_pair = threadIdx.y; // 0..15

    const bool has_left   = (blockIdx.x > 0);
    const bool has_right  = (blockIdx.x + 1 < gridDim.x);
    const bool has_top    = (blockIdx.y > 0);
    const bool has_bottom = (blockIdx.y + 1 < gridDim.y);

    // Exploit the power-of-two board dimension: all row addressing is done with shifts.
    const IndexT stride         = IndexT{1} << dim_log2;
    const IndexT x_base         = static_cast<IndexT>(blockIdx.x) << kWarpWidthLog2;
    const IndexT block_row_base = static_cast<IndexT>(blockIdx.y) << (kTileRowsLog2 + dim_log2);

    const int    local_row0  = warp_row_pair << kRowsPerWarpLog2; // 2 * warp_row_pair
    const int    shared_row0 = local_row0 + 1;
    const int    shared_row1 = shared_row0 + 1;
    const IndexT row0_base   = block_row_base + (static_cast<IndexT>(local_row0) << dim_log2) + x_base;
    const IndexT row1_base   = row0_base + stride;

    // Pack two consecutive rows handled by this warp.
    const u32 mask0 = __ballot_sync(kFullWarpMask, input[row0_base + lane] != 0);
    const u32 mask1 = __ballot_sync(kFullWarpMask, input[row1_base + lane] != 0);

    // Each warp publishes its two packed rows and their horizontal halo bits.
    u32 packed_center_lr = 0;
    if (lane == 0) {
        u32 center_lr0 = 0;
        u32 center_lr1 = 0;

        if (has_left) {
            center_lr0 |= static_cast<u32>(input[row0_base - 1] != 0);
            center_lr1 |= static_cast<u32>(input[row1_base - 1] != 0);
        }
        if (has_right) {
            center_lr0 |= static_cast<u32>(input[row0_base + kWarpWidth] != 0) << 1;
            center_lr1 |= static_cast<u32>(input[row1_base + kWarpWidth] != 0) << 1;
        }

        row_masks[shared_row0] = mask0;
        row_masks[shared_row1] = mask1;
        row_halo[shared_row0]  = center_lr0;
        row_halo[shared_row1]  = center_lr1;

        packed_center_lr = center_lr0 | (center_lr1 << 2);
    }
    packed_center_lr = __shfl_sync(kFullWarpMask, packed_center_lr, 0);

    const u32 center_lr0 = packed_center_lr & 0x3u;
    const u32 center_lr1 = (packed_center_lr >> 2) & 0x3u;

    // Top halo row for the block.
    if (warp_row_pair == 0) {
        if (has_top) {
            const IndexT top_base = row0_base - stride;
            const u32 top_mask = __ballot_sync(kFullWarpMask, input[top_base + lane] != 0);

            if (lane == 0) {
                u32 top_lr = 0;
                if (has_left) {
                    top_lr |= static_cast<u32>(input[top_base - 1] != 0);
                }
                if (has_right) {
                    top_lr |= static_cast<u32>(input[top_base + kWarpWidth] != 0) << 1;
                }
                row_masks[0] = top_mask;
                row_halo[0]  = top_lr;
            }
        } else if (lane == 0) {
            row_masks[0] = 0;
            row_halo[0]  = 0;
        }
    }

    // Bottom halo row for the block.
    if (warp_row_pair == kWarpsPerBlock - 1) {
        if (has_bottom) {
            const IndexT bottom_base = row1_base + stride;
            const u32 bottom_mask = __ballot_sync(kFullWarpMask, input[bottom_base + lane] != 0);

            if (lane == 0) {
                u32 bottom_lr = 0;
                if (has_left) {
                    bottom_lr |= static_cast<u32>(input[bottom_base - 1] != 0);
                }
                if (has_right) {
                    bottom_lr |= static_cast<u32>(input[bottom_base + kWarpWidth] != 0) << 1;
                }
                row_masks[kTileRows + 1] = bottom_mask;
                row_halo[kTileRows + 1]  = bottom_lr;
            }
        } else if (lane == 0) {
            row_masks[kTileRows + 1] = 0;
            row_halo[kTileRows + 1]  = 0;
        }
    }

    __syncthreads();

    // Reuse registers wherever possible:
    // - row0 uses north from shared, center=row0, south=row1
    // - row1 uses north=row0, center=row1, south from shared
    const u32 north0_mask = row_masks[shared_row0 - 1];
    const u32 north0_lr   = row_halo[shared_row0 - 1];
    const u32 south1_mask = row_masks[shared_row1 + 1];
    const u32 south1_lr   = row_halo[shared_row1 + 1];

    const u32 next0 = compute_next_mask(north0_mask, mask0, mask1, north0_lr, center_lr0, center_lr1);
    const u32 next1 = compute_next_mask(mask0, mask1, south1_mask, center_lr0, center_lr1, south1_lr);

    output[row0_base + lane] = ((next0 >> lane) & 1u) != 0u;
    output[row1_base + lane] = ((next1 >> lane) & 1u) != 0u;
}

} // namespace

void run_game_of_life(const bool* input, bool* output, int grid_dimensions)
{
    // The problem guarantees a power-of-two square board larger than 512, so the
    // launch tiles the board exactly with 32x32-cell blocks and no partial work.
    const int dim_log2 = log2_pow2(grid_dimensions);

    const dim3 block(kWarpWidth, kWarpsPerBlock, 1);
    const dim3 grid(
        static_cast<unsigned int>(grid_dimensions) >> kWarpWidthLog2,
        static_cast<unsigned int>(grid_dimensions) >> kTileRowsLog2,
        1);

    const auto* input_bytes = reinterpret_cast<const unsigned char*>(input);

    // Most practical boards fit in <= 2^32 elements, so keep a fast 32-bit index
    // path. Very large boards still work via the 64-bit instantiation.
    const u64 cells =
        static_cast<u64>(static_cast<unsigned int>(grid_dimensions)) *
        static_cast<u64>(static_cast<unsigned int>(grid_dimensions));

    // Launch only; caller is responsible for any desired synchronization.
    if (cells <= kMax32BitElementCount) {
        life_step_kernel<u32><<<grid, block>>>(input_bytes, output, dim_log2);
    } else {
        life_step_kernel<u64><<<grid, block>>>(input_bytes, output, dim_log2);
    }
}

#include <cuda_runtime.h>
#include <cstddef>

// High-performance one-step Conway's Game of Life for modern NVIDIA GPUs.
//
// Design notes:
// - blockDim.x == 32, so each warp owns one contiguous 32-cell row segment.
//   That makes left/right neighbors map naturally to lane +/- 1.
// - Each warp computes an 8-row strip, not just one row. The vertical
//   (north, center, south) values are rolled through registers, so after the
//   first row only one new load per thread is needed for each additional row.
// - The (north, center, south) triplet is packed into 3 bits. Two warp shuffles
//   exchange those packed triplets with the left/right lanes; a single popcount
//   then gives the 8-neighbor count.
// - Lane 0 and lane 31 keep a rolling halo column in registers for cross-warp
//   boundaries, so even the halo loads are amortized across the 8-row strip.
// - Shared memory is intentionally avoided: for byte-wide cell data it would
//   either suffer bank conflicts or require 32-bit expansion. Warp shuffles plus
//   rolling registers provide the same stencil reuse without synchronization.
// - The problem guarantees power-of-two dimensions > 512, so the launch geometry
//   exactly covers the grid and row-base computation can use shifts.

namespace {

constexpr int kBlockX               = 32;  // exactly one warp in X
constexpr int kBlockWarpsY          = 8;   // 8 independent warps per block
constexpr int kTileRowsPerWarp      = 8;   // each warp computes 8 consecutive rows
constexpr int kBlockRows            = kBlockWarpsY * kTileRowsPerWarp;  // 64 rows per block
constexpr int kBlockThreads         = kBlockX * kBlockWarpsY;

constexpr int kBlockXLog2           = 5;   // log2(32)
constexpr int kTileRowsPerWarpLog2  = 3;   // log2(8)
constexpr int kBlockRowsLog2        = 6;   // log2(64)

constexpr unsigned int kFullWarpMask = 0xFFFFFFFFu;
constexpr unsigned int kLastLane     = 31u;

static_assert(kBlockX == 32, "This kernel relies on one full warp covering 32 contiguous columns.");
static_assert((1 << kTileRowsPerWarpLog2) == kTileRowsPerWarp, "kTileRowsPerWarp must be a power of two.");
static_assert((1 << kBlockRowsLog2) == kBlockRows, "kBlockRows must be a power of two.");

// The input dimensions are guaranteed to be powers of two, so a simple shift-count
// computation is enough and avoids host-side dependencies on compiler-specific intrinsics.
inline int integer_log2_pow2(unsigned int v) {
    int log2 = 0;
    while (v > 1u) {
        v >>= 1u;
        ++log2;
    }
    return log2;
}

__device__ __forceinline__ unsigned int load_cell(const bool* __restrict__ grid, size_t idx) {
    // Typed bool loads guarantee canonical 0/1 semantics even if the caller's source
    // data did not originate from this kernel.
    return static_cast<unsigned int>(grid[idx]);
}

__device__ __forceinline__ unsigned int pack_triplet(unsigned int top,
                                                     unsigned int mid,
                                                     unsigned int bot) {
    // Pack three 0/1 values into bits [0,1,2].
    return top | (mid << 1) | (bot << 2);
}

// kInteriorY == true is the hot path used by almost all warps: their 8-row strip does
// not touch the top or bottom boundary, so all vertical boundary checks disappear.
// Only the first and last 8-row strips of the entire grid use kInteriorY == false.
template <bool kInteriorY>
__device__ __forceinline__ void process_warp_tile(const bool* __restrict__ input,
                                                  bool* __restrict__ output,
                                                  size_t idx,
                                                  unsigned int y,
                                                  unsigned int last,
                                                  size_t stride,
                                                  unsigned int lane,
                                                  bool use_left_edge,
                                                  bool use_right_edge) {
    // Rolling vertical window for the current column.
    unsigned int n;
    unsigned int c;
    unsigned int s;

    if (kInteriorY) {
        n = load_cell(input, idx - stride);
        c = load_cell(input, idx);
        s = load_cell(input, idx + stride);
    } else {
        n = (y != 0u)   ? load_cell(input, idx - stride) : 0u;
        c =               load_cell(input, idx);
        s = (y != last) ? load_cell(input, idx + stride) : 0u;
    }

    // Rolling halo window for the cross-warp neighbor column.
    // On lane 0 this is the left halo; on lane 31 this is the right halo.
    unsigned int edge_n = 0u;
    unsigned int edge_c = 0u;
    unsigned int edge_s = 0u;

    if (use_left_edge) {
        if (kInteriorY) {
            edge_n = load_cell(input, idx - stride - 1);
            edge_c = load_cell(input, idx - 1);
            edge_s = load_cell(input, idx + stride - 1);
        } else {
            edge_n = (y != 0u)   ? load_cell(input, idx - stride - 1) : 0u;
            edge_c =               load_cell(input, idx - 1);
            edge_s = (y != last) ? load_cell(input, idx + stride - 1) : 0u;
        }
    } else if (use_right_edge) {
        if (kInteriorY) {
            edge_n = load_cell(input, idx - stride + 1);
            edge_c = load_cell(input, idx + 1);
            edge_s = load_cell(input, idx + stride + 1);
        } else {
            edge_n = (y != 0u)   ? load_cell(input, idx - stride + 1) : 0u;
            edge_c =               load_cell(input, idx + 1);
            edge_s = (y != last) ? load_cell(input, idx + stride + 1) : 0u;
        }
    }

    #pragma unroll
    for (int iter = 0; iter < kTileRowsPerWarp; ++iter) {
        // Pack the vertical triplet for this thread and exchange the packed value
        // horizontally. That reduces six scalar shuffles down to two.
        const unsigned int packed = pack_triplet(n, c, s);

        unsigned int left_p  = __shfl_up_sync(kFullWarpMask, packed, 1);
        unsigned int right_p = __shfl_down_sync(kFullWarpMask, packed, 1);

        // Replace the undefined shuffle results on warp boundaries with the rolled halo.
        if (lane == 0u) {
            left_p = use_left_edge ? pack_triplet(edge_n, edge_c, edge_s) : 0u;
        } else if (lane == kLastLane) {
            right_p = use_right_edge ? pack_triplet(edge_n, edge_c, edge_s) : 0u;
        }

        // Bit layout for the popcount:
        //   left_p bits   -> NW, W,  SW
        //   n << 3        -> N
        //   s << 4        -> S
        //   right_p << 5  -> NE, E, SE
        // popcount(neighbor_bits) is therefore exactly the 8-neighbor count.
        const unsigned int neighbor_bits = left_p | (n << 3) | (s << 4) | (right_p << 5);
        const unsigned int neighbors = __popc(neighbor_bits);

        const unsigned int next =
            static_cast<unsigned int>(neighbors == 3u) |
            (c & static_cast<unsigned int>(neighbors == 2u));

        output[idx] = static_cast<bool>(next);

        if (iter != kTileRowsPerWarp - 1) {
            // Advance to the next output row in the strip.
            idx += stride;

            if (!kInteriorY) {
                ++y;
            }

            n = c;
            c = s;

            if (kInteriorY) {
                s = load_cell(input, idx + stride);

                if (use_left_edge) {
                    edge_n = edge_c;
                    edge_c = edge_s;
                    edge_s = load_cell(input, idx + stride - 1);
                } else if (use_right_edge) {
                    edge_n = edge_c;
                    edge_c = edge_s;
                    edge_s = load_cell(input, idx + stride + 1);
                }
            } else {
                const bool has_bottom = (y != last);
                s = has_bottom ? load_cell(input, idx + stride) : 0u;

                if (use_left_edge) {
                    edge_n = edge_c;
                    edge_c = edge_s;
                    edge_s = has_bottom ? load_cell(input, idx + stride - 1) : 0u;
                } else if (use_right_edge) {
                    edge_n = edge_c;
                    edge_c = edge_s;
                    edge_s = has_bottom ? load_cell(input, idx + stride + 1) : 0u;
                }
            }
        }
    }
}

__global__ __launch_bounds__(kBlockThreads, 4)
void game_of_life_step_kernel(const bool* __restrict__ input,
                              bool* __restrict__ output,
                              int grid_dimensions,
                              int grid_log2) {
    // blockDim = (32, 8):
    // - x dimension is exactly one warp
    // - y dimension is the number of independent warps in the block
    const unsigned int lane = threadIdx.x;
    const unsigned int x = (blockIdx.x << kBlockXLog2) + lane;
    const unsigned int start_y =
        (blockIdx.y << kBlockRowsLog2) + (threadIdx.y << kTileRowsPerWarpLog2);
    const unsigned int last = static_cast<unsigned int>(grid_dimensions - 1);

    const size_t stride = static_cast<size_t>(grid_dimensions);
    const size_t idx =
        (static_cast<size_t>(start_y) << grid_log2) + static_cast<size_t>(x);

    // Only lane 0 / lane 31 ever need explicit halo-column loads.
    const bool use_left_edge  = (lane == 0u)      && (x != 0u);
    const bool use_right_edge = (lane == kLastLane) && (x != last);

    // Almost all warps are interior in Y and can use the fully branch-free hot path.
    const bool interior_y_tile =
        (start_y != 0u) &&
        (start_y + static_cast<unsigned int>(kTileRowsPerWarp) <= last);

    if (interior_y_tile) {
        process_warp_tile<true>(input, output, idx, start_y, last, stride, lane,
                                use_left_edge, use_right_edge);
    } else {
        process_warp_tile<false>(input, output, idx, start_y, last, stride, lane,
                                 use_left_edge, use_right_edge);
    }
}

}  // namespace

void run_game_of_life(const bool* input, bool* output, int grid_dimensions) {
    // Assumptions guaranteed by the prompt:
    // - input/output are device pointers from cudaMalloc
    // - grid is square, dimensions are a power of two, and > 512
    // - input and output are distinct ping-pong buffers
    //
    // No synchronization or error-querying is done here; the caller owns both.

    const unsigned int dim_u = static_cast<unsigned int>(grid_dimensions);
    const int grid_log2 = integer_log2_pow2(dim_u);

    const dim3 block(kBlockX, kBlockWarpsY);
    const dim3 grid(dim_u >> kBlockXLog2, dim_u >> kBlockRowsLog2);

    game_of_life_step_kernel<<<grid, block>>>(input, output, grid_dimensions, grid_log2);
}

#include <cstddef>
#include <cstdint>
#include <cuda_runtime.h>

namespace {

// Bit-packed Game of Life on a square grid.
//
// Encoding assumption:
//   - Each 64-bit word stores 64 consecutive cells from one row.
//   - Bit i corresponds to the cell at x = word_base + i (LSB -> increasing x).
//
// Kernel mapping:
//   - One warp handles one horizontal row segment of up to 32 packed words.
//   - Each lane owns one 64-bit word = 64 cells.
//   - Only three center words are fetched from global memory per lane: row-1, row, row+1.
//   - Left/right neighbor words are obtained with warp shuffles; only segment-edge lanes
//     perform one extra global load when a neighbor word sits in an adjacent segment.
//   - Neighbor population counts are computed in bit-sliced form with a carry-save-adder tree.
//     This avoids unpacking bits or looping over individual cells.
//
// Shared memory is intentionally not used: on recent data-center GPUs, shuffle-based horizontal
// exchange plus normal caching is simpler and fast for this access pattern.

using u64 = std::uint64_t;

static_assert(sizeof(u64) == 8, "Expected 64-bit packed words.");

constexpr int kCellsPerWordShift = 6;   // 64 cells per packed word.
constexpr int kWarpSize          = 32;  // NVIDIA warp size.
constexpr int kWarpsPerBlock     = 8;   // 256 threads/block.
constexpr int kBlockThreads      = kWarpSize * kWarpsPerBlock;
constexpr unsigned kFullWarpMask = 0xFFFFFFFFu;

// 3:2 carry-save adder on 64 independent bit lanes.
// For each bit position:
//   a + b + c = sum + 2 * carry
static __device__ __forceinline__
void csa3(const u64 a, const u64 b, const u64 c, u64& sum, u64& carry) {
    const u64 ab_xor = a ^ b;
    sum   = ab_xor ^ c;
    carry = (a & b) | (c & ab_xor);
}

__global__ __launch_bounds__(kBlockThreads)
void game_of_life_kernel(const u64* __restrict__ input,
                         u64* __restrict__ output,
                         const int grid_dimensions) {
    const int words_per_row = grid_dimensions >> kCellsPerWordShift;

    const int lane          = threadIdx.x & (kWarpSize - 1);
    const int warp_in_block = threadIdx.x >> 5;
    const int row           = static_cast<int>(blockIdx.y) * kWarpsPerBlock + warp_in_block;

    if (row >= grid_dimensions) {
        return;
    }

    const int segment_word   = static_cast<int>(blockIdx.x) * kWarpSize;
    const int remaining      = words_per_row - segment_word;
    const int tile_words     = (remaining >= kWarpSize) ? kWarpSize : remaining;
    const bool active        = lane < tile_words;
    const unsigned lane_mask = __ballot_sync(kFullWarpMask, active);

    if (!active) {
        return;
    }

    const bool first_lane        = (lane == 0);
    const bool last_active_lane  = (lane == tile_words - 1);
    const bool has_segment_left  = (segment_word > 0);
    const bool has_segment_right = (segment_word + tile_words < words_per_row);

    const std::size_t row_base =
        static_cast<std::size_t>(row) * static_cast<std::size_t>(words_per_row);

    const u64* const row_seg = input  + row_base + static_cast<std::size_t>(segment_word);
    u64* const       out_seg = output + row_base + static_cast<std::size_t>(segment_word);

    // Outside-grid cells are defined as dead, so missing rows/words are injected as zero.
    const bool has_top    = (row > 0);
    const bool has_bottom = (row + 1 < grid_dimensions);

    const u64* const top_seg = has_top    ? (row_seg - words_per_row) : nullptr;
    const u64* const bot_seg = has_bottom ? (row_seg + words_per_row) : nullptr;

    const u64 top_center = has_top    ? top_seg[lane] : 0ULL;
    const u64 mid_center = row_seg[lane];
    const u64 bot_center = has_bottom ? bot_seg[lane] : 0ULL;

    // First CSA group: north, south, west
    u64 sum0, carry0;
    {
        const u64 mid_left =
            first_lane
                ? (has_segment_left ? row_seg[-1] : 0ULL)
                : __shfl_up_sync(lane_mask, mid_center, 1);

        const u64 west = (mid_center << 1) | (mid_left >> 63);
        csa3(top_center, bot_center, west, sum0, carry0);
    }

    // Second CSA group: east, northwest, northeast
    u64 sum1, carry1;
    {
        const u64 mid_right =
            last_active_lane
                ? (has_segment_right ? row_seg[tile_words] : 0ULL)
                : __shfl_down_sync(lane_mask, mid_center, 1);

        const u64 east = (mid_center >> 1) | (mid_right << 63);

        const u64 top_left =
            has_top
                ? (first_lane
                       ? (has_segment_left ? top_seg[-1] : 0ULL)
                       : __shfl_up_sync(lane_mask, top_center, 1))
                : 0ULL;

        const u64 northwest = (top_center << 1) | (top_left >> 63);

        const u64 top_right =
            has_top
                ? (last_active_lane
                       ? (has_segment_right ? top_seg[tile_words] : 0ULL)
                       : __shfl_down_sync(lane_mask, top_center, 1))
                : 0ULL;

        const u64 northeast = (top_center >> 1) | (top_right << 63);

        csa3(east, northwest, northeast, sum1, carry1);
    }

    // Remaining two neighbors: southwest and southeast
    u64 sum_sw_se, carry_sw_se;
    {
        const u64 bot_left =
            has_bottom
                ? (first_lane
                       ? (has_segment_left ? bot_seg[-1] : 0ULL)
                       : __shfl_up_sync(lane_mask, bot_center, 1))
                : 0ULL;

        const u64 southwest = (bot_center << 1) | (bot_left >> 63);

        const u64 bot_right =
            has_bottom
                ? (last_active_lane
                       ? (has_segment_right ? bot_seg[tile_words] : 0ULL)
                       : __shfl_down_sync(lane_mask, bot_center, 1))
                : 0ULL;

        const u64 southeast = (bot_center >> 1) | (bot_right << 63);

        sum_sw_se   = southwest ^ southeast;
        carry_sw_se = southwest & southeast;
    }

    // Add the 8 one-bit neighbor boards:
    //   count = ones_bit + 2*twos_bit + higher_bits
    //
    // We do not materialize the full 4-bit count because the Life rule only needs:
    //   count == 2  -> survive if currently alive
    //   count == 3  -> always alive
    //
    // That condition is equivalent to:
    //   twos_bit == 1, no 4/8 bits set, and (ones_bit == 1 || current_cell == 1)
    u64 ones_bit, carry_to_twos;
    csa3(sum0, sum1, sum_sw_se, ones_bit, carry_to_twos);

    u64 twos_partial, fours_partial;
    csa3(carry0, carry1, carry_sw_se, twos_partial, fours_partial);

    const u64 twos_bit         = twos_partial ^ carry_to_twos;
    const u64 high_bits_nonzero = fours_partial | (twos_partial & carry_to_twos);

    out_seg[lane] = twos_bit & ~high_bits_nonzero & (ones_bit | mid_center);
}

} // namespace

void run_game_of_life(const std::uint64_t* input,
                      std::uint64_t* output,
                      int grid_dimensions) {
    // The caller handles synchronization and any desired error policy.
    // This function only enqueues one step asynchronously.
    const int words_per_row = grid_dimensions >> kCellsPerWordShift;

    const dim3 block(kBlockThreads, 1, 1);
    const dim3 grid((words_per_row + kWarpSize - 1) / kWarpSize,
                    (grid_dimensions + kWarpsPerBlock - 1) / kWarpsPerBlock,
                    1);

    game_of_life_kernel<<<grid, block>>>(input, output, grid_dimensions);
}

#include <cstddef>
#include <cstdint>
#include <cuda_runtime.h>

// Conway's Game of Life, one step, on a square bit-packed grid.
//
// Encoding:
//   - Row-major.
//   - Each 64-bit word stores 64 consecutive cells from one row.
//   - Bit k of a word is cell x = word_base + k.
//   - Cells outside the grid are dead.
//
// Performance strategy:
//   - One thread computes one 64-cell output word.
//   - Shared memory is intentionally not used: warp shuffles eliminate the hot horizontal
//     reuse, and the remaining accesses are regular read-only global loads.
//   - The update is fully bit-parallel: each thread computes 64 next-state cells at once
//     with a small fixed Boolean network instead of per-cell scalar work.
//   - A 1D grid is used so very tall domains do not hit CUDA's grid.y limit.

namespace {

using u64 = std::uint64_t;

constexpr int kThreadsPerBlock = 256;
constexpr unsigned int kFullMask = 0xFFFFFFFFu;

static_assert(sizeof(u64) == 8, "Expected 64-bit words.");

__device__ __forceinline__ u64 majority3(u64 a, u64 b, u64 c) {
    // Per bit position: 1 iff at least two of {a,b,c} are 1.
    return (a & b) | (c & (a ^ b));
}

__device__ __forceinline__ u64 exactly_one_of_four(u64 a, u64 b, u64 c, u64 d) {
    // Per bit position, test "exactly one of four 1-bit values is set".
    //
    // Group the four inputs as (a,b) and (c,d):
    //   - parity == 1 for populations 1 or 3
    //   - any population of 3 must fully occupy at least one pair
    // Therefore:
    //   exactly_one = parity & ~pair_has_two
    return (a ^ b ^ c ^ d) & ~((a & b) | (c & d));
}

__device__ __forceinline__ u64 shift_west(u64 center, u64 left_word) {
    // Bit k represents x = base + k, so the west neighbor (x-1) aligns with x by shifting
    // toward larger bit indices.
    return (center << 1) | (left_word >> 63);
}

__device__ __forceinline__ u64 shift_east(u64 center, u64 right_word) {
    // The east neighbor (x+1) aligns with x by shifting toward smaller bit indices.
    return (center >> 1) | (right_word << 63);
}

static inline unsigned int log2_pow2(unsigned int v) {
    // Host-side helper. Input is guaranteed to be a power of two.
    unsigned int s = 0;
    while (v > 1u) {
        v >>= 1;
        ++s;
    }
    return s;
}

template<int STRIP_WORDS>
__global__ __launch_bounds__(kThreadsPerBlock)
void game_of_life_kernel(const u64* __restrict__ input,
                         u64* __restrict__ output,
                         int words_per_row,
                         int grid_dimensions,
                         unsigned int blocks_per_row_shift,
                         unsigned int blocks_per_row_mask) {
    static_assert(STRIP_WORDS == 16 || STRIP_WORDS == 32,
                  "Only 16-word and 32-word strips are used.");

    // 256-thread blocks:
    //   - STRIP_WORDS == 32 -> block = (32, 8), one warp per row strip
    //   - STRIP_WORDS == 16 -> block = (16, 16), one half-warp per row strip
    constexpr int BLOCK_ROWS = kThreadsPerBlock / STRIP_WORDS;
    constexpr int LAST_LANE = STRIP_WORDS - 1;

    // Flattened 2D tiling:
    //   block_col = low bits of blockIdx.x
    //   block_row = high bits of blockIdx.x
    // blocks_per_row is a power of two, so decode is just mask + shift.
    const unsigned int block_linear = blockIdx.x;
    const int block_col = static_cast<int>(block_linear & blocks_per_row_mask);
    const int block_row = static_cast<int>(block_linear >> blocks_per_row_shift);

    const int x = block_col * STRIP_WORDS + static_cast<int>(threadIdx.x);  // packed-word x
    const int y = block_row * BLOCK_ROWS + static_cast<int>(threadIdx.y);   // row y

    const std::size_t row_stride = static_cast<std::size_t>(words_per_row);
    const std::size_t idx =
        static_cast<std::size_t>(y) * row_stride + static_cast<std::size_t>(x);

    const int last_x = words_per_row - 1;
    const int last_y = grid_dimensions - 1;

    const bool has_top = (y != 0);
    const bool has_bottom = (y != last_y);
    const bool has_left = (x != 0);
    const bool has_right = (x != last_x);

    // Every thread loads only the center word of the top/middle/bottom rows.
    // Left/right neighboring words are normally obtained from adjacent lanes by shuffles.
    // Only strip boundaries (lane 0 / lane LAST_LANE) require an extra global load.
    const u64 mid_c = input[idx];
    const u64 top_c = has_top ? input[idx - row_stride] : 0ULL;
    const u64 bot_c = has_bottom ? input[idx + row_stride] : 0ULL;

    // Within a strip, threadIdx.x is the lane index.
    // For STRIP_WORDS == 16, the shuffle width partitions each warp into two independent
    // 16-lane groups, exactly matching the two row strips carried by that warp.
    const int lane = static_cast<int>(threadIdx.x);

    const u64 top_up = __shfl_up_sync(kFullMask, top_c, 1, STRIP_WORDS);
    const u64 top_dn = __shfl_down_sync(kFullMask, top_c, 1, STRIP_WORDS);
    const u64 mid_up = __shfl_up_sync(kFullMask, mid_c, 1, STRIP_WORDS);
    const u64 mid_dn = __shfl_down_sync(kFullMask, mid_c, 1, STRIP_WORDS);
    const u64 bot_up = __shfl_up_sync(kFullMask, bot_c, 1, STRIP_WORDS);
    const u64 bot_dn = __shfl_down_sync(kFullMask, bot_c, 1, STRIP_WORDS);

    // Top row: sum of west + center + east, encoded as t0 + 2*t1.
    u64 left_word = (lane != 0)
                        ? top_up
                        : ((has_top && has_left) ? input[idx - row_stride - 1] : 0ULL);
    u64 right_word = (lane != LAST_LANE)
                         ? top_dn
                         : ((has_top && has_right) ? input[idx - row_stride + 1] : 0ULL);

    u64 w = shift_west(top_c, left_word);
    u64 e = shift_east(top_c, right_word);
    const u64 t0 = w ^ top_c ^ e;
    const u64 t1 = majority3(w, top_c, e);

    // Middle row: only west + east contribute to the neighbor count.
    // Encode as m0 + 2*m1.
    left_word = (lane != 0) ? mid_up : (has_left ? input[idx - 1] : 0ULL);
    right_word = (lane != LAST_LANE) ? mid_dn : (has_right ? input[idx + 1] : 0ULL);

    w = shift_west(mid_c, left_word);
    e = shift_east(mid_c, right_word);
    const u64 m0 = w ^ e;
    const u64 m1 = w & e;

    // Bottom row: sum of west + center + east, encoded as b0 + 2*b1.
    left_word = (lane != 0)
                    ? bot_up
                    : ((has_bottom && has_left) ? input[idx + row_stride - 1] : 0ULL);
    right_word = (lane != LAST_LANE)
                     ? bot_dn
                     : ((has_bottom && has_right) ? input[idx + row_stride + 1] : 0ULL);

    w = shift_west(bot_c, left_word);
    e = shift_east(bot_c, right_word);
    const u64 b0 = w ^ bot_c ^ e;
    const u64 b1 = majority3(w, bot_c, e);

    // Neighbor-count decomposition:
    //
    //   top_count    = t0 + 2*t1
    //   mid_count    = m0 + 2*m1   (self excluded)
    //   bottom_count = b0 + 2*b1
    //
    //   total_neighbors = (t0 + m0 + b0) + 2*(t1 + m1 + b1)
    //
    // Let:
    //   s0 = low bit of (t0 + m0 + b0)
    //   c0 = carry   of (t0 + m0 + b0)
    //
    // Then:
    //   total_neighbors = s0 + 2*(c0 + t1 + m1 + b1)
    //
    // Counts 2 and 3 are exactly the cases where the upper term equals 1.
    // s0 distinguishes 2 from 3.
    const u64 s0 = t0 ^ m0 ^ b0;
    const u64 c0 = majority3(t0, m0, b0);
    const u64 upper_eq1 = exactly_one_of_four(c0, t1, m1, b1);

    // Conway rule:
    //   birth on 3
    //   survive on 2 or 3
    //
    // With the encoding above this becomes:
    //   upper_eq1 & (s0 | self)
    const u64 next = upper_eq1 & (s0 | mid_c);
    output[idx] = next;
}

}  // namespace

void run_game_of_life(const std::uint64_t* input,
                      std::uint64_t* output,
                      int grid_dimensions) {
    // Fast path only:
    //   - input/output are device pointers from cudaMalloc
    //   - grid_dimensions is a power of two, > 512
    //   - input and output are distinct ping-pong buffers
    // The caller owns synchronization and error handling, so none is done here.

    const int words_per_row = grid_dimensions >> 6;  // grid_dimensions / 64

    // Because the grid width and height are powers of two, these tiles cover the domain exactly.
    // There are no bounds checks in the hot kernel.
    if (words_per_row == 16) {
        // Minimum legal case: 1024 cells per row -> 16 packed words.
        constexpr int STRIP_WORDS = 16;
        constexpr int BLOCK_ROWS = kThreadsPerBlock / STRIP_WORDS;  // 16
        constexpr unsigned int kBlocksPerRowShift = 0;
        constexpr unsigned int kBlocksPerRowMask = 0;

        const unsigned int total_blocks =
            static_cast<unsigned int>(grid_dimensions / BLOCK_ROWS);

        game_of_life_kernel<STRIP_WORDS>
            <<<total_blocks, dim3(STRIP_WORDS, BLOCK_ROWS, 1)>>>(
                input,
                output,
                words_per_row,
                grid_dimensions,
                kBlocksPerRowShift,
                kBlocksPerRowMask);
    } else {
        // All larger legal cases have at least 32 packed words per row.
        constexpr int STRIP_WORDS = 32;
        constexpr int BLOCK_ROWS = kThreadsPerBlock / STRIP_WORDS;  // 8

        const unsigned int blocks_per_row =
            static_cast<unsigned int>(words_per_row / STRIP_WORDS);
        const unsigned int blocks_per_row_shift = log2_pow2(blocks_per_row);
        const unsigned int blocks_per_row_mask = blocks_per_row - 1u;
        const unsigned int rows_of_blocks =
            static_cast<unsigned int>(grid_dimensions / BLOCK_ROWS);
        const unsigned int total_blocks = blocks_per_row * rows_of_blocks;

        game_of_life_kernel<STRIP_WORDS>
            <<<total_blocks, dim3(STRIP_WORDS, BLOCK_ROWS, 1)>>>(
                input,
                output,
                words_per_row,
                grid_dimensions,
                blocks_per_row_shift,
                blocks_per_row_mask);
    }
}

#include <cstdint>
#include <cuda_runtime.h>

namespace {
using u32 = std::uint32_t;
using u64 = std::uint64_t;

static_assert(sizeof(u32) == 4 && sizeof(u64) == 8, "Unexpected integer sizes.");

constexpr int kWarpSize = 32;
constexpr int kSubwordBits = 32;
constexpr int kSubwordsPerWarpSegment = 32;
constexpr int kCellsPerWarpSegment = kSubwordBits * kSubwordsPerWarpSegment;  // 1024 cells
constexpr int kWarpsPerBlock = 4;
constexpr int kThreadsPerBlock = kWarpSize * kWarpsPerBlock;
constexpr unsigned int kMaxBlocks = 4096u;

__device__ __forceinline__ void carry_save_add(const u32 a,
                                               const u32 b,
                                               const u32 c,
                                               u32& lo,
                                               u32& hi) {
    // Bit-sliced 3:2 compressor:
    //   a + b + c = lo + 2*hi
    // for every bit position independently.
    const u32 ab = a ^ b;
    lo = ab ^ c;
    hi = (a & b) | (ab & c);
}

__device__ __forceinline__ u32 neighbor_from_left(const u32 left, const u32 center) {
    // Result bit i receives source bit i-1 from the logical row.
    // This is the "west neighbor aligned to the current cell" mask.
    // NVCC lowers this shift/or idiom to SHF-based code on modern GPUs.
    return (center << 1) | (left >> (kSubwordBits - 1));
}

__device__ __forceinline__ u32 neighbor_from_right(const u32 center, const u32 right) {
    // Result bit i receives source bit i+1 from the logical row.
    // This is the "east neighbor aligned to the current cell" mask.
    return (center >> 1) | (right << (kSubwordBits - 1));
}

__device__ __forceinline__ u32 evolve_subword(const u32 live,
                                              const u32 n_left,
                                              const u32 n_center,
                                              const u32 n_right,
                                              const u32 c_left,
                                              const u32 c_right,
                                              const u32 s_left,
                                              const u32 s_center,
                                              const u32 s_right) {
    // Exact 8-way bit-parallel population count using a compact carry-save tree.
    // The final bitplanes are:
    //   bit0 = 1s place
    //   bit1 = 2s place
    //   bit2 = 4s place
    //   bit3 = 8s place
    u32 p0, p1;
    u32 q0, q1;
    u32 r0, r1;

    carry_save_add(n_left, n_center, n_right, p0, p1);
    carry_save_add(c_left, c_right, s_left, q0, q1);
    carry_save_add(s_center, s_right, p0, r0, r1);

    const u32 bit0 = q0 ^ r0;
    const u32 carry0 = q0 & r0;

    u32 bit1_tmp, carry1;
    carry_save_add(p1, q1, r1, bit1_tmp, carry1);

    const u32 bit1 = bit1_tmp ^ carry0;
    const u32 carry2 = bit1_tmp & carry0;

    const u32 bit2 = carry1 ^ carry2;
    const u32 bit3 = carry1 & carry2;

    // Conway rule:
    //   alive next = (count == 3) || (live && count == 2)
    // count == 2 or 3 iff bit1=1 and bit2=bit3=0.
    const u32 count_is_2_or_3 = bit1 & ~(bit2 | bit3);
    return count_is_2_or_3 & (bit0 | live);
}

// Shared memory is intentionally not used.
// Each warp owns one contiguous row segment, keeps three row-aligned subwords in
// registers, uses warp shuffles for horizontal reuse, and only its two edge lanes
// need extra global loads.
template <int WarpsPerBlock>
__global__ __launch_bounds__(WarpsPerBlock * kWarpSize)
void game_of_life_kernel(const u32* __restrict__ input,
                         u32* __restrict__ output,
                         const u64 total_tasks,
                         const u32 subwords_per_row,
                         const u32 segments_per_row,
                         const u32 segments_per_row_mask) {
    constexpr unsigned int kFullMask = 0xFFFFFFFFu;

    const int lane = threadIdx.x & (kWarpSize - 1);
    const int warp_in_block = threadIdx.x >> 5;

    u64 task = static_cast<u64>(blockIdx.x) * WarpsPerBlock + static_cast<u64>(warp_in_block);
    const u64 task_stride = static_cast<u64>(gridDim.x) * WarpsPerBlock;

    const u64 subwords_per_row_64 = static_cast<u64>(subwords_per_row);
    const u64 segments_per_row_64 = static_cast<u64>(segments_per_row);

    while (task < total_tasks) {
        // Tasks are warp-sized row segments in row-major order.
        // Because one task always spans exactly 32 subwords, its linear base
        // subword index is simply task * 32.
        const u32 segment = static_cast<u32>(task & static_cast<u64>(segments_per_row_mask));
        const u64 row_base = task * static_cast<u64>(kSubwordsPerWarpSegment);
        const u64 north_base = row_base - subwords_per_row_64;
        const u64 south_base = row_base + subwords_per_row_64;
        const u64 idx = row_base + static_cast<u64>(lane);

        const bool has_north = (task >= segments_per_row_64);
        const bool has_south = (task + segments_per_row_64 < total_tasks);
        const bool has_left = (segment != 0u);
        const bool has_right = (segment != segments_per_row_mask);

        const u32 center = input[idx];
        const u32 north = has_north ? input[north_base + static_cast<u64>(lane)] : 0u;
        const u32 south = has_south ? input[south_base + static_cast<u64>(lane)] : 0u;

        u32 center_left = __shfl_up_sync(kFullMask, center, 1, kWarpSize);
        u32 center_right = __shfl_down_sync(kFullMask, center, 1, kWarpSize);
        u32 north_left = __shfl_up_sync(kFullMask, north, 1, kWarpSize);
        u32 north_right = __shfl_down_sync(kFullMask, north, 1, kWarpSize);
        u32 south_left = __shfl_up_sync(kFullMask, south, 1, kWarpSize);
        u32 south_right = __shfl_down_sync(kFullMask, south, 1, kWarpSize);

        // Only the segment-edge lanes need fallback loads.
        if (lane == 0) {
            center_left = has_left ? input[row_base - 1u] : 0u;
            north_left = (has_north && has_left) ? input[north_base - 1u] : 0u;
            south_left = (has_south && has_left) ? input[south_base - 1u] : 0u;
        } else if (lane == kWarpSize - 1) {
            center_right = has_right ? input[row_base + kSubwordsPerWarpSegment] : 0u;
            north_right = (has_north && has_right) ? input[north_base + kSubwordsPerWarpSegment] : 0u;
            south_right = (has_south && has_right) ? input[south_base + kSubwordsPerWarpSegment] : 0u;
        }

        output[idx] = evolve_subword(
            center,
            neighbor_from_left(north_left, north), north, neighbor_from_right(north, north_right),
            neighbor_from_left(center_left, center), neighbor_from_right(center, center_right),
            neighbor_from_left(south_left, south), south, neighbor_from_right(south, south_right));

        task += task_stride;
    }
}

}  // namespace

void run_game_of_life(const std::uint64_t* input,
                      std::uint64_t* output,
                      int grid_dimensions) {
    // The incoming storage is already on the device and already bit-packed.
    // Reinterpreting it as 32-bit subwords preserves the exact in-memory layout on
    // NVIDIA GPUs and enables native-width bit logic and cross-subword shifts.
    const auto* input32 = reinterpret_cast<const u32*>(input);
    auto* output32 = reinterpret_cast<u32*>(output);

    const u32 grid_dim_u32 = static_cast<u32>(grid_dimensions);
    const u32 subwords_per_row = grid_dim_u32 >> 5;       // N / 32
    const u32 segments_per_row = grid_dim_u32 >> 10;      // N / 1024, guaranteed >= 1
    const u32 segments_per_row_mask = segments_per_row - 1u;
    const u64 total_tasks = static_cast<u64>(grid_dim_u32) * static_cast<u64>(segments_per_row);

    const u64 max_blocks_needed =
        (total_tasks + static_cast<u64>(kWarpsPerBlock) - 1u) / static_cast<u64>(kWarpsPerBlock);

    // Fixed grid cap chosen for modern data-center GPUs:
    // enough to oversubscribe A100/H100 class hardware by several waves while
    // keeping launch-side overhead minimal.
    const unsigned int blocks = static_cast<unsigned int>(
        (max_blocks_needed < static_cast<u64>(kMaxBlocks))
            ? max_blocks_needed
            : static_cast<u64>(kMaxBlocks));

    game_of_life_kernel<kWarpsPerBlock><<<blocks, kThreadsPerBlock>>>(
        input32,
        output32,
        total_tasks,
        subwords_per_row,
        segments_per_row,
        segments_per_row_mask);
}

#include <cuda_runtime.h>
#include <cstddef>
#include <cstdint>

// Optimized one-step Conway's Game of Life for bit-packed rows on modern NVIDIA GPUs.
//
// Key design choices:
// - One thread computes one 64-bit output word, i.e. 64 cells at once.
// - Data is assumed to use the natural LSB-first packing:
//     bit i of input[row * words_per_row + word] is cell x = 64 * word + i, y = row.
// - The current row's left/right neighboring words are obtained with warp shuffles.
//   Only subwarp-boundary lanes perform extra global loads for cross-warp or row-edge words.
// - No shared memory is used; for this access pattern, warp shuffles already remove most
//   redundant horizontal traffic with less overhead.
// - The launcher exploits the guaranteed power-of-two dimensions so the kernel has no x/y
//   bounds checks in the hot path.
//
// The implementation assumes the usual double-buffered Life step:
// input and output must be distinct device buffers.

namespace {

using u64   = std::uint64_t;
using usize = std::size_t;

constexpr unsigned int kFullWarpMask         = 0xFFFFFFFFu;
constexpr unsigned int kMaxPowerOfTwoGridY   = 32768u;  // Largest power of two <= CUDA's grid.y limit.

// Hardware lane id is needed because when blockDim.x < 32, a warp spans multiple rows;
// threadIdx.x alone is not enough to identify shuffle lanes correctly.
__device__ __forceinline__ unsigned int lane_id() {
    unsigned int lane;
    asm("mov.u32 %0, %%laneid;" : "=r"(lane));
    return lane;
}

// LSB-first packing:
//   west neighbor of bit x is input(x-1), which aligns onto bit x by shifting left.
//   east neighbor of bit x is input(x+1), which aligns onto bit x by shifting right.
__device__ __forceinline__ u64 align_west(const u64 word, const u64 left_word) {
    return (word << 1) | (left_word >> 63);
}

__device__ __forceinline__ u64 align_east(const u64 word, const u64 right_word) {
    return (word >> 1) | (right_word << 63);
}

// Bit-sliced adders operating independently on all 64 bit positions in parallel.
__device__ __forceinline__ void half_adder(const u64 a, const u64 b, u64& sum, u64& carry) {
    sum   = a ^ b;
    carry = a & b;
}

__device__ __forceinline__ void full_adder(const u64 a, const u64 b, const u64 c, u64& sum, u64& carry) {
    const u64 ab_xor = a ^ b;
    sum   = ab_xor ^ c;
    carry = (a & b) | (ab_xor & c);
}

template <int SUBWARP_WIDTH>
__global__ __launch_bounds__(256)
void game_of_life_step_kernel(const u64* __restrict__ input,
                              u64* __restrict__ output,
                              int grid_dimensions,
                              int words_per_row) {
    static_assert(SUBWARP_WIDTH == 8 || SUBWARP_WIDTH == 16 || SUBWARP_WIDTH == 32,
                  "SUBWARP_WIDTH must be 8, 16, or 32.");

    // The launcher chooses exact power-of-two tiling:
    // - x is covered exactly by blockDim.x * gridDim.x
    // - y uses an exact power-of-two grid-stride loop
    // Therefore every thread in every warp/subwarp is valid for every loop iteration.
    const int word_x     = static_cast<int>(blockIdx.x) * static_cast<int>(blockDim.x) + static_cast<int>(threadIdx.x);
    const int start_row  = static_cast<int>(blockIdx.y) * static_cast<int>(blockDim.y) + static_cast<int>(threadIdx.y);
    const int row_stride = static_cast<int>(gridDim.y)  * static_cast<int>(blockDim.y);

    const usize pitch      = static_cast<usize>(words_per_row);
    const usize word_index = static_cast<usize>(word_x);
    usize idx              = static_cast<usize>(start_row) * pitch + word_index;
    const usize idx_stride = static_cast<usize>(row_stride) * pitch;

    const int  last_row       = grid_dimensions - 1;
    const bool has_left_word  = (word_x != 0);
    const bool has_right_word = (word_x != (words_per_row - 1));

    // For blockDim.x < 32, a warp contains multiple independent row segments.
    // Shuffle width keeps traffic inside one row segment:
    //   width 16 -> two rows per warp
    //   width  8 -> four rows per warp
    //   width 32 -> the common case, one row segment per warp
    const unsigned int lane             = lane_id();
    const unsigned int lane_in_subwarp  = lane & static_cast<unsigned int>(SUBWARP_WIDTH - 1);
    const bool subwarp_left_edge        = (lane_in_subwarp == 0u);
    const bool subwarp_right_edge       = (lane_in_subwarp == static_cast<unsigned int>(SUBWARP_WIDTH - 1));

    for (int row = start_row; row < grid_dimensions; row += row_stride, idx += idx_stride) {
        const bool has_north = (row != 0);
        const bool has_south = (row != last_row);

        // Load the three vertically adjacent center words.
        const u64 north   = has_north ? input[idx - pitch] : 0ULL;
        const u64 current = input[idx];
        const u64 south   = has_south ? input[idx + pitch] : 0ULL;

        // Horizontal neighbors mostly come from shuffles. Only subwarp-boundary lanes
        // need explicit global loads for cross-warp or row-edge words.
        u64 left_north    = __shfl_up_sync(kFullWarpMask, north,   1, SUBWARP_WIDTH);
        u64 right_north   = __shfl_down_sync(kFullWarpMask, north, 1, SUBWARP_WIDTH);
        u64 left_current  = __shfl_up_sync(kFullWarpMask, current,   1, SUBWARP_WIDTH);
        u64 right_current = __shfl_down_sync(kFullWarpMask, current, 1, SUBWARP_WIDTH);
        u64 left_south    = __shfl_up_sync(kFullWarpMask, south,   1, SUBWARP_WIDTH);
        u64 right_south   = __shfl_down_sync(kFullWarpMask, south, 1, SUBWARP_WIDTH);

        if (subwarp_left_edge) {
            if (has_left_word) {
                left_current = input[idx - 1];
                left_north   = has_north ? input[idx - pitch - 1] : 0ULL;
                left_south   = has_south ? input[idx + pitch - 1] : 0ULL;
            } else {
                left_current = 0ULL;
                left_north   = 0ULL;
                left_south   = 0ULL;
            }
        }

        if (subwarp_right_edge) {
            if (has_right_word) {
                right_current = input[idx + 1];
                right_north   = has_north ? input[idx - pitch + 1] : 0ULL;
                right_south   = has_south ? input[idx + pitch + 1] : 0ULL;
            } else {
                right_current = 0ULL;
                right_north   = 0ULL;
                right_south   = 0ULL;
            }
        }

        // Build the 8 aligned neighbor bitboards.
        // Current row contributes only W/E; the center cell itself is excluded from the neighbor count.
        u64 north_low, north_high;
        {
            const u64 north_west = align_west(north, left_north);
            const u64 north_east = align_east(north, right_north);
            full_adder(north_west, north, north_east, north_low, north_high);
        }

        u64 middle_low, middle_high;
        {
            const u64 west = align_west(current, left_current);
            const u64 east = align_east(current, right_current);
            half_adder(west, east, middle_low, middle_high);
        }

        u64 south_low, south_high;
        {
            const u64 south_west = align_west(south, left_south);
            const u64 south_east = align_east(south, right_south);
            full_adder(south_west, south, south_east, south_low, south_high);
        }

        // Add the three per-row counts:
        //   row count low bits  -> neighbor count bit 0 and carry into the 2's bit
        //   row count high bits -> partial 2's bit and carry into the 4's bit
        u64 ones_bit, carry_to_twos;
        full_adder(north_low, middle_low, south_low, ones_bit, carry_to_twos);

        u64 twos_from_row_highs, carry_to_fours;
        full_adder(north_high, middle_high, south_high, twos_from_row_highs, carry_to_fours);

        const u64 twos_bit = twos_from_row_highs ^ carry_to_twos;

        // twos_bit == 1 exactly for neighbor counts {2, 3, 6, 7}.
        // carry_to_fours rejects the remaining >=4 cases among those, i.e. {6, 7}.
        // Then:
        //   count == 3 -> ones_bit == 1, so the cell becomes alive regardless of current state
        //   count == 2 -> ones_bit == 0, so the cell survives only if it is currently alive
        output[idx] = twos_bit & ~carry_to_fours & (ones_bit | current);
    }
}

}  // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions) {
    const int words_per_row = grid_dimensions >> 6;

    // Smallest measured grid is 1024x1024 -> 16 packed words per row.
    // For that case, using 128-thread blocks increases block count and spreads work across more SMs.
    // Larger grids use 256-thread blocks.
    const int target_threads_per_block = (words_per_row <= 16) ? 128 : 256;

    // block_x is always a power-of-two factor of words_per_row, so x is tiled exactly.
    const int block_x = (words_per_row < target_threads_per_block) ? words_per_row : target_threads_per_block;
    const int block_y = target_threads_per_block / block_x;

    const unsigned int grid_x = static_cast<unsigned int>(words_per_row / block_x);

    // grid.y is capped at 2^15 (not 65535) because 2^15 is the largest power of two allowed by CUDA's grid.y limit.
    // Since the height is also a power of two, the resulting y-stride still partitions the domain exactly,
    // which keeps every warp/subwarp full and lets the kernel avoid bounds checks.
    const unsigned int row_block_count = static_cast<unsigned int>(grid_dimensions / block_y);
    const unsigned int grid_y = (row_block_count > kMaxPowerOfTwoGridY) ? kMaxPowerOfTwoGridY : row_block_count;

    const dim3 block(static_cast<unsigned int>(block_x),
                     static_cast<unsigned int>(block_y),
                     1u);

    const dim3 grid(grid_x, grid_y, 1u);

    // Width-32 shuffles are used for all normal wide-row cases.
    // Width-16/8 are needed only when a warp carries multiple independent rows.
    switch (block_x) {
        case 8:
            game_of_life_step_kernel<8><<<grid, block>>>(input, output, grid_dimensions, words_per_row);
            break;
        case 16:
            game_of_life_step_kernel<16><<<grid, block>>>(input, output, grid_dimensions, words_per_row);
            break;
        default:
            game_of_life_step_kernel<32><<<grid, block>>>(input, output, grid_dimensions, words_per_row);
            break;
    }
}

#include <cstddef>
#include <cstdint>
#include <cuda_runtime.h>

namespace {

// This implementation intentionally avoids shared/texture memory.
// The useful horizontal reuse is cheaper via warp shuffles, while the remaining
// vertical accesses are regular row-stride loads that cache well on modern GPUs.
//
// One thread updates one 64-bit word = 64 cells.  The kernel is fully bit-sliced:
// every bit position in a 64-bit register is an independent cell lane.

using word_t = std::uint64_t;

constexpr int kBlockThreads = 256;
constexpr unsigned kFullWarpMask = 0xFFFFFFFFu;

static_assert(sizeof(word_t) == 8, "word_t must be 64-bit.");
static_assert(kBlockThreads % 32 == 0, "Block size must be warp-aligned.");
static_assert(kBlockThreads % 16 == 0, "Block size must support 16-lane tiles.");

// Extract the word-edge bits that must cross 64-bit word boundaries.
__device__ __forceinline__ unsigned word_msb(const word_t v) {
    return static_cast<unsigned>(v >> 63);
}

__device__ __forceinline__ unsigned word_lsb(const word_t v) {
    return static_cast<unsigned>(v) & 1u;
}

// Bit-sliced 3-input full adder.
// For every bit position i:
//   a_i + b_i + c_i = sum_i + 2 * carry_i
//
// Modern NVIDIA compilers generally map these boolean expressions to very few
// LOP3 instructions.
__device__ __forceinline__ void full_add(
    const word_t a,
    const word_t b,
    const word_t c,
    word_t& sum,
    word_t& carry)
{
    const word_t ab_xor = a ^ b;
    sum   = ab_xor ^ c;
    carry = (a & b) | (ab_xor & c);
}

// Each thread needs exactly two carried-in boundary bits per row:
// - previous word's MSB for the left-shifted (west-neighbor) view
// - next word's LSB for the right-shifted (east-neighbor) view
//
// We pack the three rows' edge bits into one 3-bit integer so the whole
// 3-row exchange costs only two shuffles per thread, not six.
template <int GROUP_WIDTH>
__device__ __forceinline__ void exchange_packed_edge_bits(
    const unsigned packed_msbs,
    const unsigned packed_lsbs,
    const bool left_group_edge,
    const bool right_group_edge,
    const unsigned left_boundary_packed,
    const unsigned right_boundary_packed,
    unsigned& packed_from_left,
    unsigned& packed_from_right)
{
    packed_from_left  = __shfl_up_sync(kFullWarpMask, packed_msbs, 1, GROUP_WIDTH);
    packed_from_right = __shfl_down_sync(kFullWarpMask, packed_lsbs, 1, GROUP_WIDTH);

    // Only group-edge lanes need explicit boundary values.
    if (left_group_edge) {
        packed_from_left = left_boundary_packed;
    }
    if (right_group_edge) {
        packed_from_right = right_boundary_packed;
    }
}

// Build the 2-bit population count for one row of the 3x3 window:
//   west + center + east = sum + 2*carry
//
// Out-of-bounds cells are dead, so missing carry-in bits are zero.
__device__ __forceinline__ void count_row(
    const word_t center,
    const unsigned left_carry,
    const unsigned right_carry,
    word_t& sum,
    word_t& carry)
{
    const word_t west = (center << 1) | static_cast<word_t>(left_carry);
    const word_t east = (center >> 1) | (static_cast<word_t>(right_carry) << 63);
    full_add(west, center, east, sum, carry);
}

// We sum the full 3x3 population, center included.  Conway's rule then becomes:
//
//   next = (population == 3) | (center & (population == 4))
//
// That is cheaper than first forming the 8-neighbor count and then handling
// survival as a separate path.
__device__ __forceinline__ word_t apply_life_rule(
    const word_t center,
    const word_t low0,
    const word_t low1,
    const word_t high0,
    const word_t high1)
{
    const word_t middle_bit = low1 ^ high0;
    const word_t total_eq_3 = low0 & middle_bit & ~high1;
    const word_t total_eq_4 = ~low0 & ~middle_bit & (high1 ^ low1);
    return total_eq_3 | (center & total_eq_4);
}

template <int GROUP_WIDTH>
__global__ __launch_bounds__(kBlockThreads)
void game_of_life_kernel(
    const word_t* __restrict__ input,
    word_t* __restrict__ output,
    int grid_dimensions,
    int words_per_row_shift)
{
    static_assert(GROUP_WIDTH == 16 || GROUP_WIDTH == 32,
                  "Only 16- or 32-lane shuffle tiles are supported.");

    // Under the stated problem constraints:
    // - total word count is an exact multiple of kBlockThreads
    // - words_per_row is a power of two
    // - GROUP_WIDTH exactly tiles each row (16 for 1024x1024, otherwise 32)
    //
    // Therefore every launched thread is valid and no tail predicate is needed.
    const std::size_t idx = static_cast<std::size_t>(blockIdx.x) * kBlockThreads + threadIdx.x;

    const std::size_t row_stride = std::size_t{1} << words_per_row_shift;  // 64-bit words per row
    const std::size_t row_mask   = row_stride - 1;
    const std::size_t grid_dim   = static_cast<std::size_t>(grid_dimensions);

    const std::size_t row       = idx >> words_per_row_shift;
    const std::size_t row_local = idx & row_mask;

    const bool has_top        = (row != 0);
    const bool has_bottom     = (row + 1 != grid_dim);
    const bool has_left_word  = (row_local != 0);
    const bool has_right_word = (row_local != row_mask);

    const unsigned lane_in_group = threadIdx.x & (GROUP_WIDTH - 1);
    const bool left_group_edge   = (lane_in_group == 0u);
    const bool right_group_edge  = (lane_in_group == static_cast<unsigned>(GROUP_WIDTH - 1));

    const std::size_t top_idx = idx - row_stride;
    const std::size_t bot_idx = idx + row_stride;

    // Vertical neighbors are explicit row-stride loads.
    // Horizontal reuse is handled by exchanging just the required edge bits.
    const word_t mid_c = input[idx];
    const word_t top_c = has_top    ? input[top_idx] : word_t{0};
    const word_t bot_c = has_bottom ? input[bot_idx] : word_t{0};

    // Packed boundary bits for the group-edge lanes:
    // bit 0 = top row, bit 1 = middle row, bit 2 = bottom row.
    unsigned left_boundary_packed = 0u;
    if (left_group_edge && has_left_word) {
        left_boundary_packed = word_msb(input[idx - 1]) << 1;
        if (has_top) {
            left_boundary_packed |= word_msb(input[top_idx - 1]);
        }
        if (has_bottom) {
            left_boundary_packed |= word_msb(input[bot_idx - 1]) << 2;
        }
    }

    unsigned right_boundary_packed = 0u;
    if (right_group_edge && has_right_word) {
        right_boundary_packed = word_lsb(input[idx + 1]) << 1;
        if (has_top) {
            right_boundary_packed |= word_lsb(input[top_idx + 1]);
        }
        if (has_bottom) {
            right_boundary_packed |= word_lsb(input[bot_idx + 1]) << 2;
        }
    }

    const unsigned packed_msbs =
        word_msb(top_c) |
        (word_msb(mid_c) << 1) |
        (word_msb(bot_c) << 2);

    const unsigned packed_lsbs =
        word_lsb(top_c) |
        (word_lsb(mid_c) << 1) |
        (word_lsb(bot_c) << 2);

    unsigned packed_from_left;
    unsigned packed_from_right;
    exchange_packed_edge_bits<GROUP_WIDTH>(
        packed_msbs,
        packed_lsbs,
        left_group_edge,
        right_group_edge,
        left_boundary_packed,
        right_boundary_packed,
        packed_from_left,
        packed_from_right);

    const unsigned top_left_in  =  packed_from_left        & 1u;
    const unsigned mid_left_in  = (packed_from_left  >> 1) & 1u;
    const unsigned bot_left_in  =  packed_from_left  >> 2;

    const unsigned top_right_in =  packed_from_right       & 1u;
    const unsigned mid_right_in = (packed_from_right >> 1) & 1u;
    const unsigned bot_right_in =  packed_from_right >> 2;

    // 2-bit row sums for the three rows of the 3x3 window.
    word_t top0, top1;
    word_t mid0, mid1;
    word_t bot0, bot1;
    count_row(top_c, top_left_in, top_right_in, top0, top1);
    count_row(mid_c, mid_left_in, mid_right_in, mid0, mid1);
    count_row(bot_c, bot_left_in, bot_right_in, bot0, bot1);

    // Sum the three 2-bit row counts into a 4-bit 3x3 population count.
    word_t low0, low1;
    word_t high0, high1;
    full_add(top0, mid0, bot0, low0, low1);
    full_add(top1, mid1, bot1, high0, high1);

    output[idx] = apply_life_rule(mid_c, low0, low1, high0, high1);
}

}  // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions)
{
    // The documented preconditions are used as optimization assumptions:
    // - grid_dimensions is a power of two
    // - grid_dimensions > 512
    // - input/output are device allocations from cudaMalloc
    // - input and output do not overlap (out-of-place update)
    //
    // Because words_per_row is also a power of two, the kernel can recover
    // row/column positions with bit shifts and masks instead of division/modulo.
    const int words_per_row = grid_dimensions >> 6;

    int words_per_row_shift = 0;
    for (int t = words_per_row; t > 1; t >>= 1) {
        ++words_per_row_shift;
    }

    // One thread updates one 64-bit word.  total_words is always a power of two
    // and, with grid_dimensions > 512, an exact multiple of kBlockThreads.
    const std::size_t total_words =
        static_cast<std::size_t>(grid_dimensions) << words_per_row_shift;
    const unsigned int blocks =
        static_cast<unsigned int>(total_words / kBlockThreads);

    // Only two tile widths can occur here:
    // - 16 lanes when grid_dimensions == 1024  (16 words per row)
    // - 32 lanes for all larger grids
    //
    // The largest legal tile minimizes boundary traffic while guaranteeing that
    // shuffle groups never cross a row boundary.
    if (words_per_row == 16) {
        game_of_life_kernel<16><<<blocks, kBlockThreads>>>(
            input,
            output,
            grid_dimensions,
            words_per_row_shift);
    } else {
        game_of_life_kernel<32><<<blocks, kBlockThreads>>>(
            input,
            output,
            grid_dimensions,
            words_per_row_shift);
    }

    // The caller owns synchronization and any desired launch-error handling.
}

#include <cuda_runtime.h>
#include <cstddef>
#include <cstdint>

// Optimized bit-packed Conway's Game of Life for modern NVIDIA GPUs.
//
// Representation:
//   - The grid is row-major.
//   - Within a row, cell x is stored in bit (x & 63) of word (x >> 6).
//   - One thread updates one 64-bit word, i.e. 64 cells at once.
//   - One warp updates 32 consecutive words of one row segment.
//
// Design choices:
//   - No shared memory: the prompt notes that it is unnecessary here.
//   - Horizontal word exchange uses warp shuffles; only segment-edge lanes need
//     one fallback global load.
//   - Neighbor counting stays fully bit-packed in registers using a short boolean
//     carry-save network; the kernel never expands cells into bytes or ints.
//   - The host wrapper does not synchronize; the caller is responsible for that.

namespace {

using word_t = unsigned long long;

constexpr int kCellsPerWordShift   = 6;  // 64 cells / word.
constexpr int kLastBit             = 63; // Highest bit position in a 64-bit word.
constexpr int kWarpWords           = 32; // One warp covers 32 consecutive words.
constexpr int kWarpShift           = 5;  // log2(32).
constexpr int kRowsPerBlock        = 8;  // 8 warps / block => 256 threads.
constexpr int kRowsPerBlockShift   = 3;  // log2(8).

static_assert(kWarpWords == (1 << kWarpShift), "kWarpWords must be a power of two.");
static_assert(kRowsPerBlock == (1 << kRowsPerBlockShift), "kRowsPerBlock must be a power of two.");

__device__ __forceinline__ void add3(const word_t a, const word_t b, const word_t c,
                                     word_t& sum, word_t& carry) {
    // Full-adder applied lane-wise to 64 independent 1-bit values:
    //   sum + 2*carry == a + b + c
    const word_t ab_xor = a ^ b;
    sum   = ab_xor ^ c;
    carry = (a & b) | (c & ab_xor);
}

__device__ __forceinline__ word_t exact_one4(const word_t x, const word_t y,
                                             const word_t z, const word_t w) {
    // Return a bitmask with 1s exactly where x+y+z+w == 1, lane-wise.
    // Pairwise half-adders keep the dependency chain short.
    const word_t p = x ^ y;
    const word_t q = x & y;
    const word_t r = z ^ w;
    const word_t t = z & w;
    return (p ^ r) & ~(q | t);
}

__device__ __forceinline__ void adjacent_words(
    const unsigned active_mask,
    const unsigned lane,
    const int xw,
    const int words_per_row,
    const std::uint64_t* row_ptr,
    const word_t center,
    word_t& left,
    word_t& right) {
    // A warp covers 32 consecutive words of one row. In the common case the
    // neighboring word is already resident in the adjacent lane's register.
    // Only the first/last lane of a 32-word segment falls back to one extra load.
    const word_t shfl_left  = __shfl_up_sync(active_mask, center, 1);
    const word_t shfl_right = __shfl_down_sync(active_mask, center, 1);

    left = (xw != 0)
        ? ((lane != 0u) ? shfl_left : static_cast<word_t>(row_ptr[xw - 1]))
        : 0ull;

    right = (xw != words_per_row - 1)
        ? ((lane != static_cast<unsigned>(kWarpWords - 1))
            ? shfl_right
            : static_cast<word_t>(row_ptr[xw + 1]))
        : 0ull;
}

__global__ __launch_bounds__(kWarpWords * kRowsPerBlock)
void game_of_life_kernel(const std::uint64_t* __restrict__ input,
                         std::uint64_t* __restrict__ output,
                         int grid_dimensions,
                         int words_per_row,
                         int words_log2,
                         unsigned int row_block_mask,
                         int row_blocks_log2) {
    // grid.x is a flattened 2-D launch space:
    //   low  bits -> row block (8 rows)
    //   high bits -> 32-word x-segment
    const unsigned linear_block = blockIdx.x;
    const unsigned row_block    = linear_block & row_block_mask;
    const unsigned segment      = linear_block >> row_blocks_log2;

    const unsigned lane         = threadIdx.x;
    const unsigned row_in_block = threadIdx.y;

    const int xw = static_cast<int>((segment << kWarpShift) | lane);
    if (xw >= words_per_row) {
        // Only possible for the smallest legal board: 1024x1024 => 16 words/row.
        return;
    }

    const int y = static_cast<int>((row_block << kRowsPerBlockShift) | row_in_block);
    const int last_row = grid_dimensions - 1;
    const bool has_top = (y != 0);
    const bool has_bottom = (y != last_row);

    const unsigned active_mask = __activemask();

    // Because the problem guarantees power-of-two dimensions, all row/word address
    // calculations reduce to shifts and bitwise ors.
    const std::size_t row_offset =
        (static_cast<std::size_t>(row_block) << (words_log2 + kRowsPerBlockShift)) |
        (static_cast<std::size_t>(row_in_block) << words_log2);

    const std::uint64_t* row_ptr = input + row_offset;
    std::uint64_t* out_row_ptr   = output + row_offset;

    const word_t center = static_cast<word_t>(row_ptr[xw]);

    // Compress the three neighbors from the row above into:
    //   top_count == s_top + 2*c_top
    word_t s_top = 0ull;
    word_t c_top = 0ull;
    if (has_top) {
        const std::uint64_t* up_row = row_ptr - words_per_row;
        const word_t up = static_cast<word_t>(up_row[xw]);

        word_t up_left, up_right;
        adjacent_words(active_mask, lane, xw, words_per_row, up_row, up, up_left, up_right);

        // Shift-and-stitch across 64-bit word boundaries so each bit position is
        // aligned with the cell updated by this thread.
        const word_t up_west = (up << 1) | (up_left >> kLastBit);
        const word_t up_east = (up >> 1) | (up_right << kLastBit);

        add3(up_west, up, up_east, s_top, c_top);
    }

    // Same compression for the row below.
    word_t s_bottom = 0ull;
    word_t c_bottom = 0ull;
    if (has_bottom) {
        const std::uint64_t* down_row = row_ptr + words_per_row;
        const word_t down = static_cast<word_t>(down_row[xw]);

        word_t down_left, down_right;
        adjacent_words(active_mask, lane, xw, words_per_row, down_row, down, down_left, down_right);

        const word_t down_west = (down << 1) | (down_left >> kLastBit);
        const word_t down_east = (down >> 1) | (down_right << kLastBit);

        add3(down_west, down, down_east, s_bottom, c_bottom);
    }

    // Current-row side neighbors.
    word_t center_left, center_right;
    adjacent_words(active_mask, lane, xw, words_per_row, row_ptr, center, center_left, center_right);

    const word_t west = (center << 1) | (center_left >> kLastBit);
    const word_t east = (center >> 1) | (center_right << kLastBit);

    // Neighbor count decomposition:
    //   top    = s_top    + 2*c_top
    //   bottom = s_bottom + 2*c_bottom
    //   top + bottom + west = s_mid + 2*c_mid
    //   total_neighbors = (s_mid + east) + 2*(carry_from_low + c_mid + c_top + c_bottom)
    //
    // Conway's rule needs only counts 2 and 3:
    //   - exactly one of the four "2-weight" contributors must be present
    //   - then low_bit==1 means count==3, while low_bit==0 means count==2 and the
    //     cell survives only if it is already alive.
    word_t s_mid, c_mid;
    add3(s_top, s_bottom, west, s_mid, c_mid);

    const word_t low_bit        = s_mid ^ east;
    const word_t carry_from_low = s_mid & east;
    const word_t twos_eq_1      = exact_one4(carry_from_low, c_mid, c_top, c_bottom);
    const word_t next           = twos_eq_1 & (low_bit | center);

    out_row_ptr[xw] = static_cast<std::uint64_t>(next);
}

} // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions) {
    // The caller guarantees:
    //   - square grid
    //   - power-of-two dimension > 512
    //   - input/output are device pointers from cudaMalloc
    //   - input and output are distinct buffers
    //
    // The wrapper intentionally performs no validation and no synchronization.
    const int words_per_row = grid_dimensions >> kCellsPerWordShift;

    // One warp updates one 32-word segment. Since words_per_row is a power of two,
    // the segment count is either 1 (for 16 or 32 words/row) or another power of two.
    const unsigned int segments =
        static_cast<unsigned int>((words_per_row + kWarpWords - 1) >> kWarpShift);

    // Using grid.y for row blocks would hit the architectural 65535 limit for the
    // largest valid boards, so the launch space is flattened into grid.x instead.
    const unsigned int row_blocks =
        static_cast<unsigned int>(grid_dimensions >> kRowsPerBlockShift);

    int row_blocks_log2 = 0;
    while ((1u << row_blocks_log2) < row_blocks) {
        ++row_blocks_log2;
    }

    // row_blocks == words_per_row * 8, so:
    //   log2(words_per_row) == log2(row_blocks) - 3
    const int words_log2 = row_blocks_log2 - kRowsPerBlockShift;

    const std::uint64_t total_blocks_64 =
        static_cast<std::uint64_t>(segments) << row_blocks_log2;

    const dim3 block(kWarpWords, kRowsPerBlock, 1);
    const dim3 grid(static_cast<unsigned int>(total_blocks_64), 1, 1);

    game_of_life_kernel<<<grid, block>>>(
        input,
        output,
        grid_dimensions,
        words_per_row,
        words_log2,
        row_blocks - 1u,
        row_blocks_log2);
}

#include <cuda_runtime.h>
#include <cstddef>
#include <cstdint>

namespace {

// One thread updates one packed 64-cell word.
// One warp therefore updates 32 packed words = 2048 cells in a horizontal row tile.
using u64 = std::uint64_t;

constexpr unsigned kWarpSize          = 32;
constexpr unsigned kWarpTileShift     = 5;   // 2^5 = 32 packed words per warp tile.
constexpr unsigned kCellsPerWordShift = 6;   // 2^6 = 64 cells per packed word.
constexpr unsigned kWarpsPerBlock     = 4;   // 128-thread blocks: good distribution even for 1024x1024 boards.
constexpr unsigned kBlockThreadsX     = kWarpSize;
constexpr unsigned kBlockThreadsY     = kWarpsPerBlock;

// The kernel is written as a warp-granular grid-stride loop. 256k blocks is already far beyond
// what an A100/H100 needs for full saturation, while avoiding pathological multi-million-block
// launches on extremely large boards.
constexpr std::size_t kLaunchBlocksCap = std::size_t{1} << 18;

static_assert(kBlockThreadsX == kWarpSize, "Each block row must map to exactly one warp.");

// Host-side helper: the input is guaranteed to be a power of two, so log2 is just repeated shifts.
// This keeps the wrapper portable without relying on compiler-specific intrinsics.
inline unsigned log2_pow2(std::size_t x) {
    unsigned shift = 0;
    while (x > 1) {
        x >>= 1;
        ++shift;
    }
    return shift;
}

// On modern NVIDIA data-center GPUs, ordinary global loads from const __restrict__ memory are
// already well cached; explicit texture memory or shared-memory staging is unnecessary here.
__device__ __forceinline__ u64 load_ro(const u64* ptr) {
    return *ptr;
}

// Carry-save adder for bit-sliced accumulation.
// Every bit position is independent, so one 64-bit register represents 64 separate cells.
// a + b + c == sum + 2 * carry, evaluated independently for all 64 bit lanes.
// On Ampere/Hopper, ptxas typically lowers this boolean network to efficient LOP3 instructions.
__device__ __forceinline__ void csa(u64 a, u64 b, u64 c, u64& sum, u64& carry) {
    const u64 ab_xor = a ^ b;
    sum   = ab_xor ^ c;
    carry = (a & b) | (ab_xor & c);
}

// For the natural packing used here, bit k in a word corresponds to x = 64*word + k.
// shift_west/east align horizontal neighbors for all 64 cells in parallel, bringing in the
// cross-word carry bit from the adjacent packed word.
__device__ __forceinline__ u64 shift_west(u64 center, u64 left_word) {
    return (center << 1) | (left_word >> 63);
}

__device__ __forceinline__ u64 shift_east(u64 center, u64 right_word) {
    return (center >> 1) | (right_word << 63);
}

// High-throughput Conway step kernel.
// Key design choices:
//   - No shared memory: each thread only loads the vertically aligned words (top/current/bottom).
//   - Horizontal reuse comes from warp shuffles, so the common case is 3 loads/thread instead of 9.
//   - One linear warp-tile index maps to (row, horizontal-tile) using only shifts/masks, made
//     possible by the power-of-two grid size.
__global__ void game_of_life_kernel(const u64* __restrict__ input,
                                    u64* __restrict__ output,
                                    std::size_t grid_dim,
                                    unsigned words_per_row_shift,
                                    unsigned tiles_per_row_shift) {
    constexpr unsigned kFullMask = 0xFFFFFFFFu;

    const std::size_t words_per_row     = std::size_t{1} << words_per_row_shift;
    const std::size_t tiles_per_row_mask =
        (std::size_t{1} << tiles_per_row_shift) - std::size_t{1};
    const std::size_t total_row_tiles   = grid_dim << tiles_per_row_shift;

    const unsigned lane         = threadIdx.x;
    const unsigned warp_in_block = threadIdx.y;

    const std::size_t first_warp_tile =
        static_cast<std::size_t>(blockIdx.x) * kWarpsPerBlock + warp_in_block;
    const std::size_t warp_tile_stride =
        static_cast<std::size_t>(gridDim.x) * kWarpsPerBlock;

    for (std::size_t warp_tile = first_warp_tile;
         warp_tile < total_row_tiles;
         warp_tile += warp_tile_stride) {

        // Because tiles_per_row is a power of two, row/tile decomposition is shift+mask only.
        const std::size_t row    = warp_tile >> tiles_per_row_shift;
        const std::size_t tile   = warp_tile & tiles_per_row_mask;
        const std::size_t word_x = (tile << kWarpTileShift) + lane;

        // Only the smallest legal board (1024x1024) produces a partial warp tile:
        // 1024 cells / 64 cells-per-word = 16 packed words per row.
        const unsigned active_mask = __ballot_sync(kFullMask, word_x < words_per_row);
        const bool lane_active = (active_mask & (1u << lane)) != 0u;

        if (lane_active) {
            const std::size_t row_base = row << words_per_row_shift;

            const u64* const row_ptr = input  + row_base;
            u64* const       out_ptr = output + row_base;

            // Outside-grid cells are dead, so missing rows/words contribute zeros.
            const bool has_top    = row != 0;
            const bool has_bottom = (row + 1) != grid_dim;
            const bool has_left   = word_x != 0;
            const bool has_right  = (word_x + 1) != words_per_row;

            const u64* const top_ptr = has_top    ? (row_ptr - words_per_row) : nullptr;
            const u64* const bot_ptr = has_bottom ? (row_ptr + words_per_row) : nullptr;

            // Center words for the three rows.
            const u64 top = has_top    ? load_ro(top_ptr + word_x) : u64{0};
            const u64 mid =               load_ro(row_ptr + word_x);
            const u64 bot = has_bottom ? load_ro(bot_ptr + word_x) : u64{0};

            // Horizontal neighbors usually come from adjacent lanes in the same warp tile.
            // Only tile boundaries require an extra global load.
            u64 top_l = __shfl_up_sync  (active_mask, top, 1);
            u64 top_r = __shfl_down_sync(active_mask, top, 1);
            u64 mid_l = __shfl_up_sync  (active_mask, mid, 1);
            u64 mid_r = __shfl_down_sync(active_mask, mid, 1);
            u64 bot_l = __shfl_up_sync  (active_mask, bot, 1);
            u64 bot_r = __shfl_down_sync(active_mask, bot, 1);

            if (lane == 0u) {
                mid_l = has_left ? load_ro(row_ptr + word_x - 1) : u64{0};
                top_l = (has_top    && has_left) ? load_ro(top_ptr + word_x - 1) : u64{0};
                bot_l = (has_bottom && has_left) ? load_ro(bot_ptr + word_x - 1) : u64{0};
            }

            if (lane == (kWarpSize - 1u) || !has_right) {
                mid_r = has_right ? load_ro(row_ptr + word_x + 1) : u64{0};
                top_r = (has_top    && has_right) ? load_ro(top_ptr + word_x + 1) : u64{0};
                bot_r = (has_bottom && has_right) ? load_ro(bot_ptr + word_x + 1) : u64{0};
            }

            // Build the 8 neighbor bitboards.
            // Scope-local temporaries keep register lifetimes short.
            u64 s_top, c_top;
            {
                const u64 west = shift_west(top, top_l);
                const u64 east = shift_east(top, top_r);
                csa(west, top, east, s_top, c_top);
            }

            u64 s_mid, c_mid;
            {
                const u64 west = shift_west(mid, mid_l);
                const u64 east = shift_east(mid, mid_r);
                s_mid = west ^ east;  // half adder of the two horizontal neighbors
                c_mid = west & east;
            }

            u64 s_bot, c_bot;
            {
                const u64 west = shift_west(bot, bot_l);
                const u64 east = shift_east(bot, bot_r);
                csa(west, bot, east, s_bot, c_bot);
            }

            // Reduce the 8 one-bit neighbor masks with a carry-save tree.
            //
            // After these two CSAs:
            //   neighbors = bit0 + 2*twos_a + 2*twos_b + 4*fours
            //
            // The final 2's-place is bit1 = twos_a ^ twos_b.
            // If twos_a and twos_b are both 1, the total is already >= 4, and bit1 becomes 0.
            // Therefore:
            //   count == 2 or 3  <=>  bit1 is 1 and fours is 0
            //
            // Finally, (bit0 | mid) encodes the Life rule:
            //   - count == 3 => bit0 == 1 => birth/survival
            //   - count == 2 => bit0 == 0 => survive only if currently alive (mid == 1)
            u64 bit0, twos_a;
            csa(s_top, s_mid, s_bot, bit0, twos_a);

            u64 twos_b, fours;
            csa(c_top, c_mid, c_bot, twos_b, fours);

            const u64 bit1 = twos_a ^ twos_b;
            out_ptr[word_x] = bit1 & ~fours & (bit0 | mid);
        }
    }
}

} // namespace

void run_game_of_life(const std::uint64_t* input,
                      std::uint64_t* output,
                      int grid_dimensions) {
    // The problem statement guarantees a power-of-two square board > 512.
    // A defensive early return keeps the wrapper well-defined for accidental misuse without
    // affecting the measured kernel path.
    if (grid_dimensions <= 0) {
        return;
    }

    const std::size_t grid_dim = static_cast<std::size_t>(grid_dimensions);

    // Since grid_dim is a power of two:
    //   words_per_row      = grid_dim / 64 = 2^(log2(grid_dim) - 6)
    //   tiles_per_row      = ceil(words_per_row / 32)
    //                      = max(1, words_per_row / 32)
    //                      = power of two as well
    //
    // That lets the kernel recover row/tile coordinates with shifts and masks only.
    const unsigned grid_dim_shift      = log2_pow2(grid_dim);
    const unsigned words_per_row_shift = grid_dim_shift - kCellsPerWordShift;
    const unsigned tiles_per_row_shift =
        (words_per_row_shift > kWarpTileShift)
            ? (words_per_row_shift - kWarpTileShift)
            : 0u;

    const std::size_t total_row_tiles = grid_dim << tiles_per_row_shift;
    const std::size_t blocks_needed =
        (total_row_tiles + kWarpsPerBlock - 1) / kWarpsPerBlock;

    // The kernel itself is grid-stride, so bounding the launch size is enough to keep very large
    // boards efficient without changing the steady-state work per tile.
    const std::size_t launch_blocks =
        (blocks_needed < kLaunchBlocksCap) ? blocks_needed : kLaunchBlocksCap;

    const dim3 block(kBlockThreadsX, kBlockThreadsY);
    game_of_life_kernel<<<static_cast<unsigned int>(launch_blocks), block, 0, 0>>>(
        input,
        output,
        grid_dim,
        words_per_row_shift,
        tiles_per_row_shift);
}

#include <cuda_runtime.h>
#include <cstdint>

namespace {

// Use an explicit 64-bit unsigned type that CUDA's shuffle intrinsics accept directly.
// The public API still uses std::uint64_t; both have the same size/layout.
using u64 = unsigned long long;

static_assert(sizeof(u64) == sizeof(std::uint64_t), "u64 must match std::uint64_t in size");

// 256 threads/block = 8 warps/block.
// This is a good balance for the bitwise-heavy, register-only kernel on modern data-center GPUs.
constexpr int kBlockSize = 256;
constexpr unsigned int kWarpLanes = 32u;
constexpr unsigned int kFullWarpMask = 0xFFFFFFFFu;

static_assert((kBlockSize % kWarpLanes) == 0, "Block size must be a multiple of warp size");

// Read-only global load helper.
// On modern NVIDIA GPUs regular global loads are already well cached, but __ldg still makes the
// read-only intent explicit and is harmless for this workload.
__device__ __forceinline__ u64 ro_load(const u64* ptr) {
#if defined(__CUDA_ARCH__) && (__CUDA_ARCH__ >= 350)
    return __ldg(ptr);
#else
    return *ptr;
#endif
}

// Layout convention used by this kernel:
//   bit k of a 64-bit word represents column (word_x * 64 + k).
// Therefore, after alignment:
//   west-neighbor bitboard = shift current word left by 1 and inject bit 63 from the word on the left
//   east-neighbor bitboard = shift current word right by 1 and inject bit 0  from the word on the right
__device__ __forceinline__ u64 align_west(const u64 word, const u64 left_word) {
    return (word << 1) | (left_word >> 63);
}

__device__ __forceinline__ u64 align_east(const u64 word, const u64 right_word) {
    return (word >> 1) | (right_word << 63);
}

// Carry-save adder for bitboards.
// For every bit position independently:
//   a + b + c = sum + 2 * carry
__device__ __forceinline__ void csa(const u64 a, const u64 b, const u64 c, u64& carry, u64& sum) {
    const u64 u = a ^ b;
    sum = u ^ c;
    carry = (a & b) | (u & c);
}

// One-thread-per-word kernel.
//
// Shared memory is intentionally not used here:
// horizontal reuse is handled with warp shuffles, while vertical reuse comes from the cache.
// This keeps the instruction stream short and avoids synchronization.
//
// Template specialization:
//   RowsFitInWarp == true  : words_per_row is 16 or 32. A whole row fits inside one shuffle group
//                            (width = words_per_row), so all valid horizontal neighbor words are
//                            obtained via shuffles and no cross-warp fallback loads are needed.
//   RowsFitInWarp == false : words_per_row is >= 64. Because words_per_row is a power of two, rows
//                            start on warp boundaries; only lane 0 / lane 31 need cross-warp
//                            fallback loads for left/right words.
//
// No bounds guard is needed:
// grid_dimensions is a power of two and > 512, so total_words = N * (N / 64) is also a power of two
// and always divisible by both 32 and kBlockSize (256). The launch therefore creates exactly one
// full thread per input word and every warp is full.
template <bool RowsFitInWarp>
__global__ __launch_bounds__(kBlockSize)
void game_of_life_step_kernel(const u64* __restrict__ input,
                              u64* __restrict__ output,
                              const u64 total_words,
                              const unsigned int words_per_row,
                              const unsigned int word_mask) {
    const u64 idx = static_cast<u64>(blockIdx.x) * static_cast<u64>(kBlockSize) +
                    static_cast<u64>(threadIdx.x);

    const u64 row_stride = static_cast<u64>(words_per_row);
    const u64 last_row_start = total_words - row_stride;

    const unsigned int lane = static_cast<unsigned int>(threadIdx.x) & (kWarpLanes - 1u);
    const unsigned int xword = static_cast<unsigned int>(idx) & word_mask;

    const bool has_north = idx >= row_stride;
    const bool has_south = idx < last_row_start;
    const bool has_west  = xword != 0u;
    const bool has_east  = xword != word_mask;

    // When a row fits in a warp, shuffles are restricted to the row width (16 or 32).
    // Otherwise, use the full warp width.
    const int shuffle_width = RowsFitInWarp ? static_cast<int>(words_per_row) : static_cast<int>(kWarpLanes);

    // Vertical center words: above, current, below.
    // Missing rows are treated as all-dead words.
    const u64 center = ro_load(input + idx);
    const u64 north  = has_north ? ro_load(input + idx - row_stride) : 0ull;
    const u64 south  = has_south ? ro_load(input + idx + row_stride) : 0ull;

    // First CSA stage: NW + N + NE
    u64 h0, l0;
    {
        const u64 north_left_shfl  = __shfl_up_sync(kFullWarpMask, north, 1, shuffle_width);
        const u64 north_right_shfl = __shfl_down_sync(kFullWarpMask, north, 1, shuffle_width);

        u64 north_left_word  = 0ull;
        u64 north_right_word = 0ull;

        if (RowsFitInWarp) {
            if (has_west) north_left_word = north_left_shfl;
            if (has_east) north_right_word = north_right_shfl;
        } else {
            if (has_west) {
                north_left_word = (lane != 0u)
                    ? north_left_shfl
                    : (has_north ? ro_load(input + idx - row_stride - 1ull) : 0ull);
            }
            if (has_east) {
                north_right_word = (lane != (kWarpLanes - 1u))
                    ? north_right_shfl
                    : (has_north ? ro_load(input + idx - row_stride + 1ull) : 0ull);
            }
        }

        csa(align_west(north, north_left_word),
            north,
            align_east(north, north_right_word),
            h0, l0);
    }

    // Second CSA stage: SW + S + SE
    u64 h1, l1;
    {
        const u64 south_left_shfl  = __shfl_up_sync(kFullWarpMask, south, 1, shuffle_width);
        const u64 south_right_shfl = __shfl_down_sync(kFullWarpMask, south, 1, shuffle_width);

        u64 south_left_word  = 0ull;
        u64 south_right_word = 0ull;

        if (RowsFitInWarp) {
            if (has_west) south_left_word = south_left_shfl;
            if (has_east) south_right_word = south_right_shfl;
        } else {
            if (has_west) {
                south_left_word = (lane != 0u)
                    ? south_left_shfl
                    : (has_south ? ro_load(input + idx + row_stride - 1ull) : 0ull);
            }
            if (has_east) {
                south_right_word = (lane != (kWarpLanes - 1u))
                    ? south_right_shfl
                    : (has_south ? ro_load(input + idx + row_stride + 1ull) : 0ull);
            }
        }

        csa(align_west(south, south_left_word),
            south,
            align_east(south, south_right_word),
            h1, l1);
    }

    // Third CSA stage: l0 + l1 + W
    // East is kept separate so it can be added as the final 1-bit input.
    u64 h2, l2, east;
    {
        const u64 center_left_shfl  = __shfl_up_sync(kFullWarpMask, center, 1, shuffle_width);
        const u64 center_right_shfl = __shfl_down_sync(kFullWarpMask, center, 1, shuffle_width);

        u64 center_left_word  = 0ull;
        u64 center_right_word = 0ull;

        if (RowsFitInWarp) {
            if (has_west) center_left_word = center_left_shfl;
            if (has_east) center_right_word = center_right_shfl;
        } else {
            if (has_west) {
                center_left_word = (lane != 0u)
                    ? center_left_shfl
                    : ro_load(input + idx - 1ull);
            }
            if (has_east) {
                center_right_word = (lane != (kWarpLanes - 1u))
                    ? center_right_shfl
                    : ro_load(input + idx + 1ull);
            }
        }

        const u64 west = align_west(center, center_left_word);
        east = align_east(center, center_right_word);

        csa(l0, l1, west, h2, l2);
    }

    // Final reduction.
    //
    // Let the 8-neighbor count be:
    //   count = NW + N + NE + W + E + SW + S + SE
    //
    // After the three CSA stages above:
    //   NW + N + NE = l0 + 2*h0
    //   SW + S + SE = l1 + 2*h1
    //   l0 + l1 + W = l2 + 2*h2
    //
    // So before adding E:
    //   count_without_E = l2 + 2*(h0 + h1 + h2)
    //
    // Add E explicitly:
    //   b0     = l2 ^ E       (count bit 0)
    //   carry0 = l2 & E       (a 1-bit carry into the "2s" place)
    //
    // Reduce h0 + h1 + h2:
    //   h0 + h1 + h2 = l3 + 2*h3
    //
    // Then:
    //   count = b0 + 2*(carry0 + l3 + 2*h3)
    //
    // Conway's rule only needs to know whether count is exactly 2 or 3.
    // That happens iff the higher-weight term equals exactly 1:
    //   carry0 + l3 + 2*h3 == 1
    // which is equivalent to:
    //   h3 == 0 and (l3 ^ carry0) == 1
    //
    // Finally:
    //   next = (count == 3) | (alive & (count == 2))
    //        = (b0 | alive) & high_is_one
    u64 h3, l3;
    csa(h0, h1, h2, h3, l3);

    const u64 b0 = l2 ^ east;
    const u64 carry0 = l2 & east;
    const u64 high_is_one = (l3 ^ carry0) & ~h3;

    output[idx] = (b0 | center) & high_is_one;
}

}  // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions) {
    // The kernel operates directly on the bit-packed representation; no unpacking is needed.
    // The caller owns synchronization and error handling, so this function only launches the kernel.

    const unsigned int dim = static_cast<unsigned int>(grid_dimensions);
    const unsigned int words_per_row = dim >> 6;                 // grid_dimensions / 64
    const unsigned int word_mask = words_per_row - 1u;
    const u64 total_words = static_cast<u64>(dim) * static_cast<u64>(words_per_row);

    // Flatten the 2D word grid into a 1D launch so very large boards are not limited by gridDim.y.
    // Under the problem constraints total_words is always divisible by kBlockSize exactly.
    const unsigned int blocks = static_cast<unsigned int>(total_words / static_cast<u64>(kBlockSize));

    const u64* in = reinterpret_cast<const u64*>(input);
    u64* out = reinterpret_cast<u64*>(output);

    // Specialize the horizontal neighbor path:
    //   16 or 32 words/row  -> row fits inside one shuffle group
    //   >= 64 words/row     -> cross-warp fallback loads required at lane 0 / lane 31
    if (words_per_row <= kWarpLanes) {
        game_of_life_step_kernel<true><<<blocks, kBlockSize>>>(in, out, total_words, words_per_row, word_mask);
    } else {
        game_of_life_step_kernel<false><<<blocks, kBlockSize>>>(in, out, total_words, words_per_row, word_mask);
    }
}

#include <cstdint>
#include <cuda_runtime.h>

// One Conway step directly on the bit-packed device representation.
//
// Layout / bit order:
// - The grid is row-major in 64-bit words.
// - Bit i of each word stores cell x = word_base + i, i.e. LSB -> increasing x.
//
// Performance-oriented design for A100/H100-class GPUs:
// - One lane updates one 64-bit word = 64 cells at once.
// - Horizontal neighbor words come from warp shuffles, so only subgroup-boundary
//   lanes issue extra global loads.
// - No shared memory: for this access pattern, shuffles + hardware caches are
//   sufficient and simpler.
// - Neighbor counts are formed with bit-sliced boolean arithmetic. Only counts
//   2 and 3 matter for Life, so keeping the count modulo 8 is enough; the only
//   wrapped case is count 8 -> 0, which is harmless for the rule.
// - The 1024x1024 case (16 words/row) is specialized so each hardware warp
//   updates two rows via two independent 16-lane subgroups.

namespace {

using u64 = std::uint64_t;

constexpr int kWarpSize               = 32;
constexpr int kHalfWarpSize           = 16;
constexpr int kWarpsPerBlock          = 8;
constexpr int kBlockThreads           = kWarpSize * kWarpsPerBlock;
constexpr unsigned int kWarpWordShift = 5u;  // log2(32 words)
constexpr unsigned int kHalfRowShift  = 4u;  // log2(16 words)
constexpr u64 kHalfWordsPerRow        = 1ull << kHalfRowShift;

// Majority of three 64-bit bitboards. Written in a form NVCC lowers well.
__device__ __forceinline__ u64 majority3(u64 a, u64 b, u64 c) {
    return (a & b) | (c & (a | b));
}

// Load the current word and its left/right neighbor words from the same row.
// The subgroup width is either 32 (full warp) or 16 (half warp specialization).
// __activemask() is intentionally captured here so the same helper remains
// correct inside the half-warp kernel's top/bottom boundary-divergent branches.
template <int GROUP_WIDTH>
__device__ __forceinline__ void load_triplet(
    const u64* __restrict__ input,
    u64 word_index,
    u64 x_word,
    u64 words_per_row,
    unsigned int lane_local,
    u64& left,
    u64& center,
    u64& right)
{
    const unsigned int mask = __activemask();

    center = input[word_index];

    left = __shfl_up_sync(mask, center, 1, GROUP_WIDTH);
    if (lane_local == 0) {
        left = (x_word != 0) ? input[word_index - 1] : 0ull;
    }

    right = __shfl_down_sync(mask, center, 1, GROUP_WIDTH);
    if (lane_local == static_cast<unsigned int>(GROUP_WIDTH - 1)) {
        right = (x_word + 1 < words_per_row) ? input[word_index + 1] : 0ull;
    }
}

// Encode a neighboring row's 3-cell horizontal stencil (west, center, east)
// into two bitplanes: lo + 2*hi, i.e. the population count 0..3 for each bit.
template <int GROUP_WIDTH>
__device__ __forceinline__ void encode_three_cell_row(
    const u64* __restrict__ input,
    u64 word_index,
    u64 x_word,
    u64 words_per_row,
    unsigned int lane_local,
    u64& lo,
    u64& hi)
{
    u64 left, center, right;
    load_triplet<GROUP_WIDTH>(input, word_index, x_word, words_per_row, lane_local,
                              left, center, right);

    const u64 west = (center << 1) | (left >> 63);
    const u64 east = (center >> 1) | (right << 63);

    lo = west ^ center ^ east;
    hi = majority3(west, center, east);
}

// Encode the current row's horizontal neighbors (west/east only; the center
// cell itself is excluded from the neighbor count) into two bitplanes.
template <int GROUP_WIDTH>
__device__ __forceinline__ void encode_two_cell_row(
    const u64* __restrict__ input,
    u64 word_index,
    u64 x_word,
    u64 words_per_row,
    unsigned int lane_local,
    u64& self_word,
    u64& lo,
    u64& hi)
{
    u64 left, center, right;
    load_triplet<GROUP_WIDTH>(input, word_index, x_word, words_per_row, lane_local,
                              left, center, right);

    self_word = center;

    const u64 west = (center << 1) | (left >> 63);
    const u64 east = (center >> 1) | (right << 63);

    lo = west ^ east;
    hi = west & east;
}

// Combine:
//   north_count = n0 + 2*n1   (0..3)
//   mid_count   = m0 + 2*m1   (0..2)
//   south_count = s0 + 2*s1   (0..3)
// into the 3 low bits of the total neighbor count.
//
// Count 8 wraps to 0 modulo 8; that is fine because the Life rule only accepts
// counts 2 and 3. The final boolean is:
//   next = (count == 3) | (self & (count == 2))
//        = cnt1 & ~cnt2 & (cnt0 | self)
__device__ __forceinline__ u64 finalize_word(
    u64 self_word,
    u64 n0, u64 n1,
    u64 m0, u64 m1,
    u64 s0, u64 s1)
{
    const u64 cnt0 = n0 ^ m0 ^ s0;
    const u64 carry0 = majority3(n0, m0, s0);

    const u64 pair01_lo = n1 ^ m1;
    const u64 pair01_hi = n1 & m1;
    const u64 pair23_lo = s1 ^ carry0;
    const u64 pair23_hi = s1 & carry0;

    const u64 cnt1 = pair01_lo ^ pair23_lo;
    const u64 cnt2 = pair01_hi ^ pair23_hi ^ (pair01_lo & pair23_lo);

    return (cnt1 & ~cnt2) & (cnt0 | self_word);
}

// Full-warp kernel for rows with at least 32 packed words (grid >= 2048).
// Task space is "one 32-word tile of one row per hardware warp". Because the
// row length is a power of two, row index and x-within-row are recovered with
// shifts/masks instead of division/modulo.
__global__ __launch_bounds__(kBlockThreads)
void game_of_life_kernel_full(
    const u64* __restrict__ input,
    u64* __restrict__ output,
    u64 rows,
    unsigned int words_per_row_shift)
{
    const unsigned int lane = threadIdx.x;
    const unsigned int warp_in_block = threadIdx.y;

    const u64 words_per_row = 1ull << words_per_row_shift;
    const u64 row_mask      = words_per_row - 1ull;
    const unsigned int task_shift = words_per_row_shift - kWarpWordShift;
    const u64 total_tasks = rows << task_shift;

    const u64 warp_id     = static_cast<u64>(blockIdx.x) * kWarpsPerBlock + warp_in_block;
    const u64 warp_stride = static_cast<u64>(gridDim.x) * kWarpsPerBlock;

    for (u64 task = warp_id; task < total_tasks; task += warp_stride) {
        const u64 word_index = (task << kWarpWordShift) | static_cast<u64>(lane);
        const u64 y          = task >> task_shift;
        const u64 x_word     = word_index & row_mask;

        u64 n0 = 0ull, n1 = 0ull;
        if (y != 0) {
            encode_three_cell_row<kWarpSize>(
                input, word_index - words_per_row, x_word, words_per_row, lane, n0, n1);
        }

        u64 self_word, m0, m1;
        encode_two_cell_row<kWarpSize>(
            input, word_index, x_word, words_per_row, lane, self_word, m0, m1);

        u64 s0 = 0ull, s1 = 0ull;
        if (y + 1 < rows) {
            encode_three_cell_row<kWarpSize>(
                input, word_index + words_per_row, x_word, words_per_row, lane, s0, s1);
        }

        output[word_index] = finalize_word(self_word, n0, n1, m0, m1, s0, s1);
    }
}

// Specialized kernel for exactly 16 packed words per row (1024 cells/row).
// Each hardware warp updates two rows at once using two 16-lane subgroups.
__global__ __launch_bounds__(kBlockThreads)
void game_of_life_kernel_half(
    const u64* __restrict__ input,
    u64* __restrict__ output,
    u64 rows)
{
    const unsigned int lane       = threadIdx.x;
    const unsigned int warp_in_block = threadIdx.y;
    const unsigned int subwarp    = lane >> kHalfRowShift;            // 0 or 1
    const unsigned int lane16     = lane & (kHalfWarpSize - 1);      // 0..15
    const u64 x_word              = static_cast<u64>(lane16);

    const u64 pair_count  = rows >> 1; // rows is guaranteed even
    const u64 pair_id     = static_cast<u64>(blockIdx.x) * kWarpsPerBlock + warp_in_block;
    const u64 pair_stride = static_cast<u64>(gridDim.x) * kWarpsPerBlock;

    for (u64 pair = pair_id; pair < pair_count; pair += pair_stride) {
        const u64 y = (pair << 1) | static_cast<u64>(subwarp);

        // One pair contains two rows * 16 words = 32 words total.
        const u64 word_index =
            (pair << kWarpWordShift) |
            (static_cast<u64>(subwarp) << kHalfRowShift) |
            x_word;

        u64 n0 = 0ull, n1 = 0ull;
        if (y != 0) {
            encode_three_cell_row<kHalfWarpSize>(
                input, word_index - kHalfWordsPerRow, x_word, kHalfWordsPerRow, lane16, n0, n1);
        }

        u64 self_word, m0, m1;
        encode_two_cell_row<kHalfWarpSize>(
            input, word_index, x_word, kHalfWordsPerRow, lane16, self_word, m0, m1);

        u64 s0 = 0ull, s1 = 0ull;
        if (y + 1 < rows) {
            encode_three_cell_row<kHalfWarpSize>(
                input, word_index + kHalfWordsPerRow, x_word, kHalfWordsPerRow, lane16, s0, s1);
        }

        output[word_index] = finalize_word(self_word, n0, n1, m0, m1, s0, s1);
    }
}

inline u64 ceil_div_u64(u64 n, u64 d) {
    return (n + d - 1ull) / d;
}

inline unsigned int log2_pow2_u64(u64 x) {
    unsigned int s = 0;
    while (x > 1ull) {
        x >>= 1;
        ++s;
    }
    return s;
}

// For grid-stride kernels, launching roughly one fully resident wave of blocks
// avoids underfilling the GPU without overscheduling far beyond residency.
inline unsigned int choose_grid_blocks(u64 task_count, int sm_count, int blocks_per_sm) {
    const u64 blocks_needed = ceil_div_u64(task_count, static_cast<u64>(kWarpsPerBlock));
    const u64 resident_blocks =
        static_cast<u64>(sm_count > 0 ? sm_count : 1) *
        static_cast<u64>(blocks_per_sm > 0 ? blocks_per_sm : 1);

    u64 blocks = (blocks_needed < resident_blocks) ? blocks_needed : resident_blocks;
    if (blocks == 0) blocks = 1;
    return static_cast<unsigned int>(blocks);
}

// Cached per host thread / current device. These queries are host-side only,
// and caching keeps repeated time-step launches cheap.
struct LaunchConfigCache {
    int device = -1;
    int sm_count = 0;
    int full_blocks_per_sm = 0;
    int half_blocks_per_sm = 0;
};

inline const LaunchConfigCache& get_launch_config_cache() {
    thread_local LaunchConfigCache cache;

    int device = 0;
    cudaGetDevice(&device);

    if (device != cache.device) {
        cache.device = device;

        cudaDeviceGetAttribute(&cache.sm_count, cudaDevAttrMultiProcessorCount, device);

        cudaOccupancyMaxActiveBlocksPerMultiprocessor(
            &cache.full_blocks_per_sm,
            game_of_life_kernel_full,
            kBlockThreads,
            0);

        cudaOccupancyMaxActiveBlocksPerMultiprocessor(
            &cache.half_blocks_per_sm,
            game_of_life_kernel_half,
            kBlockThreads,
            0);

        if (cache.sm_count < 1) cache.sm_count = 1;
        if (cache.full_blocks_per_sm < 1) cache.full_blocks_per_sm = 1;
        if (cache.half_blocks_per_sm < 1) cache.half_blocks_per_sm = 1;
    }

    return cache;
}

} // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions) {
    // Hot-path launcher: no synchronization and no error checking here by design.
    // The caller owns synchronization/error semantics and must provide distinct
    // input/output device buffers.

    const u64 rows = static_cast<u64>(grid_dimensions);
    const u64 words_per_row = rows >> 6; // 64 cells per 64-bit word

    // words_per_row is also a power of two because grid_dimensions is.
    const unsigned int words_per_row_shift = log2_pow2_u64(words_per_row);

    const auto& cache = get_launch_config_cache();
    const dim3 block(kWarpSize, kWarpsPerBlock, 1);

    if (words_per_row == kHalfWordsPerRow) {
        const u64 pair_count = rows >> 1;
        const unsigned int grid_blocks =
            choose_grid_blocks(pair_count, cache.sm_count, cache.half_blocks_per_sm);

        game_of_life_kernel_half<<<grid_blocks, block>>>(input, output, rows);
    } else {
        const u64 task_count = rows << (words_per_row_shift - kWarpWordShift);
        const unsigned int grid_blocks =
            choose_grid_blocks(task_count, cache.sm_count, cache.full_blocks_per_sm);

        game_of_life_kernel_full<<<grid_blocks, block>>>(input, output, rows, words_per_row_shift);
    }
}

#include <cstddef>
#include <cstdint>
#include <cuda_runtime.h>

/*
  High-throughput bit-packed Conway's Game of Life step for modern NVIDIA GPUs.

  Design choices:
  - One thread updates one 64-bit word, i.e. 64 cells at once.
  - blockDim.x is fixed to 32, so each warp covers one contiguous 32-word segment
    of a single grid row.
  - Each lane loads only the word directly above/current/below at its own x.
    Left/right neighboring words inside the segment are exchanged with warp
    shuffles; only segment-edge lanes need extra global loads.
  - The 8-neighbor population count is computed with a bit-sliced boolean adder
    network, so all 64 cells in the word are advanced in parallel with bitwise
    operations only.
  - Shared/texture memory are intentionally not used. After shuffle-based reuse of
    horizontal neighbors, additional staging only adds complexity and pressure.
*/

namespace {

using u64 = std::uint64_t;

constexpr int kWarpLanes = 32;
constexpr int kWarpShift = 5;          // log2(32)
constexpr int kBlockRows = 8;
constexpr int kBlockRowsShift = 3;     // log2(8)
constexpr unsigned int kFullWarpMask = 0xFFFFFFFFu;
constexpr unsigned int kMaxGridY = 65535u;

static_assert(kWarpLanes == (1 << kWarpShift), "kWarpShift must match kWarpLanes");
static_assert(kBlockRows == (1 << kBlockRowsShift), "kBlockRowsShift must match kBlockRows");

// Read-only input load. On modern GPUs this lets the compiler pick the best
// read-only cache path for the input buffer.
__device__ __forceinline__ u64 load_ro(const u64* __restrict__ ptr) {
    return __ldg(ptr);
}

// Majority-of-three on bitboards. NVCC lowers this boolean form well on Ampere/Hopper.
__device__ __forceinline__ u64 majority3(const u64 a, const u64 b, const u64 c) {
    return (a & b) | (a & c) | (b & c);
}

// Each warp processes one 32-word span of one row. The center word for this lane
// is already in a register; this helper fetches horizontally adjacent words.
// Inside the span, shuffles provide neighbors. Only span-edge lanes perform the
// fallback global loads needed to cross warp-segment boundaries.
__device__ __forceinline__ void gather_lr(
    const u64 center,
    u64& left,
    u64& right,
    const unsigned active_mask,
    const u64* __restrict__ center_ptr,
    const bool has_left_word,
    const bool has_right_word,
    const int lane)
{
    left  = __shfl_up_sync(active_mask, center, 1);
    right = __shfl_down_sync(active_mask, center, 1);

    if (lane == 0) {
        left = has_left_word ? load_ro(center_ptr - 1) : 0ULL;
    }
    if (lane == kWarpLanes - 1 || !has_right_word) {
        right = has_right_word ? load_ro(center_ptr + 1) : 0ULL;
    }
}

// Bit i of a word encodes cell x = word_index * 64 + i.
// With that convention, west neighbors are formed with a left shift and east
// neighbors with a right shift. No tail mask is needed because the problem
// guarantees grid_dimensions is a power of two, hence a multiple of 64.
__global__ __launch_bounds__(kWarpLanes * kBlockRows)
void game_of_life_kernel(
    const u64* __restrict__ input,
    u64* __restrict__ output,
    const int grid_dimensions,
    const int row_shift)
{
    const std::size_t dim = static_cast<std::size_t>(grid_dimensions);
    const std::size_t words_per_row = std::size_t{1} << row_shift;

    const int lane = static_cast<int>(threadIdx.x);

    const std::size_t word =
        (static_cast<std::size_t>(blockIdx.x) << kWarpShift) +
        static_cast<std::size_t>(lane);

    // grid.y is capped at 65,535; grid.z extends the row dimension when needed.
    const std::size_t row_tile =
        static_cast<std::size_t>(blockIdx.z) * static_cast<std::size_t>(gridDim.y) +
        static_cast<std::size_t>(blockIdx.y);
    const std::size_t row =
        (row_tile << kBlockRowsShift) + static_cast<std::size_t>(threadIdx.y);

    const bool active = (row < dim) && (word < words_per_row);
    const unsigned active_mask = __ballot_sync(kFullWarpMask, active);
    if (!active) {
        return;
    }

    // words_per_row is a power of two, so row_base is a shift rather than a 64-bit multiply.
    const std::size_t row_base = row << row_shift;
    const std::size_t index = row_base + word;

    const bool has_prev = (row != 0);
    const bool has_next = ((row + 1) < dim);
    const bool has_left_word = (word != 0);
    const bool has_right_word = ((word + 1) < words_per_row);

    const u64* const center_ptr = input + index;
    const u64* const prev_ptr = has_prev ? (center_ptr - words_per_row) : nullptr;
    const u64* const next_ptr = has_next ? (center_ptr + words_per_row) : nullptr;

    u64 left, right;

    // Sum the three cells from the row above into a 2-bit bit-sliced number:
    // north = north_lo + 2*north_hi
    u64 north_lo = 0ULL;
    u64 north_hi = 0ULL;
    if (has_prev) {
        const u64 north = load_ro(prev_ptr);
        gather_lr(north, left, right, active_mask, prev_ptr, has_left_word, has_right_word, lane);

        const u64 nw = (north << 1) | (left >> 63);
        const u64 ne = (north >> 1) | (right << 63);

        north_lo = nw ^ north ^ ne;
        north_hi = majority3(nw, north, ne);
    }

    // Sum the two horizontal neighbors from the current row:
    // horiz = horiz_lo + 2*horiz_hi
    const u64 self = load_ro(center_ptr);
    gather_lr(self, left, right, active_mask, center_ptr, has_left_word, has_right_word, lane);

    const u64 west = (self << 1) | (left >> 63);
    const u64 east = (self >> 1) | (right << 63);

    const u64 horiz_lo = west ^ east;
    const u64 horiz_hi = west & east;

    // Sum the three cells from the row below into:
    // south = south_lo + 2*south_hi
    u64 south_lo = 0ULL;
    u64 south_hi = 0ULL;
    if (has_next) {
        const u64 south = load_ro(next_ptr);
        gather_lr(south, left, right, active_mask, next_ptr, has_left_word, has_right_word, lane);

        const u64 sw = (south << 1) | (left >> 63);
        const u64 se = (south >> 1) | (right << 63);

        south_lo = sw ^ south ^ se;
        south_hi = majority3(sw, south, se);
    }

    // Bit-sliced population count of the eight neighbors:
    //   north = north_lo + 2*north_hi
    //   horiz = horiz_lo + 2*horiz_hi
    //   south = south_lo + 2*south_hi
    const u64 count0 = north_lo ^ south_lo ^ horiz_lo;
    const u64 carry0 = majority3(north_lo, south_lo, horiz_lo);

    const u64 high_lo = north_hi ^ south_hi ^ horiz_hi;
    const u64 high_hi = majority3(north_hi, south_hi, horiz_hi);

    // count1 is the 2's bit of the final neighbor count.
    // count_ge_4 flags counts 4..8, which are all deaths in Life.
    const u64 count1 = high_lo ^ carry0;
    const u64 count_ge_4 = high_hi | (high_lo & carry0);

    // Conway rule in bit-sliced form:
    //   next = (count == 3) | (self & count == 2)
    //        = (~count_ge_4) & count1 & (count0 | self)
    const u64 count_2_or_3 = (~count_ge_4) & count1;
    output[index] = count_2_or_3 & (count0 | self);
}

} // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions)
{
    // Problem guarantees:
    // - square grid
    // - grid_dimensions is a power of two
    // - grid_dimensions > 512
    // - input/output are already device pointers from cudaMalloc
    //
    // The caller handles synchronization and error observation; this function
    // only enqueues the kernel.

    const std::size_t words_per_row = static_cast<std::size_t>(grid_dimensions) >> 6;
    const std::size_t word_tiles = (words_per_row + (kWarpLanes - 1)) >> kWarpShift;
    const std::size_t row_tiles = static_cast<std::size_t>(grid_dimensions) >> kBlockRowsShift;

    // words_per_row is a power of two, so row_shift = log2(words_per_row).
    // This host-side setup is not on the hot path.
    int row_shift = 0;
    for (std::size_t w = words_per_row; w > 1; w >>= 1) {
        ++row_shift;
    }

    const unsigned int grid_y =
        static_cast<unsigned int>(row_tiles > kMaxGridY ? kMaxGridY : row_tiles);
    const unsigned int grid_z =
        static_cast<unsigned int>(
            (row_tiles + static_cast<std::size_t>(grid_y) - 1) /
            static_cast<std::size_t>(grid_y));

    const dim3 block(kWarpLanes, kBlockRows, 1);
    const dim3 grid(static_cast<unsigned int>(word_tiles), grid_y, grid_z);

    game_of_life_kernel<<<grid, block>>>(input, output, grid_dimensions, row_shift);
}

// High-throughput single-step Conway's Game of Life for a square grid stored as
// 8x8 bit tiles in device memory.
//
// Tile-local bit packing assumed by this kernel:
//   bits  0.. 7 : row 0, columns 0..7
//   bits  8..15 : row 1, columns 0..7
//   ...
//   bits 56..63 : row 7, columns 0..7
//
// In other words, bit index = row * 8 + col, the low byte is the tile's top row,
// and within each byte the LSB is the leftmost cell.
//
// Performance-oriented design choices:
//   - One thread updates one 8x8 tile = 64 cells at once.
//   - blockDim.x is fixed to one warp, so west/east neighbor tiles are exchanged
//     with warp shuffles instead of extra global loads.
//   - Neighbor counts are accumulated with bit-sliced carry-save adders, so all
//     64 cell counts in the tile are processed in parallel with integer bitwise ops.
//   - No shared or texture memory: for this access pattern on modern NVIDIA
//     data-center GPUs, global memory + warp shuffles is simpler and faster.

#include <cstddef>
#include <cstdint>
#include <cuda_runtime.h>

namespace {

using u64 = std::uint64_t;

constexpr int kBlockX = 32;      // exactly one warp in X
constexpr int kBlockY = 8;
constexpr int kBlockXShift = 5;  // log2(kBlockX)
constexpr int kBlockYShift = 3;  // log2(kBlockY)

static_assert(kBlockX == 32, "This kernel assumes blockDim.x == 32.");
static_assert((1 << kBlockXShift) == kBlockX, "kBlockXShift must match kBlockX.");
static_assert((1 << kBlockYShift) == kBlockY, "kBlockYShift must match kBlockY.");

constexpr unsigned kFullWarpMask = 0xFFFFFFFFu;

constexpr u64 kCol0      = 0x0101010101010101ULL;
constexpr u64 kCol7      = 0x8080808080808080ULL;
constexpr u64 kNotCol0   = 0xFEFEFEFEFEFEFEFEULL;
constexpr u64 kNotCol7   = 0x7F7F7F7F7F7F7F7FULL;
constexpr u64 kByteMask  = 0xFFULL;
constexpr u64 kByteNoLsb = 0xFEULL;
constexpr u64 kByteNoMsb = 0x7FULL;

// 64-bit shuffle wrappers. Casting through unsigned long long avoids depending on
// the exact host-side typedef behind std::uint64_t.
__device__ __forceinline__ u64 shfl_up_u64(u64 v, unsigned delta) {
    return static_cast<u64>(
        __shfl_up_sync(kFullWarpMask, static_cast<unsigned long long>(v), delta));
}

__device__ __forceinline__ u64 shfl_down_u64(u64 v, unsigned delta) {
    return static_cast<u64>(
        __shfl_down_sync(kFullWarpMask, static_cast<unsigned long long>(v), delta));
}

// Carry-save adder for bit-sliced popcount.
// For every bit position i:
//   sum[i]   = low bit of a[i] + b[i] + c[i]
//   carry[i] = high bit of a[i] + b[i] + c[i]
//
// Because each u64 contains 64 independent one-bit cell values, this is a
// 64-way parallel 3:2 compressor.
__device__ __forceinline__ void csa(u64 a, u64 b, u64 c, u64& sum, u64& carry) {
    const u64 ab_xor = a ^ b;
    sum   = ab_xor ^ c;
    carry = (a & b) | (ab_xor & c);
}

__global__ __launch_bounds__(kBlockX * kBlockY, 2)
void game_of_life_step_kernel(const u64* __restrict__ input,
                              u64* __restrict__ output,
                              int tiles_per_row) {
    // Each warp covers 32 consecutive tiles on one tile-row; each thread owns one tile.
    const int x = (static_cast<int>(blockIdx.x) << kBlockXShift) + static_cast<int>(threadIdx.x);
    const int y = (static_cast<int>(blockIdx.y) << kBlockYShift) + static_cast<int>(threadIdx.y);
    const int lane = static_cast<int>(threadIdx.x);

    const int last = tiles_per_row - 1;
    const bool has_north = (y != 0);
    const bool has_south = (y != last);

    const std::size_t row_stride = static_cast<std::size_t>(tiles_per_row);
    const std::size_t idx =
        static_cast<std::size_t>(y) * row_stride + static_cast<std::size_t>(x);

    // Direct loads: north / center / south tile words.
    // Missing rows beyond the grid are treated as zero, which exactly implements
    // the "outside cells are dead" boundary condition.
    const u64 n = has_north ? input[idx - row_stride] : 0ULL;
    const u64 c = input[idx];
    const u64 s = has_south ? input[idx + row_stride] : 0ULL;

    // West/east neighbor tiles are usually supplied by the adjacent lane in the warp.
    u64 w  = shfl_up_u64(c, 1);
    u64 e  = shfl_down_u64(c, 1);
    u64 nw = shfl_up_u64(n, 1);
    u64 ne = shfl_down_u64(n, 1);
    u64 sw = shfl_up_u64(s, 1);
    u64 se = shfl_down_u64(s, 1);

    // Shuffle exchange does not cross warp boundaries, so only lane 0 / lane 31
    // need explicit global loads. That keeps average memory traffic per tile low.
    if (lane == 0) {
        const bool has_west = (x != 0);
        w  = has_west ? input[idx - 1] : 0ULL;
        nw = (has_west && has_north) ? input[idx - row_stride - 1] : 0ULL;
        sw = (has_west && has_south) ? input[idx + row_stride - 1] : 0ULL;
    }

    if (lane == kBlockX - 1) {
        const bool has_east = (x != last);
        e  = has_east ? input[idx + 1] : 0ULL;
        ne = (has_east && has_north) ? input[idx - row_stride + 1] : 0ULL;
        se = (has_east && has_south) ? input[idx + row_stride + 1] : 0ULL;
    }

    // Pre-extract the only parts of neighbor tiles needed for cross-tile alignment.
    const u64 c_no_col7 = c & kNotCol7;
    const u64 c_no_col0 = c & kNotCol0;
    const u64 n_row7    = n >> 56;          // north tile row 7 moved into low byte
    const u64 s_row0    = s & kByteMask;    // south tile row 0
    const u64 w_col7    = w & kCol7;        // west tile column 7 in-place
    const u64 e_col0    = e & kCol0;        // east tile column 0 in-place

    // Build aligned neighbor bitboards. Each bit position now refers to the same
    // cell position inside the current tile.
    const u64 north_bits = (c << 8) | n_row7;
    const u64 south_bits = (c >> 8) | (s_row0 << 56);
    const u64 west_bits  = (c_no_col7 << 1) | (w_col7 >> 7);

    u64 ones_a, twos_a;
    csa(north_bits, south_bits, west_bits, ones_a, twos_a);

    const u64 east_bits =
        (c_no_col0 >> 1) | (e_col0 << 7);

    const u64 northwest_bits =
        (c_no_col7 << 9) |
        ((n_row7 & kByteNoMsb) << 1) |
        (w_col7 << 1) |
        (nw >> 63);

    const u64 northeast_bits =
        (c_no_col0 << 7) |
        ((n_row7 & kByteNoLsb) >> 1) |
        (e_col0 << 15) |
        (((ne >> 56) & 0x1ULL) << 7);

    u64 ones_b, twos_b;
    csa(east_bits, northwest_bits, northeast_bits, ones_b, twos_b);

    const u64 southwest_bits =
        (c_no_col7 >> 7) |
        ((s_row0 & kByteNoMsb) << 57) |
        (w_col7 >> 15) |
        (((sw >> 7) & 0x1ULL) << 56);

    const u64 southeast_bits =
        (c_no_col0 >> 9) |
        ((s_row0 & kByteNoLsb) << 55) |
        (e_col0 >> 1) |
        ((se & 0x1ULL) << 63);

    const u64 ones_c = southwest_bits ^ southeast_bits;
    const u64 twos_c = southwest_bits & southeast_bits;

    // Bit-sliced popcount of the eight neighbors.
    u64 ones, twos_d;
    csa(ones_a, ones_b, ones_c, ones, twos_d);

    u64 twos_e, fours_a;
    csa(twos_a, twos_b, twos_c, twos_e, fours_a);

    // Let count = ones + 2*K, where K = twos_a + twos_b + twos_c + twos_d.
    // Counts 2 and 3 are exactly the cases K == 1.
    //
    // twos_e ^ twos_d is parity(K).
    // fours_a is already 1 whenever K >= 3.
    // The remaining K != 1 case is K == 2, and parity(K) is then 0.
    // Therefore:
    //   ((twos_e ^ twos_d) & ~fours_a)  <=>  neighbor count is 2 or 3.
    const u64 count_2_or_3 = (twos_e ^ twos_d) & ~fours_a;

    // Final Life rule:
    //   count == 2 -> survive iff currently alive
    //   count == 3 -> alive regardless of current state
    //
    // Under count_2_or_3:
    //   count == 2 => ones == 0, so (ones | c) == c
    //   count == 3 => ones == 1, so (ones | c) == 1
    output[idx] = count_2_or_3 & (ones | c);
}

}  // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions) {
    // Out-of-place update: input and output are expected to be different device buffers.
    //
    // One 64-bit word stores one 8x8 tile, so the tile grid is (N/8) x (N/8).
    // The problem contract guarantees N is a power of 2 and N > 512, therefore:
    //   tiles_per_row = N / 8
    // is also a power of 2, and is divisible by both 32 and 8. That lets us launch
    // an exact grid without a per-thread x/y bounds check in the kernel body.
    const int tiles_per_row = grid_dimensions >> 3;

    const dim3 block(kBlockX, kBlockY, 1);
    const dim3 grid(static_cast<unsigned int>(tiles_per_row >> kBlockXShift),
                    static_cast<unsigned int>(tiles_per_row >> kBlockYShift),
                    1);

    // Caller controls synchronization and error handling policy; this function only
    // enqueues a single asynchronous kernel launch on the default stream.
    game_of_life_step_kernel<<<grid, block>>>(input, output, tiles_per_row);
}

#include <cuda_runtime.h>

#include <cstddef>
#include <cstdint>

// Conway's Game of Life, one step, for a square grid bit-packed as 8x8 tiles.
//
// Assumed layout (the only layout directly implied by "one uint64_t per 8x8 tile"):
//   - Tiles are stored row-major in a (grid_dimensions / 8) x (grid_dimensions / 8) array.
//   - Inside each 64-bit tile, bit (local_y * 8 + local_x) stores cell (local_x, local_y),
//     where local_x increases to the right and local_y increases downward.
//   - Therefore each tile row is exactly one byte.
//
// Performance strategy:
//   - One thread computes one output tile (64 cells).
//   - blockDim.x == 32, so each warp spans 32 consecutive tiles along x.
//     Horizontal neighbor tiles are therefore usually obtained with warp shuffles instead of
//     redundant global loads; only lane 0 / lane 31 need fallback loads because shuffles do
//     not cross warp boundaries.
//   - No shared memory is used: the problem statement explicitly says it is unnecessary here,
//     and warp shuffles already remove most horizontal load redundancy while keeping the code
//     simple and fast on modern data-center GPUs.
//   - Within a tile, all 64 cells are updated in parallel with bitwise logic. Neighbor counts
//     are accumulated as three bit-planes (ones/twos/fours) modulo 8. Count 8 wraps to 0,
//     which is harmless because Conway's rule only cares about neighbor counts 2 and 3.

namespace {

using word_t = std::uint64_t;
static_assert(sizeof(word_t) == sizeof(unsigned long long), "Expected 64-bit words.");

constexpr int kTileEdge = 8;
constexpr int kBlockX   = 32;  // exactly one warp in x
constexpr int kBlockY   = 8;
constexpr int kBlockThreads = kBlockX * kBlockY;
static_assert(kBlockX == 32, "This kernel relies on blockDim.x being exactly one warp.");

constexpr unsigned kFullWarpMask = 0xFFFFFFFFu;

// Bit masks for the 8x8 tile encoding described above.
constexpr word_t kCol0 = 0x0101010101010101ULL;
constexpr word_t kCol7 = 0x8080808080808080ULL;
constexpr word_t kNotCol0 = 0xFEFEFEFEFEFEFEFEULL;
constexpr word_t kNotCol7 = 0x7F7F7F7F7F7F7F7FULL;
constexpr word_t kRow0 = 0x00000000000000FFULL;

// Low-byte masks used after extracting a tile row into the low byte.
constexpr word_t kRowByteNoCol0 = 0x00000000000000FEULL;  // x = 1..7
constexpr word_t kRowByteNoCol7 = 0x000000000000007FULL;  // x = 0..6

// Individual bit masks used for the diagonal corner fills.
constexpr word_t kBit0  = 0x0000000000000001ULL;
constexpr word_t kBit7  = 0x0000000000000080ULL;
constexpr word_t kBit56 = 0x0100000000000000ULL;

__device__ __forceinline__ word_t shfl_up_u64(const unsigned mask, const word_t value, const unsigned delta) {
    return static_cast<word_t>(
        __shfl_up_sync(mask, static_cast<unsigned long long>(value), static_cast<int>(delta)));
}

__device__ __forceinline__ word_t shfl_down_u64(const unsigned mask, const word_t value, const unsigned delta) {
    return static_cast<word_t>(
        __shfl_down_sync(mask, static_cast<unsigned long long>(value), static_cast<int>(delta)));
}

__device__ __forceinline__ void add_neighbor_mod8(
    const word_t neighbor,
    word_t& ones,
    word_t& twos,
    word_t& fours)
{
    // Bit-sliced increment of a 3-bit counter.
    //
    // Every bit position in "neighbor" is one 1-bit addend for the corresponding cell.
    // The counter is kept modulo 8:
    //   count 0..7 are represented exactly by (ones, twos, fours),
    //   count 8 wraps to 0 (overflow discarded).
    //
    // This is valid for Game of Life because the rule only distinguishes:
    //   - exactly 2 neighbors
    //   - exactly 3 neighbors
    //   - everything else
    // and count 8 belongs to "everything else".
    word_t carry = ones & neighbor;
    ones ^= neighbor;

    word_t carry2 = twos & carry;
    twos ^= carry;

    fours ^= carry2;
}

__device__ __forceinline__ word_t evolve_tile(
    const word_t nw, const word_t n, const word_t ne,
    const word_t w,  const word_t c, const word_t e,
    const word_t sw, const word_t s, const word_t se)
{
    // Pre-extract/reuse the pieces that appear in multiple directions.
    const word_t c_no_col7 = c & kNotCol7;
    const word_t c_no_col0 = c & kNotCol0;
    const word_t w_col7    = w & kCol7;
    const word_t e_col0    = e & kCol0;
    const word_t n_row7    = n >> 56;   // north tile's last row, moved into the low byte
    const word_t s_row0    = s & kRow0; // south tile's first row, already in the low byte

    word_t ones  = 0;
    word_t twos  = 0;
    word_t fours = 0;
    word_t neighbor;

    // Cardinal directions.
    neighbor = (c << 8) | n_row7;                      // north
    add_neighbor_mod8(neighbor, ones, twos, fours);

    neighbor = (c >> 8) | (s_row0 << 56);             // south
    add_neighbor_mod8(neighbor, ones, twos, fours);

    neighbor = (c_no_col7 << 1) | (w_col7 >> 7);      // west
    add_neighbor_mod8(neighbor, ones, twos, fours);

    neighbor = (c_no_col0 >> 1) | (e_col0 << 7);      // east
    add_neighbor_mod8(neighbor, ones, twos, fours);

    // Diagonals.
    neighbor = (c_no_col7 << 9)                        // current tile interior contribution
             | ((n_row7 & kRowByteNoCol7) << 1)       // north tile, row 7, x = 0..6 -> x = 1..7
             | (w_col7 << 1)                          // west tile, col 7, y = 0..6 -> y = 1..7
             | (nw >> 63);                            // north-west corner tile, bit 63 -> bit 0
    add_neighbor_mod8(neighbor, ones, twos, fours);   // north-west

    neighbor = (c_no_col0 << 7)
             | ((n_row7 & kRowByteNoCol0) >> 1)       // north tile, row 7, x = 1..7 -> x = 0..6
             | (e_col0 << 15)                         // east tile, col 0, y = 0..6 -> y = 1..7
             | ((ne & kBit56) >> 49);                 // north-east corner tile, bit 56 -> bit 7
    add_neighbor_mod8(neighbor, ones, twos, fours);   // north-east

    neighbor = (c_no_col7 >> 7)
             | ((s_row0 & kRowByteNoCol7) << 57)      // south tile, row 0, x = 0..6 -> x = 1..7
             | (w_col7 >> 15)                         // west tile, col 7, y = 1..7 -> y = 0..6
             | ((sw & kBit7) << 49);                  // south-west corner tile, bit 7 -> bit 56
    add_neighbor_mod8(neighbor, ones, twos, fours);   // south-west

    neighbor = (c_no_col0 >> 9)
             | ((s_row0 & kRowByteNoCol0) << 55)      // south tile, row 0, x = 1..7 -> x = 0..6
             | (e_col0 >> 1)                          // east tile, col 0, y = 1..7 -> y = 0..6
             | ((se & kBit0) << 63);                  // south-east corner tile, bit 0 -> bit 63
    add_neighbor_mod8(neighbor, ones, twos, fours);   // south-east

    // Conway rule:
    //   alive next step iff neighbor_count == 3, or (currently alive and neighbor_count == 2)
    //
    // With the bit-sliced counter:
    //   count == 2  -> ones=0, twos=1, fours=0
    //   count == 3  -> ones=1, twos=1, fours=0
    //
    // So "neighbor_count is 2 or 3" is: twos & ~fours
    // and then (count == 3) OR (current cell alive) becomes: ones | c
    const word_t life_mask = twos & ~fours;
    return life_mask & (ones | c);
}

__global__ __launch_bounds__(kBlockThreads)
void game_of_life_kernel(
    const word_t* __restrict__ input,
    word_t* __restrict__ output,
    const int tiles_per_side)
{
    // Because blockDim.x == 32 and tiles_per_side is a power of two >= 64, each warp covers
    // exactly one contiguous 32-tile segment in x, with no partial x-warps.
    const int tx = static_cast<int>(blockIdx.x) * kBlockX + static_cast<int>(threadIdx.x);
    const int ty = static_cast<int>(blockIdx.y) * kBlockY + static_cast<int>(threadIdx.y);

    // This branch is warp-uniform because threadIdx.x spans the whole warp while threadIdx.y
    // is constant within a warp when blockDim.x == 32.
    if (ty >= tiles_per_side) {
        return;
    }

    const std::size_t stride = static_cast<std::size_t>(tiles_per_side);
    const std::size_t idx = static_cast<std::size_t>(ty) * stride + static_cast<std::size_t>(tx);

    // Missing neighboring tiles are treated as zero, which exactly implements "cells outside
    // the grid are dead" while still preserving all intra-tile neighbors.
    const bool has_n = (ty > 0);
    const bool has_s = (ty + 1 < tiles_per_side);

    const word_t c = input[idx];
    const word_t n = has_n ? input[idx - stride] : 0;
    const word_t s = has_s ? input[idx + stride] : 0;

    // Horizontal neighbors usually come from warp shuffles of the current/adjacent rows.
    // lane 0 / lane 31 are fixed up below because shuffles do not cross warp boundaries.
    word_t w  = shfl_up_u64(kFullWarpMask, c, 1);
    word_t e  = shfl_down_u64(kFullWarpMask, c, 1);
    word_t nw = shfl_up_u64(kFullWarpMask, n, 1);
    word_t ne = shfl_down_u64(kFullWarpMask, n, 1);
    word_t sw = shfl_up_u64(kFullWarpMask, s, 1);
    word_t se = shfl_down_u64(kFullWarpMask, s, 1);

    const int lane = static_cast<int>(threadIdx.x);

    if (lane == 0) {
        if (tx > 0) {
            w  = input[idx - 1];
            nw = has_n ? input[idx - stride - 1] : 0;
            sw = has_s ? input[idx + stride - 1] : 0;
        } else {
            w = nw = sw = 0;
        }
    }

    if (lane == 31) {
        if (tx + 1 < tiles_per_side) {
            e  = input[idx + 1];
            ne = has_n ? input[idx - stride + 1] : 0;
            se = has_s ? input[idx + stride + 1] : 0;
        } else {
            e = ne = se = 0;
        }
    }

    output[idx] = evolve_tile(nw, n, ne, w, c, e, sw, s, se);
}

}  // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions) {
    // The caller guarantees valid device pointers allocated by cudaMalloc and handles all
    // synchronization externally. This function intentionally only enqueues the kernel.
    //
    // Standard double-buffered Game of Life is assumed: input and output must not overlap.
    if (grid_dimensions <= 0) {
        return;
    }

    const int tiles_per_side = grid_dimensions / kTileEdge;
    if (tiles_per_side <= 0) {
        return;
    }

    // Problem constraints guarantee:
    //   - grid_dimensions is a power of two and > 512
    //   - therefore tiles_per_side is also a power of two and >= 64
    //   - therefore tiles_per_side is divisible by 32, so grid.x is exact
    const dim3 block(kBlockX, kBlockY);
    const dim3 grid(
        static_cast<unsigned>(tiles_per_side / kBlockX),
        static_cast<unsigned>((tiles_per_side + kBlockY - 1) / kBlockY));

    game_of_life_kernel<<<grid, block>>>(input, output, tiles_per_side);
}

#include <cuda_runtime.h>
#include <cstddef>
#include <cstdint>

// CUDA Game of Life for a bit-packed 8x8-tile layout.
//
// Assumed in-memory layout (the natural interpretation of "one uint64_t per 8x8 tile"):
//   * tiles are stored in row-major order
//   * within one 64-bit tile, bit index (8 * local_y + local_x) stores cell (local_x, local_y)
//     so every byte is one tile row
//
// Why this implementation is fast on modern NVIDIA GPUs:
//   * one thread updates one entire 8x8 tile = 64 cells at once
//   * neighbor counts are computed with bit-sliced boolean adders, so all 64 cells in the tile
//     are updated in parallel with plain integer logic
//   * along X, one warp spans exactly 32 adjacent tiles; west/east/diagonal neighbor tiles are
//     exchanged with warp shuffles, so the hot interior kernel only loads center/north/south
//     tiles from global memory for most threads
//   * Y boundaries are split into a tiny dedicated kernel, keeping the large interior kernel free
//     of per-thread Y-boundary checks
//
// Fast-path assumption:
//   * input and output are distinct device buffers (standard ping-pong update)

namespace {

using u64 = unsigned long long;
using index_t = std::size_t;

static_assert(sizeof(u64) == sizeof(std::uint64_t), "u64 must match std::uint64_t size");

constexpr int kWarpTiles = 32;   // one warp covers 32 adjacent tiles along X
constexpr int kBlockRows = 2;    // two warps per CTA; enough CTA granularity even for 1024x1024 grids
constexpr unsigned kFullWarpMask = 0xFFFFFFFFu;

constexpr u64 kCol0    = 0x0101010101010101ull; // x == 0 in every byte-row
constexpr u64 kCol7    = 0x8080808080808080ull; // x == 7 in every byte-row
constexpr u64 kNotCol0 = 0xFEFEFEFEFEFEFEFEull;
constexpr u64 kNotCol7 = 0x7F7F7F7F7F7F7F7Full;
constexpr u64 kByteMask = 0xFFull;

__device__ __forceinline__ u64 load_ro(const u64* p) {
#if defined(__CUDA_ARCH__) && (__CUDA_ARCH__ >= 350)
    return __ldg(p);
#else
    return *p;
#endif
}

// 3-input majority; the compiler maps this well to LOP3 on recent architectures.
__device__ __forceinline__ u64 majority(u64 a, u64 b, u64 c) {
    return (a & b) | (a & c) | (b & c);
}

// Count four 1-bit inputs at each bit position into three bit-planes:
//   ones  -> count bit 0
//   twos  -> count bit 1
//   fours -> count bit 2
// No carries propagate across bit positions: every bit position is an independent population count.
__device__ __forceinline__ void count4(
    u64 a, u64 b, u64 c, u64 d,
    u64& ones, u64& twos, u64& fours)
{
    const u64 xab = a ^ b;
    const u64 xcd = c ^ d;
    const u64 cab = a & b;
    const u64 ccd = c & d;

    ones = xab ^ xcd;
    const u64 carry = xab & xcd;
    twos = cab ^ ccd ^ carry;
    fours = majority(cab, ccd, carry);
}

// Compute the next-generation 8x8 tile from the 3x3 tile neighborhood.
//
// Each argument is an 8x8 bitboard (one bit per cell). The center tile is 'c'; the other
// arguments are the eight neighboring tiles. Missing tiles outside the grid are passed as zero.
//
// The core idea is to build eight "aligned neighbor" bitboards:
//   for example, in n_aligned, bit p equals the north neighbor of output cell p.
// Then a carry-save style boolean adder counts those eight aligned bitboards per bit position.
__device__ __forceinline__ u64 step_tile(
    u64 c,  u64 n,  u64 s,
    u64 w,  u64 e,
    u64 nw, u64 ne,
    u64 sw, u64 se)
{
    // Horizontal neighbors from the center row, with byte-local wrap suppressed.
    const u64 w_aligned = ((c & kNotCol7) << 1) | ((w & kCol7) >> 7);
    const u64 e_aligned = ((c & kNotCol0) >> 1) | ((e & kCol0) << 7);

    // Halo rows from the tiles above/below.
    const u64 n_row7 = n >> 56;         // bottom row of north tile -> low byte
    const u64 s_row0 = s & kByteMask;   // top row of south tile   -> low byte

    // Vertical neighbors from the center column.
    const u64 n_aligned = (c << 8) | n_row7;
    const u64 s_aligned = (c >> 8) | (s_row0 << 56);

    // First half of the 8-neighbor population count: N, S, W, E.
    u64 ones0, twos0, fours0;
    count4(n_aligned, s_aligned, w_aligned, e_aligned, ones0, twos0, fours0);

    // Diagonals reuse the already-aligned W/E bitboards and inject only one halo byte.
    const u64 nw_aligned =
        (w_aligned << 8) |
        (((n_row7 & 0x7Full) << 1) | (nw >> 63));

    const u64 ne_aligned =
        (e_aligned << 8) |
        (((n_row7 & 0xFEull) >> 1) | (((ne >> 56) & 0x1ull) << 7));

    const u64 sw_aligned =
        (w_aligned >> 8) |
        ((((s_row0 & 0x7Full) << 1) | ((sw & 0x80ull) >> 7)) << 56);

    const u64 se_aligned =
        (e_aligned >> 8) |
        ((((s_row0 & 0xFEull) >> 1) | ((se & 0x1ull) << 7)) << 56);

    // Second half of the 8-neighbor population count: NW, NE, SW, SE.
    u64 ones1, twos1, fours1;
    count4(nw_aligned, ne_aligned, sw_aligned, se_aligned, ones1, twos1, fours1);

    // Add the two 3-bit partial counts into a full 4-bit count (0..8).
    const u64 bit0 = ones0 ^ ones1;
    const u64 carry0 = ones0 & ones1;

    const u64 bit1 = twos0 ^ twos1 ^ carry0;
    const u64 carry1 = majority(twos0, twos1, carry0);

    const u64 bit2 = fours0 ^ fours1 ^ carry1;
    const u64 bit3 = majority(fours0, fours1, carry1);

    // Life rule:
    //   next = (count == 3) | (alive & (count == 2))
    //
    // With count bits [bit3 bit2 bit1 bit0]:
    //   count in {2,3}  <=>  bit1 && !bit2 && !bit3
    //   among {2,3}, count==3 is exactly bit0==1
    //
    // So the rule simplifies to:
    //   next = (count in {2,3}) & (bit0 | alive)
    const u64 two_or_three = bit1 & ~(bit2 | bit3);
    return two_or_three & (bit0 | c);
}

// Hot kernel: all tile rows except the first and last.
//
// Launch shape is fixed to blockDim.x == 32, blockDim.y == 2:
// each warp handles 32 adjacent tiles in one tile row, so west/east and diagonal neighbor tiles
// come from warp shuffles. Only lane 0 / lane 31 perform extra halo loads across warp boundaries.
__global__ __launch_bounds__(64)
void game_of_life_interior_kernel(
    const u64* __restrict__ input,
    u64* __restrict__ output,
    int tiles_per_dim)
{
    const int x = static_cast<int>(blockIdx.x) * kWarpTiles + static_cast<int>(threadIdx.x);
    const int y = static_cast<int>(blockIdx.y) * static_cast<int>(blockDim.y) + static_cast<int>(threadIdx.y) + 1;
    if (y >= tiles_per_dim - 1) {
        return;
    }

    const int lane = static_cast<int>(threadIdx.x);
    const index_t pitch = static_cast<index_t>(tiles_per_dim);
    const index_t idx = static_cast<index_t>(y) * pitch + static_cast<index_t>(x);

    const u64 c = load_ro(input + idx);
    const u64 n = load_ro(input + idx - pitch);
    const u64 s = load_ro(input + idx + pitch);

    u64 w  = __shfl_up_sync(kFullWarpMask, c, 1);
    u64 e  = __shfl_down_sync(kFullWarpMask, c, 1);
    u64 nw = __shfl_up_sync(kFullWarpMask, n, 1);
    u64 ne = __shfl_down_sync(kFullWarpMask, n, 1);
    u64 sw = __shfl_up_sync(kFullWarpMask, s, 1);
    u64 se = __shfl_down_sync(kFullWarpMask, s, 1);

    if (lane == 0) {
        if (x > 0) {
            w  = load_ro(input + idx - 1);
            nw = load_ro(input + idx - pitch - 1);
            sw = load_ro(input + idx + pitch - 1);
        } else {
            w = 0ull;
            nw = 0ull;
            sw = 0ull;
        }
    } else if (lane == kWarpTiles - 1) {
        if (x + 1 < tiles_per_dim) {
            e  = load_ro(input + idx + 1);
            ne = load_ro(input + idx - pitch + 1);
            se = load_ro(input + idx + pitch + 1);
        } else {
            e = 0ull;
            ne = 0ull;
            se = 0ull;
        }
    }

    output[idx] = step_tile(c, n, s, w, e, nw, ne, sw, se);
}

// Tiny boundary kernel for the first and last tile rows.
//
// Left/right tile boundaries are already handled naturally by the warp-halo logic above.
// Splitting only the Y-boundaries keeps the much larger interior kernel branch-free in Y.
__global__ __launch_bounds__(64)
void game_of_life_top_bottom_kernel(
    const u64* __restrict__ input,
    u64* __restrict__ output,
    int tiles_per_dim)
{
    const int x = static_cast<int>(blockIdx.x) * kWarpTiles + static_cast<int>(threadIdx.x);
    const int lane = static_cast<int>(threadIdx.x);
    const index_t pitch = static_cast<index_t>(tiles_per_dim);

    if (threadIdx.y == 0) {
        // Top tile row: north-side halo is dead.
        const index_t idx = static_cast<index_t>(x);
        const u64 c = load_ro(input + idx);
        const u64 s = load_ro(input + idx + pitch);

        u64 w  = __shfl_up_sync(kFullWarpMask, c, 1);
        u64 e  = __shfl_down_sync(kFullWarpMask, c, 1);
        u64 sw = __shfl_up_sync(kFullWarpMask, s, 1);
        u64 se = __shfl_down_sync(kFullWarpMask, s, 1);

        if (lane == 0) {
            if (x > 0) {
                w  = load_ro(input + idx - 1);
                sw = load_ro(input + idx + pitch - 1);
            } else {
                w = 0ull;
                sw = 0ull;
            }
        } else if (lane == kWarpTiles - 1) {
            if (x + 1 < tiles_per_dim) {
                e  = load_ro(input + idx + 1);
                se = load_ro(input + idx + pitch + 1);
            } else {
                e = 0ull;
                se = 0ull;
            }
        }

        output[idx] = step_tile(c, 0ull, s, w, e, 0ull, 0ull, sw, se);
    } else {
        // Bottom tile row: south-side halo is dead.
        const index_t idx = (pitch - 1) * pitch + static_cast<index_t>(x);
        const u64 c = load_ro(input + idx);
        const u64 n = load_ro(input + idx - pitch);

        u64 w  = __shfl_up_sync(kFullWarpMask, c, 1);
        u64 e  = __shfl_down_sync(kFullWarpMask, c, 1);
        u64 nw = __shfl_up_sync(kFullWarpMask, n, 1);
        u64 ne = __shfl_down_sync(kFullWarpMask, n, 1);

        if (lane == 0) {
            if (x > 0) {
                w  = load_ro(input + idx - 1);
                nw = load_ro(input + idx - pitch - 1);
            } else {
                w = 0ull;
                nw = 0ull;
            }
        } else if (lane == kWarpTiles - 1) {
            if (x + 1 < tiles_per_dim) {
                e  = load_ro(input + idx + 1);
                ne = load_ro(input + idx - pitch + 1);
            } else {
                e = 0ull;
                ne = 0ull;
            }
        }

        output[idx] = step_tile(c, n, 0ull, w, e, nw, ne, 0ull, 0ull);
    }
}

} // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions) {
    // Problem guarantees:
    //   * square grid
    //   * power-of-two side length
    //   * side length > 512
    // Therefore:
    //   tiles_per_dim = grid_dimensions / 8 is a power of two >= 128,
    //   hence divisible by 32 and perfect for one-warp-per-32-tiles mapping.
    //
    // No host synchronization is performed here; launch ordering/synchronization is owned
    // by the caller. The function operates directly on the original bit-packed tile format.
    const int tiles_per_dim = grid_dimensions >> 3;

    const auto* in  = reinterpret_cast<const u64*>(input);
    auto* out = reinterpret_cast<u64*>(output);

    const dim3 block(kWarpTiles, kBlockRows);

    // Interior: all tile rows except the first and last.
    const dim3 grid_interior(
        static_cast<unsigned>(tiles_per_dim / kWarpTiles),
        static_cast<unsigned>((tiles_per_dim - 2 + kBlockRows - 1) / kBlockRows),
        1u);

    game_of_life_interior_kernel<<<grid_interior, block>>>(in, out, tiles_per_dim);

    // Top and bottom tile rows.
    const dim3 grid_top_bottom(
        static_cast<unsigned>(tiles_per_dim / kWarpTiles),
        1u,
        1u);

    game_of_life_top_bottom_kernel<<<grid_top_bottom, block>>>(in, out, tiles_per_dim);
}

#include <cuda_runtime.h>
#include <cstdint>

/*
 * Optimized one-step Conway's Game of Life for the problem's native storage format.
 *
 * Storage / bit layout assumed by this implementation:
 *   - The grid is stored as a row-major array of 8x8 tiles.
 *   - Each std::uint64_t stores one tile.
 *   - Bit (row * 8 + col) encodes the cell at local tile coordinate (row, col).
 *   - Row 0 lives in the least-significant byte, row 7 in the most-significant byte.
 *   - Within each byte, bit 0 is column 0 and bit 7 is column 7.
 *
 * This makes each 64-bit word a "byte-per-row" bitboard:
 *   - vertical movement is a shift by 8 bits
 *   - horizontal movement is a shift by 1 bit, plus a byte-edge fixup from the neighboring tile
 *
 * Kernel strategy:
 *   - One CUDA thread computes one 8x8 output tile (64 cells).
 *   - The thread loads the 3x3 neighborhood of input tiles.
 *   - It constructs the eight aligned neighbor bitboards (N, S, W, E, NW, NE, SW, SE).
 *   - Those eight 1-bit planes are summed with a carry-save adder tree, producing the exact
 *     4-bit neighbor count for all 64 cells in parallel.
 *   - The Conway rule is then applied with pure bitwise logic.
 *
 * Shared memory is intentionally not used. For this packed representation the working set per tile
 * is already tiny, neighboring threads naturally reuse overlapping tiles through L1/L2, and keeping
 * everything in registers avoids synchronization and extra complexity.
 */

namespace {
using u64 = std::uint64_t;

/*
 * 128 threads is a good fit here:
 *   - it is the largest power-of-two block size that always divides every legal tile-row length
 *     (tiles_per_dim is a power of two and, because grid_dimensions > 512, tiles_per_dim >= 128)
 *   - that lets run_game_of_life choose a grid size whose grid-stride step is an exact integer
 *     number of tile rows, preserving row alignment across loop iterations
 *   - it also keeps enough blocks available for smaller legal grids
 */
constexpr int kBlockThreads = 128;
constexpr int kQueuedOccupancyWaves = 8;

constexpr u64 kCol0Mask    = 0x0101010101010101ULL;
constexpr u64 kCol7Mask    = 0x8080808080808080ULL;
constexpr u64 kNotCol0Mask = 0xFEFEFEFEFEFEFEFEULL;
constexpr u64 kNotCol7Mask = 0x7F7F7F7F7F7F7F7FULL;

__device__ __forceinline__ u64 load_ro(const u64* ptr) {
#if __CUDA_ARCH__ >= 350
    return __ldg(ptr);
#else
    return *ptr;
#endif
}

/* Align the north/south neighbor rows to the current tile's bit positions. */
__device__ __forceinline__ u64 align_north(u64 center, u64 north) {
    return (center << 8) | (north >> 56);
}

__device__ __forceinline__ u64 align_south(u64 center, u64 south) {
    return (center >> 8) | (south << 56);
}

/* Shift within 8-bit rows and stitch the missing edge bit from the adjacent tile. */
__device__ __forceinline__ u64 shift_west(u64 center, u64 west) {
    return ((center & kNotCol7Mask) << 1) | ((west & kCol7Mask) >> 7);
}

__device__ __forceinline__ u64 shift_east(u64 center, u64 east) {
    return ((center & kNotCol0Mask) >> 1) | ((east & kCol0Mask) << 7);
}

/*
 * Three-input carry-save adder on 64 independent bit positions.
 * For each bit position:
 *   sum   = low bit of a+b+c
 *   carry = high bit of a+b+c
 */
__device__ __forceinline__ void csa(u64& carry, u64& sum, u64 a, u64 b, u64 c) {
    const u64 u = a ^ b;
    carry = (a & b) | (u & c);
    sum = u ^ c;
}

__global__ void game_of_life_kernel(const u64* __restrict__ input,
                                    u64* __restrict__ output,
                                    unsigned int tiles_per_dim,
                                    u64 num_tiles) {
    const u64 tid = static_cast<u64>(blockIdx.x) * blockDim.x + threadIdx.x;
    const u64 stride = static_cast<u64>(blockDim.x) * gridDim.x;

    const u64 row_stride = static_cast<u64>(tiles_per_dim);
    const u64 south_limit = num_tiles - row_stride;
    const unsigned int x_mask = tiles_per_dim - 1u;

    /*
     * run_game_of_life chooses gridDim.x so that stride is always an integer number of tile rows.
     * Therefore a thread's x coordinate is invariant across grid-stride iterations and can be hoisted
     * out of the loop.
     */
    const unsigned int x = static_cast<unsigned int>(tid) & x_mask;
    const bool has_w_static = (x != 0u);
    const bool has_e_static = (x != x_mask);
    const bool x_is_interior = has_w_static & has_e_static;

    for (u64 idx = tid; idx < num_tiles; idx += stride) {
        const bool has_n = (idx >= row_stride);
        const bool has_s = (idx < south_limit);
        const bool interior = x_is_interior & has_n & has_s;

        const u64 west_idx  = idx - 1;
        const u64 east_idx  = idx + 1;
        const u64 north_idx = idx - row_stride;
        const u64 south_idx = idx + row_stride;

        const u64 tC = load_ro(input + idx);

        u64 tNW, tN, tNE;
        u64 tW,  tE;
        u64 tSW, tS, tSE;

        if (interior) {
            /* Fast path: the overwhelmingly common case. No boundary predicates required. */
            tNW = load_ro(input + north_idx - 1);
            tN  = load_ro(input + north_idx);
            tNE = load_ro(input + north_idx + 1);

            tW  = load_ro(input + west_idx);
            tE  = load_ro(input + east_idx);

            tSW = load_ro(input + south_idx - 1);
            tS  = load_ro(input + south_idx);
            tSE = load_ro(input + south_idx + 1);
        } else {
            /* Slow path: cells outside the grid are defined as dead, so missing tiles are zero. */
            const bool has_nw = has_n & has_w_static;
            const bool has_ne = has_n & has_e_static;
            const bool has_sw = has_s & has_w_static;
            const bool has_se = has_s & has_e_static;

            tN  = has_n       ? load_ro(input + north_idx)     : 0;
            tS  = has_s       ? load_ro(input + south_idx)     : 0;
            tW  = has_w_static ? load_ro(input + west_idx)     : 0;
            tE  = has_e_static ? load_ro(input + east_idx)     : 0;

            tNW = has_nw      ? load_ro(input + north_idx - 1) : 0;
            tNE = has_ne      ? load_ro(input + north_idx + 1) : 0;
            tSW = has_sw      ? load_ro(input + south_idx - 1) : 0;
            tSE = has_se      ? load_ro(input + south_idx + 1) : 0;
        }

        /* Build the eight aligned neighbor planes. */
        const u64 north_bits = align_north(tC, tN);
        const u64 south_bits = align_south(tC, tS);
        const u64 west_bits  = shift_west(tC, tW);
        const u64 east_bits  = shift_east(tC, tE);

        const u64 nw_bits = shift_west(north_bits, align_north(tW, tNW));
        const u64 ne_bits = shift_east(north_bits, align_north(tE, tNE));
        const u64 sw_bits = shift_west(south_bits, align_south(tW, tSW));
        const u64 se_bits = shift_east(south_bits, align_south(tE, tSE));

        /*
         * Exact population count of the eight neighbor planes with a carry-save adder tree.
         * Final bitboards:
         *   ones   -> count bit 0
         *   twos   -> count bit 1
         *   fours  -> count bit 2
         *   eights -> count bit 3
         */
        const u64 s01 = north_bits ^ south_bits;
        const u64 c01 = north_bits & south_bits;

        const u64 s23 = west_bits ^ east_bits;
        const u64 c23 = west_bits & east_bits;

        const u64 s45 = nw_bits ^ ne_bits;
        const u64 c45 = nw_bits & ne_bits;

        const u64 s67 = sw_bits ^ se_bits;
        const u64 c67 = sw_bits & se_bits;

        const u64 s0123 = s01 ^ s23;
        const u64 k0123 = s01 & s23;
        u64 c0123, twos0123;
        csa(c0123, twos0123, c01, c23, k0123);

        const u64 s4567 = s45 ^ s67;
        const u64 k4567 = s45 & s67;
        u64 c4567, twos4567;
        csa(c4567, twos4567, c45, c67, k4567);

        const u64 ones = s0123 ^ s4567;
        const u64 ones_to_twos = s0123 & s4567;

        u64 twos_to_fours, twos;
        csa(twos_to_fours, twos, twos0123, twos4567, ones_to_twos);

        u64 eights, fours;
        csa(eights, fours, c0123, c4567, twos_to_fours);

        /*
         * Conway rule in bit-sliced form:
         *   - count == 3 => birth or survival
         *   - count == 2 => survival only if the current cell is already alive
         *
         * twos=1 with no higher count bits means the count is 2 or 3.
         * (ones | tC) then selects:
         *   - count 3: ones=1 -> always alive next
         *   - count 2: ones=0 -> alive next only if current cell (tC) is alive
         */
        const u64 eligible_counts = twos & ~(fours | eights);
        output[idx] = eligible_counts & (ones | tC);
    }
}

} // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions) {
    const unsigned int tiles_per_dim = static_cast<unsigned int>(grid_dimensions) >> 3;
    const std::uint64_t tiles_per_dim64 = static_cast<std::uint64_t>(tiles_per_dim);
    const std::uint64_t num_tiles = tiles_per_dim64 * tiles_per_dim64;

    /*
     * Host-side launch tuning is intentionally lightweight and cached per host thread.
     * Error handling / synchronization is deliberately left to the caller, as requested.
     */
    thread_local int cached_device = -1;
    thread_local int cached_max_blocks = 0;

    int device = 0;
    (void)cudaGetDevice(&device);

    if (device != cached_device) {
        int sm_count = 0;
        int active_blocks = 0;

        (void)cudaDeviceGetAttribute(&sm_count, cudaDevAttrMultiProcessorCount, device);

        /* No shared memory is used, so prefer L1 for the overlapping 3x3-tile reads. */
        (void)cudaFuncSetCacheConfig(game_of_life_kernel, cudaFuncCachePreferL1);

        (void)cudaOccupancyMaxActiveBlocksPerMultiprocessor(
            &active_blocks, game_of_life_kernel, kBlockThreads, 0);

        if (active_blocks < 1) {
            active_blocks = 1;
        }

        cached_max_blocks = sm_count * active_blocks * kQueuedOccupancyWaves;
        if (cached_max_blocks < 1) {
            cached_max_blocks = 1;
        }

        cached_device = device;
    }

    /*
     * num_tiles is exactly divisible by 128 under the stated problem constraints:
     *   tiles_per_dim is a power of two and >= 128, so num_tiles = tiles_per_dim^2 is a multiple of 128.
     */
    std::uint64_t launch_blocks = num_tiles / static_cast<std::uint64_t>(kBlockThreads);

    if (launch_blocks > static_cast<std::uint64_t>(cached_max_blocks)) {
        /*
         * Keep gridDim.x * blockDim.x equal to a whole-number multiple of the tile-row length.
         * Since one tile row contains tiles_per_dim tiles and each block contributes kBlockThreads threads,
         * that means gridDim.x must be a multiple of tiles_per_dim / kBlockThreads blocks.
         *
         * This preserves row alignment across grid-stride iterations:
         *   stride = gridDim.x * blockDim.x = integer_multiple * tiles_per_dim
         * so each thread keeps the same x coordinate on every loop trip, which in turn preserves
         * coalesced row-wise accesses and lets the kernel hoist x/left/right state out of the loop.
         */
        const std::uint64_t blocks_per_tile_row =
            tiles_per_dim64 / static_cast<std::uint64_t>(kBlockThreads);

        std::uint64_t capped_blocks =
            static_cast<std::uint64_t>(cached_max_blocks);
        capped_blocks -= capped_blocks % blocks_per_tile_row;

        if (capped_blocks == 0) {
            capped_blocks = blocks_per_tile_row;
        }

        launch_blocks = capped_blocks;
    }

    game_of_life_kernel<<<static_cast<int>(launch_blocks), kBlockThreads>>>(
        input, output, tiles_per_dim, num_tiles);
}

#include <cuda_runtime.h>

#include <cstddef>
#include <cstdint>

namespace {

// Internal scalar aliases.
using u32 = std::uint32_t;
using u64 = std::uint64_t;

// The problem guarantees power-of-two dimensions > 512, so the number of 8x8 tiles
// per row/column is also a power of two and at least 128. We choose a block shape
// that maps exactly to that geometry:
//
// - blockDim.x == 32, so each warp spans one contiguous horizontal strip of 32 tiles.
//   This lets us obtain left/right neighboring tiles with warp shuffles instead of
//   extra global memory loads.
// - blockDim.y == 8, so each CTA contains 8 warps and still stays light enough for
//   high occupancy on A100/H100-class GPUs.
constexpr int kTileLog2 = 3;   // 8 cells per tile edge.
constexpr int kBlockX   = 32;  // Exactly one warp wide.
constexpr int kBlockY   = 8;
constexpr int kThreadsPerBlock = kBlockX * kBlockY;

static_assert(kBlockX == 32, "This kernel relies on blockDim.x being exactly one warp.");
constexpr u32 kLastLane = static_cast<u32>(kBlockX - 1);
constexpr u32 kFullWarpMask = 0xFFFFFFFFu;

// Intra-tile bit layout assumed by this implementation:
//
//   bit index = 8 * local_y + local_x
//
// So each byte is one tile row, row 0 lives in bits [0..7], row 7 in bits [56..63],
// and within each row-byte, column 0 is the least-significant bit.
//
// The 64-bit masks below therefore select tile borders directly.
constexpr u64 kCol0 = 0x0101010101010101ull;
constexpr u64 kCol7 = 0x8080808080808080ull;
constexpr u64 kRow0 = 0x00000000000000FFull;
constexpr u64 kRow7 = 0xFF00000000000000ull;

constexpr u64 kNotCol0 = 0xFEFEFEFEFEFEFEFEull;
constexpr u64 kNotCol7 = 0x7F7F7F7F7F7F7F7Full;

constexpr u64 kCornerNW = 0x8000000000000000ull;
constexpr u64 kCornerNE = 0x0100000000000000ull;
constexpr u64 kCornerSW = 0x0000000000000080ull;
constexpr u64 kCornerSE = 0x0000000000000001ull;

// Warp shuffle helpers for 64-bit values.
// Implemented via two 32-bit shuffles so the code is robust regardless of the exact
// host typedef behind std::uint64_t on the compilation platform.
__device__ __forceinline__ u64 shfl_up_1_u64(const u64 v) {
    const u32 lo = __shfl_up_sync(kFullWarpMask, static_cast<u32>(v), 1);
    const u32 hi = __shfl_up_sync(kFullWarpMask, static_cast<u32>(v >> 32), 1);
    return (static_cast<u64>(hi) << 32) | static_cast<u64>(lo);
}

__device__ __forceinline__ u64 shfl_down_1_u64(const u64 v) {
    const u32 lo = __shfl_down_sync(kFullWarpMask, static_cast<u32>(v), 1);
    const u32 hi = __shfl_down_sync(kFullWarpMask, static_cast<u32>(v >> 32), 1);
    return (static_cast<u64>(hi) << 32) | static_cast<u64>(lo);
}

// Bit-sliced full adder.
// For every bit position independently, this adds three 1-bit values and returns:
//   sum   = low bit of the 3-input sum
//   carry = high bit of the 3-input sum
//
// Because one 64-bit word represents 64 cells, this is effectively 64 independent
// full adders running in parallel.
__device__ __forceinline__ void full_adder(
    const u64 a, const u64 b, const u64 c, u64& sum, u64& carry) {
    const u64 t = a ^ b;
    sum   = t ^ c;
    carry = (a & b) | (c & t);
}

// One thread updates one 8x8 output tile.
//
// Key performance choices:
// - No shared memory: horizontal reuse is cheaper via warp shuffles, and the remaining
//   vertical reuse is handled well by the normal caches on modern datacenter GPUs.
// - No bounds checks for thread validity: the problem guarantees the launch geometry
//   divides the tiled grid exactly.
// - Only 3 compulsory global loads per interior thread (center/north/south tiles).
//   West/east neighbors of those rows are exchanged within the warp; only lane 0 and
//   lane 31 perform extra cross-warp/block fallback loads.
__global__ __launch_bounds__(kThreadsPerBlock)
void game_of_life_kernel(
    const u64* __restrict__ input,
    u64* __restrict__ output,
    const std::size_t tiles_per_dim) {

    const u32 lane = threadIdx.x;

    const std::size_t tx =
        static_cast<std::size_t>(blockIdx.x) * static_cast<std::size_t>(kBlockX) +
        static_cast<std::size_t>(threadIdx.x);
    const std::size_t ty =
        static_cast<std::size_t>(blockIdx.y) * static_cast<std::size_t>(kBlockY) +
        static_cast<std::size_t>(threadIdx.y);

    const std::size_t idx  = ty * tiles_per_dim + tx;
    const std::size_t last = tiles_per_dim - 1;

    const bool has_north = (ty != 0);
    const bool has_south = (ty != last);
    const bool has_west  = (tx != 0);
    const bool has_east  = (tx != last);

    // Each thread loads only its own column from the previous/current/next tile row.
    const u64 c = input[idx];
    const u64 n = has_north ? input[idx - tiles_per_dim] : 0ull;
    const u64 s = has_south ? input[idx + tiles_per_dim] : 0ull;

    // Horizontal neighbors come from warp shuffles because each warp spans one
    // contiguous 32-tile strip. Only warp-edge lanes need true global fallback loads.
    u64 w  = shfl_up_1_u64(c);
    u64 e  = shfl_down_1_u64(c);
    u64 nw = shfl_up_1_u64(n);
    u64 ne = shfl_down_1_u64(n);
    u64 sw = shfl_up_1_u64(s);
    u64 se = shfl_down_1_u64(s);

    if (lane == 0) {
        w  = has_west ? input[idx - 1] : 0ull;
        nw = (has_north && has_west) ? input[idx - tiles_per_dim - 1] : 0ull;
        sw = (has_south && has_west) ? input[idx + tiles_per_dim - 1] : 0ull;
    }

    if (lane == kLastLane) {
        e  = has_east ? input[idx + 1] : 0ull;
        ne = (has_north && has_east) ? input[idx - tiles_per_dim + 1] : 0ull;
        se = (has_south && has_east) ? input[idx + tiles_per_dim + 1] : 0ull;
    }

    // Cache the border bits reused by multiple directional alignments.
    const u64 w_col7 = w & kCol7;
    const u64 e_col0 = e & kCol0;
    const u64 n_row7 = n & kRow7;
    const u64 s_row0 = s & kRow0;

    // Build the 8 aligned neighbor bitboards:
    // every bit position now represents "is the neighbor in that direction alive for
    // the current cell at this bit position?"
    //
    // Example: west has the cell immediately to the left of each current cell aligned
    // into the current cell's bit position, including cross-tile carry-in from the
    // western tile's column 7.
    u64 sum_a, carry_a;
    {
        const u64 west  = ((c << 1) & kNotCol0) | (w_col7 >> 7);
        const u64 east  = ((c >> 1) & kNotCol7) | (e_col0 << 7);
        const u64 north = (c << 8) | (n_row7 >> 56);
        full_adder(west, east, north, sum_a, carry_a);
    }

    u64 sum_b, carry_b;
    {
        const u64 south = (c >> 8) | (s_row0 << 56);

        const u64 northwest =
            ((c << 9) & kNotCol0) |
            ((n_row7 >> 55) & kNotCol0) |
            (w_col7 << 1) |
            ((nw & kCornerNW) >> 63);

        const u64 northeast =
            ((c << 7) & kNotCol7) |
            (n_row7 >> 57) |
            (e_col0 << 15) |
            ((ne & kCornerNE) >> 49);

        full_adder(south, northwest, northeast, sum_b, carry_b);
    }

    const u64 southwest =
        ((c >> 7) & kNotCol0) |
        (s_row0 << 57) |
        (w_col7 >> 15) |
        ((sw & kCornerSW) << 49);

    const u64 southeast =
        ((c >> 9) & kNotCol7) |
        ((s_row0 << 55) & kNotCol7) |
        (e_col0 >> 1) |
        ((se & kCornerSE) << 63);

    // Bit-sliced population count of the 8 neighbors.
    //
    // At this point we have 8 one-bit inputs per cell:
    //   {west, east, north, south, northwest, northeast, southwest, southeast}
    //
    // The adder tree below computes a 4-bit binary neighbor count for all 64 cells in
    // parallel. The final rule application is then:
    //   next = (count == 3) || (current && count == 2)
    //
    // Instead of materializing equality tests separately, we observe that:
    //   count in {2,3}  <=>  bit1 == 1 and bit2 == 0 and bit3 == 0
    // and the low bit decides between 2 and 3:
    //   bit0 == 0 -> count 2
    //   bit0 == 1 -> count 3
    const u64 partial_lo0 = sum_a ^ sum_b;
    const u64 partial_hi0 = sum_a & sum_b;
    const u64 partial_lo1 = southwest ^ southeast;
    const u64 partial_hi1 = southwest & southeast;

    const u64 bit0   = partial_lo0 ^ partial_lo1;
    const u64 carry0 = partial_lo0 & partial_lo1;

    u64 mid, high;
    full_adder(partial_hi0, partial_hi1, carry0, mid, high);

    u64 bit1, carry1;
    full_adder(mid, carry_a, carry_b, bit1, carry1);

    const u64 bit2 = carry1 ^ high;
    const u64 bit3 = carry1 & high;

    const u64 valid23 = bit1 & ~(bit2 | bit3);
    output[idx] = valid23 & (bit0 | c);
}

}  // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions) {
    // The hot path assumes standard ping-pong usage: input and output are distinct
    // device buffers. No synchronization is done here; the caller owns ordering.
    //
    // grid_dimensions is guaranteed to be a power of two > 512, so:
    //   tiles_per_dim = grid_dimensions / 8
    // is also a power of two and therefore divisible by both 32 and 8 exactly.
    // That lets the kernel omit per-thread bounds checks entirely.
    const std::size_t tiles_per_dim =
        static_cast<std::size_t>(grid_dimensions) >> kTileLog2;

    const dim3 block(kBlockX, kBlockY);
    const dim3 grid(
        static_cast<unsigned int>(tiles_per_dim / static_cast<std::size_t>(kBlockX)),
        static_cast<unsigned int>(tiles_per_dim / static_cast<std::size_t>(kBlockY)));

    game_of_life_kernel<<<grid, block>>>(input, output, tiles_per_dim);
}

#include <cstddef>
#include <cstdint>
#include <cuda_runtime.h>

/*
Optimized Conway's Game of Life for a grid stored as row-major 8x8 tiles.

Assumed layout:
  - The tile array itself is row-major over 8x8 tiles.
  - Inside each 64-bit tile, bit index (local_y << 3) | local_x encodes cell (local_x, local_y).
    Equivalently: each tile is eight 8-bit rows packed from the least-significant byte upward.
    This is the common "bitboard" convention where moving north is << 8 and moving east is >> 1.

Performance strategy:
  - One CUDA thread updates one 8x8 tile, so 64 cells are processed in parallel with bitwise logic.
  - blockDim.x == 32, so every warp covers 32 adjacent tiles in x.
    Horizontal neighbor tiles are exchanged with warp shuffles; only the two warp-edge lanes
    need extra global loads.
  - The eight neighbor planes are added with bit-sliced arithmetic; shared/texture memory are
    intentionally avoided because they are unnecessary here for this layout.

The kernel expects input and output to be distinct device buffers.
*/

namespace {

using u64 = unsigned long long;

constexpr int kTileSide      = 8;
constexpr int kTileSideShift = 3;

constexpr int kBlockX      = 32;  // exactly one warp in x
constexpr int kBlockXShift = 5;
constexpr int kBlockY      = 8;   // 8 warp-rows per block => 256 threads/block
constexpr int kBlockYShift = 3;

constexpr int kThreadsPerBlock = kBlockX * kBlockY;

static_assert(sizeof(u64) == sizeof(std::uint64_t), "64-bit type mismatch.");
static_assert(kTileSide == 8, "This implementation is specialized for 8x8 packed tiles.");
static_assert(kBlockX == 32, "blockDim.x must equal one warp.");
static_assert((1 << kTileSideShift) == kTileSide, "Tile shift mismatch.");
static_assert((1 << kBlockXShift) == kBlockX, "Block X shift mismatch.");
static_assert((1 << kBlockYShift) == kBlockY, "Block Y shift mismatch.");

// Column masks inside an 8x8 tile.
constexpr u64 kCol0    = 0x0101010101010101ULL; // x == 0 in each row
constexpr u64 kCol7    = kCol0 << 7;            // x == 7 in each row
constexpr u64 kNotCol0 = ~kCol0;
constexpr u64 kNotCol7 = ~kCol7;

constexpr unsigned kFullWarpMask = 0xFFFFFFFFu;

// Majority of three 64-bit bitboards.
// On modern NVIDIA GPUs this typically lowers to efficient LOP3-style logic.
__device__ __forceinline__ u64 majority3(u64 a, u64 b, u64 c) {
    return (a & b) | (c & (a | b));
}

// Aligned-neighbor extraction helpers.
// The returned bitboard contains, at each cell position, the state of that neighbor.
// Missing tiles are passed as zero, which naturally implements the required dead boundary.
__device__ __forceinline__ u64 align_west(u64 tile, u64 west_tile) {
    return ((tile & kNotCol7) << 1) | ((west_tile & kCol7) >> 7);
}

__device__ __forceinline__ u64 align_east(u64 tile, u64 east_tile) {
    return ((tile & kNotCol0) >> 1) | ((east_tile & kCol0) << 7);
}

__device__ __forceinline__ u64 align_north(u64 tile, u64 north_tile) {
    return (tile << kTileSide) | (north_tile >> (64 - kTileSide));
}

__device__ __forceinline__ u64 align_south(u64 tile, u64 south_tile) {
    return (tile >> kTileSide) | (south_tile << (64 - kTileSide));
}

// 64 parallel 4-input additions.
// For every bit position, the outputs are the 1/2/4 bits of the local 0..4 population count.
__device__ __forceinline__ void sum4(
    u64 a, u64 b, u64 c, u64 d,
    u64& ones, u64& twos, u64& fours)
{
    const u64 ab_xor = a ^ b;
    const u64 ab_and = a & b;
    const u64 cd_xor = c ^ d;
    const u64 cd_and = c & d;

    ones = ab_xor ^ cd_xor;

    const u64 carry_into_twos = ab_xor & cd_xor;
    twos  = ab_and ^ cd_and ^ carry_into_twos;
    fours = majority3(ab_and, cd_and, carry_into_twos);
}

__global__ __launch_bounds__(kThreadsPerBlock)
void game_of_life_kernel(
    const std::uint64_t* __restrict__ input,
    std::uint64_t* __restrict__ output,
    int tiles_per_row)
{
    // Because blockDim.x == 32, each warp is one contiguous strip of tiles in x.
    const int lane   = static_cast<int>(threadIdx.x);
    const int tile_x = (static_cast<int>(blockIdx.x) << kBlockXShift) + lane;
    const int tile_y = (static_cast<int>(blockIdx.y) << kBlockYShift) + static_cast<int>(threadIdx.y);

    const int last_tile = tiles_per_row - 1;

    const bool has_north = (tile_y != 0);
    const bool has_south = (tile_y != last_tile);
    const bool has_west  = (tile_x != 0);
    const bool has_east  = (tile_x != last_tile);

    const std::size_t linear_tile =
        static_cast<std::size_t>(tile_y) * static_cast<std::size_t>(tiles_per_row) +
        static_cast<std::size_t>(tile_x);

    const std::ptrdiff_t stride = static_cast<std::ptrdiff_t>(tiles_per_row);
    const std::uint64_t* const center_ptr = input + linear_tile;

    // Vertical neighbors are loaded directly.
    const u64 tile_center = static_cast<u64>(*center_ptr);
    const u64 tile_north  = has_north ? static_cast<u64>(*(center_ptr - stride)) : 0ULL;
    const u64 tile_south  = has_south ? static_cast<u64>(*(center_ptr + stride)) : 0ULL;

    // Horizontal neighbors mostly come from neighboring lanes in the same warp.
    // Only warp-edge lanes need explicit global loads to cross the 32-tile warp boundary.
    u64 tile_west = __shfl_up_sync(kFullWarpMask,   tile_center, 1);
    u64 tile_east = __shfl_down_sync(kFullWarpMask, tile_center, 1);

    u64 tile_nw   = __shfl_up_sync(kFullWarpMask,   tile_north,  1);
    u64 tile_ne   = __shfl_down_sync(kFullWarpMask, tile_north,  1);

    u64 tile_sw   = __shfl_up_sync(kFullWarpMask,   tile_south,  1);
    u64 tile_se   = __shfl_down_sync(kFullWarpMask, tile_south,  1);

    if (lane == 0) {
        tile_west = has_west ? static_cast<u64>(*(center_ptr - 1)) : 0ULL;
        tile_nw   = (has_north && has_west) ? static_cast<u64>(*(center_ptr - stride - 1)) : 0ULL;
        tile_sw   = (has_south && has_west) ? static_cast<u64>(*(center_ptr + stride - 1)) : 0ULL;
    }

    if (lane == kBlockX - 1) {
        tile_east = has_east ? static_cast<u64>(*(center_ptr + 1)) : 0ULL;
        tile_ne   = (has_north && has_east) ? static_cast<u64>(*(center_ptr - stride + 1)) : 0ULL;
        tile_se   = (has_south && has_east) ? static_cast<u64>(*(center_ptr + stride + 1)) : 0ULL;
    }

    // Build the eight aligned neighbor planes for the 64 cells in this tile.
    const u64 north_row      = align_north(tile_center, tile_north);
    const u64 north_row_west = align_north(tile_west,   tile_nw);
    const u64 north_row_east = align_north(tile_east,   tile_ne);

    const u64 neighbor_nw = align_west(north_row, north_row_west);
    const u64 neighbor_ne = align_east(north_row, north_row_east);
    const u64 neighbor_w  = align_west(tile_center, tile_west);

    const u64 south_row      = align_south(tile_center, tile_south);
    const u64 south_row_west = align_south(tile_west,   tile_sw);
    const u64 south_row_east = align_south(tile_east,   tile_se);

    const u64 neighbor_sw = align_west(south_row, south_row_west);
    const u64 neighbor_se = align_east(south_row, south_row_east);
    const u64 neighbor_e  = align_east(tile_center, tile_east);

    // Sum the eight neighbor planes as two independent 4-input groups.
    // The center tile is intentionally excluded from this count.
    u64 ones0, twos0, fours0;
    sum4(neighbor_nw, north_row, neighbor_ne, neighbor_w, ones0, twos0, fours0);

    u64 ones1, twos1, fours1;
    sum4(neighbor_e, neighbor_sw, south_row, neighbor_se, ones1, twos1, fours1);

    // Combine the two 0..4 partial counts into the total 0..8 count.
    const u64 ones_bit         = ones0 ^ ones1;
    const u64 carry_into_twos  = ones0 & ones1;
    const u64 twos_bit         = twos0 ^ twos1 ^ carry_into_twos;
    const u64 carry_into_fours = majority3(twos0, twos1, carry_into_twos);

    // twos_bit is 1 for total counts {2,3,6,7}.
    // Any contribution in the 4's place means the total is >= 4, so filtering that out
    // leaves exactly {2,3}. The 1's bit then distinguishes 3 from 2:
    //   - 3  -> ones_bit = 1 => birth or survive
    //   - 2  -> ones_bit = 0 => survive only if currently alive
    const u64 ge4             = fours0 | fours1 | carry_into_fours;
    const u64 count_is_2_or_3 = twos_bit & ~ge4;
    const u64 next_tile       = count_is_2_or_3 & (ones_bit | tile_center);

    output[linear_tile] = static_cast<std::uint64_t>(next_tile);
}

} // anonymous namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions)
{
    // grid_dimensions is guaranteed to be a power of two > 512.
    // Therefore tiles_per_row = grid_dimensions / 8 is also a power of two and is divisible
    // by both 32 and 8, so this launch covers the tile grid exactly with no bounds checks.
    const int tiles_per_row = grid_dimensions >> kTileSideShift;

    const dim3 block(kBlockX, kBlockY);
    const dim3 grid(
        static_cast<unsigned int>(tiles_per_row >> kBlockXShift),
        static_cast<unsigned int>(tiles_per_row >> kBlockYShift));

    // Launch only; synchronization and any desired error handling are intentionally left to the caller.
    game_of_life_kernel<<<grid, block>>>(input, output, tiles_per_row);
}

#include <cstdint>
#include <cuda_runtime.h>

/*
 * Optimized CUDA Game of Life update for the problem's native bit-packed format.
 *
 * Storage model assumed by this implementation:
 *   - The board is partitioned into 8x8 tiles stored row-major.
 *   - Each 64-bit word stores one 8x8 tile in row-major bit order:
 *       bit ((local_y << 3) | local_x) == cell (local_x, local_y)
 *     with local_x in [0, 7] and local_y in [0, 7].
 *
 * Performance strategy:
 *   - One CUDA thread updates one 8x8 output tile, i.e. 64 cells at once.
 *   - The eight neighbor directions are formed as aligned 64-bit masks and then
 *     summed with bit-sliced boolean arithmetic ("SWAR" / bitboard style).
 *   - Horizontal tile neighbors are exchanged with warp shuffles so that the
 *     common path needs only three coalesced global loads per thread:
 *       north / center / south
 *   - Only lane 0 and lane 31 of each warp perform a few extra loads to bridge
 *     warp boundaries or inject zeroes at the outer board boundary.
 *   - No shared memory or texture memory is used, per the prompt.
 *
 * This warp mapping relies directly on the stated constraints:
 *   grid_dimensions is a power of two > 512
 *   => tiles_per_dim = grid_dimensions / 8 is a power of two >= 128
 *   => every tile row length is a multiple of 32
 *   => a warp of 32 consecutive thread/tile indices never crosses a tile-row boundary.
 */

namespace {

using u32 = std::uint32_t;
using u64 = std::uint64_t;

constexpr int kWarpSize = 32;
constexpr int kThreadsPerBlock = 256;
constexpr u32 kFullWarpMask = 0xFFFFFFFFu;

static_assert((kThreadsPerBlock % kWarpSize) == 0,
              "kThreadsPerBlock must be a whole number of warps.");

// Bit masks for the standard row-major 8x8 bitboard layout.
constexpr u64 COL0_MASK     = 0x0101010101010101ULL;  // x == 0
constexpr u64 COL7_MASK     = 0x8080808080808080ULL;  // x == 7
constexpr u64 NOT_COL0_MASK = 0xFEFEFEFEFEFEFEFEULL;  // x != 0
constexpr u64 NOT_COL7_MASK = 0x7F7F7F7F7F7F7F7FULL;  // x != 7

// Individual corner bits inside a tile.
constexpr u64 BIT_R0_C0 = 0x0000000000000001ULL;
constexpr u64 BIT_R0_C7 = 0x0000000000000080ULL;
constexpr u64 BIT_R7_C0 = 0x0100000000000000ULL;
constexpr u64 BIT_R7_C7 = 0x8000000000000000ULL;

/*
 * Compute the next-state 8x8 tile from its 3x3 input-tile neighborhood.
 *
 * The implementation forms eight aligned neighbor masks:
 *   nbr_n, nbr_s, nbr_e, nbr_w, nbr_nw, nbr_ne, nbr_sw, nbr_se
 *
 * In each mask, bit i answers "is the corresponding neighbor of cell i alive?".
 * The eight 1-bit values per cell are then summed with a small carry-save / full-adder
 * tree, producing the 4-bit neighbor count in bit-sliced form across all 64 cells.
 *
 * Finally, the Life rule is applied in fully bit-parallel form:
 *   next = (count == 3) | (current & (count == 2))
 */
__device__ __forceinline__ u64 step_tile_8x8(
    const u64 tile_c,
    const u64 tile_n,
    const u64 tile_s,
    const u64 tile_w,
    const u64 tile_e,
    const u64 tile_nw,
    const u64 tile_ne,
    const u64 tile_sw,
    const u64 tile_se)
{
    // North / south aligned to destination cell positions.
    const u64 nbr_n = (tile_c << 8) | (tile_n >> 56);
    const u64 nbr_s = (tile_c >> 8) | (tile_s << 56);

    // Pairwise add N + S.
    const u64 p01 = nbr_n ^ nbr_s;
    const u64 c01 = nbr_n & nbr_s;

    // East / west aligned to destination cell positions.
    u64 x0 = ((tile_c & NOT_COL0_MASK) >> 1) | ((tile_e & COL0_MASK) << 7);
    u64 x1 = ((tile_c & NOT_COL7_MASK) << 1) | ((tile_w & COL7_MASK) >> 7);

    // Pairwise add E + W.
    const u64 p23 = x0 ^ x1;
    const u64 c23 = x0 & x1;

    // First four directions -> partial count a2:a1:a0 (0..4 per cell).
    u64 carry = p01 & p23;
    u64 t = c01 ^ c23;
    const u64 a0 = p01 ^ p23;
    const u64 a1 = t ^ carry;
    const u64 a2 = (c01 & c23) | (carry & t);

    // Diagonals reuse the already-aligned north/south masks:
    //   NW = west-shifted north + west-edge injection + NW corner injection
    //   NE = east-shifted north + east-edge injection + NE corner injection
    x0 = ((nbr_n & NOT_COL7_MASK) << 1)
       | ((tile_w & COL7_MASK) << 1)
       | ((tile_nw & BIT_R7_C7) >> 63);

    x1 = ((nbr_n & NOT_COL0_MASK) >> 1)
       | ((tile_e & COL0_MASK) << 15)
       | ((tile_ne & BIT_R7_C0) >> 49);

    const u64 p45 = x0 ^ x1;
    const u64 c45 = x0 & x1;

    x0 = ((nbr_s & NOT_COL7_MASK) << 1)
       | ((tile_w & COL7_MASK) >> 15)
       | ((tile_sw & BIT_R0_C7) << 49);

    x1 = ((nbr_s & NOT_COL0_MASK) >> 1)
       | ((tile_e & COL0_MASK) >> 1)
       | ((tile_se & BIT_R0_C0) << 63);

    const u64 p67 = x0 ^ x1;
    const u64 c67 = x0 & x1;

    // Last four directions -> partial count b2:b1:b0 (0..4 per cell).
    carry = p45 & p67;
    t = c45 ^ c67;
    const u64 b0 = p45 ^ p67;
    const u64 b1 = t ^ carry;
    const u64 b2 = (c45 & c67) | (carry & t);

    // Add the two 3-bit partial counts -> full 4-bit count count3:count2:count1:count0.
    carry = a0 & b0;
    t = a1 ^ b1;
    const u64 count0 = a0 ^ b0;
    const u64 count1 = t ^ carry;
    const u64 carry1 = (a1 & b1) | (carry & t);

    t = a2 ^ b2;
    const u64 count2 = t ^ carry1;
    const u64 count3 = (a2 & b2) | (carry1 & t);

    // Bit-sliced Life rule:
    //   count == 2 or 3  <=>  count1 == 1 and no higher count bits are set
    //   count == 3       <=>  count0 == 1
    //   count == 2       <=>  count0 == 0
    //
    // Therefore:
    //   next = (count == 3) | (current & (count == 2))
    //        = count1 & ~(count2 | count3) & (count0 | current)
    return count1 & ~(count2 | count3) & (count0 | tile_c);
}

__global__ __launch_bounds__(kThreadsPerBlock)
void game_of_life_kernel(
    const u64* __restrict__ input,
    u64* __restrict__ output,
    const u32 tiles_per_dim,
    const u32 tiles_mask,
    const u64 south_limit)
{
    const u64 idx =
        static_cast<u64>(blockIdx.x) * static_cast<u64>(kThreadsPerBlock) +
        static_cast<u64>(threadIdx.x);

    const u64 stride = static_cast<u64>(tiles_per_dim);
    const u32 lane = static_cast<u32>(threadIdx.x) & static_cast<u32>(kWarpSize - 1);

    // Out-of-grid tiles are treated as all-zero (dead).
    const bool has_n = idx >= stride;
    const bool has_s = idx < south_limit;

    const u64 tile_c = input[idx];
    const u64 tile_n = has_n ? input[idx - stride] : 0ULL;
    const u64 tile_s = has_s ? input[idx + stride] : 0ULL;

    // Fast horizontal neighbor exchange through the warp.
    // The problem constraints guarantee that a warp never crosses a tile-row boundary.
    u64 tile_w  = __shfl_up_sync  (kFullWarpMask, tile_c, 1, kWarpSize);
    u64 tile_e  = __shfl_down_sync(kFullWarpMask, tile_c, 1, kWarpSize);
    u64 tile_nw = __shfl_up_sync  (kFullWarpMask, tile_n, 1, kWarpSize);
    u64 tile_ne = __shfl_down_sync(kFullWarpMask, tile_n, 1, kWarpSize);
    u64 tile_sw = __shfl_up_sync  (kFullWarpMask, tile_s, 1, kWarpSize);
    u64 tile_se = __shfl_down_sync(kFullWarpMask, tile_s, 1, kWarpSize);

    // Only warp-edge lanes need true cross-warp loads.
    if (lane == 0u) {
        const bool has_w = (static_cast<u32>(idx) & tiles_mask) != 0u;
        if (has_w) {
            const u64 idx_left = idx - 1ULL;
            tile_w  = input[idx_left];
            tile_nw = has_n ? input[idx_left - stride] : 0ULL;
            tile_sw = has_s ? input[idx_left + stride] : 0ULL;
        } else {
            tile_w = 0ULL;
            tile_nw = 0ULL;
            tile_sw = 0ULL;
        }
    }

    if (lane == static_cast<u32>(kWarpSize - 1)) {
        const bool has_e = (static_cast<u32>(idx) & tiles_mask) != tiles_mask;
        if (has_e) {
            const u64 idx_right = idx + 1ULL;
            tile_e  = input[idx_right];
            tile_ne = has_n ? input[idx_right - stride] : 0ULL;
            tile_se = has_s ? input[idx_right + stride] : 0ULL;
        } else {
            tile_e = 0ULL;
            tile_ne = 0ULL;
            tile_se = 0ULL;
        }
    }

    output[idx] = step_tile_8x8(
        tile_c,
        tile_n, tile_s,
        tile_w, tile_e,
        tile_nw, tile_ne,
        tile_sw, tile_se);
}

}  // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions)
{
    // Enqueue exactly one thread per 8x8 tile on the default stream.
    // The caller is responsible for any host-device synchronization.
    const u32 tiles_per_dim = static_cast<u32>(grid_dimensions) >> 3;
    const u32 tiles_mask = tiles_per_dim - 1u;
    const u64 total_tiles = static_cast<u64>(tiles_per_dim) * static_cast<u64>(tiles_per_dim);
    const u64 south_limit = total_tiles - static_cast<u64>(tiles_per_dim);

    // Under the problem constraints, total_tiles is always a multiple of 256,
    // so we launch an exact number of threads and omit a bounds check in the kernel.
    const u32 blocks = static_cast<u32>(total_tiles / static_cast<u64>(kThreadsPerBlock));

    game_of_life_kernel<<<blocks, kThreadsPerBlock>>>(
        input,
        output,
        tiles_per_dim,
        tiles_mask,
        south_limit);
}

#include <cstdint>
#include <cuda_runtime.h>

namespace {

// Bit layout assumed inside each 8x8 tile word:
//
//   bit (row * 8 + col)  <=>  local cell (col, row)
//
// So each tile row is exactly one byte:
//   bits   0.. 7 -> row 0
//   bits   8..15 -> row 1
//   ...
//   bits  56..63 -> row 7
//
// The full board is a row-major array of these 8x8 tiles.
//
// Performance choices:
// - One thread updates one 8x8 tile entirely in registers.
// - No shared memory is used; the 3x3 tile neighborhood is tiny and hardware caches
//   handle the overlap well on modern data-center GPUs.
// - A single kernel is used with a fast interior path and a rare boundary path.
// - A 1D launch is used to avoid grid-y limits on very large boards. Because the tile
//   row width is a power of two, x = tile_idx & (stride - 1) is enough to recover the
//   tile x-coordinate without division.
// - kBlockSize is 128, matching the minimum legal tile-row width. Since every legal
//   tile-row width is a power of two >= 128, blocks never cross tile-row boundaries.

using u64 = std::uint64_t;

constexpr int kBlockShift = 7;
constexpr int kBlockSize  = 1 << kBlockShift;
static_assert((kBlockSize & 31) == 0, "Block size must be a whole number of warps.");

constexpr u64 kCol0    = 0x0101010101010101ULL; // column 0 in every row byte
constexpr u64 kCol7    = 0x8080808080808080ULL; // column 7 in every row byte
constexpr u64 kNotCol0 = 0xFEFEFEFEFEFEFEFEULL; // clear column 0 in every row byte
constexpr u64 kNotCol7 = 0x7F7F7F7F7F7F7F7FULL; // clear column 7 in every row byte
constexpr u64 kLowByteCol7 = 0x0000000000000080ULL; // bit 7 of the low byte

// Half adder for 64 independent 1-bit lanes packed into a 64-bit word.
__device__ __forceinline__ void half_add(u64 a, u64 b, u64& sum, u64& carry) {
    sum   = a ^ b;
    carry = a & b;
}

// Full adder for 64 independent 1-bit lanes packed into a 64-bit word.
// The compiler maps this very well to modern NVIDIA ternary-logic instructions.
__device__ __forceinline__ void full_add(u64 a, u64 b, u64 c, u64& sum, u64& carry) {
    const u64 ab = a ^ b;
    sum   = ab ^ c;
    carry = (a & b) | (ab & c);
}

// Evolve one 8x8 tile. The 3x3 neighborhood is passed as 9 tile words:
//
//   nw  n  ne
//    w  c   e
//   sw  s  se
//
// All neighbor generation and counting is fully bit-parallel across the 64 cells.
__device__ __forceinline__ u64 evolve_tile(
    u64 nw, u64 n, u64 ne,
    u64 w,  u64 c, u64 e,
    u64 sw, u64 s, u64 se)
{
    const u64 west_edge = w & kCol7;
    const u64 east_edge = e & kCol0;

    // Cardinal neighbors aligned to the destination cell positions.
    const u64 north = (c << 8) | (n >> 56);
    const u64 south = (c >> 8) | (s << 56);

    // Carry-save adder network for the 8 one-bit neighbor boards.
    // We only keep the count modulo 8 (ones/twos/fours). That is sufficient because
    // the true count range is 0..8, and the only truncated value is 8 -> 0 mod 8;
    // 8 is neither 2 nor 3, which are the only counts Conway's rules care about.
    u64 s0, c0;
    {
        const u64 east = ((c >> 1) & kNotCol7) | (east_edge << 7);
        full_add(north, south, east, s0, c0);
    }

    u64 s1, c1;
    {
        const u64 west       = ((c << 1) & kNotCol0) | (west_edge >> 7);
        const u64 north_east = ((north >> 1) & kNotCol7) | (east_edge << 15) | ((ne >> 49) & kLowByteCol7);
        const u64 north_west = ((north << 1) & kNotCol0) | (west_edge << 1) | (nw >> 63);
        full_add(west, north_east, north_west, s1, c1);
    }

    u64 s2, c2;
    {
        const u64 south_east = ((south >> 1) & kNotCol7) | (east_edge >> 1) | ((se & 1ULL) << 63);
        const u64 south_west = ((south << 1) & kNotCol0) | (west_edge >> 15) | ((sw & kLowByteCol7) << 49);
        full_add(south_east, south_west, s0, s2, c2);
    }

    u64 ones, carry_to_twos;
    half_add(s1, s2, ones, carry_to_twos);

    u64 twos_partial, carry_to_fours_a;
    full_add(c0, c1, c2, twos_partial, carry_to_fours_a);

    u64 twos, carry_to_fours_b;
    half_add(twos_partial, carry_to_twos, twos, carry_to_fours_b);

    const u64 fours = carry_to_fours_a ^ carry_to_fours_b;

    // Conway rule:
    //   next = (count == 3) | (alive & (count == 2))
    // With the bit-planes above this simplifies to:
    //   next = twos & ~fours & (ones | alive)
    return twos & ~fours & (ones | c);
}

__global__ __launch_bounds__(kBlockSize)
void game_of_life_kernel(
    const u64* __restrict__ input,
    u64* __restrict__ output,
    u64 stride,          // tiles per row = grid_dimensions / 8
    u64 x_mask,          // stride - 1, valid because stride is a power of two
    u64 last_row_start)  // first tile index of the last tile row
{
    // Exact launch shape: because stride is a power of two >= 128, the total tile count
    // is an exact multiple of kBlockSize, so no tail guard is needed.
    const u64 tile_idx =
        (static_cast<u64>(blockIdx.x) << kBlockShift) + static_cast<u64>(threadIdx.x);

    const u64 x = tile_idx & x_mask;

    const bool has_w = (x != 0ULL);
    const bool has_e = (x != x_mask);
    const bool has_n = (tile_idx >= stride);
    const bool has_s = (tile_idx < last_row_start);

    const u64 c = input[tile_idx];

    u64 nw, n, ne;
    u64 w,  e;
    u64 sw, s, se;

    // Fast path for the overwhelming majority of tiles: all 8 neighboring tiles exist.
    if (has_w && has_e && has_n && has_s) {
        const u64 north_idx = tile_idx - stride;
        const u64 south_idx = tile_idx + stride;

        nw = input[north_idx - 1];
        n  = input[north_idx];
        ne = input[north_idx + 1];

        w  = input[tile_idx - 1];
        e  = input[tile_idx + 1];

        sw = input[south_idx - 1];
        s  = input[south_idx];
        se = input[south_idx + 1];
    } else {
        // Boundary path: cells outside the grid are dead, so missing neighboring tiles
        // are simply injected as zero. No toroidal wrap-around.
        w = has_w ? input[tile_idx - 1] : 0ULL;
        e = has_e ? input[tile_idx + 1] : 0ULL;

        if (has_n) {
            const u64 north_idx = tile_idx - stride;
            n  = input[north_idx];
            nw = has_w ? input[north_idx - 1] : 0ULL;
            ne = has_e ? input[north_idx + 1] : 0ULL;
        } else {
            nw = 0ULL;
            n  = 0ULL;
            ne = 0ULL;
        }

        if (has_s) {
            const u64 south_idx = tile_idx + stride;
            s  = input[south_idx];
            sw = has_w ? input[south_idx - 1] : 0ULL;
            se = has_e ? input[south_idx + 1] : 0ULL;
        } else {
            sw = 0ULL;
            s  = 0ULL;
            se = 0ULL;
        }
    }

    output[tile_idx] = evolve_tile(nw, n, ne, w, c, e, sw, s, se);
}

} // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions) {
    // Per the problem statement:
    // - input/output are already device pointers allocated by cudaMalloc
    // - grid_dimensions is a power of two and > 512
    // - the caller handles any synchronization around this launch
    //
    // input and output are assumed to be distinct buffers (double-buffered simulation step).

    const u64 stride = static_cast<u64>(grid_dimensions) >> 3; // tiles per row
    const u64 num_tiles = stride * stride;
    const u64 x_mask = stride - 1;
    const u64 last_row_start = num_tiles - stride;

    // Exact because num_tiles is a power of two and kBlockSize == 128.
    const unsigned int grid_blocks = static_cast<unsigned int>(num_tiles >> kBlockShift);

    game_of_life_kernel<<<grid_blocks, kBlockSize>>>(input, output, stride, x_mask, last_row_start);
}

#include <cstdint>
#include <cuda_runtime.h>

// CUDA Game of Life step for an 8x8-tiled, bit-packed board.
//
// Encoding assumed by this implementation:
//   - Tiles are stored row-major in memory.
//   - Inside each 64-bit tile, bit (local_y * 8 + local_x) is the cell at
//     tile-local coordinates (local_x, local_y).
//   - Bit 0 is the tile-local top-left cell; increasing the bit index moves
//     right within a row, then down to the next row.
//
// This bit order is what makes the shift/mask logic below correct. If a caller
// uses a different intra-tile bit order, only the masks/shifts in evolve_tile()
// need to change; the kernel launch structure can stay the same.
//
// Performance strategy:
//   - One thread updates one 8x8 tile (64 cells at once).
//   - Each warp spans 32 consecutive tiles in one tile row.
//   - Every thread only loads its north/center/south tiles directly.
//   - West/east tiles and corner tiles are obtained mostly through warp shuffles;
//     only lane 0 and lane 31 issue the extra cross-warp loads.
//   - All 64 cells of a tile are evolved in parallel using SWAR / bit-sliced
//     arithmetic. There are no per-cell loops and no shared memory.
//
// The prompt guarantees:
//   - grid_dimensions is a power of 2
//   - grid_dimensions > 512
// Therefore:
//   - tiles_per_row = grid_dimensions / 8 is a power of 2 >= 64
//   - tiles_per_row is divisible by both 32 and 8
// So a 32x8 block tiles the domain exactly: no tail predicates, no partial warps.

namespace {

using u64 = std::uint64_t;

constexpr int kBlockXLog2 = 5;               // 32 tiles per warp in x
constexpr int kBlockYLog2 = 3;               // 8 warps per CTA in y
constexpr int kBlockX     = 1 << kBlockXLog2;
constexpr int kBlockY     = 1 << kBlockYLog2;
constexpr int kBlockThreads = kBlockX * kBlockY;
constexpr unsigned kFullWarpMask = 0xFFFFFFFFu;

static_assert(kBlockX == 32, "This kernel maps exactly one warp to one tile row.");

// Tile masks for the row-major, bit0=top-left 8x8 packing described above.
constexpr u64 kCol0Mask   = 0x0101010101010101ULL;
constexpr u64 kCol7Mask   = 0x8080808080808080ULL;
constexpr u64 kNoCol0Mask = 0xFEFEFEFEFEFEFEFEULL;
constexpr u64 kNoCol7Mask = 0x7F7F7F7F7F7F7F7FULL;

// Low-byte masks. These are used after extracting a tile edge row into the low byte.
constexpr u64 kRow0Mask   = 0x00000000000000FFULL;
constexpr u64 kRow0NoCol0 = 0x00000000000000FEULL;
constexpr u64 kRow0NoCol7 = 0x000000000000007FULL;
constexpr u64 kRow0Col7   = 0x0000000000000080ULL;

// High-position corner mask used directly on an unshifted neighbor tile.
constexpr u64 kRow7Col0   = 0x0100000000000000ULL;

__device__ __forceinline__ u64 ro_load(const u64* ptr) {
#if __CUDA_ARCH__ >= 350
    return __ldg(ptr);
#else
    return *ptr;
#endif
}

__device__ __forceinline__ u64 majority(u64 a, u64 b, u64 c) {
    // Per-bit majority: the carry of adding three 1-bit values.
    return (a & b) | (a & c) | (b & c);
}

__device__ __forceinline__ u64 evolve_tile(
    u64 center,
    u64 north,
    u64 south,
    u64 west,
    u64 east,
    u64 northwest,
    u64 northeast,
    u64 southwest,
    u64 southeast)
{
    // Reused masked versions. Precomputing these saves several repeated ANDs.
    const u64 center_no_col0 = center & kNoCol0Mask;
    const u64 center_no_col7 = center & kNoCol7Mask;
    const u64 east_col0      = east   & kCol0Mask;
    const u64 west_col7      = west   & kCol7Mask;

    // Extract the halo rows that are needed multiple times.
    const u64 north_row7 = north >> 56;          // north tile's bottom row -> low byte
    const u64 south_row0 = south & kRow0Mask;    // south tile's top row    -> low byte

    // Build the eight directional bitboards.
    // For each direction, a set bit means "the neighbor in that direction is alive"
    // for the corresponding cell position inside the current 8x8 tile.
    const u64 dir_n  = (center << 8) | north_row7;
    const u64 dir_s  = (center >> 8) | (south_row0 << 56);
    const u64 dir_e  = (center_no_col0 >> 1) | (east_col0 << 7);
    const u64 dir_w  = (center_no_col7 << 1) | (west_col7 >> 7);

    const u64 dir_ne = (center_no_col0 << 7)
                     | (north_row7 >> 1)
                     | (east_col0 << 15)
                     | ((northeast & kRow7Col0) >> 49);

    const u64 dir_nw = (center_no_col7 << 9)
                     | ((north_row7 & kRow0NoCol7) << 1)
                     | (west_col7 << 1)
                     | (northwest >> 63);

    const u64 dir_se = (center_no_col0 >> 9)
                     | ((south_row0 & kRow0NoCol0) << 55)
                     | (east_col0 >> 1)
                     | (southeast << 63);

    const u64 dir_sw = (center_no_col7 >> 7)
                     | ((south_row0 & kRow0NoCol7) << 57)
                     | (west_col7 >> 15)
                     | ((southwest & kRow0Col7) << 49);

    // Compress N/S/E/W into a 3-bit per-cell count (count_a2:count_a1:count_a0).
    const u64 ns_xor  = dir_n ^ dir_s;
    const u64 ns_and  = dir_n & dir_s;
    const u64 ew_xor  = dir_e ^ dir_w;
    const u64 ew_and  = dir_e & dir_w;

    const u64 count_a0 = ns_xor ^ ew_xor;
    const u64 carry_a  = ns_xor & ew_xor;
    const u64 count_a1 = ns_and ^ ew_and ^ carry_a;
    const u64 count_a2 = majority(ns_and, ew_and, carry_a);

    // Compress NE/NW/SE/SW into another 3-bit per-cell count (count_b2:count_b1:count_b0).
    const u64 nwne_xor = dir_ne ^ dir_nw;
    const u64 nwne_and = dir_ne & dir_nw;
    const u64 swse_xor = dir_se ^ dir_sw;
    const u64 swse_and = dir_se & dir_sw;

    const u64 count_b0 = nwne_xor ^ swse_xor;
    const u64 carry_b  = nwne_xor & swse_xor;
    const u64 count_b1 = nwne_and ^ swse_and ^ carry_b;
    const u64 count_b2 = majority(nwne_and, swse_and, carry_b);

    // Add the two 3-bit counters to obtain the full 0..8 neighbor count.
    const u64 count_bit0 = count_a0 ^ count_b0;
    const u64 carry_1    = count_a0 & count_b0;

    const u64 sum_1      = count_a1 ^ count_b1;
    const u64 count_bit1 = sum_1 ^ carry_1;
    const u64 carry_2    = majority(count_a1, count_b1, carry_1);

    const u64 sum_2      = count_a2 ^ count_b2;
    const u64 count_bit2 = sum_2 ^ carry_2;
    const u64 count_bit3 = majority(count_a2, count_b2, carry_2);

    // Conway rule in binary form:
    //   next = (count == 3) | (alive & (count == 2))
    //
    // For counts 0..8:
    //   count in {2,3} iff count_bit1 = 1 and count_bit2 = count_bit3 = 0.
    //   count_bit0 distinguishes 2 from 3.
    //
    // Therefore:
    //   next = !count_bit2 & !count_bit3 & count_bit1 & (alive | count_bit0)
    return (~(count_bit2 | count_bit3)) & count_bit1 & (center | count_bit0);
}

__global__ __launch_bounds__(kBlockThreads, 2)
void game_of_life_step_kernel(
    const u64* __restrict__ input,
    u64* __restrict__ output,
    int tiles_per_row)
{
    // Because blockDim.x == 32, each warp corresponds to a single tile row
    // inside the CTA, which makes left/right neighbor exchange a plain shuffle.
    const unsigned lane = threadIdx.x;
    const int x = (static_cast<int>(blockIdx.x) << kBlockXLog2) + static_cast<int>(lane);
    const int y = (static_cast<int>(blockIdx.y) << kBlockYLog2) + static_cast<int>(threadIdx.y);
    const int idx = y * tiles_per_row + x;

    // Grid boundary conditions: everything outside the board is dead.
    const bool has_n = (y != 0);
    const bool has_s = (y + 1 != tiles_per_row);
    const bool has_w = (x != 0);
    const bool has_e = (x + 1 != tiles_per_row);

    const int north_idx = idx - tiles_per_row;
    const int south_idx = idx + tiles_per_row;

    // Mandatory loads: north / center / south tiles for this x position.
    u64 north  = has_n ? ro_load(input + north_idx) : 0ULL;
    u64 center = ro_load(input + idx);
    u64 south  = has_s ? ro_load(input + south_idx) : 0ULL;

    // Neighbor tiles inside the same warp are exchanged through shuffles.
    u64 north_w = __shfl_up_sync(kFullWarpMask, north, 1);
    u64 center_w = __shfl_up_sync(kFullWarpMask, center, 1);
    u64 south_w = __shfl_up_sync(kFullWarpMask, south, 1);

    u64 north_e = __shfl_down_sync(kFullWarpMask, north, 1);
    u64 center_e = __shfl_down_sync(kFullWarpMask, center, 1);
    u64 south_e = __shfl_down_sync(kFullWarpMask, south, 1);

    // Warp-edge lanes need explicit cross-warp loads (or zeros at the true grid edge).
    if (lane == 0) {
        north_w  = (has_w && has_n) ? ro_load(input + north_idx - 1) : 0ULL;
        center_w = has_w            ? ro_load(input + idx - 1)       : 0ULL;
        south_w  = (has_w && has_s) ? ro_load(input + south_idx - 1) : 0ULL;
    }

    if (lane == kBlockX - 1) {
        north_e  = (has_e && has_n) ? ro_load(input + north_idx + 1) : 0ULL;
        center_e = has_e            ? ro_load(input + idx + 1)       : 0ULL;
        south_e  = (has_e && has_s) ? ro_load(input + south_idx + 1) : 0ULL;
    }

    output[idx] = evolve_tile(
        center,
        north,
        south,
        center_w,
        center_e,
        north_w,
        north_e,
        south_w,
        south_e);
}

} // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions) {
    // One word stores one 8x8 tile, so the number of tiles per side is / 8.
    // The problem constraints make this an exact power-of-two division.
    const int tiles_per_row = grid_dimensions >> 3;

    // Exact tiling of the tile-grid:
    //   - x: 32 tiles per block (one warp-wide tile row)
    //   - y:  8 tile rows per block
    // No host-device synchronization is performed here; the caller owns that.
    const dim3 block(kBlockX, kBlockY, 1);
    const dim3 grid(
        static_cast<unsigned int>(tiles_per_row >> kBlockXLog2),
        static_cast<unsigned int>(tiles_per_row >> kBlockYLog2),
        1u);

    // Input and output are expected to be distinct device buffers (standard ping-pong step).
    game_of_life_step_kernel<<<grid, block>>>(input, output, tiles_per_row);
}

#include <cstdint>
#include <cuda_runtime.h>

/*
  High-throughput Conway step for the exact packed layout described in the prompt.

  Assumed memory layout (the natural interpretation of "one uint64_t stores one 8x8 tile"):
    - Tiles are stored in row-major order across the whole grid.
    - Inside each 64-bit tile, bit (8 * local_y + local_x) is the cell at (local_y, local_x).
    - local_x == 0 is the least-significant bit of each byte, local_x == 7 the most-significant.

  Design choices tuned for modern data-center GPUs (A100/H100 class):
    - One thread updates one 8x8 tile, i.e. 64 cells at once in pure bit-parallel form.
    - blockDim.x is fixed to 32 so each warp spans 32 consecutive tiles of one tile row.
      West/east neighbor tiles are therefore exchanged with warp shuffles instead of extra
      global loads; each thread only loads its N/C/S tiles from memory, plus two boundary
      threads per warp perform the missing edge loads.
    - No shared memory / texture memory: for this representation they add complexity without
      helping enough; the reduced load count plus normal caches are sufficient.
    - Neighbor counts are accumulated with a SWAR half-adder tree over eight 64-bit neighbor
      bit-planes. Only the low three count bits are required:
        count == bit0 + 2*bit1 + 4*bit2   (mod 8)
      The only discarded overflow case is count==8 -> 0 mod 8, which is harmless because
      Conway's rules only care about counts 2 and 3.
    - Input and output are assumed to be distinct ping-pong buffers.
*/

namespace {

using u64 = std::uint64_t;

constexpr int kTileShift = 3;   // 8x8 tile
constexpr int kBlockX    = 32;  // exactly one warp in x
constexpr int kSmallBlockY = 4; // keeps enough blocks for the smallest legal grid (1024x1024)
constexpr int kLargeBlockY = 8; // slightly lower launch overhead for larger grids

static_assert(kBlockX == 32, "This kernel relies on one warp spanning exactly one tile stripe.");

constexpr u64 kCol0Mask    = 0x0101010101010101ULL; // local_x == 0 in every row byte
constexpr u64 kCol7Mask    = 0x8080808080808080ULL; // local_x == 7 in every row byte
constexpr u64 kNotCol0Mask = 0xFEFEFEFEFEFEFEFEULL;
constexpr u64 kNotCol7Mask = 0x7F7F7F7F7F7F7F7FULL;

__device__ __forceinline__ u64 shfl_up_1(const u64 v) {
    return static_cast<u64>(
        __shfl_up_sync(0xFFFFFFFFu, static_cast<unsigned long long>(v), 1, 32)
    );
}

__device__ __forceinline__ u64 shfl_down_1(const u64 v) {
    return static_cast<u64>(
        __shfl_down_sync(0xFFFFFFFFu, static_cast<unsigned long long>(v), 1, 32)
    );
}

__device__ __forceinline__ void half_add(const u64 a, const u64 b, u64& sum, u64& carry) {
    sum   = a ^ b;
    carry = a & b;
}

__device__ __forceinline__ u64 majority3(const u64 a, const u64 b, const u64 c) {
    // 3-input majority; modern compilers map this kind of boolean expression to LOP3.
    return (a & b) | (c & (a | b));
}

template <int BLOCK_Y>
__global__ __launch_bounds__(kBlockX * BLOCK_Y)
void game_of_life_kernel(const u64* __restrict__ input,
                         u64* __restrict__ output,
                         int tiles_per_dim) {
    static_assert(BLOCK_Y == kSmallBlockY || BLOCK_Y == kLargeBlockY,
                  "Only tuned block heights are supported.");

    const int tx = static_cast<int>(blockIdx.x * kBlockX + threadIdx.x);
    const int ty = static_cast<int>(blockIdx.y * BLOCK_Y + threadIdx.y);
    const int idx = ty * tiles_per_dim + tx;

    const int last_tile = tiles_per_dim - 1;
    const bool has_n = (ty != 0);
    const bool has_s = (ty != last_tile);
    const bool has_w = (tx != 0);
    const bool has_e = (tx != last_tile);

    const unsigned lane = threadIdx.x;

    // Center column of the 3x3 tile neighborhood. Top/bottom boundaries are zeroed
    // because cells outside the grid are defined to be dead.
    const u64 c = input[idx];
    const u64 n = has_n ? input[idx - tiles_per_dim] : 0ULL;
    const u64 s = has_s ? input[idx + tiles_per_dim] : 0ULL;

    // Warp-local west/east tiles. Because blockDim.x == 32, each warp is exactly one
    // horizontal tile stripe. Interior lanes get W/E from shuffle; lane 0 / 31 patch
    // the missing values with a single extra global load each.
    u64 c_w = shfl_up_1(c);
    u64 c_e = shfl_down_1(c);
    u64 n_w = shfl_up_1(n);
    u64 n_e = shfl_down_1(n);
    u64 s_w = shfl_up_1(s);
    u64 s_e = shfl_down_1(s);

    if (lane == 0u) {
        c_w = has_w ? input[idx - 1] : 0ULL;
        n_w = (has_w && has_n) ? input[idx - tiles_per_dim - 1] : 0ULL;
        s_w = (has_w && has_s) ? input[idx + tiles_per_dim - 1] : 0ULL;
    }
    if (lane == 31u) {
        c_e = has_e ? input[idx + 1] : 0ULL;
        n_e = (has_e && has_n) ? input[idx - tiles_per_dim + 1] : 0ULL;
        s_e = (has_e && has_s) ? input[idx + tiles_per_dim + 1] : 0ULL;
    }

    // Align the eight neighbor directions to the current tile's 64 bit positions.
    //
    // north/south:
    //   shift by 8 bits (one row) and inject the bordering row from the adjacent tile.
    //
    // west/east:
    //   shift within each byte (one column) while masking row wrap, and inject the
    //   bordering column from the adjacent tile.
    //
    // diagonals:
    //   derived from aligned north/south plus the missing border column coming from the
    //   west/east or diagonal tiles.
    const u64 north = (c << 8) | (n >> 56);
    const u64 south = (c >> 8) | (s << 56);

    // Pair 0: north + south.
    u64 lo0, hi0;
    half_add(north, south, lo0, hi0);

    const u64 cw7 = c_w & kCol7Mask;
    const u64 ce0 = c_e & kCol0Mask;

    // Pair 1: west + east.
    u64 lo1, hi1;
    {
        const u64 west = ((c & kNotCol7Mask) << 1) | (cw7 >> 7);
        const u64 east = ((c & kNotCol0Mask) >> 1) | (ce0 << 7);
        half_add(west, east, lo1, hi1);
    }

    const u64 north_l = (north & kNotCol7Mask) << 1; // NW internal part
    const u64 north_r = (north & kNotCol0Mask) >> 1; // NE internal part
    const u64 south_l = (south & kNotCol7Mask) << 1; // SW internal part
    const u64 south_r = (south & kNotCol0Mask) >> 1; // SE internal part

    // Pair 2: northwest + northeast.
    u64 lo2, hi2;
    {
        const u64 northwest = north_l | (cw7 << 1) | ((n_w & kCol7Mask) >> 63);
        const u64 northeast = north_r | (ce0 << 15) | ((n_e & kCol0Mask) >> 49);
        half_add(northwest, northeast, lo2, hi2);
    }

    // Pair 3: southwest + southeast.
    u64 lo3, hi3;
    {
        const u64 southwest = south_l | (cw7 >> 15) | ((s_w & kCol7Mask) << 49);
        const u64 southeast = south_r | (ce0 >> 1) | ((s_e & kCol0Mask) << 63);
        half_add(southwest, southeast, lo3, hi3);
    }

    // Sum the four 2-bit partial sums:
    //   lo* are the weight-1 bits, hi* are the weight-2 bits.
    //
    // Final count bits are:
    //   count = count0 + 2*count1 + 4*count2   (mod 8)
    //
    // The discarded bit-3 overflow only represents count==8, which is irrelevant for
    // Conway's rule evaluation because only counts 2 and 3 can produce a live output.
    u64 s01, c01;
    u64 s23, c23;
    half_add(lo0, lo1, s01, c01);
    half_add(lo2, lo3, s23, c23);

    const u64 count0 = s01 ^ s23;
    const u64 carry0 = s01 & s23;
    const u64 mid1   = carry0 ^ c01 ^ c23;
    const u64 mid2   = majority3(carry0, c01, c23);

    u64 t01, u01;
    u64 t23, u23;
    half_add(hi0, hi1, t01, u01);
    half_add(hi2, hi3, t23, u23);

    const u64 q0 = t01 ^ t23;
    const u64 q1 = (t01 & t23) ^ u01 ^ u23;

    const u64 count1 = mid1 ^ q0;
    const u64 count2 = mid2 ^ q1 ^ (mid1 & q0);

    // Conway's rule in bit-sliced form:
    //   next = (count == 3) | (current & (count == 2))
    //
    // Using the count bit-planes:
    //   count==2 or 3  <=>  count1==1 and count2==0
    //   count==3       <=>  above and count0==1
    //
    // So:
    //   next = (count1 & ~count2) & (count0 | current)
    const u64 two_or_three = count1 & ~count2;
    output[idx] = two_or_three & (count0 | c);
}

template <int BLOCK_Y>
inline void launch_game_of_life_kernel(const u64* input, u64* output, int tiles_per_dim) {
    const dim3 block(kBlockX, BLOCK_Y, 1);
    const dim3 grid(
        static_cast<unsigned int>(tiles_per_dim / kBlockX),
        static_cast<unsigned int>(tiles_per_dim / BLOCK_Y),
        1
    );
    game_of_life_kernel<BLOCK_Y><<<grid, block>>>(input, output, tiles_per_dim);
}

} // namespace

void run_game_of_life(const std::uint64_t* input,
                      std::uint64_t* output,
                      int grid_dimensions) {
    // The prompt guarantees:
    //   - square grid
    //   - power-of-two dimensions
    //   - grid_dimensions > 512
    //
    // Therefore tiles_per_dim = grid_dimensions / 8 is also a power of two and is
    // always divisible by both 32 and the chosen BLOCK_Y, so the launch needs no tail
    // predicates and the kernel contains no output bounds checks.
    const int tiles_per_dim = grid_dimensions >> kTileShift;

    // Smallest legal grid is 1024x1024 => 128x128 tiles.
    // With BLOCK_Y=8 that would be only 64 blocks total, which underutilizes A100/H100.
    // Use a 4-row block there; otherwise use 8-row blocks to slightly reduce launch and
    // scheduling overhead.
    if (tiles_per_dim <= 128) {
        launch_game_of_life_kernel<kSmallBlockY>(input, output, tiles_per_dim);
    } else {
        launch_game_of_life_kernel<kLargeBlockY>(input, output, tiles_per_dim);
    }

    // Intentionally no synchronization and no error checking here:
    // the caller is responsible for synchronization, and avoiding extra host overhead
    // keeps the step launch as lean as possible.
}

#include <cstdint>
#include <cuda_runtime.h>

// High-throughput one-step Conway's Game of Life for a square, bit-packed board.
//
// Layout:
// - The board is stored row-major.
// - Each 64-bit word stores 64 consecutive cells from one row.
// - Bit i in a word corresponds to x = word_base + i.
// - Bit value 1 means alive, 0 means dead.
//
// Mapping:
// - One CUDA thread updates one 64-bit word, so no atomics are required.
// - The kernel is intentionally register-only plus warp shuffles:
//   shared memory is unnecessary here and would only add complexity.
//
// Boundary handling:
// - Cells outside the board are dead.
// - For bit 0 and bit 63, horizontal neighbors may come from the left/right words of
//   the same row, and likewise for the rows above and below.
// - The west/east alignment helpers below import those cross-word boundary bits.

namespace {
using u64 = std::uint64_t;

constexpr int kBlockSize = 256;
constexpr unsigned int kFullWarpMask = 0xFFFFFFFFu;

static_assert((kBlockSize % 32) == 0, "kBlockSize must be a multiple of the warp size.");

// 3-input majority. On modern NVIDIA GPUs this boolean pattern maps cleanly to LOP3.
__device__ __forceinline__ u64 majority3_u64(const u64 a, const u64 b, const u64 c) {
    return (a & b) | (c & (a | b));
}

// 64-bit warp shuffles. The explicit cast keeps the overload selection unambiguous.
__device__ __forceinline__ u64 shfl_up_u64(const u64 v, const unsigned int delta) {
    return static_cast<u64>(
        __shfl_up_sync(kFullWarpMask, static_cast<unsigned long long>(v), delta));
}

__device__ __forceinline__ u64 shfl_down_u64(const u64 v, const unsigned int delta) {
    return static_cast<u64>(
        __shfl_down_sync(kFullWarpMask, static_cast<unsigned long long>(v), delta));
}

// Bit i in the result is the west neighbor of cell i.
// Since bit 0 is the leftmost cell within the 64-cell span, west is a logical left shift.
// The new bit 0 comes from bit 63 of the word immediately to the left.
__device__ __forceinline__ u64 west_aligned(const u64 word, const u64 left_word) {
    return (word << 1) | (left_word >> 63);
}

// Bit i in the result is the east neighbor of cell i.
// East is a logical right shift, with the new bit 63 imported from bit 0 of the word
// immediately to the right.
__device__ __forceinline__ u64 east_aligned(const u64 word, const u64 right_word) {
    return (word >> 1) | (right_word << 63);
}

__global__ __launch_bounds__(kBlockSize)
void game_of_life_step_kernel(const u64* __restrict__ input,
                              u64* __restrict__ output,
                              const u64 total_words,
                              const unsigned int words_per_row) {
    // Linear indexing avoids 2D-grid limits for very large boards and avoids idle threads
    // when a row contains only a small number of 64-bit words.
    const u64 idx = static_cast<u64>(blockIdx.x) * static_cast<u64>(kBlockSize) + threadIdx.x;
    const u64 stride = static_cast<u64>(words_per_row);

    // Because words_per_row is a power of two, x = idx % words_per_row is just a mask.
    // Using x rather than lane id for row-edge tests also handles the smallest valid board
    // (1024x1024, 16 words per row), where one warp spans two rows.
    const unsigned int row_mask = words_per_row - 1u;
    const unsigned int x = static_cast<unsigned int>(idx) & row_mask;
    const unsigned int lane = threadIdx.x & 31u;

    const bool at_row_start = (x == 0u);
    const bool at_row_end = (x == row_mask);
    const bool has_north = (idx >= stride);
    const bool has_south = (idx < (total_words - stride));

    // Outside-of-grid words are treated as zero, exactly matching the problem statement.
    //
    // Each thread loads only the vertically aligned words:
    //   north/current/south at the same x position.
    // Horizontal neighbor words are recovered via warp shuffles. Only warp-edge lanes that
    // are not also row edges need a fallback global load.
    const u64 north = has_north ? input[idx - stride] : 0ull;
    const u64 alive = input[idx];
    const u64 south = has_south ? input[idx + stride] : 0ull;

    const u64 north_from_prev_lane = shfl_up_u64(north, 1);
    const u64 north_from_next_lane = shfl_down_u64(north, 1);
    const u64 alive_from_prev_lane = shfl_up_u64(alive, 1);
    const u64 alive_from_next_lane = shfl_down_u64(alive, 1);
    const u64 south_from_prev_lane = shfl_up_u64(south, 1);
    const u64 south_from_next_lane = shfl_down_u64(south, 1);

    u64 north_left = 0ull;
    u64 north_right = 0ull;
    u64 alive_left = 0ull;
    u64 alive_right = 0ull;
    u64 south_left = 0ull;
    u64 south_right = 0ull;

    if (!at_row_start) {
        north_left = (lane != 0u)
                         ? north_from_prev_lane
                         : (has_north ? input[idx - stride - 1ull] : 0ull);
        alive_left = (lane != 0u) ? alive_from_prev_lane : input[idx - 1ull];
        south_left = (lane != 0u)
                         ? south_from_prev_lane
                         : (has_south ? input[idx + stride - 1ull] : 0ull);
    }

    if (!at_row_end) {
        north_right = (lane != 31u)
                          ? north_from_next_lane
                          : (has_north ? input[idx - stride + 1ull] : 0ull);
        alive_right = (lane != 31u) ? alive_from_next_lane : input[idx + 1ull];
        south_right = (lane != 31u)
                          ? south_from_next_lane
                          : (has_south ? input[idx + stride + 1ull] : 0ull);
    }

    // Build the eight aligned neighbor bitboards for this word:
    //
    //   north_west  north  north_east
    //   west               east
    //   south_west  south  south_east
    //
    // Bit i in each mask corresponds to the neighbor of cell i.
    const u64 north_west = west_aligned(north, north_left);
    const u64 north_east = east_aligned(north, north_right);
    const u64 west = west_aligned(alive, alive_left);
    const u64 east = east_aligned(alive, alive_right);
    const u64 south_west = west_aligned(south, south_left);
    const u64 south_east = east_aligned(south, south_right);

    // Bit-sliced population count over all 64 cells in parallel.
    //
    // First compress each row neighborhood into low/high bit planes:
    // - top_lo/top_hi encode (north_west + north + north_east)
    // - mid_lo/mid_hi encode (west + east)
    // - bot_lo/bot_hi encode (south_west + south + south_east)
    //
    // For a 3-input sum, parity is the low bit and majority is the high bit:
    //   a + b + c = (a ^ b ^ c) + 2*majority(a,b,c)
    const u64 top_lo = north_west ^ north ^ north_east;
    const u64 top_hi = majority3_u64(north_west, north, north_east);

    const u64 mid_lo = west ^ east;
    const u64 mid_hi = west & east;

    const u64 bot_lo = south_west ^ south ^ south_east;
    const u64 bot_hi = majority3_u64(south_west, south, south_east);

    // Sum the three low planes:
    //   top_lo + mid_lo + bot_lo = count_bit0 + 2*carry_to_twos
    const u64 count_bit0 = top_lo ^ mid_lo ^ bot_lo;
    const u64 carry_to_twos = majority3_u64(top_lo, mid_lo, bot_lo);

    // Now sum the four weight-2 contributors:
    //   carry_to_twos + top_hi + mid_hi + bot_hi
    //
    // This yields the upper three bits of the full 4-bit neighbor count:
    //   count = count_bit0 + 2*count_bit1 + 4*count_bit2 + 8*count_bit3
    const u64 pair_lo0 = carry_to_twos ^ top_hi;
    const u64 pair_hi0 = carry_to_twos & top_hi;
    const u64 pair_lo1 = mid_hi ^ bot_hi;
    const u64 pair_hi1 = mid_hi & bot_hi;

    const u64 count_bit1 = pair_lo0 ^ pair_lo1;
    const u64 carry_to_fours = pair_lo0 & pair_lo1;
    const u64 count_bit2 = carry_to_fours ^ pair_hi0 ^ pair_hi1;
    const u64 count_bit3 = majority3_u64(carry_to_fours, pair_hi0, pair_hi1);

    // Game of Life rule:
    //   next = (count == 3) | (alive & count == 2)
    //
    // With count bits c3:c2:c1:c0 this simplifies to:
    //   next = ~(c2 | c3) & c1 & (c0 | alive)
    const u64 count_is_2_or_3 = (~(count_bit2 | count_bit3)) & count_bit1;
    output[idx] = count_is_2_or_3 & (count_bit0 | alive);
}

}  // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions) {
    // The intended usage is a ping-pong update, so input and output are treated as
    // non-overlapping device buffers.
    //
    // words_per_row = grid_dimensions / 64
    // total_words   = grid_dimensions * words_per_row = grid_dimensions^2 / 64
    //
    // Because grid_dimensions is guaranteed to be a power of two > 512:
    // - words_per_row is also a power of two,
    // - total_words is a power of two,
    // - total_words is therefore divisible by the fixed 256-thread block size.
    //
    // That exact divisibility is why the kernel can use full-warp shuffles with no
    // tail handling and no bounds check on idx.
    const unsigned int words_per_row = static_cast<unsigned int>(grid_dimensions) >> 6;
    const std::uint64_t total_words =
        static_cast<std::uint64_t>(grid_dimensions) * static_cast<std::uint64_t>(words_per_row);
    const unsigned int blocks = static_cast<unsigned int>(total_words / kBlockSize);

    // No synchronization or error polling here by design; the caller owns stream ordering
    // and any required synchronization.
    game_of_life_step_kernel<<<blocks, kBlockSize>>>(input, output, total_words, words_per_row);
}

#include <cuda_runtime.h>
#include <cstdint>

using u64 = std::uint64_t;

namespace
{
/*
    Performance-oriented Conway's Game of Life on a bit-packed grid.

    Key design choices:
    - One CUDA thread computes exactly one 64-bit word => 64 cells per thread.
    - No shared memory: for this access pattern on modern data-center GPUs,
      read-only global loads plus warp shuffles are simpler and typically faster.
    - The three center words needed by each thread (north/current/south) are loaded
      from global memory once. Left/right neighboring words are obtained mostly via
      warp shuffles because adjacent threads own adjacent words.
    - Neighbor counts are accumulated in a bit-sliced *saturating* counter:
          ones  : exact bit 0 of the count while count < 4
          twos  : exact bit 1 of the count while count < 4
          ge4   : "count >= 4" saturation flag
      This is sufficient because Game of Life only distinguishes:
          count == 2, count == 3, and everything else.
    - Bit 0 / bit 63 cross-word handling is performed by:
          left-aligned  neighbors: (word << 1) | (left_word  >> 63)
          right-aligned neighbors: (word >> 1) | (right_word << 63)
      This exactly covers the required upper-left / left / lower-left and
      upper-right / right / lower-right cases.
*/

constexpr int kBlockSize = 256;
constexpr unsigned int kFullWarpMask = 0xFFFFFFFFu;

static_assert((kBlockSize % 32) == 0, "Block size must be a whole number of warps.");

/* Read-only load helper. The input grid is immutable for the duration of the step. */
__device__ __forceinline__ u64 load_ro(const u64* ptr)
{
    return __ldg(ptr);
}

/* Warp-local access to the previous / next thread's word. */
__device__ __forceinline__ u64 shfl_up_u64(const u64 value)
{
    return __shfl_up_sync(kFullWarpMask, value, 1);
}

__device__ __forceinline__ u64 shfl_down_u64(const u64 value)
{
    return __shfl_down_sync(kFullWarpMask, value, 1);
}

/*
    Add one aligned neighbor bitboard into the saturated bit-sliced counter.

    Per bit position, the state encoding is:
        000 -> 0 neighbors
        001 -> 1 neighbor
        010 -> 2 neighbors
        011 -> 3 neighbors
        100 -> 4 or more neighbors (saturated)

    Transition when x = 1:
        000 -> 001
        001 -> 010
        010 -> 011
        011 -> 100
        100 -> 100
*/
__device__ __forceinline__ void add_neighbor_saturated(
    const u64 x,
    u64& ones,
    u64& twos,
    u64& ge4)
{
    const u64 active = x & ~ge4;    // once count >= 4, further increments are irrelevant
    const u64 carry  = ones & active;

    ge4  |= twos & carry;           // only the 3 -> 4 transition sets the saturation flag
    ones ^= active;
    twos ^= carry;
}

__global__ __launch_bounds__(kBlockSize)
void game_of_life_step_kernel(
    const u64* __restrict__ input,
    u64* __restrict__ output,
    const unsigned int words_per_row,
    const unsigned int words_per_row_mask,
    const u64 last_row_start)
{
    /*
        Exact-launch kernel:
        - The host launches exactly one thread per packed 64-bit word.
        - Therefore there is no tail check here.

        Indexing notes:
        - words_per_row is a power of two, so x can be computed with a mask.
        - total word count can exceed 2^31 on large GPUs / grids, so indices are 64-bit.
    */
    const u64 row_stride = static_cast<u64>(words_per_row);
    const u64 idx =
        static_cast<u64>(blockIdx.x) * static_cast<u64>(kBlockSize) +
        static_cast<u64>(threadIdx.x);

    const unsigned int lane = threadIdx.x & 31u;
    const unsigned int x = static_cast<unsigned int>(idx & static_cast<u64>(words_per_row_mask));

    const bool has_up    = idx >= row_stride;
    const bool has_down  = idx < last_row_start;
    const bool has_left  = x != 0u;
    const bool has_right = x != words_per_row_mask;

    /*
        These are only dereferenced when the corresponding boundary predicate is true.
        north_idx intentionally wraps on the first row, but is never used there.
    */
    const u64 north_idx = idx - row_stride;
    const u64 south_idx = idx + row_stride;

    /* Center words for north/current/south rows. Missing rows are treated as all-dead. */
    const u64 current = load_ro(input + idx);
    const u64 north   = has_up   ? load_ro(input + north_idx) : u64{0};
    const u64 south   = has_down ? load_ro(input + south_idx) : u64{0};

    /* Saturated bit-sliced neighbor counter. */
    u64 ones = 0;
    u64 twos = 0;
    u64 ge4  = 0;

    /*
        North row contribution.
        The shuffles are unconditional so every lane in the warp executes the same warp
        intrinsic. x/has_left/has_right then decide whether the shuffled value is valid
        for this thread's row segment. This remains correct even for the smallest allowed
        case (words_per_row == 16), where a warp spans two rows.
    */
    const u64 north_from_left  = shfl_up_u64(north);
    const u64 north_from_right = shfl_down_u64(north);

    if (has_up)
    {
        u64 north_left_word  = 0;
        u64 north_right_word = 0;

        if (has_left)
        {
            north_left_word = (lane != 0u) ? north_from_left
                                           : load_ro(input + north_idx - 1u);
        }

        if (has_right)
        {
            north_right_word = (lane != 31u) ? north_from_right
                                             : load_ro(input + north_idx + 1u);
        }

        add_neighbor_saturated((north << 1) | (north_left_word >> 63), ones, twos, ge4);
        add_neighbor_saturated(north,                                      ones, twos, ge4);
        add_neighbor_saturated((north >> 1) | (north_right_word << 63),   ones, twos, ge4);
    }

    /* Current row contribution: only left/right neighbors, never the cell itself. */
    const u64 current_from_left  = shfl_up_u64(current);
    const u64 current_from_right = shfl_down_u64(current);

    u64 current_left_word  = 0;
    u64 current_right_word = 0;

    if (has_left)
    {
        current_left_word = (lane != 0u) ? current_from_left
                                         : load_ro(input + idx - 1u);
    }

    if (has_right)
    {
        current_right_word = (lane != 31u) ? current_from_right
                                           : load_ro(input + idx + 1u);
    }

    add_neighbor_saturated((current << 1) | (current_left_word >> 63),  ones, twos, ge4);
    add_neighbor_saturated((current >> 1) | (current_right_word << 63), ones, twos, ge4);

    /* South row contribution. */
    const u64 south_from_left  = shfl_up_u64(south);
    const u64 south_from_right = shfl_down_u64(south);

    if (has_down)
    {
        u64 south_left_word  = 0;
        u64 south_right_word = 0;

        if (has_left)
        {
            south_left_word = (lane != 0u) ? south_from_left
                                           : load_ro(input + south_idx - 1u);
        }

        if (has_right)
        {
            south_right_word = (lane != 31u) ? south_from_right
                                             : load_ro(input + south_idx + 1u);
        }

        add_neighbor_saturated((south << 1) | (south_left_word >> 63), ones, twos, ge4);
        add_neighbor_saturated(south,                                    ones, twos, ge4);
        add_neighbor_saturated((south >> 1) | (south_right_word << 63), ones, twos, ge4);
    }

    /*
        Game of Life rule:
            next = (neighbors == 3) || (alive && neighbors == 2)

        With the saturated counter:
            neighbors == 2  => twos=1, ones=0, ge4=0
            neighbors == 3  => twos=1, ones=1, ge4=0

        Therefore:
            next = twos & ~ge4 & (ones | alive)
    */
    output[idx] = twos & ~ge4 & (ones | current);
}

} // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions)
{
    /*
        The caller provides device pointers allocated by cudaMalloc and handles any
        synchronization. This function only launches the kernel.

        The implementation assumes the standard ping-pong update pattern:
        input and output should be distinct buffers.
    */

    const unsigned int words_per_row = static_cast<unsigned int>(grid_dimensions) >> 6;
    const u64 total_words =
        static_cast<u64>(grid_dimensions) * static_cast<u64>(words_per_row);

    /*
        Since grid_dimensions = 2^n with n >= 10:
            words_per_row = 2^(n-6)
            total_words   = 2^(2n-6)
        Hence total_words is a power of two and, in particular, divisible by 256.
        That lets us launch exactly one thread per packed word with no tail handling.
    */
    const u64 last_row_start = total_words - static_cast<u64>(words_per_row);
    const unsigned int num_blocks =
        static_cast<unsigned int>(total_words / static_cast<u64>(kBlockSize));

    game_of_life_step_kernel<<<num_blocks, kBlockSize>>>(
        input,
        output,
        words_per_row,
        words_per_row - 1u,
        last_row_start);
}

#include <cstddef>
#include <cstdint>
#include <cuda_runtime.h>

namespace {

// Use an explicit 64-bit type that has CUDA shuffle overloads on all supported hosts.
using word_t = unsigned long long;

// 256 threads/block = 8 warps/block.
// No shared memory is used, so occupancy is typically limited only by registers.
constexpr unsigned kWarpSize      = 32u;
constexpr unsigned kFullMask      = 0xffffffffu;
constexpr int      kHalfWarpWidth = 16;
constexpr int      kBlockThreads  = 256;
constexpr unsigned kWarpsPerBlock = static_cast<unsigned>(kBlockThreads) / kWarpSize;
constexpr std::size_t kHalfStrideWords = 16;  // 1024x1024 board => 16 packed words/row.

static_assert(kBlockThreads % static_cast<int>(kWarpSize) == 0, "Block size must be warp-aligned.");
static_assert(sizeof(word_t) == 8, "word_t must be 64 bits.");
static_assert(sizeof(std::uint64_t) == 8, "std::uint64_t must be 64 bits.");

// Read one packed 64-cell word from global memory.
__device__ __forceinline__ word_t load_word(const std::uint64_t* __restrict__ base, std::size_t idx) {
    return static_cast<word_t>(base[idx]);
}

// Two-input half adder, lane-wise across all 64 bit positions.
__device__ __forceinline__ void half_add(word_t& carry, word_t& sum, word_t a, word_t b) {
    sum   = a ^ b;
    carry = a & b;
}

// Three-input carry-save adder, lane-wise across all 64 bit positions.
// For every bit position independently: a + b + c == sum + 2*carry.
__device__ __forceinline__ void csa(word_t& carry, word_t& sum, word_t a, word_t b, word_t c) {
    const word_t ab_xor = a ^ b;
    sum   = ab_xor ^ c;
    carry = (a & b) | (ab_xor & c);
}

// Compute the next Game-of-Life state for one packed 64-cell word.
//
// The nine arguments are the raw neighboring packed words in the 3x3 word stencil:
//
//   top_left_word   top_word   top_right_word
//   mid_left_word   mid_word   mid_right_word
//   bot_left_word   bot_word   bot_right_word
//
// Each of those raw words is aligned to the current word's bit positions with shifts.
// The inserted carry bit from the adjacent word handles bit 0 / bit 63 exactly:
// - (row << 1) | (left >> 63)  supplies the "west" neighbor for every bit lane,
//   including bit 0 from the word to the left.
// - (row >> 1) | (right << 63) supplies the "east" neighbor for every bit lane,
//   including bit 63 from the word to the right.
//
// After alignment, the eight neighbors are counted with a bit-sliced carry-save adder
// network. This counts all 64 cells in parallel using only bitwise integer ops.
__device__ __forceinline__ word_t evolve_from_raw_neighbors(
    word_t top_left_word, word_t top_word, word_t top_right_word,
    word_t mid_left_word, word_t mid_word, word_t mid_right_word,
    word_t bot_left_word, word_t bot_word, word_t bot_right_word)
{
    // Horizontally align neighbors from the three rows around the current word.
    const word_t nw = (top_word << 1) | (top_left_word >> 63);
    const word_t ne = (top_word >> 1) | (top_right_word << 63);
    const word_t w  = (mid_word << 1) | (mid_left_word >> 63);
    const word_t e  = (mid_word >> 1) | (mid_right_word << 63);
    const word_t sw = (bot_word << 1) | (bot_left_word >> 63);
    const word_t se = (bot_word >> 1) | (bot_right_word << 63);

    // Count the 8 neighbors with a small CSA tree.
    // Grouping:
    //   top row:    nw + n + ne
    //   bottom row: sw + s + se
    //   middle row: w + e
    //
    // Final count representation:
    //   count = ones + 2*twos + 4*fours + 8*eights
    word_t c_top, s_top;
    csa(c_top, s_top, nw, top_word, ne);

    word_t c_bot, s_bot;
    csa(c_bot, s_bot, sw, bot_word, se);

    word_t c_mid, s_mid;
    half_add(c_mid, s_mid, w, e);

    word_t c_ones, ones;
    csa(c_ones, ones, s_top, s_bot, s_mid);

    word_t c_twos_hi, s_twos_lo;
    csa(c_twos_hi, s_twos_lo, c_top, c_bot, c_mid);

    word_t c_twos_carry, twos;
    half_add(c_twos_carry, twos, s_twos_lo, c_ones);

    word_t eights, fours;
    half_add(eights, fours, c_twos_hi, c_twos_carry);

    // Life rule:
    // - count == 3 => alive
    // - count == 2 => preserve current state
    //
    // `twos & ~(fours | eights)` selects counts 2 or 3.
    // Within that subset, `ones | mid_word` distinguishes:
    //   count 2: ones=0 => keep only if currently alive
    //   count 3: ones=1 => always alive
    const word_t two_or_three = twos & ~(fours | eights);
    return two_or_three & (ones | mid_word);
}

// Special-case kernel for the only legal board width below one full warp of words:
// 1024x1024 cells => 16 packed 64-bit words/row.
//
// One warp processes two rows:
// - lanes  0..15 -> one full 16-word row
// - lanes 16..31 -> the next full 16-word row
//
// Shuffles use width=16 so the lower and upper half-warp act as independent row groups.
// This avoids wasting 16 inactive lanes per row and removes all inter-segment boundary loads
// because the whole row fits inside one half-warp.
__global__ __launch_bounds__(kBlockThreads)
void game_of_life_kernel_halfwarp16(
    const std::uint64_t* __restrict__ input,
    std::uint64_t* __restrict__ output,
    int grid_dimensions,
    std::size_t total_warps)
{
    const unsigned lane = static_cast<unsigned>(threadIdx.x) & (kWarpSize - 1u);
    const std::size_t global_thread =
        static_cast<std::size_t>(blockIdx.x) * static_cast<std::size_t>(kBlockThreads) +
        static_cast<std::size_t>(threadIdx.x);
    const std::size_t warp_id = global_thread >> 5;

    if (warp_id >= total_warps) {
        return;
    }

    const unsigned rows     = static_cast<unsigned>(grid_dimensions);
    const unsigned last_row = rows - 1u;

    const unsigned half    = lane >> 4;   // 0 for lower half-warp, 1 for upper half-warp
    const unsigned sublane = lane & 15u;  // 0..15 within its row
    const unsigned row     = static_cast<unsigned>(warp_id << 1) + half;

    // Because each warp covers 32 consecutive packed words and each row has 16 words,
    // the linear word index is simply warp_id*32 + lane.
    const std::size_t idx = (warp_id << 5) + static_cast<std::size_t>(lane);

    const bool has_top    = (row != 0u);
    const bool has_bottom = (row != last_row);

    const word_t top = has_top    ? load_word(input, idx - kHalfStrideWords) : 0ULL;
    const word_t mid =                 load_word(input, idx);
    const word_t bot = has_bottom ? load_word(input, idx + kHalfStrideWords) : 0ULL;

    // Within each half-warp, neighboring words are already in neighboring lanes.
    word_t top_left_word = __shfl_up_sync(kFullMask, top, 1, kHalfWarpWidth);
    word_t mid_left_word = __shfl_up_sync(kFullMask, mid, 1, kHalfWarpWidth);
    word_t bot_left_word = __shfl_up_sync(kFullMask, bot, 1, kHalfWarpWidth);

    word_t top_right_word = __shfl_down_sync(kFullMask, top, 1, kHalfWarpWidth);
    word_t mid_right_word = __shfl_down_sync(kFullMask, mid, 1, kHalfWarpWidth);
    word_t bot_right_word = __shfl_down_sync(kFullMask, bot, 1, kHalfWarpWidth);

    // Entire row fits in the half-warp, so row edges map directly to zero.
    if (sublane == 0u) {
        top_left_word = 0ULL;
        mid_left_word = 0ULL;
        bot_left_word = 0ULL;
    }
    if (sublane == 15u) {
        top_right_word = 0ULL;
        mid_right_word = 0ULL;
        bot_right_word = 0ULL;
    }

    const word_t next = evolve_from_raw_neighbors(
        top_left_word, top, top_right_word,
        mid_left_word, mid, mid_right_word,
        bot_left_word, bot, bot_right_word);

    output[idx] = static_cast<std::uint64_t>(next);
}

// General kernel for rows that are at least 32 packed words wide.
//
// One warp processes one contiguous 32-word row segment.
// Most left/right neighboring words are exchanged with warp shuffles, so each thread
// normally performs only 3 global reads: row above, current row, row below.
// Only lane 0 and lane 31 need extra global reads at segment boundaries.
__global__ __launch_bounds__(kBlockThreads)
void game_of_life_kernel_segments32(
    const std::uint64_t* __restrict__ input,
    std::uint64_t* __restrict__ output,
    int grid_dimensions,
    int segments_shift,
    unsigned int segments_mask,
    std::size_t total_warps)
{
    const unsigned lane = static_cast<unsigned>(threadIdx.x) & (kWarpSize - 1u);
    const std::size_t global_thread =
        static_cast<std::size_t>(blockIdx.x) * static_cast<std::size_t>(kBlockThreads) +
        static_cast<std::size_t>(threadIdx.x);
    const std::size_t warp_id = global_thread >> 5;

    if (warp_id >= total_warps) {
        return;
    }

    const unsigned rows     = static_cast<unsigned>(grid_dimensions);
    const unsigned last_row = rows - 1u;

    // Since segments_per_row is a power of two, row/segment decoding is shift+mask.
    const unsigned segment = static_cast<unsigned>(warp_id) & segments_mask;
    const unsigned row     = static_cast<unsigned>(warp_id >> segments_shift);

    // Each warp owns 32 consecutive packed words in memory, so the global word index is
    // again warp_id*32 + lane.
    const std::size_t idx = (warp_id << 5) + static_cast<std::size_t>(lane);

    // words_per_row = 32 * segments_per_row = 2^(segments_shift + 5)
    const std::size_t stride = std::size_t{1} << (segments_shift + 5);

    const bool has_top    = (row != 0u);
    const bool has_bottom = (row != last_row);

    const word_t top = has_top    ? load_word(input, idx - stride) : 0ULL;
    const word_t mid =                 load_word(input, idx);
    const word_t bot = has_bottom ? load_word(input, idx + stride) : 0ULL;

    // Pull neighboring words from adjacent lanes for the common case.
    word_t top_left_word = __shfl_up_sync(kFullMask, top, 1);
    word_t mid_left_word = __shfl_up_sync(kFullMask, mid, 1);
    word_t bot_left_word = __shfl_up_sync(kFullMask, bot, 1);

    word_t top_right_word = __shfl_down_sync(kFullMask, top, 1);
    word_t mid_right_word = __shfl_down_sync(kFullMask, mid, 1);
    word_t bot_right_word = __shfl_down_sync(kFullMask, bot, 1);

    // Lane 0 needs the real left neighboring word only when this segment is not the first
    // segment in the row. Otherwise the outside of the board is dead => zero.
    if (lane == 0u) {
        if (segment != 0u) {
            top_left_word = has_top    ? load_word(input, idx - stride - 1) : 0ULL;
            mid_left_word =               load_word(input, idx - 1);
            bot_left_word = has_bottom ? load_word(input, idx + stride - 1) : 0ULL;
        } else {
            top_left_word = 0ULL;
            mid_left_word = 0ULL;
            bot_left_word = 0ULL;
        }
    }

    // Lane 31 needs the real right neighboring word only when this segment is not the last
    // segment in the row. Otherwise the outside of the board is dead => zero.
    if (lane == (kWarpSize - 1u)) {
        if (segment != segments_mask) {
            top_right_word = has_top    ? load_word(input, idx - stride + 1) : 0ULL;
            mid_right_word =               load_word(input, idx + 1);
            bot_right_word = has_bottom ? load_word(input, idx + stride + 1) : 0ULL;
        } else {
            top_right_word = 0ULL;
            mid_right_word = 0ULL;
            bot_right_word = 0ULL;
        }
    }

    const word_t next = evolve_from_raw_neighbors(
        top_left_word, top, top_right_word,
        mid_left_word, mid, mid_right_word,
        bot_left_word, bot, bot_right_word);

    output[idx] = static_cast<std::uint64_t>(next);
}

}  // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions) {
    // The caller guarantees:
    // - square board
    // - power-of-two dimensions
    // - dimensions > 512
    // - input/output are device pointers allocated with cudaMalloc
    //
    // This function intentionally does not synchronize and does not check launch errors,
    // because the prompt states that synchronization is handled by the caller and only
    // simulation throughput matters.

    const int words_per_row = grid_dimensions >> 6;

    // The only legal sub-32-word case is 16 words/row (1024x1024 board).
    // Use the dedicated half-warp kernel so every lane remains useful.
    if (words_per_row == 16) {
        const std::size_t total_warps = static_cast<std::size_t>(grid_dimensions) >> 1;  // 2 rows/warp
        const unsigned int grid_x = static_cast<unsigned int>(
            (total_warps + static_cast<std::size_t>(kWarpsPerBlock) - 1u) /
            static_cast<std::size_t>(kWarpsPerBlock));

        game_of_life_kernel_halfwarp16<<<grid_x, kBlockThreads>>>(input, output, grid_dimensions, total_warps);
        return;
    }

    // For all larger boards, row width is 32, 64, 128, ...
    // segments_per_row = words_per_row / 32 = 2^segments_shift.
    int segments_shift = 0;
    for (int words = words_per_row; words > 32; words >>= 1) {
        ++segments_shift;
    }

    const unsigned int segments_mask = (1u << segments_shift) - 1u;
    const std::size_t total_warps = static_cast<std::size_t>(grid_dimensions) << segments_shift;
    const unsigned int grid_x = static_cast<unsigned int>(
        (total_warps + static_cast<std::size_t>(kWarpsPerBlock) - 1u) /
        static_cast<std::size_t>(kWarpsPerBlock));

    // 1D launch is deliberate:
    // it keeps the warp-to-segment mapping trivial and avoids 2D grid dimension limits
    // on very large boards.
    game_of_life_kernel_segments32<<<grid_x, kBlockThreads>>>(
        input, output, grid_dimensions, segments_shift, segments_mask, total_warps);
}

#include <cstddef>
#include <cstdint>
#include <cuda_runtime.h>

namespace {

using u64 = std::uint64_t;

// The kernel is intentionally built around 256-thread blocks.
// That is a good fit for modern data-center GPUs while keeping enough warps
// resident to hide memory latency.
constexpr int kBlockThreads   = 256;
constexpr int kSegmentWidth16 = 16;
constexpr int kBlockY16       = 16;
constexpr int kSegmentWidth32 = 32;
constexpr int kBlockY32       = 8;

static_assert(kSegmentWidth16 * kBlockY16 == kBlockThreads, "Unexpected 16-wide block shape.");
static_assert(kSegmentWidth32 * kBlockY32 == kBlockThreads, "Unexpected 32-wide block shape.");

// Bit 0 is treated as the leftmost cell inside a 64-bit word and bit 63 as the rightmost.
// align_west() produces, for every bit position i, the state of the west neighbor (x - 1)
// aligned back to bit i. The carry-in for bit 0 comes from the previous 64-bit word.
__device__ __forceinline__ u64 align_west(u64 center, u64 west_word) {
    return (center << 1) | (west_word >> 63);
}

// align_east() produces, for every bit position i, the state of the east neighbor (x + 1)
// aligned back to bit i. The carry-in for bit 63 comes from the next 64-bit word.
__device__ __forceinline__ u64 align_east(u64 center, u64 east_word) {
    return (center >> 1) | (east_word << 63);
}

// Bit-sliced half adder: every one of the 64 bit positions behaves like an independent 1-bit lane.
// Integer '+' cannot be used here because carries would leak between different cell positions.
__device__ __forceinline__ void add2(u64 a, u64 b, u64& sum, u64& carry) {
    sum   = a ^ b;
    carry = a & b;
}

// Bit-sliced full adder for three 1-bit planes.
__device__ __forceinline__ void add3(u64 a, u64 b, u64 c, u64& sum, u64& carry) {
    const u64 x = a ^ b;
    sum   = x ^ c;
    carry = (a & b) | (x & c);
}

// For four 1-bit planes a, b, c, d:
//   parity = (a + b + c + d) & 1
//   ge2    = (a + b + c + d) >= 2
//
// In this kernel these four inputs are the contributors to the "2's" bit of the
// total neighbor count. Therefore ge2 is exactly the mask "neighbor_count >= 4",
// which is all Conway's rule needs above 3.
__device__ __forceinline__ void parity_and_ge2_of4(
    u64 a, u64 b, u64 c, u64 d,
    u64& parity, u64& ge2)
{
    const u64 p = a ^ b;
    const u64 q = c ^ d;
    parity = p ^ q;
    ge2    = (a & b) | (c & d) | (p & q);
}

// SEGMENT_WIDTH is the X extent of one independently shuffled row segment.
//   * SEGMENT_WIDTH == 32:
//       one whole warp maps to one row segment.
//   * SEGMENT_WIDTH == 16:
//       one warp maps to two row segments, but the shuffle width keeps the two
//       16-lane halves fully independent.
//
// This lets interior threads obtain west/east neighboring words via warp shuffles,
// reducing the common-case global loads from 9 words down to 3 words per thread
// (north/current/south). Only segment-boundary lanes fall back to global memory
// for the extra west/east words.
template <int SEGMENT_WIDTH, int BLOCK_Y>
__global__ __launch_bounds__(kBlockThreads)
void game_of_life_kernel(
    const u64* __restrict__ input,
    u64* __restrict__ output,
    int grid_dimensions,
    int words_per_row)
{
    static_assert(SEGMENT_WIDTH * BLOCK_Y == kBlockThreads, "Unexpected block shape.");
    static_assert(SEGMENT_WIDTH == 16 || SEGMENT_WIDTH == 32, "Unexpected shuffle width.");

    const int lane = static_cast<int>(threadIdx.x);
    const int col  = static_cast<int>(blockIdx.x) * SEGMENT_WIDTH + lane;
    const int row  = static_cast<int>(blockIdx.y) * BLOCK_Y + static_cast<int>(threadIdx.y);

    // run_game_of_life() exploits the problem guarantees:
    //   - grid_dimensions is a power of 2 and > 512
    //   - words_per_row = grid_dimensions / 64 is therefore also a power of 2
    //   - words_per_row is either 16 (only for 1024x1024) or a multiple of 32
    //
    // That allows exact tiling with no out-of-range threads:
    //   - SEGMENT_WIDTH = 16 when words_per_row == 16
    //   - SEGMENT_WIDTH = 32 otherwise
    // grid_dimensions is also an exact multiple of BLOCK_Y, so no Y-boundary masking
    // is needed beyond the Game-of-Life edge rules themselves.
    const bool has_top    = (row != 0);
    const bool has_bottom = (row + 1 != grid_dimensions);
    const bool has_left   = (col != 0);
    const bool has_right  = (col + 1 != words_per_row);

    const std::size_t stride   = static_cast<std::size_t>(words_per_row);
    const std::size_t row_base = static_cast<std::size_t>(row) * stride;

    const u64* const row_ptr = input + row_base;
    const u64* const top_ptr = has_top    ? (row_ptr - stride) : nullptr;
    const u64* const bot_ptr = has_bottom ? (row_ptr + stride) : nullptr;

    // Mandatory loads for this output word: north/current/south in the same column.
    const u64 top = has_top    ? top_ptr[col] : 0ull;
    const u64 mid = row_ptr[col];
    const u64 bot = has_bottom ? bot_ptr[col] : 0ull;

    // Latest CUDA allows 64-bit values in shuffles directly.
    // The width parameter keeps 16-lane specializations confined to half-warps.
    constexpr unsigned kFullMask = 0xFFFFFFFFu;
    const u64 top_from_west = __shfl_up_sync  (kFullMask, top, 1, SEGMENT_WIDTH);
    const u64 top_from_east = __shfl_down_sync(kFullMask, top, 1, SEGMENT_WIDTH);
    const u64 mid_from_west = __shfl_up_sync  (kFullMask, mid, 1, SEGMENT_WIDTH);
    const u64 mid_from_east = __shfl_down_sync(kFullMask, mid, 1, SEGMENT_WIDTH);
    const u64 bot_from_west = __shfl_up_sync  (kFullMask, bot, 1, SEGMENT_WIDTH);
    const u64 bot_from_east = __shfl_down_sync(kFullMask, bot, 1, SEGMENT_WIDTH);

    // Default west/east words come from neighboring lanes inside the same shuffled segment.
    // For the segment boundary lanes, fall back to explicit global loads if the board actually
    // has a west/east word there; otherwise keep zero to model "outside the grid is dead".
    u64 west_top_word = (lane != 0) ? top_from_west : 0ull;
    u64 west_mid_word = (lane != 0) ? mid_from_west : 0ull;
    u64 west_bot_word = (lane != 0) ? bot_from_west : 0ull;

    if (lane == 0 && has_left) {
        const int west_col = col - 1;
        if (has_top)    west_top_word = top_ptr[west_col];
        west_mid_word = row_ptr[west_col];
        if (has_bottom) west_bot_word = bot_ptr[west_col];
    }

    u64 east_top_word = (lane + 1 != SEGMENT_WIDTH) ? top_from_east : 0ull;
    u64 east_mid_word = (lane + 1 != SEGMENT_WIDTH) ? mid_from_east : 0ull;
    u64 east_bot_word = (lane + 1 != SEGMENT_WIDTH) ? bot_from_east : 0ull;

    if (lane + 1 == SEGMENT_WIDTH && has_right) {
        const int east_col = col + 1;
        if (has_top)     east_top_word = top_ptr[east_col];
        east_mid_word = row_ptr[east_col];
        if (has_bottom)  east_bot_word = bot_ptr[east_col];
    }

    // Build the six horizontally shifted bitboards that complete the 3x3 neighborhood.
    // Each bit position now sees its own aligned north-west / west / south-west etc.
    const u64 top_l = align_west(top, west_top_word);
    const u64 top_r = align_east(top, east_top_word);
    const u64 mid_l = align_west(mid, west_mid_word);
    const u64 mid_r = align_east(mid, east_mid_word);
    const u64 bot_l = align_west(bot, west_bot_word);
    const u64 bot_r = align_east(bot, east_bot_word);

    // First stage: horizontal population counts per row.
    //
    // top_count    = top_l + top + top_r      in [0, 3]
    // middle_count = mid_l + mid_r            in [0, 2]   (center cell excluded)
    // bottom_count = bot_l + bot + bot_r      in [0, 3]
    //
    // Each count is represented in bit-sliced form:
    //   row0 -> low bit of the per-cell row sum
    //   row1 -> high bit of the per-cell row sum
    u64 top0, top1;
    add3(top_l, top, top_r, top0, top1);

    u64 mid0, mid1;
    add2(mid_l, mid_r, mid0, mid1);

    u64 bot0, bot1;
    add3(bot_l, bot, bot_r, bot0, bot1);

    // Second stage: add the three row counts vertically.
    //
    // count0 is the exact LSB of the total 8-neighbor count.
    // carry_low/top1/mid1/bot1 are the four contributors to the "2's" bit.
    u64 count0, carry_low;
    add3(top0, mid0, bot0, count0, carry_low);

    // count1 is the exact second bit of the total neighbor count.
    // ge4 is the exact mask "neighbor_count >= 4".
    u64 count1, ge4;
    parity_and_ge2_of4(carry_low, top1, mid1, bot1, count1, ge4);

    // Conway rule:
    //   next = (count == 3) | (alive & count == 2)
    //
    // Counts 2 and 3 share:
    //   ge4    == 0
    //   count1 == 1
    //
    // count0 distinguishes them:
    //   count0 == 0 -> exactly 2
    //   count0 == 1 -> exactly 3
    const u64 two_or_three = ~ge4 & count1;
    output[row_base + static_cast<std::size_t>(col)] = two_or_three & (count0 | mid);
}

}  // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions) {
    // The caller owns synchronization/stream semantics; this function only enqueues one kernel.
    //
    // Because grid_dimensions is a power of 2 and > 512:
    //   words_per_row = grid_dimensions / 64
    // is also a power of 2, therefore either:
    //   * 16  (only for a 1024x1024 grid), or
    //   * a multiple of 32
    //
    // We use that to pick an exact launch shape with no out-of-range threads.
    const int words_per_row = grid_dimensions >> 6;

    if (words_per_row == kSegmentWidth16) {
        const dim3 block(kSegmentWidth16, kBlockY16, 1);
        const dim3 grid(1u, static_cast<unsigned int>(grid_dimensions / kBlockY16), 1);
        game_of_life_kernel<kSegmentWidth16, kBlockY16>
            <<<grid, block>>>(input, output, grid_dimensions, words_per_row);
    } else {
        const dim3 block(kSegmentWidth32, kBlockY32, 1);
        const dim3 grid(
            static_cast<unsigned int>(words_per_row / kSegmentWidth32),
            static_cast<unsigned int>(grid_dimensions / kBlockY32),
            1);
        game_of_life_kernel<kSegmentWidth32, kBlockY32>
            <<<grid, block>>>(input, output, grid_dimensions, words_per_row);
    }
}

#include <cstddef>
#include <cstdint>
#include <cuda_runtime.h>

// High-performance bit-packed Conway step for modern NVIDIA GPUs.
//
// Design choices:
// - One CUDA thread updates one 64-bit packed word (64 cells), so no atomics are needed.
// - Bit k of a word stores cell x = word_x * 64 + k, i.e. bit 0 is the leftmost cell in the word
//   and bit 63 is the rightmost cell in the word.
// - grid_dimensions is a power of two and > 512, so every row contains an integer number of
//   fully-used 64-bit words; no tail masking is required.
// - Shared/texture memory are intentionally not used. The access pattern is regular, neighboring
//   threads naturally reuse the same cache lines, and direct global loads keep the kernel simpler.
// - A 1D launch is used on purpose: because words_per_row is also a power of two, recovering
//   (row, word_x) from the linear thread index is just shift+mask, and this avoids 2D-grid limits
//   for very large boards.

namespace detail {

using u32 = std::uint32_t;
using u64 = std::uint64_t;

constexpr int kThreadsPerBlock = 256;

// Carry-save adder for bit-sliced arithmetic.
// For every bit position independently:
//   a + b + c = sum + 2 * carry
__device__ __forceinline__ void csa(u64& carry, u64& sum, const u64 a, const u64 b, const u64 c) {
    const u64 ab_xor = a ^ b;
    sum = ab_xor ^ c;
    carry = (a & b) | (ab_xor & c);
}

// Evaluate one 64-cell word given the surrounding 3x3 word neighborhood.
//
// The "special handling" for bit 0 / bit 63 requested by the prompt is encoded by these stitched
// shifts:
//   west  = (center << 1) | (left  >> 63)
//   east  = (center >> 1) | (right << 63)
// and likewise for the rows above/below. Therefore:
// - bit 0 can see above_left / left / below_left
// - bit 63 can see above_right / right / below_right
//
// Neighbor counts are computed in bit-sliced form with carry-save adders, so all 64 cells are
// updated in parallel using integer logic only.
//
// Only the low three bits of the 8-neighbor count are needed:
// - count 2 => 0b010
// - count 3 => 0b011
// - count 8 => 0b000 modulo 8, which is harmless because Life only distinguishes 2 and 3.
__device__ __forceinline__ u64 evaluate_neighborhood(
    const u64 above_left,  const u64 above,  const u64 above_right,
    const u64 left,        const u64 center, const u64 right,
    const u64 below_left,  const u64 below,  const u64 below_right)
{
    // Top row of neighbors: NW, N, NE.
    const u64 north_west = (above << 1) | (above_left >> 63);
    const u64 north_east = (above >> 1) | (above_right << 63);
    u64 carry_top, sum_top;
    csa(carry_top, sum_top, above, north_west, north_east);

    // Bottom row of neighbors: SW, S, SE.
    const u64 south_west = (below << 1) | (below_left >> 63);
    const u64 south_east = (below >> 1) | (below_right << 63);
    u64 carry_bottom, sum_bottom;
    csa(carry_bottom, sum_bottom, below, south_west, south_east);

    // Same-row neighbors: W, E.
    const u64 west = (center << 1) | (left >> 63);
    const u64 east = (center >> 1) | (right << 63);
    const u64 sum_lr = west ^ east;
    const u64 carry_lr = west & east;

    // Combine the low bits from the three row groups.
    u64 carry_low, ones;
    csa(carry_low, ones, sum_top, sum_bottom, sum_lr);

    // Combine the carry bits from the three row groups. These are already weight-2 contributions.
    u64 carry_high, twos_partial;
    csa(carry_high, twos_partial, carry_top, carry_bottom, carry_lr);

    // Add carry_low (another weight-2 contribution) to the partial twos/fours representation.
    const u64 twos  = twos_partial ^ carry_low;
    const u64 fours = carry_high ^ (twos_partial & carry_low);

    // Conway rule:
    //   next = (count == 3) || (alive && count == 2)
    // With bit-sliced count bits (ones, twos, fours):
    //   count == 2 -> ones=0, twos=1, fours=0
    //   count == 3 -> ones=1, twos=1, fours=0
    return twos & ~fours & (ones | center);
}

// Fast path for non-boundary words: all 3x3 surrounding words exist, so loads are unconditional.
__device__ __forceinline__ u64 update_word_interior(
    const u64* __restrict__ input,
    const std::size_t idx,
    const std::size_t row_words)
{
    const u64* const above_row = input + idx - row_words - 1;
    const u64* const here_row  = input + idx - 1;
    const u64* const below_row = input + idx + row_words - 1;

    return evaluate_neighborhood(
        above_row[0], above_row[1], above_row[2],
        here_row[0],  here_row[1],  here_row[2],
        below_row[0], below_row[1], below_row[2]);
}

// Boundary path: words beyond the board are treated as zero, exactly matching
// "all cells outside the grid are dead".
__device__ __forceinline__ u64 update_word_boundary(
    const u64* __restrict__ input,
    const std::size_t idx,
    const int x,
    const int y,
    const int last_word,
    const int last_row,
    const std::size_t row_words)
{
    const bool has_left  = (x != 0);
    const bool has_right = (x != last_word);
    const bool has_up    = (y != 0);
    const bool has_down  = (y != last_row);

    const u64 center      = input[idx];
    const u64 left        = has_left               ? input[idx - 1] : 0ull;
    const u64 right       = has_right              ? input[idx + 1] : 0ull;
    const u64 above       = has_up                 ? input[idx - row_words] : 0ull;
    const u64 below       = has_down               ? input[idx + row_words] : 0ull;
    const u64 above_left  = (has_up   && has_left) ? input[idx - row_words - 1] : 0ull;
    const u64 above_right = (has_up   && has_right)? input[idx - row_words + 1] : 0ull;
    const u64 below_left  = (has_down && has_left) ? input[idx + row_words - 1] : 0ull;
    const u64 below_right = (has_down && has_right)? input[idx + row_words + 1] : 0ull;

    return evaluate_neighborhood(
        above_left, above, above_right,
        left, center, right,
        below_left, below, below_right);
}

// Template keeps the common case on 32-bit indices while still supporting very large boards.
template <typename IndexT>
__global__ __launch_bounds__(kThreadsPerBlock)
void game_of_life_kernel(
    const u64* __restrict__ input,
    u64* __restrict__ output,
    const IndexT total_words,
    const std::size_t row_words,
    const int row_shift,
    const int last_word,
    const int last_row)
{
    const IndexT linear =
        static_cast<IndexT>(blockIdx.x) * static_cast<IndexT>(kThreadsPerBlock) +
        static_cast<IndexT>(threadIdx.x);

    if (linear >= total_words) {
        return;
    }

    const IndexT word_mask = static_cast<IndexT>(last_word);
    const int x = static_cast<int>(linear & word_mask);
    const int y = static_cast<int>(linear >> row_shift);
    const std::size_t idx = static_cast<std::size_t>(linear);

    // Nearly all words are interior for large boards, so keep a fast branch-free interior path
    // and only fall back to zero-extended loads on the actual boundary.
    const bool boundary = (x == 0) || (x == last_word) || (y == 0) || (y == last_row);

    if (!boundary) {
        output[idx] = update_word_interior(input, idx, row_words);
    } else {
        output[idx] = update_word_boundary(input, idx, x, y, last_word, last_row, row_words);
    }
}

} // namespace detail

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions) {
    // Preconditions guaranteed by the problem statement:
    // - input and output are valid cudaMalloc device buffers
    // - the board is square
    // - grid_dimensions is a power of two and > 512
    // - input and output are distinct buffers (in-place update is intentionally unsupported)
    //
    // No synchronization or launch-error handling is done here because the caller handles
    // synchronization and the task is explicitly performance-focused.

    const int words_per_row = grid_dimensions >> 6;
    const int last_word = words_per_row - 1;
    const int last_row = grid_dimensions - 1;
    const std::size_t row_words = static_cast<std::size_t>(words_per_row);

    const std::uint64_t total_words =
        static_cast<std::uint64_t>(words_per_row) * static_cast<std::uint64_t>(grid_dimensions);

    // words_per_row is a power of two, so:
    //   word_x = linear & (words_per_row - 1)
    //   row    = linear >> row_shift
    int row_shift = 0;
    for (int tmp = words_per_row; tmp > 1; tmp >>= 1) {
        ++row_shift;
    }

    const std::uint64_t threads_per_block = static_cast<std::uint64_t>(detail::kThreadsPerBlock);
    const unsigned int blocks =
        static_cast<unsigned int>((total_words + threads_per_block - 1ull) / threads_per_block);

    // Use 32-bit indexing whenever possible; only extremely large boards need the 64-bit variant.
    if (total_words <= 0xFFFFFFFFull) {
        detail::game_of_life_kernel<detail::u32><<<blocks, detail::kThreadsPerBlock>>>(
            input,
            output,
            static_cast<detail::u32>(total_words),
            row_words,
            row_shift,
            last_word,
            last_row);
    } else {
        detail::game_of_life_kernel<detail::u64><<<blocks, detail::kThreadsPerBlock>>>(
            input,
            output,
            static_cast<detail::u64>(total_words),
            row_words,
            row_shift,
            last_word,
            last_row);
    }
}

#include <cuda_runtime.h>
#include <cstdint>

namespace {

// One warp owns one 32-word horizontal segment from a single board row.
// This is intentional: it lets us reuse west/east neighbor words with warp
// shuffles instead of shared memory or redundant global loads.
using word_t = std::uint64_t;
using u32 = std::uint32_t;

constexpr u32 kWarpWidth     = 32u;
constexpr u32 kBlockX        = kWarpWidth;
constexpr u32 kBlockY        = 8u;
constexpr u32 kBlockThreads  = kBlockX * kBlockY;

// Roughly one million threads in flight at most (4096 * 256). Larger boards are
// covered with grid-stride loops. This is a good fixed launch target for A100/H100
// class GPUs without paying the overhead of launching a block per logical tile.
constexpr u32 kTargetBlocks  = 4096u;
constexpr u32 kMaxGridXTiles = 64u;

// Bit-sliced carry-save adder:
// for every bit position independently, a + b + c = sum + 2 * carry.
__device__ __forceinline__ void csa(
    const word_t a,
    const word_t b,
    const word_t c,
    word_t& carry,
    word_t& sum)
{
    const word_t u = a ^ b;
    carry = (a & b) | (u & c);
    sum   = u ^ c;
}

// One kernel step of Conway's Game of Life on a bit-packed board.
//
// Representation:
//   - Each 64-bit word stores 64 consecutive cells from one row.
//   - Bit value 1 means alive, 0 means dead.
//   - Bit 0 is treated as the leftmost cell inside the word, matching the prompt:
//       * left  neighbors => (word << 1) | (west_word >> 63)
//       * right neighbors => (word >> 1) | (east_word << 63)
//
// Mapping:
//   - One CUDA thread computes exactly one 64-bit output word.
//   - Each warp processes 32 consecutive words from a single row segment.
//   - West/east neighboring words are obtained with warp shuffles when they stay
//     inside the warp tile; only warp/tile boundaries fall back to direct global
//     loads. This captures the useful reuse without shared memory.
//
// Boundaries:
//   - Everything outside the board is dead, so border rows/columns inject zero words.
__global__ __launch_bounds__(kBlockThreads)
void game_of_life_kernel(
    const word_t* __restrict__ input,
    word_t* __restrict__ output,
    const u32 words_per_row,
    const u32 grid_dimensions)
{
    const u32 lane      = static_cast<u32>(threadIdx.x);
    const u32 row0      = static_cast<u32>(blockIdx.y) * kBlockY + static_cast<u32>(threadIdx.y);
    const u32 col0      = static_cast<u32>(blockIdx.x) * kBlockX + lane;
    const u32 row_stride = static_cast<u32>(gridDim.y) * kBlockY;
    const u32 col_stride = static_cast<u32>(gridDim.x) * kBlockX;

    for (u32 row = row0; row < grid_dimensions; row += row_stride) {
        const bool has_north = (row != 0u);
        const bool has_south = (row + 1u < grid_dimensions);

        const std::uint64_t row_base =
            static_cast<std::uint64_t>(row) * static_cast<std::uint64_t>(words_per_row);

        const word_t* const row_ptr       = input  + row_base;
        const word_t* const north_row_ptr = row_ptr - (has_north ? words_per_row : 0u);
        const word_t* const south_row_ptr = row_ptr + (has_south ? words_per_row : 0u);
        word_t* const       out_ptr       = output + row_base;

        for (u32 col = col0; col < words_per_row; col += col_stride) {
            const word_t self  = row_ptr[col];
            const word_t north = has_north ? north_row_ptr[col] : 0ull;
            const word_t south = has_south ? south_row_ptr[col] : 0ull;

            // This is full-mask almost always; __activemask() keeps the code correct
            // for the only partial-x case here (1024x1024 boards => 16 words/row).
            const unsigned mask = __activemask();

            // Fast path: neighboring words already loaded by adjacent lanes.
            word_t west_word       = __shfl_up_sync(mask,   self,  1);
            word_t east_word       = __shfl_down_sync(mask, self,  1);
            word_t north_west_word = __shfl_up_sync(mask,   north, 1);
            word_t north_east_word = __shfl_down_sync(mask, north, 1);
            word_t south_west_word = __shfl_up_sync(mask,   south, 1);
            word_t south_east_word = __shfl_down_sync(mask, south, 1);

            const bool has_global_west = (col != 0u);
            const bool has_global_east = (col + 1u < words_per_row);

            const bool has_warp_west =
                (lane != 0u) &&
                ((mask & (1u << (lane - 1u))) != 0u);

            const bool has_warp_east =
                (lane + 1u < kWarpWidth) &&
                ((mask & (1u << (lane + 1u))) != 0u);

            // Warp/tile boundaries: fetch the needed three words on the left/right
            // (north/current/south), or inject zeros at the true board boundary.
            if (!has_warp_west) {
                if (has_global_west) {
                    west_word       = row_ptr[col - 1u];
                    north_west_word = has_north ? north_row_ptr[col - 1u] : 0ull;
                    south_west_word = has_south ? south_row_ptr[col - 1u] : 0ull;
                } else {
                    west_word = north_west_word = south_west_word = 0ull;
                }
            }

            if (!has_warp_east) {
                if (has_global_east) {
                    east_word       = row_ptr[col + 1u];
                    north_east_word = has_north ? north_row_ptr[col + 1u] : 0ull;
                    south_east_word = has_south ? south_row_ptr[col + 1u] : 0ull;
                } else {
                    east_word = north_east_word = south_east_word = 0ull;
                }
            }

            // Align all eight neighbor directions to the current cell positions.
            const word_t north_left  = (north << 1) | (north_west_word >> 63);
            const word_t north_right = (north >> 1) | (north_east_word << 63);
            const word_t west        = (self  << 1) | (west_word       >> 63);
            const word_t east        = (self  >> 1) | (east_word       << 63);
            const word_t south_left  = (south << 1) | (south_west_word >> 63);
            const word_t south_right = (south >> 1) | (south_east_word << 63);

            // Count the 8 neighbors for all 64 cells in parallel with a bit-sliced
            // adder tree. We only need:
            //   - ones: low count bit
            //   - twos: second count bit
            //   - ge4 : whether the count is at least 4
            //
            // The Life rule:
            //   next = (count == 3) | (self & (count == 2))
            //        = twos & ~ge4 & (ones | self)
            word_t h0, l0;
            csa(north_left, north, north_right, h0, l0);

            word_t h1, l1;
            csa(south_left, south, south_right, h1, l1);

            const word_t h2 = west & east;
            const word_t l2 = west ^ east;

            word_t h3, ones;
            csa(l0, l1, l2, h3, ones);

            word_t h4, twos_a;
            csa(h0, h1, h2, h4, twos_a);

            // twos_a and h3 are both weight-2 planes:
            //   twos = low 2s bit
            //   twos_a & h3 = carry into the 4s plane
            const word_t twos = twos_a ^ h3;
            const word_t ge4  = h4 | (twos_a & h3);

            out_ptr[col] = twos & ~ge4 & (ones | self);
        }
    }
}

} // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions)
{
    // Assumptions from the problem statement:
    //   - square board
    //   - grid_dimensions is a power of two
    //   - grid_dimensions > 512
    // Therefore:
    //   - words_per_row = grid_dimensions / 64 is exact
    //   - there are no partial words at the end of a row
    const std::uint32_t dim = static_cast<std::uint32_t>(grid_dimensions);
    const std::uint32_t words_per_row = dim >> 6;

    // Launch a capped number of logical tiles and let the kernel grid-stride over
    // larger boards. This keeps the launch geometry in a sweet spot for modern
    // data-center GPUs while still handling very large boards.
    const std::uint32_t tiles_x = (words_per_row + kBlockX - 1u) / kBlockX;
    const std::uint32_t tiles_y = (dim          + kBlockY - 1u) / kBlockY;

    const std::uint32_t grid_x = (tiles_x < kMaxGridXTiles) ? tiles_x : kMaxGridXTiles;
    const std::uint32_t grid_y_cap = kTargetBlocks / grid_x;
    const std::uint32_t grid_y = (tiles_y < grid_y_cap) ? tiles_y : grid_y_cap;

    const dim3 block(kBlockX, kBlockY);
    const dim3 grid(grid_x, grid_y);

    // The caller owns synchronization/stream semantics; this function only launches
    // one simulation step.
    game_of_life_kernel<<<grid, block>>>(input, output, words_per_row, dim);
}

#include <cuda_runtime.h>
#include <cstddef>
#include <cstdint>

namespace {

// Optimized CUDA implementation of one Conway's Game of Life step for the exact problem statement.
//
// Design choices focused purely on throughput on modern data-center GPUs:
//
// 1) One thread updates one 64-bit word (64 cells) exactly as requested.
//    The input/output format is already the desired packed format, so no unpack/repack is needed.
//
// 2) A 1D grid-stride launch is used instead of a 2D grid.
//    This avoids grid.y limits for very large boards while keeping addressing cheap because
//    words_per_row is a power of two:
//        x = word_index & (words_per_row - 1)
//        y = word_index >> log2(words_per_row)
//
// 3) Shared memory is intentionally not used.
//    Horizontal neighbor reuse is handled with warp shuffles, which are cheaper and simpler here.
//    Every thread always loads only its vertically aligned words (up/current/down). The horizontal
//    words are obtained from neighboring lanes; only segment-edge lanes fall back to extra global
//    loads when a row is wider than one shuffle segment.
//
// 4) Neighbor counts for all 64 cells in a word are computed in parallel with a bit-sliced adder
//    tree. No per-bit loops, no atomics, and no unpacking.
//
// 5) The problem constraints are exploited directly:
//    - grid_dimensions is a power of two and > 512
//    - therefore words_per_row is also a power of two and >= 16
//    - total_words is a power of two and, with the chosen block size, has no launch tail
//
// The block-count cap is kept as a power of two on purpose. Under the stated constraints that keeps
// the grid-stride length as a power of two as well, so all threads execute the same number of loop
// iterations and every warp is fully active for every iteration.

using u64 = std::uint64_t;

constexpr unsigned int kCellsPerWordShift = 6u;  // 64 cells / word.
constexpr int          kBlockSize         = 256; // 8 warps per block.
constexpr unsigned int kMaxBlocks         = 2048u;
constexpr unsigned int kFullWarpMask      = 0xFFFFFFFFu;

static_assert(sizeof(u64) == 8, "u64 must be 64 bits");
static_assert((kBlockSize & (kBlockSize - 1)) == 0, "kBlockSize must be a power of two");
static_assert((kBlockSize & 31) == 0, "kBlockSize must be a multiple of the warp size");
static_assert((kMaxBlocks & (kMaxBlocks - 1u)) == 0u, "kMaxBlocks must be a power of two");

__device__ __forceinline__ u64 majority64(const u64 a, const u64 b, const u64 c) {
    // Carry bit of a 3-input full adder.
    // This boolean form maps well to modern NVIDIA LOP3 instructions.
    return (a & b) | (c & (a ^ b));
}

__device__ __forceinline__ u64 evolve_word(
    const u64 center,
    const u64 up_left,   const u64 up,   const u64 up_right,
    const u64 mid_left,                    const u64 mid_right,
    const u64 down_left, const u64 down, const u64 down_right)
{
    // The prompt's boundary note implies the bit layout inside a word is:
    //   bit 0  = leftmost cell of the 64-cell run
    //   bit 63 = rightmost cell
    //
    // With that convention:
    //   west-aligned(row, left_word) = (row << 1) | (left_word  >> 63)
    //   east-aligned(row, right_word)= (row >> 1) | (right_word << 63)
    //
    // We sum the eight neighbor bitboards in two 4-neighbor groups:
    //   A = NW + N + NE + W
    //   B = E + SW + S + SE
    // Then A + B gives the 3-bit neighbor count for all 64 cells at once.
    //
    // The final rule
    //     next = (count == 3) | (alive & (count == 2))
    // can be written as
    //     next = (~ge4) & bit1 & (bit0 | alive)
    // where:
    //   bit0 = count bit 0
    //   bit1 = count bit 1
    //   ge4  = 1 for counts 4..8
    //
    // The scopes below intentionally keep live ranges short to help register allocation.

    u64 a0, a1, a2;
    {
        const u64 nw = (up << 1) | (up_left >> 63);
        const u64 n  = up;
        const u64 ne = (up >> 1) | (up_right << 63);
        const u64 w  = (center << 1) | (mid_left >> 63);

        const u64 p0 = nw ^ n;
        const u64 p1 = nw & n;
        const u64 q0 = ne ^ w;
        const u64 q1 = ne & w;

        const u64 carry0 = p0 & q0;
        const u64 t1     = p1 ^ q1;

        a0 = p0 ^ q0;
        a1 = t1 ^ carry0;
        a2 = majority64(p1, q1, carry0);
    }

    u64 b0, b1, b2;
    {
        const u64 e  = (center >> 1) | (mid_right << 63);
        const u64 sw = (down << 1) | (down_left >> 63);
        const u64 s  = down;
        const u64 se = (down >> 1) | (down_right << 63);

        const u64 p0 = e ^ sw;
        const u64 p1 = e & sw;
        const u64 q0 = s ^ se;
        const u64 q1 = s & se;

        const u64 carry0 = p0 & q0;
        const u64 t1     = p1 ^ q1;

        b0 = p0 ^ q0;
        b1 = t1 ^ carry0;
        b2 = majority64(p1, q1, carry0);
    }

    const u64 bit0   = a0 ^ b0;
    const u64 carry0 = a0 & b0;
    const u64 t1     = a1 ^ b1;
    const u64 bit1   = t1 ^ carry0;
    const u64 carry1 = (a1 & b1) | (t1 & carry0);
    const u64 ge4    = a2 | b2 | carry1;

    return ~ge4 & bit1 & (bit0 | center);
}

template <int ShuffleWidth, bool CrossWarpX>
__global__ __launch_bounds__(kBlockSize)
void game_of_life_kernel(const u64* __restrict__ input,
                         u64* __restrict__ output,
                         std::size_t total_words,
                         unsigned int words_per_row,
                         unsigned int word_mask,
                         unsigned int word_shift,
                         unsigned int rows)
{
    static_assert(ShuffleWidth == 16 || ShuffleWidth == 32,
                  "ShuffleWidth must match the only two row-segment sizes used here");

    // CrossWarpX == false:
    //   The shuffle segment is the full row.
    //   This happens for 1024x1024 boards (16 words/row -> two 16-lane segments per warp)
    //   and 2048x2048 boards (32 words/row -> one 32-lane segment per warp).
    //
    // CrossWarpX == true:
    //   The row is wider than one 32-word warp segment.
    //   Only the first/last lane of each segment must fetch the missing horizontal word
    //   from global memory; all interior lanes get it from shuffles.

    const std::size_t row_stride  = static_cast<std::size_t>(words_per_row);
    const std::size_t grid_stride = static_cast<std::size_t>(gridDim.x) * static_cast<std::size_t>(kBlockSize);
    const unsigned int seg_lane   = static_cast<unsigned int>(threadIdx.x) & static_cast<unsigned int>(ShuffleWidth - 1);
    const unsigned int seg_last   = static_cast<unsigned int>(ShuffleWidth - 1);
    const unsigned int last_row   = rows - 1u;

    for (std::size_t idx = static_cast<std::size_t>(blockIdx.x) * static_cast<std::size_t>(kBlockSize) +
                           static_cast<std::size_t>(threadIdx.x);
         idx < total_words;
         idx += grid_stride)
    {
        const unsigned int y        = static_cast<unsigned int>(idx >> word_shift);
        const bool has_up           = (y != 0u);
        const bool has_down         = (y != last_row);

        // Every thread always loads only the vertically aligned words.
        const u64 center = input[idx];
        const u64 up     = has_up   ? input[idx - row_stride] : u64{0};
        const u64 down   = has_down ? input[idx + row_stride] : u64{0};

        // Horizontal neighbors come from the warp whenever possible.
        // ShuffleWidth is 16 for the 1024x1024 case and 32 otherwise.
        u64 mid_left   = __shfl_up_sync  (kFullWarpMask, center, 1, ShuffleWidth);
        u64 mid_right  = __shfl_down_sync(kFullWarpMask, center, 1, ShuffleWidth);
        u64 up_left    = __shfl_up_sync  (kFullWarpMask, up,     1, ShuffleWidth);
        u64 up_right   = __shfl_down_sync(kFullWarpMask, up,     1, ShuffleWidth);
        u64 down_left  = __shfl_up_sync  (kFullWarpMask, down,   1, ShuffleWidth);
        u64 down_right = __shfl_down_sync(kFullWarpMask, down,   1, ShuffleWidth);

        if (CrossWarpX) {
            // Only segment-edge lanes need special handling.
            if (seg_lane == 0u) {
                const bool has_left = ((static_cast<unsigned int>(idx) & word_mask) != 0u);

                mid_left  = has_left              ? input[idx - 1]                : u64{0};
                up_left   = (has_left && has_up)  ? input[idx - row_stride - 1]   : u64{0};
                down_left = (has_left && has_down)? input[idx + row_stride - 1]   : u64{0};
            } else if (seg_lane == seg_last) {
                const bool has_right = ((static_cast<unsigned int>(idx) & word_mask) != word_mask);

                mid_right  = has_right               ? input[idx + 1]               : u64{0};
                up_right   = (has_right && has_up)   ? input[idx - row_stride + 1]  : u64{0};
                down_right = (has_right && has_down) ? input[idx + row_stride + 1]  : u64{0};
            }
        } else {
            // Here each shuffle segment is an entire row, so segment boundaries are physical
            // grid boundaries and the missing words are simply dead.
            if (seg_lane == 0u) {
                mid_left  = u64{0};
                up_left   = u64{0};
                down_left = u64{0};
            } else if (seg_lane == seg_last) {
                mid_right  = u64{0};
                up_right   = u64{0};
                down_right = u64{0};
            }
        }

        output[idx] = evolve_word(center,
                                  up_left, up, up_right,
                                  mid_left, mid_right,
                                  down_left, down, down_right);
    }
}

} // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions) {
    // The caller guarantees valid cudaMalloc'ed device pointers.
    // Double-buffering is assumed: input and output must not alias.
    // No synchronization or error checking is inserted here because the caller explicitly owns that,
    // and avoiding extra host-side API traffic matters in tight multi-step simulations.

    if (grid_dimensions <= 0) {
        return;
    }

    const unsigned int rows          = static_cast<unsigned int>(grid_dimensions);
    const unsigned int words_per_row = rows >> kCellsPerWordShift;
    const unsigned int word_mask     = words_per_row - 1u;

    // Portable log2(words_per_row) for a power-of-two value.
    unsigned int word_shift = 0u;
    for (unsigned int t = words_per_row; t > 1u; t >>= 1u) {
        ++word_shift;
    }

    const std::size_t total_words =
        static_cast<std::size_t>(rows) * static_cast<std::size_t>(words_per_row);

    // Under the stated constraints:
    //   rows          = 2^n, n >= 10
    //   words_per_row = 2^(n-6)
    //   total_words   = 2^(2n-6)
    // so total_words is always a multiple of kBlockSize (256). That means there is no tail.
    const std::size_t blocks_needed = total_words / static_cast<std::size_t>(kBlockSize);
    const unsigned int blocks = static_cast<unsigned int>(
        (blocks_needed < static_cast<std::size_t>(kMaxBlocks))
            ? blocks_needed
            : static_cast<std::size_t>(kMaxBlocks));

    // Three launch variants cover every legal board size:
    //   16 words/row  -> 1024x1024 board, two independent 16-lane row segments per warp
    //   32 words/row  -> 2048x2048 board, one full row per warp
    //   >32 words/row -> wider rows, segment-edge lanes fetch cross-warp horizontal neighbors
    if (words_per_row == 16u) {
        game_of_life_kernel<16, false><<<blocks, kBlockSize>>>(
            input, output, total_words, words_per_row, word_mask, word_shift, rows);
    } else if (words_per_row == 32u) {
        game_of_life_kernel<32, false><<<blocks, kBlockSize>>>(
            input, output, total_words, words_per_row, word_mask, word_shift, rows);
    } else {
        game_of_life_kernel<32, true><<<blocks, kBlockSize>>>(
            input, output, total_words, words_per_row, word_mask, word_shift, rows);
    }
}

#include <cuda_runtime.h>
#include <cstddef>
#include <cstdint>

namespace {

using u64 = std::uint64_t;

constexpr int kBlockSize = 256;
constexpr unsigned int kLaunchWaves = 4;

/*
  Bit-sliced three-input add primitives.

  For each bit position across the 64-bit word, xor3() returns the low bit of the
  population count of (a, b, c), and majority3() returns the high/carry bit.
  On modern NVIDIA GPUs, current CUDA compilers lower these boolean forms well
  (typically to LOP3-based code per 32-bit half).
*/
__device__ __forceinline__ u64 xor3(const u64 a, const u64 b, const u64 c) {
    return a ^ b ^ c;
}

__device__ __forceinline__ u64 majority3(const u64 a, const u64 b, const u64 c) {
    return (a & b) | (c & (a | b));
}

/*
  One thread computes one packed 64-cell word.

  A flat 1D grid-stride kernel is used for two reasons:
    1) it avoids the grid.y launch limit for very large boards,
    2) words_per_row is a power of two, so recovering (x, y) from a flat word index
       is just a mask + shift instead of division/modulo.

  Bit ordering assumption:
    - Bit i of a 64-bit word corresponds to column (word_x * 64 + i).
    - Therefore:
        west  neighbor alignment is a left shift  (<< 1),
        east  neighbor alignment is a right shift (>> 1).

  X-boundary optimization:
    - Because words_per_row is a power of two, the left/right word index inside a row
      can be wrapped with (x +/- 1) & row_mask.
    - That keeps left/right neighbor-word loads always in-bounds and branch-free.
    - The only incorrect data introduced by this wrap is the single carry bit imported
      from the wrapped word on the true left/right borders; that carry bit is explicitly
      zeroed with lsb/msb carry masks.

  Y-boundary handling:
    - Only the top and bottom rows need special handling.
    - Those rows are a tiny fraction of the total work, so simple branches are cheaper
      than masking six extra loaded words for every interior thread.

  Count construction:
    - Top row (NW, N, NE)      -> 2-bit count: top_hi:top_lo
    - Bottom row (SW, S, SE)   -> 2-bit count: bot_hi:bot_lo
    - Middle row side cells
      (W, E)                   -> 2-bit count: side_hi:side_lo

    First add top + bottom exactly to a 3-bit partial sum sum2:sum1:sum0.
    Then add W + E with a specialized 2-input adder.

    Any neighbor count >= 4 is collapsed into ge4 because the Life rule only needs
    to distinguish:
      - count == 2
      - count == 3
      - count >= 4 / count < 2
*/
__global__ __launch_bounds__(256)
void game_of_life_kernel(const u64* __restrict__ input,
                         u64* __restrict__ output,
                         const std::size_t total_words,
                         const unsigned int words_per_row,
                         const unsigned int row_mask,
                         const unsigned int row_shift,
                         const unsigned int grid_dim) {
    const std::size_t thread_idx =
        static_cast<std::size_t>(blockIdx.x) * static_cast<std::size_t>(blockDim.x) +
        static_cast<std::size_t>(threadIdx.x);
    const std::size_t stride =
        static_cast<std::size_t>(blockDim.x) * static_cast<std::size_t>(gridDim.x);

    const std::size_t pitch = static_cast<std::size_t>(words_per_row);
    const std::size_t row_mask_sz = static_cast<std::size_t>(row_mask);
    const unsigned int last_word_x = row_mask;
    const unsigned int last_row = grid_dim - 1u;

    for (std::size_t idx = thread_idx; idx < total_words; idx += stride) {
        // Recover word coordinates from the flat word index.
        const unsigned int x = static_cast<unsigned int>(idx) & row_mask;
        const unsigned int y = static_cast<unsigned int>(idx >> row_shift);

        // Row base has all low row-index bits cleared because words_per_row is a power of two.
        const std::size_t row_base = idx & ~row_mask_sz;

        // Wrap x inside the row; true border carries are zeroed by the masks below.
        const unsigned int left_x = (x - 1u) & row_mask;
        const unsigned int right_x = (x + 1u) & row_mask;
        const std::size_t left_word_idx = row_base | static_cast<std::size_t>(left_x);
        const std::size_t right_word_idx = row_base | static_cast<std::size_t>(right_x);

        // Only the injected cross-word carry bit must be suppressed at the actual borders.
        const u64 lsb_carry_mask = static_cast<u64>(x != 0u);                  // 0 or 1 at bit 0
        const u64 msb_carry_mask = static_cast<u64>(x != last_word_x) << 63;   // 0 or 1 at bit 63

        const u64 center = input[idx];

        // Middle row side neighbors (W, E). The center cell itself is excluded here.
        const u64 west =
            (center << 1) | ((input[left_word_idx] >> 63) & lsb_carry_mask);
        const u64 east =
            (center >> 1) | ((input[right_word_idx] << 63) & msb_carry_mask);

        const u64 side_lo = west ^ east;   // bit 0 of (W + E)
        const u64 side_hi = west & east;   // bit 1 of (W + E)

        // Top row (NW, N, NE) -> 2-bit count.
        u64 top_lo = 0ULL;
        u64 top_hi = 0ULL;
        if (y != 0u) {
            const std::size_t up_idx = idx - pitch;
            const u64 north = input[up_idx];
            const u64 north_west =
                (north << 1) | ((input[left_word_idx - pitch] >> 63) & lsb_carry_mask);
            const u64 north_east =
                (north >> 1) | ((input[right_word_idx - pitch] << 63) & msb_carry_mask);

            top_lo = xor3(north_west, north, north_east);
            top_hi = majority3(north_west, north, north_east);
        }

        // Bottom row (SW, S, SE) -> 2-bit count.
        u64 bottom_lo = 0ULL;
        u64 bottom_hi = 0ULL;
        if (y != last_row) {
            const std::size_t down_idx = idx + pitch;
            const u64 south = input[down_idx];
            const u64 south_west =
                (south << 1) | ((input[left_word_idx + pitch] >> 63) & lsb_carry_mask);
            const u64 south_east =
                (south >> 1) | ((input[right_word_idx + pitch] << 63) & msb_carry_mask);

            bottom_lo = xor3(south_west, south, south_east);
            bottom_hi = majority3(south_west, south, south_east);
        }

        // Exact addition of top + bottom -> 3-bit partial sum sum2:sum1:sum0.
        const u64 sum0 = top_lo ^ bottom_lo;
        const u64 carry0 = top_lo & bottom_lo;
        const u64 sum1 = xor3(top_hi, bottom_hi, carry0);
        const u64 sum2 = majority3(top_hi, bottom_hi, carry0);

        // Add the middle-row side count (W + E).
        // side_hi and (sum0 & side_lo) are mutually exclusive, so they merge into one carry.
        const u64 carry1 = side_hi | (sum0 & side_lo);
        const u64 count_lo = sum0 ^ side_lo;
        const u64 count_hi = sum1 ^ carry1;
        const u64 ge4 = sum2 | (sum1 & carry1);

        // Conway rule in bit-sliced form:
        //   next = (count == 3) | (alive & count == 2)
        //        = (~ge4) & count_hi & (count_lo | alive)
        const u64 two_or_three = count_hi & ~ge4;
        output[idx] = two_or_three & (count_lo | center);
    }
}

} // namespace

/*
  Executes one Game-of-Life step.

  Notes:
    - input/output are assumed to be distinct device buffers (double-buffered update).
    - No synchronization is performed here; the caller explicitly manages that.
    - Host-side launch configuration work is intentionally done here because only the
      device-side step performance matters.
*/
void run_game_of_life(const std::uint64_t* input,
                      std::uint64_t* output,
                      int grid_dimensions) {
    const unsigned int grid_dim = static_cast<unsigned int>(grid_dimensions);
    const unsigned int words_per_row = grid_dim >> 6; // grid_dimensions is a power of two > 512, so divisible by 64.
    const std::size_t total_words =
        static_cast<std::size_t>(grid_dim) * static_cast<std::size_t>(words_per_row);

    if (total_words == 0) {
        return;
    }

    // log2(words_per_row); words_per_row is also a power of two.
    unsigned int row_shift = 0;
    for (unsigned int w = words_per_row; w > 1u; w >>= 1u) {
        ++row_shift;
    }

    // The kernel uses no shared memory, so prefer L1 for the read-heavy access pattern.
    cudaFuncSetCacheConfig(game_of_life_kernel, cudaFuncCachePreferL1);

    int device = 0;
    cudaGetDevice(&device);

    int sm_count = 0;
    cudaDeviceGetAttribute(&sm_count, cudaDevAttrMultiProcessorCount, device);
    if (sm_count < 1) {
        sm_count = 1;
    }

    int blocks_per_sm = 0;
    cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &blocks_per_sm, game_of_life_kernel, kBlockSize, 0);
    if (blocks_per_sm < 1) {
        blocks_per_sm = 1;
    }

    // Compact occupancy-sized launch + grid-stride loop:
    // avoids gigantic grids for very large boards while still keeping all SMs busy.
    const std::size_t max_blocks_needed =
        (total_words + static_cast<std::size_t>(kBlockSize) - 1u) /
        static_cast<std::size_t>(kBlockSize);

    std::size_t launch_blocks =
        static_cast<std::size_t>(sm_count) *
        static_cast<std::size_t>(blocks_per_sm) *
        static_cast<std::size_t>(kLaunchWaves);

    if (launch_blocks > max_blocks_needed) {
        launch_blocks = max_blocks_needed;
    }
    if (launch_blocks == 0) {
        launch_blocks = 1;
    }

    game_of_life_kernel<<<static_cast<unsigned int>(launch_blocks), kBlockSize>>>(
        input,
        output,
        total_words,
        words_per_row,
        words_per_row - 1u,
        row_shift,
        grid_dim);
}

#include <cstddef>
#include <cstdint>
#include <cuda_runtime.h>

// High-performance one-step Conway kernel for a bit-packed square grid.
// - One thread owns one 64-bit word = 64 cells, so no atomics are needed.
// - Shared/texture memory is intentionally avoided. The only profitable cross-thread reuse here is
//   horizontal word reuse inside a warp, and warp shuffles provide that more cheaply than shared memory.
// - Input and output are assumed to be distinct device buffers.

namespace {

constexpr unsigned int kCellsPerWordLog2 = 6u;  // 64 cells per packed word.

// Use an explicit 64-bit type that is guaranteed to work with 64-bit warp shuffle overloads.
// The public API still uses std::uint64_t.
using word_t = unsigned long long;
static_assert(sizeof(word_t) == sizeof(std::uint64_t), "Expected 64-bit packed words.");

// Host-side helper: x is always a power of two under the problem constraints.
inline unsigned int log2_pow2_u32(unsigned int x) {
    unsigned int s = 0u;
    while (x > 1u) {
        x >>= 1u;
        ++s;
    }
    return s;
}

// Bitwise half/full adders. The compiler maps these boolean forms efficiently on modern NVIDIA GPUs.
__device__ __forceinline__ void half_adder(word_t a, word_t b, word_t& sum, word_t& carry) {
    sum = a ^ b;
    carry = a & b;
}

__device__ __forceinline__ void full_adder(word_t a, word_t b, word_t c, word_t& sum, word_t& carry) {
    const word_t ab_xor = a ^ b;
    sum = ab_xor ^ c;
    carry = (a & b) | (c & ab_xor);
}

// Update one packed 64-cell word.
// Bit layout follows the prompt's natural mapping: bit i stores cell x+i within the row.
//
// Neighbor alignment for each bit position:
//   west  = (center << 1) | (left  >> 63)
//   east  = (center >> 1) | (right << 63)
// and likewise for the rows above and below.
//
// The 8 neighbor bitboards are reduced with a small carry-save tree so all 64 cells in the word are
// updated in parallel. If the final neighbor count is written as
//   count = b0 + 2*m
// then the Game of Life rule only cares about count == 2 or 3, i.e. m == 1. When m == 1, b0 tells
// 2 from 3, so
//   next = (m == 1) & (alive | b0).
__device__ __forceinline__ word_t evolve_word(word_t center,
                                              word_t left, word_t right,
                                              word_t above_left, word_t above, word_t above_right,
                                              word_t below_left, word_t below, word_t below_right) {
    word_t s0, c0;
    full_adder((above << 1) | (above_left >> 63),
               above,
               (above >> 1) | (above_right << 63),
               s0, c0);

    word_t s1, c1;
    full_adder((center << 1) | (left >> 63),
               (center >> 1) | (right << 63),
               (below << 1) | (below_left >> 63),
               s1, c1);

    word_t s2, c2;
    half_adder(below,
               (below >> 1) | (below_right << 63),
               s2, c2);

    word_t b0, sc;
    full_adder(s0, s1, s2, b0, sc);

    word_t t0, t1;
    full_adder(sc, c0, c1, t0, t1);

    const word_t count_is_2_or_3 = (t0 ^ c2) & ~t1;
    return count_is_2_or_3 & (center | b0);
}

template<int BX, int BY>
__global__ __launch_bounds__(256)
void game_of_life_kernel(const std::uint64_t* __restrict__ input,
                         std::uint64_t* __restrict__ output,
                         unsigned int grid_dim,
                         unsigned int words_per_row,
                         unsigned int tiles_per_row_mask,
                         unsigned int tiles_per_row_shift) {
    static_assert(BX == 16 || BX == 32, "BX must be 16 or 32 to match supported shuffle widths.");
    static_assert(BX * BY <= 256, "Block size must fit the launch-bounds contract.");

    // Flatten the logical 2D tile grid into blockIdx.x so very large grids do not depend on grid.y.
    const unsigned int tile_linear = blockIdx.x;
    const unsigned int tile_x = tile_linear & tiles_per_row_mask;
    const unsigned int tile_y = tile_linear >> tiles_per_row_shift;

    const unsigned int word_x = tile_x * BX + threadIdx.x;
    const unsigned int row = tile_y * BY + threadIdx.y;

    const std::size_t idx =
        static_cast<std::size_t>(row) * static_cast<std::size_t>(words_per_row) +
        static_cast<std::size_t>(word_x);

    const std::ptrdiff_t stride = static_cast<std::ptrdiff_t>(words_per_row);
    const std::uint64_t* const p = input + idx;

    const unsigned int last_word = words_per_row - 1u;
    const unsigned int last_row = grid_dim - 1u;

    // Because words_per_row is a power of two and BX exactly tiles the row, true row edges always
    // coincide with subgroup edges. Only subgroup-edge lanes ever need special left/right handling.
    const bool has_left = word_x > 0u;
    const bool has_right = word_x < last_word;
    const bool has_up = row > 0u;
    const bool has_down = row < last_row;

    // Load only the center word from the three relevant rows.
    const word_t center = static_cast<word_t>(p[0]);

    const std::uint64_t* up_ptr = nullptr;
    const std::uint64_t* down_ptr = nullptr;

    word_t above = 0ull;
    word_t below = 0ull;

    if (has_up) {
        up_ptr = p - stride;
        above = static_cast<word_t>(up_ptr[0]);
    }
    if (has_down) {
        down_ptr = p + stride;
        below = static_cast<word_t>(down_ptr[0]);
    }

    // Horizontal neighbor words come from warp shuffles.
    // - BX == 32: one subgroup == one warp row segment.
    // - BX == 16: the width argument partitions a warp into two independent half-warps.
    constexpr unsigned int kFullWarpMask = 0xffffffffu;
    constexpr unsigned int kLastLane = static_cast<unsigned int>(BX - 1);

    word_t left = __shfl_up_sync(kFullWarpMask, center, 1, BX);
    word_t right = __shfl_down_sync(kFullWarpMask, center, 1, BX);

    word_t above_left = __shfl_up_sync(kFullWarpMask, above, 1, BX);
    word_t above_right = __shfl_down_sync(kFullWarpMask, above, 1, BX);

    word_t below_left = __shfl_up_sync(kFullWarpMask, below, 1, BX);
    word_t below_right = __shfl_down_sync(kFullWarpMask, below, 1, BX);

    const unsigned int lane = threadIdx.x;

    // Subgroup-edge lanes need halo words from global memory because shuffles do not cross subgroup
    // boundaries. This also naturally handles true grid boundaries by substituting zero.
    if (lane == 0u) {
        left = 0ull;
        above_left = 0ull;
        below_left = 0ull;

        if (has_left) {
            left = static_cast<word_t>(p[-1]);
            if (has_up) {
                above_left = static_cast<word_t>(up_ptr[-1]);
            }
            if (has_down) {
                below_left = static_cast<word_t>(down_ptr[-1]);
            }
        }
    }

    if (lane == kLastLane) {
        right = 0ull;
        above_right = 0ull;
        below_right = 0ull;

        if (has_right) {
            right = static_cast<word_t>(p[1]);
            if (has_up) {
                above_right = static_cast<word_t>(up_ptr[1]);
            }
            if (has_down) {
                below_right = static_cast<word_t>(down_ptr[1]);
            }
        }
    }

    const word_t next =
        evolve_word(center, left, right, above_left, above, above_right, below_left, below, below_right);

    output[idx] = static_cast<std::uint64_t>(next);
}

template<int BX, int BY>
inline void launch_game_of_life_kernel(const std::uint64_t* input,
                                       std::uint64_t* output,
                                       unsigned int grid_dim,
                                       unsigned int words_per_row) {
    const unsigned int tiles_per_row = words_per_row / BX;  // Exact: both are powers of two.
    const unsigned int tiles_per_col = grid_dim / BY;       // Exact: BY is also a power of two.
    const unsigned int tiles_per_row_shift = log2_pow2_u32(tiles_per_row);

    const std::uint64_t total_tiles =
        static_cast<std::uint64_t>(tiles_per_row) * static_cast<std::uint64_t>(tiles_per_col);

    game_of_life_kernel<BX, BY><<<static_cast<unsigned int>(total_tiles), dim3(BX, BY, 1)>>>(
        input,
        output,
        grid_dim,
        words_per_row,
        tiles_per_row - 1u,
        tiles_per_row_shift);
}

}  // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions) {
    // The caller owns synchronization and error handling; this function only launches the kernel.
    const unsigned int grid_dim = static_cast<unsigned int>(grid_dimensions);
    const unsigned int words_per_row = grid_dim >> kCellsPerWordLog2;

    // Smallest legal grid: 1024x1024 => 16 packed words per row.
    // Use 16-lane subgroups there, but only 8 rows per block so the launch still exposes enough blocks
    // to occupy a large GPU. All larger grids use the common 32-lane path.
    if (words_per_row == 16u) {
        launch_game_of_life_kernel<16, 8>(input, output, grid_dim, words_per_row);
    } else {
        launch_game_of_life_kernel<32, 8>(input, output, grid_dim, words_per_row);
    }
}

#include <cstddef>
#include <cstdint>
#include <cuda_runtime.h>

// Optimized single-step Conway's Game of Life for a square, bit-packed board.
//
// Key implementation choices:
//
// 1. One CUDA thread owns one 64-bit word (64 cells), so every output word is
//    written exactly once and no atomics are needed.
//
// 2. One warp owns one horizontal tile of 32 consecutive words from a single row.
//    That mapping lets adjacent threads exchange left/right words with warp shuffles
//    instead of shared memory. Only warp-edge lanes fall back to an extra global load.
//
// 3. Outside-the-board cells are treated as dead by zero-filling missing neighbor
//    words at top/bottom/left/right boundaries.
//
// 4. Neighbor counts are computed bit-slicewise with carry-save adders, so each thread
//    updates all 64 cells in its word in parallel using integer logic only.
//
// 5. A 1D grid plus a grid-stride loop avoids the grid.y limit for very large boards
//    and avoids launching millions of tiny blocks on large inputs.

namespace gol_detail {

// Use a 64-bit unsigned type that is accepted by warp shuffle intrinsics across host ABIs.
using word_t = unsigned long long;
static_assert(sizeof(word_t) == sizeof(std::uint64_t), "Expected 64-bit words.");

constexpr int kWarpSize        = 32;
constexpr int kWarpShift       = 5;   // log2(32)
constexpr int kWordShift       = 6;   // log2(64)
constexpr int kWarpsPerBlock   = 8;
constexpr int kThreadsPerBlock = kWarpSize * kWarpsPerBlock;
constexpr unsigned int kMaxBlocks = 2048;  // Enough queued work for A100/H100-class GPUs.

static_assert(kThreadsPerBlock <= 1024, "Block size exceeds CUDA limits.");
static_assert((kThreadsPerBlock % kWarpSize) == 0, "Block must contain whole warps.");

__device__ __forceinline__ word_t load_word(const std::uint64_t* __restrict__ ptr, std::size_t idx) {
    return static_cast<word_t>(ptr[idx]);
}

// After alignment:
//   align_west(center, left): bit i == original cell (i-1)
//   align_east(center, right): bit i == original cell (i+1)
// For bit 0 / bit 63, the carry-in comes from the adjacent word or zero at the board edge.
__device__ __forceinline__ word_t align_west(word_t center, word_t left) {
    return (center << 1) | (left >> 63);
}

__device__ __forceinline__ word_t align_east(word_t center, word_t right) {
    return (center >> 1) | (right << 63);
}

// Carry-save adder for bit-sliced population counting:
//   a + b + c = lo + 2*hi
__device__ __forceinline__ void csa(word_t& hi, word_t& lo, word_t a, word_t b, word_t c) {
    const word_t u = a ^ b;
    hi = (a & b) | (u & c);
    lo = u ^ c;
}

// Exactly one of four one-bit bit-planes is set.
// Inputs are paired so we only need one "any" term and one "pair" term per pair.
__device__ __forceinline__ word_t exact_one_of_four(word_t a, word_t b, word_t c, word_t d) {
    const word_t ab_any = a | b;
    const word_t cd_any = c | d;
    return (ab_any ^ cd_any) & ~((a & b) | (c & d));
}

__global__ __launch_bounds__(kThreadsPerBlock)
void game_of_life_step_kernel(const std::uint64_t* __restrict__ input,
                              std::uint64_t* __restrict__ output,
                              int grid_dimensions,
                              std::uint64_t total_tiles,
                              int words_per_row,
                              int tiles_shift,
                              unsigned int tiles_mask) {
    const unsigned int lane          = threadIdx.x & (kWarpSize - 1);
    const unsigned int warp_in_block = threadIdx.x >> kWarpShift;

    std::uint64_t warp_idx =
        static_cast<std::uint64_t>(blockIdx.x) * static_cast<std::uint64_t>(kWarpsPerBlock) +
        static_cast<std::uint64_t>(warp_in_block);

    const std::uint64_t warp_stride =
        static_cast<std::uint64_t>(gridDim.x) * static_cast<std::uint64_t>(kWarpsPerBlock);

    for (; warp_idx < total_tiles; warp_idx += warp_stride) {
        // One warp == one 32-word tile from one row.
        const int row    = static_cast<int>(warp_idx >> tiles_shift);
        const int tile_x = static_cast<int>(warp_idx & static_cast<std::uint64_t>(tiles_mask));
        const int word_x = (tile_x << kWarpShift) + static_cast<int>(lane);

        // The only possible partial tile is the smallest legal board: 1024x1024,
        // which has 16 words per row. Let the upper half-warp peel off here;
        // __activemask() below then shrinks naturally to the participating lanes.
        if (word_x >= words_per_row) {
            continue;
        }

        const std::size_t pitch = static_cast<std::size_t>(words_per_row);
        const std::size_t idx   = static_cast<std::size_t>(row) * pitch + static_cast<std::size_t>(word_x);

        const bool has_up    = (row > 0);
        const bool has_down  = (row + 1 < grid_dimensions);
        const bool has_left  = (word_x > 0);
        const bool has_right = (word_x + 1 < words_per_row);

        // Each thread directly loads only the vertically aligned words.
        // Left/right words are fetched via shuffles whenever the neighbor is in the same warp tile.
        const word_t center = load_word(input, idx);
        const word_t north  = has_up   ? load_word(input, idx - pitch) : 0ULL;
        const word_t south  = has_down ? load_word(input, idx + pitch) : 0ULL;

        const unsigned int active = __activemask();

        // ---------------- Top row neighbors: NW, N, NE ----------------
        word_t tmp = __shfl_up_sync(active, north, 1);
        const word_t north_left_word =
            (lane != 0)
                ? tmp
                : ((has_up && has_left) ? load_word(input, idx - pitch - 1) : 0ULL);

        tmp = __shfl_down_sync(active, north, 1);
        const word_t north_right_word =
            (lane != kWarpSize - 1 && has_right)
                ? tmp
                : ((has_up && has_right) ? load_word(input, idx - pitch + 1) : 0ULL);

        word_t top1, top0;
        csa(top1, top0,
            align_west(north, north_left_word),
            north,
            align_east(north, north_right_word));

        // ---------------- Middle row neighbors: W, E ----------------
        // The center cell itself must not be counted.
        tmp = __shfl_up_sync(active, center, 1);
        const word_t left_word =
            (lane != 0)
                ? tmp
                : (has_left ? load_word(input, idx - 1) : 0ULL);

        tmp = __shfl_down_sync(active, center, 1);
        const word_t right_word =
            (lane != kWarpSize - 1 && has_right)
                ? tmp
                : (has_right ? load_word(input, idx + 1) : 0ULL);

        word_t mid1, mid0;
        csa(mid1, mid0,
            align_west(center, left_word),
            align_east(center, right_word),
            0ULL);

        // ---------------- Bottom row neighbors: SW, S, SE ----------------
        tmp = __shfl_up_sync(active, south, 1);
        const word_t south_left_word =
            (lane != 0)
                ? tmp
                : ((has_down && has_left) ? load_word(input, idx + pitch - 1) : 0ULL);

        tmp = __shfl_down_sync(active, south, 1);
        const word_t south_right_word =
            (lane != kWarpSize - 1 && has_right)
                ? tmp
                : ((has_down && has_right) ? load_word(input, idx + pitch + 1) : 0ULL);

        word_t bot1, bot0;
        csa(bot1, bot0,
            align_west(south, south_left_word),
            south,
            align_east(south, south_right_word));

        // Bit-sliced reduction:
        //
        //   top = top0 + 2*top1
        //   mid = mid0 + 2*mid1
        //   bot = bot0 + 2*bot1
        //
        // First add the low bits:
        //   top0 + mid0 + bot0 = sum0 + 2*carry0
        //
        // Therefore:
        //   count = sum0 + 2*(carry0 + top1 + mid1 + bot1)
        //
        // count is 2 or 3 iff exactly one of {carry0, top1, mid1, bot1} is set.
        // sum0 then distinguishes:
        //   sum0 = 0 -> count == 2
        //   sum0 = 1 -> count == 3
        word_t carry0, sum0;
        csa(carry0, sum0, top0, mid0, bot0);

        const word_t q_eq1 = exact_one_of_four(carry0, top1, mid1, bot1);
        const word_t eq3   = q_eq1 & sum0;
        const word_t eq2   = q_eq1 & ~sum0;

        // Conway rule:
        //   next = (count == 3) || (alive && count == 2)
        const word_t next = eq3 | (center & eq2);
        output[idx] = static_cast<std::uint64_t>(next);
    }
}

}  // namespace gol_detail

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions) {
    // grid_dimensions is a power of two and > 512.
    // Each 64-bit word stores 64 consecutive cells from a row.
    const int words_per_row = grid_dimensions >> gol_detail::kWordShift;

    // One warp covers 32 words horizontally, so the number of tiles per row is:
    //   ceil(words_per_row / 32)
    // Under the problem constraints, this is always a power of two:
    //   16 -> 1, 32 -> 1, 64 -> 2, 128 -> 4, ...
    const int tiles_per_row = (words_per_row + (gol_detail::kWarpSize - 1)) >> gol_detail::kWarpShift;
    const unsigned int tiles_mask = static_cast<unsigned int>(tiles_per_row - 1);

    // Because tiles_per_row is a power of two, row/tile decomposition in the kernel
    // can use a shift and a mask instead of division and modulo.
    int tiles_shift = 0;
    for (int t = tiles_per_row; t > 1; t >>= 1) {
        ++tiles_shift;
    }

    const std::uint64_t total_tiles =
        static_cast<std::uint64_t>(grid_dimensions) * static_cast<std::uint64_t>(tiles_per_row);

    // Cap the launch size and let the kernel grid-stride over tiles.
    // This keeps enough queued work to saturate modern data-center GPUs while
    // avoiding the overhead of launching millions of tiny blocks on very large boards.
    const std::uint64_t blocks_needed =
        (total_tiles + static_cast<std::uint64_t>(gol_detail::kWarpsPerBlock) - 1ULL) /
        static_cast<std::uint64_t>(gol_detail::kWarpsPerBlock);

    const unsigned int grid_x =
        static_cast<unsigned int>(blocks_needed < gol_detail::kMaxBlocks
                                      ? blocks_needed
                                      : static_cast<std::uint64_t>(gol_detail::kMaxBlocks));

    // No explicit synchronization or error polling here; the caller owns stream/error handling.
    gol_detail::game_of_life_step_kernel<<<grid_x, gol_detail::kThreadsPerBlock>>>(
        input,
        output,
        grid_dimensions,
        total_tiles,
        words_per_row,
        tiles_shift,
        tiles_mask);
}

#include <cuda_runtime.h>
#include <cstddef>
#include <cstdint>

namespace
{
using u64 = std::uint64_t;
constexpr unsigned int kFullWarpMask = 0xFFFFFFFFu;
constexpr int kCellsPerWord = 64;

/*
This kernel is optimized for the problem's actual performance-critical structure:

- The board is already bit-packed, so one thread updates one 64-bit word = 64 cells.
- A per-bit implementation can be improved with __popc/__popcll, but it still performs
  64 neighborhood counts per thread. On modern NVIDIA data-center GPUs, it is faster to
  keep the data packed and evaluate all 64 cells in parallel with bit-sliced logic.
- Shared memory and texture memory are intentionally avoided. The access pattern is regular,
  adjacent words are naturally exchanged with warp/half-warp shuffles, and the remaining
  loads are straightforward global reads.

The adder tree below computes the 8-neighbor count for all 64 cells at once:
  north trio  -> s0 + 2*c0
  south trio  -> s1 + 2*c1
  west+east   -> s2 + 2*c2

Then:
  total_neighbors = s0+s1+s2 + 2*(c0+c1+c2)
                  = ones + 2*(twos_a + sum_twos + 2*carry_twos)

Life needs total_neighbors == 2 or 3.
That means the parenthesized term must be exactly 1, and the low bit (ones) determines
whether it is 2 (ones=0) or 3 (ones=1). The final rule therefore becomes:
  next = exact_two_or_three & (ones | current)
where exact_two_or_three = ((twos_a ^ sum_twos) & ~carry_twos).
*/

// Carry-save adder over 64 independent 1-bit lanes.
// For each bit position i:
//   a_i + b_i + c_i = sum_i + 2 * carry_i
__device__ __forceinline__ void csa64(const u64 a, const u64 b, const u64 c, u64& sum, u64& carry)
{
    const u64 ab = a ^ b;
    sum = ab ^ c;
    carry = (a & b) | (ab & c);
}

// Finish the Life rule once the neighborhood has been reduced to the three partial counters:
//   north = s0 + 2*c0
//   south = s1 + 2*c1
//   horiz = s2 + 2*c2
__device__ __forceinline__ u64 finish_word(const u64 current,
                                           const u64 s0, const u64 c0,
                                           const u64 s1, const u64 c1,
                                           const u64 s2, const u64 c2)
{
    u64 ones, twos_a;
    csa64(s0, s1, s2, ones, twos_a);

    u64 sum_twos, carry_twos;
    csa64(c0, c1, c2, sum_twos, carry_twos);

    const u64 exact_two_or_three = (twos_a ^ sum_twos) & ~carry_twos;
    return exact_two_or_three & (ones | current);
}

/*
Interior path:
- No boundary checks.
- Adjacent packed words are obtained from neighboring lanes with __shfl*_sync.
- BLOCK_X is both the block width and the shuffle subgroup width:
    * 32 -> one full warp per row segment
    * 16 -> one half-warp per row segment
  This keeps left/right exchanges within a single row segment.
*/
template <int BLOCK_X>
__device__ __forceinline__ u64 evolve_shfl_interior(const u64* __restrict__ input,
                                                    std::size_t idx,
                                                    int words_per_row)
{
    static_assert(BLOCK_X == 16 || BLOCK_X == 32, "BLOCK_X must be 16 or 32");

    const u64* __restrict__ p = input + idx;
    const int stride = words_per_row;
    const int lane_in_row = static_cast<int>(threadIdx.x);

    const u64 current = p[0];

    u64 s2, c2;
    {
        u64 left_word  = __shfl_up_sync(kFullWarpMask, current, 1, BLOCK_X);
        u64 right_word = __shfl_down_sync(kFullWarpMask, current, 1, BLOCK_X);

        if (lane_in_row == 0) {
            left_word = p[-1];
        }
        if (lane_in_row == BLOCK_X - 1) {
            right_word = p[1];
        }

        const u64 west = (current << 1) | (left_word >> 63);
        const u64 east = (current >> 1) | (right_word << 63);

        s2 = west ^ east;
        c2 = west & east;
    }

    u64 s0, c0;
    {
        const u64 up = p[-stride];

        u64 up_left_word  = __shfl_up_sync(kFullWarpMask, up, 1, BLOCK_X);
        u64 up_right_word = __shfl_down_sync(kFullWarpMask, up, 1, BLOCK_X);

        if (lane_in_row == 0) {
            up_left_word = p[-stride - 1];
        }
        if (lane_in_row == BLOCK_X - 1) {
            up_right_word = p[-stride + 1];
        }

        const u64 north_west = (up << 1) | (up_left_word >> 63);
        const u64 north_east = (up >> 1) | (up_right_word << 63);

        csa64(north_west, up, north_east, s0, c0);
    }

    u64 s1, c1;
    {
        const u64 down = p[stride];

        u64 down_left_word  = __shfl_up_sync(kFullWarpMask, down, 1, BLOCK_X);
        u64 down_right_word = __shfl_down_sync(kFullWarpMask, down, 1, BLOCK_X);

        if (lane_in_row == 0) {
            down_left_word = p[stride - 1];
        }
        if (lane_in_row == BLOCK_X - 1) {
            down_right_word = p[stride + 1];
        }

        const u64 south_west = (down << 1) | (down_left_word >> 63);
        const u64 south_east = (down >> 1) | (down_right_word << 63);

        csa64(south_west, down, south_east, s1, c1);
    }

    return finish_word(current, s0, c0, s1, c1, s2, c2);
}

/*
Boundary path:
- Same shuffle-based structure as the interior path.
- Missing words outside the board are replaced with zero, implementing the required
  "outside the grid is dead" semantics.
- Only boundary blocks take this path, so a few extra predicates are acceptable.
*/
template <int BLOCK_X>
__device__ __forceinline__ u64 evolve_shfl_boundary(const u64* __restrict__ input,
                                                    std::size_t idx,
                                                    int row,
                                                    int col,
                                                    int grid_dimensions,
                                                    int words_per_row)
{
    static_assert(BLOCK_X == 16 || BLOCK_X == 32, "BLOCK_X must be 16 or 32");

    const u64* __restrict__ p = input + idx;
    const int stride = words_per_row;
    const int lane_in_row = static_cast<int>(threadIdx.x);

    const int last_row  = grid_dimensions - 1;
    const int last_word = words_per_row - 1;

    const bool has_up   = (row != 0);
    const bool has_down = (row != last_row);

    const u64 current = p[0];

    u64 s2, c2;
    {
        u64 left_word  = __shfl_up_sync(kFullWarpMask, current, 1, BLOCK_X);
        u64 right_word = __shfl_down_sync(kFullWarpMask, current, 1, BLOCK_X);

        if (lane_in_row == 0) {
            left_word = (col != 0) ? p[-1] : u64{0};
        }
        if (lane_in_row == BLOCK_X - 1) {
            right_word = (col != last_word) ? p[1] : u64{0};
        }

        const u64 west = (current << 1) | (left_word >> 63);
        const u64 east = (current >> 1) | (right_word << 63);

        s2 = west ^ east;
        c2 = west & east;
    }

    u64 s0, c0;
    {
        const u64 up = has_up ? p[-stride] : u64{0};

        u64 up_left_word  = __shfl_up_sync(kFullWarpMask, up, 1, BLOCK_X);
        u64 up_right_word = __shfl_down_sync(kFullWarpMask, up, 1, BLOCK_X);

        if (lane_in_row == 0) {
            up_left_word = (has_up && (col != 0)) ? p[-stride - 1] : u64{0};
        }
        if (lane_in_row == BLOCK_X - 1) {
            up_right_word = (has_up && (col != last_word)) ? p[-stride + 1] : u64{0};
        }

        const u64 north_west = (up << 1) | (up_left_word >> 63);
        const u64 north_east = (up >> 1) | (up_right_word << 63);

        csa64(north_west, up, north_east, s0, c0);
    }

    u64 s1, c1;
    {
        const u64 down = has_down ? p[stride] : u64{0};

        u64 down_left_word  = __shfl_up_sync(kFullWarpMask, down, 1, BLOCK_X);
        u64 down_right_word = __shfl_down_sync(kFullWarpMask, down, 1, BLOCK_X);

        if (lane_in_row == 0) {
            down_left_word = (has_down && (col != 0)) ? p[stride - 1] : u64{0};
        }
        if (lane_in_row == BLOCK_X - 1) {
            down_right_word = (has_down && (col != last_word)) ? p[stride + 1] : u64{0};
        }

        const u64 south_west = (down << 1) | (down_left_word >> 63);
        const u64 south_east = (down >> 1) | (down_right_word << 63);

        csa64(south_west, down, south_east, s1, c1);
    }

    return finish_word(current, s0, c0, s1, c1, s2, c2);
}

/*
The kernel is launched as a 1D grid of 2D blocks.

Why 1D blocks-in-grid instead of a conventional 2D grid?
- It avoids the legacy 2D-grid Y-dimension limit for very large boards.
- The board width in packed words is a power of two, and BLOCK_X is also a power of two,
  so blocks_per_row is a power of two.
- That lets the kernel recover (block_row, block_col) from blockIdx.x using one shift
  and one mask instead of division/modulo.
*/
template <int BLOCK_X, int BLOCK_Y>
__global__ __launch_bounds__(BLOCK_X * BLOCK_Y)
void game_of_life_kernel(const u64* __restrict__ input,
                         u64* __restrict__ output,
                         int grid_dimensions,
                         int words_per_row,
                         int blocks_per_row,
                         int blocks_per_row_log2,
                         int block_rows)
{
    static_assert(BLOCK_X * BLOCK_Y == 256, "Block configuration must contain exactly 256 threads");
    static_assert((BLOCK_X & (BLOCK_X - 1)) == 0, "BLOCK_X must be a power of two");

    const unsigned int block_linear = blockIdx.x;
    const int block_col = static_cast<int>(block_linear & static_cast<unsigned int>(blocks_per_row - 1));
    const int block_row = static_cast<int>(block_linear >> blocks_per_row_log2);

    const int col = block_col * BLOCK_X + static_cast<int>(threadIdx.x);
    const int row = block_row * BLOCK_Y + static_cast<int>(threadIdx.y);

    const std::size_t idx =
        static_cast<std::size_t>(row) * static_cast<std::size_t>(words_per_row) +
        static_cast<std::size_t>(col);

    const bool block_interior =
        (block_col > 0) && (block_col + 1 < blocks_per_row) &&
        (block_row > 0) && (block_row + 1 < block_rows);

    if (block_interior) {
        output[idx] = evolve_shfl_interior<BLOCK_X>(input, idx, words_per_row);
    } else {
        output[idx] = evolve_shfl_boundary<BLOCK_X>(input, idx, row, col, grid_dimensions, words_per_row);
    }
}

// Host-side utility; this is not on the measured path.
inline int log2_power_of_two(unsigned int x)
{
    int s = 0;
    while ((1u << s) < x) {
        ++s;
    }
    return s;
}

} // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions)
{
    // The caller is expected to provide distinct ping-pong buffers and handle synchronization.
    // The launch itself is intentionally asynchronous.

    const int words_per_row = grid_dimensions >> 6; // grid_dimensions / 64

    // Two tuned shapes:
    //   32x8  -> one full warp updates one row segment of 32 packed words
    //   16x16 -> one half-warp updates one row segment of 16 packed words
    //
    // Because the board dimensions are powers of two and > 512, these tile the board exactly.
    if (words_per_row >= 32) {
        constexpr int BLOCK_X = 32;
        constexpr int BLOCK_Y = 8;

        const int blocks_per_row = words_per_row / BLOCK_X;
        const int block_rows = grid_dimensions / BLOCK_Y;
        const int blocks_per_row_log2 = log2_power_of_two(static_cast<unsigned int>(blocks_per_row));
        const unsigned int total_blocks =
            static_cast<unsigned int>(static_cast<std::size_t>(blocks_per_row) *
                                      static_cast<std::size_t>(block_rows));

        const dim3 block(BLOCK_X, BLOCK_Y);
        const dim3 grid(total_blocks);

        game_of_life_kernel<BLOCK_X, BLOCK_Y><<<grid, block>>>(
            input,
            output,
            grid_dimensions,
            words_per_row,
            blocks_per_row,
            blocks_per_row_log2,
            block_rows);
    } else {
        constexpr int BLOCK_X = 16;
        constexpr int BLOCK_Y = 16;

        const int blocks_per_row = words_per_row / BLOCK_X;
        const int block_rows = grid_dimensions / BLOCK_Y;
        const int blocks_per_row_log2 = log2_power_of_two(static_cast<unsigned int>(blocks_per_row));
        const unsigned int total_blocks =
            static_cast<unsigned int>(static_cast<std::size_t>(blocks_per_row) *
                                      static_cast<std::size_t>(block_rows));

        const dim3 block(BLOCK_X, BLOCK_Y);
        const dim3 grid(total_blocks);

        game_of_life_kernel<BLOCK_X, BLOCK_Y><<<grid, block>>>(
            input,
            output,
            grid_dimensions,
            words_per_row,
            blocks_per_row,
            blocks_per_row_log2,
            block_rows);
    }
}

#include <cuda_runtime.h>
#include <cstddef>
#include <cstdint>

// High-throughput Conway's Game of Life step for a bit-packed square grid.
//
// Design choices driven purely by performance on modern data-center GPUs:
// - One CUDA thread updates exactly one 64-bit word (64 cells), so no atomics are needed.
// - Shared memory is intentionally avoided: each thread touches only a 3x3 word neighborhood,
//   and the hardware caches on A100/H100-class GPUs handle the reuse well enough that extra
//   staging usually adds complexity without helping.
// - A naive implementation would iterate over 64 bits and use __popc/__popcll on extracted
//   neighborhoods. That is much better than scalar per-cell masking, but a fully bit-sliced
//   implementation is faster still: it updates all 64 cells in parallel using Boolean ops and
//   a carry-save adder tree.
//
// Bit layout assumption used here:
// - Bit i in a 64-bit word corresponds to column (word_base + i).
// - Therefore, shifting a row word left by 1 aligns the west neighbor for each cell lane.
// - Shifting a row word right by 1 aligns the east neighbor for each cell lane.

namespace {
using u64 = std::uint64_t;

constexpr int kBlockSize = 256;

// Align the west neighbor of every cell in a 64-bit word into the current word's bit lanes.
// left_word contributes only to bit 0 (the cross-word boundary case).
__device__ __forceinline__ u64 align_west(u64 center_word, u64 left_word) {
    return (center_word << 1) | (left_word >> 63);
}

// Align the east neighbor of every cell in a 64-bit word into the current word's bit lanes.
// right_word contributes only to bit 63 (the cross-word boundary case).
__device__ __forceinline__ u64 align_east(u64 center_word, u64 right_word) {
    return (center_word >> 1) | (right_word << 63);
}

// 64-lane carry-save adder.
// For every bit position i independently:
//     a_i + b_i + c_i = sum_i + 2 * carry_i
//
// This is the core primitive that lets us sum eight 1-bit neighbor bitboards for 64 cells
// in parallel without looping over the individual bits.
__device__ __forceinline__ void csa(u64& carry, u64& sum, u64 a, u64 b, u64 c) {
    const u64 ab_xor = a ^ b;
    carry = (a & b) | (ab_xor & c);
    sum   = ab_xor ^ c;
}

__global__ __launch_bounds__(kBlockSize)
void game_of_life_kernel(const u64* __restrict__ input,
                         u64* __restrict__ output,
                         std::size_t total_words,
                         std::size_t stride_words) {
    const std::size_t linear =
        static_cast<std::size_t>(blockIdx.x) * static_cast<std::size_t>(blockDim.x) +
        static_cast<std::size_t>(threadIdx.x);

    if (linear >= total_words) {
        return;
    }

    // Because the grid width is a power of two and divisible by 64, the number of 64-bit words
    // per row is also a power of two. That makes x-within-row a cheap bit-mask operation.
    const std::size_t row_mask = stride_words - 1;
    const std::size_t x_in_row = linear & row_mask;

    const bool has_left  = x_in_row != 0;
    const bool has_right = x_in_row != row_mask;
    const bool has_up    = linear >= stride_words;
    const bool has_down  = linear < (total_words - stride_words);

    const u64 center = input[linear];

    // Same-row neighbor words. Outside-grid words are treated as zero.
    u64 left_word  = 0;
    u64 right_word = 0;
    if (has_left)  left_word  = input[linear - 1];
    if (has_right) right_word = input[linear + 1];

    // Same-row aligned neighbor bitboards.
    const u64 west = align_west(center, left_word);
    const u64 east = align_east(center, right_word);

    // Top row: produce two bitboards representing the per-cell sum of (NW, N, NE):
    //   top_sum   = low bit of that 0..3 count
    //   top_carry = high bit of that 0..3 count
    u64 top_sum   = 0;
    u64 top_carry = 0;
    if (has_up) {
        const std::size_t up = linear - stride_words;

        const u64 up_center = input[up];
        u64 up_left  = 0;
        u64 up_right = 0;
        if (has_left)  up_left  = input[up - 1];
        if (has_right) up_right = input[up + 1];

        csa(top_carry, top_sum,
            align_west(up_center, up_left),
            up_center,
            align_east(up_center, up_right));
    }

    // Bottom row: same idea for (SW, S, SE).
    u64 bottom_sum   = 0;
    u64 bottom_carry = 0;
    if (has_down) {
        const std::size_t down = linear + stride_words;

        const u64 down_center = input[down];
        u64 down_left  = 0;
        u64 down_right = 0;
        if (has_left)  down_left  = input[down - 1];
        if (has_right) down_right = input[down + 1];

        csa(bottom_carry, bottom_sum,
            align_west(down_center, down_left),
            down_center,
            align_east(down_center, down_right));
    }

    // Middle row contributes only W and E.
    // For each cell lane:
    //   west_i + east_i = middle_sum_i + 2 * middle_carry_i
    const u64 middle_sum   = west ^ east;
    const u64 middle_carry = west & east;

    // Combine the three low-bit sources (top_sum, bottom_sum, middle_sum).
    // Result:
    //   ones   = 1's bit of the total 0..8 neighbor count
    //   carry2 = carry into the 2's place from those low-bit additions
    u64 carry2 = 0;
    u64 ones   = 0;
    csa(carry2, ones, top_sum, bottom_sum, middle_sum);

    // Combine the existing 2's-place contributors.
    // Result:
    //   twos_base = one source of the 2's bit
    //   carry4    = carry into the 4's place
    u64 carry4   = 0;
    u64 twos_base = 0;
    csa(carry4, twos_base, top_carry, bottom_carry, middle_carry);

    // Merge the two different sources of the 2's bit.
    const u64 twos = twos_base ^ carry2;
    const u64 carry4_from_twos = twos_base & carry2;

    // Final 4's and 8's bits of the 0..8 neighbor count.
    const u64 fours  = carry4 ^ carry4_from_twos;
    const u64 eights = carry4 & carry4_from_twos;

    // Conway rule in bit-sliced form:
    // - count == 3  => ones=1, twos=1, higher bits clear => cell becomes alive
    // - count == 2  => ones=0, twos=1, higher bits clear => cell keeps current state
    //
    // Therefore:
    //   count in {2,3} <=> twos == 1 and no 4's/8's bits are set
    //   next = (count==3) | (current & count==2)
    //        = count_is_2_or_3 & (ones | current)
    const u64 count_is_2_or_3 = twos & ~(fours | eights);
    output[linear] = count_is_2_or_3 & (ones | center);
}
}  // namespace

void run_game_of_life(const std::uint64_t* input,
                      std::uint64_t* output,
                      int grid_dimensions) {
    // Expected by contract:
    // - input and output are device pointers allocated by cudaMalloc
    // - input and output do not alias (Game of Life is not an in-place update)
    // - grid_dimensions is the width/height of the square grid
    // - grid_dimensions is a power of two, > 512, and thus divisible by 64
    //
    // The launch is intentionally asynchronous. No error checking or synchronization is done here
    // because the caller owns stream ordering and synchronization policy.

    const std::size_t n = static_cast<std::size_t>(grid_dimensions);
    const std::size_t stride_words = n >> 6;       // grid_dimensions / 64
    const std::size_t total_words  = n * stride_words;

    const unsigned int blocks = static_cast<unsigned int>(
        (total_words + static_cast<std::size_t>(kBlockSize) - 1) /
        static_cast<std::size_t>(kBlockSize));

    game_of_life_kernel<<<blocks, kBlockSize>>>(input, output, total_words, stride_words);
}

#include <cstddef>
#include <cstdint>
#include <cuda_runtime.h>

namespace {

constexpr int kCellsPerWordShift = 6;  // 2^6 == 64 cells per packed word.
constexpr int kThreadsPerBlock   = 256;

// The public API uses std::uint64_t exactly as requested. Internally we use
// unsigned long long for the bitwise/shuffle math because CUDA explicitly
// guarantees shuffle support for that 64-bit type.
using storage_t = std::uint64_t;
using word_t    = unsigned long long;

__device__ __forceinline__ word_t xor3(const word_t a, const word_t b, const word_t c) {
    return a ^ b ^ c;
}

__device__ __forceinline__ word_t maj3(const word_t a, const word_t b, const word_t c) {
    return (a & b) | (a & c) | (b & c);
}

// Host-side setup cost is not performance-critical for this task, so a tiny
// portable helper loop is fine here.
inline int log2_pow2(unsigned int x) {
    int shift = 0;
    while (x > 1u) {
        x >>= 1u;
        ++shift;
    }
    return shift;
}

/*
 * Each thread updates one 64-bit packed word (64 cells).
 *
 * A straightforward "one thread per word" implementation still loops over the
 * 64 bit positions and uses masked popcount operations for each cell. The prompt
 * mentions popcount as an improvement over naive masking, but on modern NVIDIA
 * GPUs it is still slower than treating the 64 bits of a word as 64 SIMD lanes
 * and updating all of them at once.
 *
 * This kernel therefore:
 *   1) Loads the current word plus the vertical neighbors (row above/below).
 *   2) Uses warp shuffles to obtain the left/right words for those three rows.
 *      Only subgroup-boundary threads need fallback global loads. This removes
 *      the six extra global loads that a naive per-thread halo load would do.
 *   3) Builds the eight aligned neighbor bitboards (NW, N, NE, W, E, SW, S, SE).
 *   4) Adds those eight 1-bit bitboards with a carry-save / bit-sliced boolean
 *      network, producing the 1's, 2's, and 4's place of the neighbor count for
 *      all 64 cells in parallel.
 *   5) Applies the Life rule with pure bitwise logic.
 *
 * BLOCK_X is either:
 *   - 32 (kernel shape 32x8): one warp == one 32-word row segment.
 *   - 16 (kernel shape 16x16): width-16 shuffles split each warp into two
 *     independent 16-lane groups, which exactly match the smallest legal board
 *     width (1024 cells => 16 packed words per row).
 *
 * A 1D grid of 2D blocks is used so very tall boards do not hit grid.y limits.
 * Because the board width is a power-of-two and BLOCK_X is a power-of-two,
 * blocks_per_row is also a power-of-two. The kernel reconstructs
 * (block_row, block_col) from blockIdx.x with a shift and a mask instead of
 * division and modulo.
 */
template <int BLOCK_X, int BLOCK_Y>
__global__ __launch_bounds__(kThreadsPerBlock)
void game_of_life_kernel(const storage_t* __restrict__ input,
                         storage_t* __restrict__ output,
                         int grid_dimensions,
                         int words_per_row,
                         int blocks_per_row_shift,
                         int blocks_per_row_mask)
{
    static_assert(BLOCK_X * BLOCK_Y == kThreadsPerBlock, "Kernel tuned for 256-thread blocks.");
    static_assert(BLOCK_X == 16 || BLOCK_X == 32, "Unsupported block width.");

    const unsigned int block_linear = blockIdx.x;
    const int block_row = static_cast<int>(block_linear >> blocks_per_row_shift);
    const int block_col = static_cast<int>(block_linear & static_cast<unsigned int>(blocks_per_row_mask));

    const int row = block_row * BLOCK_Y + static_cast<int>(threadIdx.y);
    const int col = block_col * BLOCK_X + static_cast<int>(threadIdx.x);

    const std::size_t stride = static_cast<std::size_t>(words_per_row);
    const std::size_t idx = static_cast<std::size_t>(row) * stride + static_cast<std::size_t>(col);

    const int last_row = grid_dimensions - 1;
    const bool has_up   = (row != 0);
    const bool has_down = (row != last_row);

    const std::size_t idx_up   = idx - stride;
    const std::size_t idx_down = idx + stride;

    // Common-case memory traffic per thread is only three loads: current row,
    // row above, and row below.
    const word_t center = static_cast<word_t>(input[idx]);
    const word_t up     = has_up   ? static_cast<word_t>(input[idx_up])   : 0ULL;
    const word_t down   = has_down ? static_cast<word_t>(input[idx_down]) : 0ULL;

    // Exchange the three loaded words horizontally inside the subgroup.
    // width == BLOCK_X keeps the 16-wide special case confined to independent
    // half-warps and the 32-wide case as a full warp.
    const unsigned int shuffle_mask = 0xffffffffu;
    word_t left_center  = __shfl_up_sync  (shuffle_mask, center, 1, BLOCK_X);
    word_t right_center = __shfl_down_sync(shuffle_mask, center, 1, BLOCK_X);
    word_t left_up      = __shfl_up_sync  (shuffle_mask, up,     1, BLOCK_X);
    word_t right_up     = __shfl_down_sync(shuffle_mask, up,     1, BLOCK_X);
    word_t left_down    = __shfl_up_sync  (shuffle_mask, down,   1, BLOCK_X);
    word_t right_down   = __shfl_down_sync(shuffle_mask, down,   1, BLOCK_X);

    const int lane = static_cast<int>(threadIdx.x);

    if (BLOCK_X == 16) {
        // This specialization is only launched when words_per_row == 16, so each
        // 16-lane subgroup spans the full row and its horizontal halo is outside
        // the board.
        if (lane == 0) {
            left_center = 0ULL;
            left_up     = 0ULL;
            left_down   = 0ULL;
        }
        if (lane == 15) {
            right_center = 0ULL;
            right_up     = 0ULL;
            right_down   = 0ULL;
        }
    } else {
        // For the 32x8 kernel, subgroup boundaries may lie inside a row. Only
        // the boundary threads need fallback global loads to cross from one
        // 32-word segment to the next.
        const int last_col = words_per_row - 1;
        const bool has_left  = (col != 0);
        const bool has_right = (col != last_col);

        if (lane == 0) {
            left_center = has_left ? static_cast<word_t>(input[idx - 1]) : 0ULL;
            left_up     = (has_up   && has_left) ? static_cast<word_t>(input[idx_up   - 1]) : 0ULL;
            left_down   = (has_down && has_left) ? static_cast<word_t>(input[idx_down - 1]) : 0ULL;
        }
        if (lane == 31) {
            right_center = has_right ? static_cast<word_t>(input[idx + 1]) : 0ULL;
            right_up     = (has_up   && has_right) ? static_cast<word_t>(input[idx_up   + 1]) : 0ULL;
            right_down   = (has_down && has_right) ? static_cast<word_t>(input[idx_down + 1]) : 0ULL;
        }
    }

    // Align the eight neighbor directions so bit i corresponds to the i-th cell
    // in 'center'. The 0th and 63rd bits automatically pick up their halo bits
    // from the left/right words handled above.
    const word_t nw   = (up     << 1) | (left_up      >> 63);
    const word_t ne   = (up     >> 1) | (right_up     << 63);
    const word_t west = (center << 1) | (left_center  >> 63);
    const word_t east = (center >> 1) | (right_center << 63);
    const word_t sw   = (down   << 1) | (left_down    >> 63);
    const word_t se   = (down   >> 1) | (right_down   << 63);

    // Add the eight 1-bit neighbor bitboards in parallel across all 64 lanes.
    // We keep only the 1's, 2's, and 4's place of the count. Count==8 would
    // require the 8's place, but it has the 2's place clear, so it is already
    // rejected by the final Life rule expression.
    const word_t p0 = nw ^ up;
    const word_t q0 = nw & up;
    const word_t p1 = ne ^ west;
    const word_t q1 = ne & west;

    const word_t s0 = p0 ^ p1;
    const word_t k0 = p0 & p1;
    const word_t t0 = xor3(q0, q1, k0);
    const word_t f0 = maj3(q0, q1, k0);

    const word_t p2 = east ^ sw;
    const word_t q2 = east & sw;
    const word_t p3 = down ^ se;
    const word_t q3 = down & se;

    const word_t s1 = p2 ^ p3;
    const word_t k1 = p2 & p3;
    const word_t t1 = xor3(q2, q3, k1);
    const word_t f1 = maj3(q2, q3, k1);

    // cnt1/cnt2/cnt4 are the 1's, 2's, and 4's place of the neighbor count.
    const word_t cnt1 = s0 ^ s1;
    const word_t k2   = s0 & s1;
    const word_t cnt2 = xor3(t0, t1, k2);
    const word_t k3   = maj3(t0, t1, k2);
    const word_t cnt4 = xor3(f0, f1, k3);

    // Conway's Game of Life:
    //   next = (count == 3) | (alive & count == 2)
    //
    // In terms of the count bitplanes:
    //   count in {2,3} <=> cnt2 == 1 and cnt4 == 0
    //   among those, count == 3 iff cnt1 == 1
    //
    // Therefore:
    //   next = (cnt2 & ~cnt4) & (cnt1 | center)
    const word_t next = (cnt2 & ~cnt4) & (cnt1 | center);
    output[idx] = static_cast<storage_t>(next);
}

template <int BLOCK_X, int BLOCK_Y>
inline void launch_game_of_life_kernel(const storage_t* input,
                                       storage_t* output,
                                       int grid_dimensions,
                                       int words_per_row)
{
    static_assert(BLOCK_X * BLOCK_Y == kThreadsPerBlock, "Kernel tuned for 256-thread blocks.");

    // Given the problem constraints:
    //   - grid_dimensions is a power-of-two
    //   - words_per_row = grid_dimensions / 64 is therefore a power-of-two
    //   - BLOCK_X and BLOCK_Y are powers-of-two
    // Hence blocks_per_row and block_rows are exact powers-of-two as well.
    const int blocks_per_row = words_per_row / BLOCK_X;
    const int block_rows = grid_dimensions / BLOCK_Y;
    const int blocks_per_row_shift = log2_pow2(static_cast<unsigned int>(blocks_per_row));
    const int blocks_per_row_mask = blocks_per_row - 1;

    const unsigned int total_blocks = static_cast<unsigned int>(
        static_cast<std::uint64_t>(blocks_per_row) *
        static_cast<std::uint64_t>(block_rows));

    const dim3 grid(total_blocks, 1, 1);
    const dim3 block(BLOCK_X, BLOCK_Y, 1);

    game_of_life_kernel<BLOCK_X, BLOCK_Y>
        <<<grid, block>>>(input,
                          output,
                          grid_dimensions,
                          words_per_row,
                          blocks_per_row_shift,
                          blocks_per_row_mask);
}

}  // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions)
{
    // One 64-bit word stores 64 consecutive cells from a single row.
    const int words_per_row = grid_dimensions >> kCellsPerWordShift;

    // No synchronization or error handling here by design: the caller owns
    // synchronization, and only kernel performance matters for this task.
    if (words_per_row == 16) {
        // Smallest legal board: 1024x1024 cells => 16 packed words per row.
        // 16x16 keeps the block fully utilized and uses width-16 shuffles.
        launch_game_of_life_kernel<16, 16>(input, output, grid_dimensions, words_per_row);
    } else {
        // All larger legal boards have at least 32 packed words per row.
        // 32x8 makes one warp map cleanly to one 32-word row segment.
        launch_game_of_life_kernel<32, 8>(input, output, grid_dimensions, words_per_row);
    }
}

#include <cstdint>
#include <cuda_runtime.h>

/*
    High-performance bit-packed Conway's Game of Life for modern NVIDIA GPUs.

    Design choices driven purely by kernel throughput:

    1) One logical work item produces one 64-bit output word (64 cells), so there are no atomics.

    2) No shared memory and no texture memory.
       For this stencil, the simplest high-performance path on A100/H100-class GPUs is:
         - load the center word from the three relevant rows,
         - obtain left/right neighbor words with warp shuffles,
         - only let tile-edge lanes fall back to direct global loads.

    3) Avoid 64 scalar neighbor counts per thread.
       Using __popc is already much better than a naive bit-by-bit masking loop, but the fastest path
       here is to count all 64 cells in parallel with a bit-sliced counter:
         - ones : low bit of the 0..3 neighbor count modulo 4
         - twos : second bit of the 0..3 neighbor count modulo 4
         - ge4  : latched once a cell reaches 4 or more neighbors
       Then:
         next = twos & (ones | current) & ~ge4
       which exactly encodes:
         - birth on 3 neighbors,
         - survival on 2 neighbors if currently alive,
         - death for <2 or >3 neighbors.

    4) The board size is a power of two and the input is bit-packed.
       We exploit that in two places:
         - row stride in words is a power of two, so row-major indexing uses a shift instead of a
           general multiply/divide,
         - the number of word tiles across a row is exact, so there are no partial x-tiles.

    5) Bit 0 and bit 63 cross-word handling:
         west neighbors: (center << 1) | (left  >> 63)
         east neighbors: (center >> 1) | (right << 63)
       This naturally imports the carry-in bit from the adjacent 64-bit word.
*/

namespace {

using u64 = std::uint64_t;

constexpr unsigned int kWarpWidth = 32u;
constexpr unsigned int kBlockRows = 8u;      // 32 x 8 = 256 threads per block
constexpr unsigned int kMaxBlocks = 2048u;   // enough to fully cover A100/H100-class GPUs
constexpr unsigned int kFullWarpMask = 0xFFFFFFFFu;

// Bit i of the returned value is the west neighbor for output bit i.
// Bit 0 imports bit 63 from the word on the left.
__device__ __forceinline__ u64 align_west(const u64 center, const u64 left) {
    return (center << 1) | (left >> 63);
}

// Bit i of the returned value is the east neighbor for output bit i.
// Bit 63 imports bit 0 from the word on the right.
__device__ __forceinline__ u64 align_east(const u64 center, const u64 right) {
    return (center >> 1) | (right << 63);
}

// Add one 64-bit neighbor bitboard into a bit-sliced counter.
//
// For every bit position independently:
//   - ones/twos hold the low two bits of the neighbor count modulo 4
//   - ge4 latches once the count reaches 4 or more
//
// This is effectively a carry chain for 1-bit increments, executed in parallel across all 64 cells.
__device__ __forceinline__ void accumulate_neighbor(const u64 neighbor,
                                                    u64& ones,
                                                    u64& twos,
                                                    u64& ge4) {
    const u64 carry_to_twos = ones & neighbor;
    ones ^= neighbor;
    ge4 |= twos & carry_to_twos;
    twos ^= carry_to_twos;
}

// Given the 3x3 word neighborhood around the current word:
//
//   n0 n1 n2
//   c0 c1 c2
//   s0 s1 s2
//
// compute the next-generation output word for c1.
//
// Note that c1 itself is not part of the neighbor count; it is only used in the final
// survival condition.
__device__ __forceinline__ u64 evolve_word(const u64 n0, const u64 n1, const u64 n2,
                                           const u64 c0, const u64 c1, const u64 c2,
                                           const u64 s0, const u64 s1, const u64 s2) {
    u64 ones = 0;
    u64 twos = 0;
    u64 ge4  = 0;

    // Cardinal neighbors.
    accumulate_neighbor(n1,                  ones, twos, ge4);
    accumulate_neighbor(s1,                  ones, twos, ge4);
    accumulate_neighbor(align_west(c1, c0),  ones, twos, ge4);
    accumulate_neighbor(align_east(c1, c2),  ones, twos, ge4);

    // Diagonal neighbors.
    accumulate_neighbor(align_west(n1, n0),  ones, twos, ge4);
    accumulate_neighbor(align_east(n1, n2),  ones, twos, ge4);
    accumulate_neighbor(align_west(s1, s0),  ones, twos, ge4);
    accumulate_neighbor(align_east(s1, s2),  ones, twos, ge4);

    // Conway rule application:
    //   count == 3 -> twos=1, ones=1, ge4=0
    //   count == 2 -> twos=1, ones=0, ge4=0, but only survives if c1 was alive
    return twos & (ones | c1) & ~ge4;
}

/*
    TileWidth == 32:
      - one warp handles one 32-word horizontal tile of one row

    TileWidth == 16:
      - one warp is split into two independent 16-lane subwarps via the shuffle width parameter,
        so the same warp handles two rows at once (the only narrow legal case is 16 words/row,
        i.e. a 1024x1024 board)

    grid.x covers the row exactly in TileWidth-word tiles.
    grid.y is capped, and the kernel grid-strides over rows.
*/
template <unsigned int TileWidth>
__global__ __launch_bounds__(256)
void game_of_life_shuffle_kernel(const u64* __restrict__ input,
                                 u64* __restrict__ output,
                                 const unsigned int rows,
                                 const unsigned int word_shift) {
    static_assert(TileWidth == 16u || TileWidth == 32u, "TileWidth must be 16 or 32.");

    constexpr unsigned int kGroupsPerWarp = kWarpWidth / TileWidth;

    // blockDim.x is always launched as 32.
    const unsigned int lane  = threadIdx.x & (TileWidth - 1u);
    const unsigned int group = threadIdx.x / TileWidth;

    // Exact x-tiling of the row; no partial tiles.
    const unsigned int col = blockIdx.x * TileWidth + lane;

    // In the 16-wide specialization, each warp contains two independent 16-lane groups.
    // Because the board height is a power of two, rows are even, so both groups enter/leave
    // the loop body together; using a full-warp mask is therefore valid.
    unsigned int row = (blockIdx.y * blockDim.y + threadIdx.y) * kGroupsPerWarp + group;
    const unsigned int row_step = blockDim.y * gridDim.y * kGroupsPerWarp;

    const size_t row_stride = size_t{1} << word_shift;

    for (; row < rows; row += row_step) {
        const size_t idx = (static_cast<size_t>(row) << word_shift) + static_cast<size_t>(col);

        const bool has_top    = row != 0u;
        const bool has_bottom = (row + 1u) < rows;

        // Left/right edge tests are tile/lane based. grid.x spans the row exactly.
        const bool has_left  = (lane != 0u) || (blockIdx.x != 0u);
        const bool has_right = (lane != (TileWidth - 1u)) || ((blockIdx.x + 1u) < gridDim.x);

        // Center column of the 3x3 word stencil.
        const u64 c1 = input[idx];

        size_t north = 0;
        size_t south = 0;
        u64 n1 = 0;
        u64 s1 = 0;

        if (has_top) {
            north = idx - row_stride;
            n1 = input[north];
        }

        if (has_bottom) {
            south = idx + row_stride;
            s1 = input[south];
        }

        // Left/right words usually come from neighboring lanes. Only tile-edge lanes need
        // direct global loads to bridge the shuffle boundary.
        u64 c0 = __shfl_up_sync  (kFullWarpMask, c1, 1, TileWidth);
        u64 c2 = __shfl_down_sync(kFullWarpMask, c1, 1, TileWidth);
        u64 n0 = __shfl_up_sync  (kFullWarpMask, n1, 1, TileWidth);
        u64 n2 = __shfl_down_sync(kFullWarpMask, n1, 1, TileWidth);
        u64 s0 = __shfl_up_sync  (kFullWarpMask, s1, 1, TileWidth);
        u64 s2 = __shfl_down_sync(kFullWarpMask, s1, 1, TileWidth);

        if (lane == 0u) {
            c0 = has_left ? input[idx - 1] : 0;
            n0 = (has_top    && has_left) ? input[north - 1] : 0;
            s0 = (has_bottom && has_left) ? input[south - 1] : 0;
        } else if (lane == (TileWidth - 1u)) {
            c2 = has_right ? input[idx + 1] : 0;
            n2 = (has_top    && has_right) ? input[north + 1] : 0;
            s2 = (has_bottom && has_right) ? input[south + 1] : 0;
        }

        output[idx] = evolve_word(n0, n1, n2, c0, c1, c2, s0, s1, s2);
    }
}

template <unsigned int TileWidth>
inline void launch_game_of_life_kernel(const u64* input,
                                       u64* output,
                                       const unsigned int rows,
                                       const unsigned int words_per_row,
                                       const unsigned int word_shift) {
    static_assert(TileWidth == 16u || TileWidth == 32u, "TileWidth must be 16 or 32.");

    constexpr unsigned int kGroupsPerWarp = kWarpWidth / TileWidth;

    // Exact x-coverage of the row. Because words_per_row is a power of two, this is also exact
    // for both TileWidth specializations.
    const unsigned int grid_x = words_per_row / TileWidth;

    // Keep the total block count around kMaxBlocks and let the kernel grid-stride over rows.
    // This avoids over-scheduling millions of tiny blocks while still providing enough work to
    // fully occupy modern data-center GPUs.
    const unsigned int logical_rows_per_block = kBlockRows * kGroupsPerWarp;
    const unsigned int needed_grid_y =
        (rows + logical_rows_per_block - 1u) / logical_rows_per_block;

    unsigned int max_grid_y = kMaxBlocks / grid_x;
    if (max_grid_y == 0u) {
        max_grid_y = 1u;
    }

    const unsigned int grid_y = (needed_grid_y < max_grid_y) ? needed_grid_y : max_grid_y;

    const dim3 block(kWarpWidth, kBlockRows);
    const dim3 grid(grid_x, grid_y);

    game_of_life_shuffle_kernel<TileWidth><<<grid, block>>>(input, output, rows, word_shift);
}

}  // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions) {
    // The problem statement guarantees:
    //   - square board
    //   - power-of-two dimensions
    //   - dimensions > 512
    //   - input/output are separate cudaMalloc allocations
    //
    // No synchronization is done here; the caller handles it.
    const unsigned int rows = static_cast<unsigned int>(grid_dimensions);
    if (rows == 0u) {
        return;
    }

    const unsigned int words_per_row = rows >> 6;  // 64 cells per 64-bit word

    // log2(words_per_row). words_per_row is guaranteed to be a power of two.
    unsigned int word_shift = 0u;
    for (unsigned int x = words_per_row; x > 1u; x >>= 1u) {
        ++word_shift;
    }

    // For 2048x2048 and larger boards, a 32-word warp tile is the natural mapping.
    // The only narrower legal case is 1024x1024 -> 16 words/row; the 16-wide specialization
    // handles that by splitting each warp into two independent 16-lane subwarps.
    if (words_per_row >= 32u) {
        launch_game_of_life_kernel<32u>(input, output, rows, words_per_row, word_shift);
    } else {
        launch_game_of_life_kernel<16u>(input, output, rows, words_per_row, word_shift);
    }
}

#include <cuda_runtime.h>
#include <cstdint>

// One-step Conway's Game of Life for a bit-packed square grid on the GPU.
// Row-major layout:
//   - each 64-bit word stores 64 consecutive cells from one row
//   - bit 0 is the first cell in the word
//   - bit 63 is the last cell in the word
//
// One thread updates exactly one 64-bit word, so no atomics are needed.

namespace {

using word_t = std::uint64_t;
using reg_t  = unsigned long long;

constexpr int kBlockSize = 256;
constexpr unsigned int kWarpSize = 32u;
constexpr unsigned int kWarpMask = 0xFFFFFFFFu;

static_assert(kBlockSize % kWarpSize == 0, "Block size must be a multiple of the warp size.");
static_assert(sizeof(word_t) == sizeof(reg_t), "This implementation requires 64-bit words.");

__device__ __forceinline__ void csa(reg_t& carry, reg_t& sum,
                                    const reg_t a, const reg_t b, const reg_t c) {
    // Carry-save adder for three 1-bit-per-lane inputs:
    //   a + b + c = sum + 2 * carry
    const reg_t u = a ^ b;
    carry = (a & b) | (u & c);
    sum = u ^ c;
}

__global__ __launch_bounds__(kBlockSize)
void game_of_life_kernel(const word_t* __restrict__ input,
                         word_t* __restrict__ output,
                         const unsigned int words_per_row,
                         const std::uint64_t last_row_start) {
    const std::uint64_t idx =
        static_cast<std::uint64_t>(blockIdx.x) * static_cast<std::uint64_t>(kBlockSize) +
        static_cast<std::uint64_t>(threadIdx.x);

    // words_per_row is a power of two, so x can be recovered with a mask instead of a modulo.
    const unsigned int last_x = words_per_row - 1u;
    const unsigned int x = static_cast<unsigned int>(idx) & last_x;
    const unsigned int lane = threadIdx.x & (kWarpSize - 1u);

    const bool has_up    = idx >= words_per_row;
    const bool has_down  = idx < last_row_start;
    const bool has_left  = x != 0u;
    const bool has_right = x != last_x;

    const word_t* const center = input + idx;

    // Shared memory is intentionally avoided. The profitable reuse here is horizontal reuse of
    // neighboring words inside a warp, and warp shuffles recover that reuse more cheaply than
    // staging tiles in shared memory.
    //
    // Every thread always loads only the vertically aligned words (above/current/below).
    // Immediate left/right words are taken from adjacent lanes when possible, with a single
    // fallback global load only at warp boundaries.
    const reg_t mc = static_cast<reg_t>(*center);

    reg_t uc = 0ull;
    reg_t dc = 0ull;
    if (has_up) {
        uc = static_cast<reg_t>(*(center - words_per_row));
    }
    if (has_down) {
        dc = static_cast<reg_t>(*(center + words_per_row));
    }

    const reg_t uc_l = __shfl_up_sync(kWarpMask, uc, 1);
    const reg_t mc_l = __shfl_up_sync(kWarpMask, mc, 1);
    const reg_t dc_l = __shfl_up_sync(kWarpMask, dc, 1);

    const reg_t uc_r = __shfl_down_sync(kWarpMask, uc, 1);
    const reg_t mc_r = __shfl_down_sync(kWarpMask, mc, 1);
    const reg_t dc_r = __shfl_down_sync(kWarpMask, dc, 1);

    // Missing neighbor words are zero, which directly implements "cells outside the grid are dead".
    reg_t ul = 0ull, ml = 0ull, dl = 0ull;
    if (has_left) {
        if (lane != 0u) {
            ul = uc_l;
            ml = mc_l;
            dl = dc_l;
        } else {
            ml = static_cast<reg_t>(*(center - 1));
            if (has_up) {
                ul = static_cast<reg_t>(*(center - words_per_row - 1u));
            }
            if (has_down) {
                dl = static_cast<reg_t>(*(center + words_per_row - 1u));
            }
        }
    }

    reg_t ur = 0ull, mr = 0ull, dr = 0ull;
    if (has_right) {
        if (lane != kWarpSize - 1u) {
            ur = uc_r;
            mr = mc_r;
            dr = dc_r;
        } else {
            mr = static_cast<reg_t>(*(center + 1));
            if (has_up) {
                ur = static_cast<reg_t>(*(center - words_per_row + 1u));
            }
            if (has_down) {
                dr = static_cast<reg_t>(*(center + words_per_row + 1u));
            }
        }
    }

    // Align neighbor bits so that bit i in every mask refers to the neighborhood of cell i.
    // This is where the special handling for bit 0 and bit 63 happens:
    //   - bit 0 pulls bit 63 from the word on the left   via (left_word  >> 63)
    //   - bit 63 pulls bit 0 from the word on the right via (right_word << 63)
    const reg_t up_left    = (uc << 1) | (ul >> 63);
    const reg_t up_right   = (uc >> 1) | (ur << 63);
    const reg_t mid_left   = (mc << 1) | (ml >> 63);
    const reg_t mid_right  = (mc >> 1) | (mr << 63);
    const reg_t down_left  = (dc << 1) | (dl >> 63);
    const reg_t down_right = (dc >> 1) | (dr << 63);

    // The prompt mentions __popc as the fast scalar way to evaluate a 3x3 neighborhood.
    // That is a good improvement over naive masking, but for the required "one thread owns one
    // 64-bit word" mapping, the fastest strategy on modern NVIDIA data-center GPUs is a bit-sliced
    // population count:
    //   - the eight neighbor bitboards are added with a carry-save adder tree
    //   - all 64 per-cell neighbor counts are computed in parallel
    reg_t h0, l0, h1, l1, h2, l2, h4, l4;
    csa(h0, l0, up_left,  uc,        up_right);
    csa(h1, l1, mid_left, mid_right, down_left);
    csa(h2, l2, l0,       l1,        dc);

    const reg_t ones = l2 ^ down_right;
    const reg_t h3   = l2 & down_right;

    csa(h4, l4, h0, h1, h2);

    const reg_t twos   = l4 ^ h3;
    const reg_t higher = h4 | (l4 & h3);

    // Life rule in bit-sliced form:
    //   count == 2 -> survive iff currently alive
    //   count == 3 -> always alive
    const reg_t next = twos & ~higher & (ones | mc);

    output[idx] = static_cast<word_t>(next);
}

}  // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions) {
    const unsigned int dim = static_cast<unsigned int>(grid_dimensions);
    const unsigned int words_per_row = dim >> 6;
    const std::uint64_t total_words =
        static_cast<std::uint64_t>(dim) * static_cast<std::uint64_t>(words_per_row);
    const std::uint64_t last_row_start = total_words - words_per_row;

    // Given the stated constraints:
    //   - dim is a power of two and > 512
    //   - words_per_row is therefore a power of two
    //   - total_words = dim * words_per_row is a power of two >= 2^14
    //   - total_words is divisible by kBlockSize
    //
    // Because kBlockSize is also a multiple of 32, every launched warp is full, so the kernel can
    // use a fixed full-warp shuffle mask and omit a tail guard entirely.
    const unsigned int block_count = static_cast<unsigned int>(total_words / kBlockSize);

    // Intentionally enqueue only; synchronization and any error-handling policy are owned by the caller.
    game_of_life_kernel<<<block_count, kBlockSize>>>(input, output, words_per_row, last_row_start);
}

#include <cstddef>
#include <cstdint>
#include <cuda_runtime.h>

namespace {

constexpr int kBlockThreads = 256;

// Use an intrinsic-friendly 64-bit register type for shuffles and bitwise arithmetic.
// The public API still uses std::uint64_t exactly as requested.
using u64 = unsigned long long;
static_assert(sizeof(u64) == sizeof(std::uint64_t), "Unexpected 64-bit type size");

// Plain cached global load. On modern data-center GPUs (A100/H100), regular read-only
// global loads are already well cached; the important optimization here is eliminating
// redundant neighbor loads with warp shuffles, not forcing a legacy __ldg path.
__device__ __forceinline__ u64 load64(const std::uint64_t* ptr) {
    return static_cast<u64>(*ptr);
}

// 3-input majority, bitwise and lane-parallel across all 64 cells in the word.
// For each bit position i, the result bit is 1 iff at least two of {a,b,c} have bit i set.
__device__ __forceinline__ u64 majority3(u64 a, u64 b, u64 c) {
    return (a & b) | (c & (a | b));
}

// 4-input exact-1 detector, again bitwise across all 64 cells.
// For each bit position i, the result bit is 1 iff exactly one of {a,b,c,d} has bit i set.
__device__ __forceinline__ u64 exactly_one_of_four(u64 a, u64 b, u64 c, u64 d) {
    const u64 ab_xor = a ^ b;
    const u64 cd_xor = c ^ d;
    return (ab_xor ^ cd_xor) & ~((a & b) | (c & d) | (ab_xor & cd_xor));
}

/*
  One thread updates one 64-bit word (64 cells).

  Performance-critical choices:
    - No shared memory: it only adds address arithmetic and synchronization here.
    - No texture memory: regular global loads plus cache are enough for this stencil.
    - Same-row neighbor words are exchanged with warp shuffles, so the common case loads
      only {center, north, south}. Only the first/last lane of each row fragment falls
      back to a global load for the left/right neighbor word.
    - The neighborhood count is computed with a bit-sliced adder network, not 64 scalar
      neighborhood extractions and 64 scalar popcounts. A scalar __popc-based approach is
      better than naive masking, but a bit-parallel adder is faster still because it updates
      all 64 cells in the word at once.

  Bit-sliced population count:
    top    = NW + N + NE  -> t0 + 2*t1
    middle =  W + E       -> m0 + 2*m1
    bottom = SW + S + SE  -> b0 + 2*b1

    t0 + m0 + b0 = l0 + 2*l1
    neighbors    = l0 + 2*(l1 + t1 + m1 + b1)

  Only counts 2 and 3 matter:
    - if (l1 + t1 + m1 + b1) != 1, the next state is 0
    - otherwise neighbors = 2 + l0
        l0 == 0 -> exactly 2 neighbors -> survive iff current cell is alive
        l0 == 1 -> exactly 3 neighbors -> cell is alive next generation

  Therefore:
    next = exact1(l1, t1, m1, b1) & (l0 | center)
*/
template <int SUBWARP>
__global__ __launch_bounds__(kBlockThreads)
void game_of_life_kernel(const std::uint64_t* __restrict__ input,
                         std::uint64_t* __restrict__ output,
                         unsigned int words_per_row,
                         unsigned int grid_dimensions,
                         unsigned int block_rows_total) {
    static_assert(SUBWARP == 8 || SUBWARP == 16 || SUBWARP == 32, "Unsupported subwarp width");
    static_assert(kBlockThreads % SUBWARP == 0, "Invalid block geometry");
    constexpr int ROWS_PER_BLOCK = kBlockThreads / SUBWARP;

    // A 3D launch is used only to bypass the 65535 limit on gridDim.y for very large boards.
    const std::size_t block_row =
        static_cast<std::size_t>(blockIdx.y) +
        static_cast<std::size_t>(blockIdx.z) * static_cast<std::size_t>(gridDim.y);
    if (block_row >= static_cast<std::size_t>(block_rows_total)) {
        return;
    }

    // Under the stated constraints, words_per_row is a power of two and SUBWARP divides it
    // exactly, so x is always in range for valid inputs and there is no x-bounds check here.
    const unsigned int x = blockIdx.x * SUBWARP + threadIdx.x;
    const unsigned int y = static_cast<unsigned int>(block_row) * ROWS_PER_BLOCK + threadIdx.y;
    if (y >= grid_dimensions) {
        return;
    }

    const std::size_t stride = static_cast<std::size_t>(words_per_row);
    const std::size_t idx = static_cast<std::size_t>(y) * stride + static_cast<std::size_t>(x);

    const bool row_left_edge = (x == 0);
    const bool row_right_edge = (x + 1u == words_per_row);
    const bool has_up = (y != 0);
    const bool has_down = (y + 1u < grid_dimensions);
    const bool segment_left_edge = (threadIdx.x == 0);
    const bool segment_right_edge = (threadIdx.x == SUBWARP - 1);

    const u64 center = load64(input + idx);

    u64 north = 0ull;
    u64 south = 0ull;
    if (has_up) {
        north = load64(input + idx - stride);
    }
    if (has_down) {
        south = load64(input + idx + stride);
    }

    // Using the active mask makes the kernel robust even if a future caller violates the
    // exact divisibility assumptions and creates partial warps in the last tile.
    const unsigned int active = __activemask();

    // Middle row: W + E
    u64 left_word = __shfl_up_sync(active, center, 1, SUBWARP);
    if (segment_left_edge) {
        left_word = row_left_edge ? 0ull : load64(input + idx - 1);
    }
    const u64 west = (center << 1) | (left_word >> 63);

    u64 right_word = __shfl_down_sync(active, center, 1, SUBWARP);
    if (segment_right_edge) {
        right_word = row_right_edge ? 0ull : load64(input + idx + 1);
    }
    const u64 east = (center >> 1) | (right_word << 63);

    const u64 m0 = west ^ east;
    const u64 m1 = west & east;

    // Top row: NW + N + NE
    left_word = __shfl_up_sync(active, north, 1, SUBWARP);
    if (segment_left_edge) {
        left_word = (has_up && !row_left_edge) ? load64(input + idx - stride - 1) : 0ull;
    }
    const u64 northwest = (north << 1) | (left_word >> 63);

    right_word = __shfl_down_sync(active, north, 1, SUBWARP);
    if (segment_right_edge) {
        right_word = (has_up && !row_right_edge) ? load64(input + idx - stride + 1) : 0ull;
    }
    const u64 northeast = (north >> 1) | (right_word << 63);

    const u64 t0 = northwest ^ north ^ northeast;
    const u64 t1 = majority3(northwest, north, northeast);

    // Bottom row: SW + S + SE
    left_word = __shfl_up_sync(active, south, 1, SUBWARP);
    if (segment_left_edge) {
        left_word = (has_down && !row_left_edge) ? load64(input + idx + stride - 1) : 0ull;
    }
    const u64 southwest = (south << 1) | (left_word >> 63);

    right_word = __shfl_down_sync(active, south, 1, SUBWARP);
    if (segment_right_edge) {
        right_word = (has_down && !row_right_edge) ? load64(input + idx + stride + 1) : 0ull;
    }
    const u64 southeast = (south >> 1) | (right_word << 63);

    const u64 b0 = southwest ^ south ^ southeast;
    const u64 b1 = majority3(southwest, south, southeast);

    // neighbors = l0 + 2*(l1 + t1 + m1 + b1)
    const u64 l0 = t0 ^ m0 ^ b0;
    const u64 l1 = majority3(t0, m0, b0);

    const u64 next = exactly_one_of_four(l1, t1, m1, b1) & (l0 | center);
    output[idx] = static_cast<std::uint64_t>(next);
}

template <int SUBWARP>
inline void launch_game_of_life(const std::uint64_t* input,
                                std::uint64_t* output,
                                unsigned int grid_dimensions) {
    constexpr unsigned int ROWS_PER_BLOCK = kBlockThreads / SUBWARP;
    constexpr unsigned int kMaxGridY = 65535u;

    const unsigned int words_per_row = grid_dimensions >> 6;
    const unsigned int block_rows_total = (grid_dimensions + ROWS_PER_BLOCK - 1u) / ROWS_PER_BLOCK;

    // Choose a balanced (y,z) factorization so grid.y never exceeds 65535 while also avoiding
    // the pathological case where the last z-slice would contain almost entirely empty blocks.
    const unsigned int grid_z = (block_rows_total + kMaxGridY - 1u) / kMaxGridY;
    const unsigned int grid_y = (block_rows_total + grid_z - 1u) / grid_z;

    const dim3 block(static_cast<unsigned int>(SUBWARP), ROWS_PER_BLOCK, 1u);
    const dim3 grid(words_per_row / SUBWARP, grid_y, grid_z);

    game_of_life_kernel<SUBWARP><<<grid, block>>>(input, output, words_per_row, grid_dimensions, block_rows_total);
}

}  // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions) {
    // Per the prompt, the caller owns synchronization. This function only launches the kernel.
    // Input and output are assumed to be distinct device buffers (standard double-buffered Life).
    if (grid_dimensions <= 0) {
        return;
    }

    const unsigned int dim = static_cast<unsigned int>(grid_dimensions);
    const unsigned int words_per_row = dim >> 6;

    // Under the stated constraints (>512 and power of two), the only valid cases are:
    //   1024x1024 -> 16 words/row -> SUBWARP = 16
    //   >=2048x2048 -> >=32 words/row -> SUBWARP = 32
    // An 8-word case is kept so the code still works if reused for a 512x512 board.
    if (words_per_row == 8u) {
        launch_game_of_life<8>(input, output, dim);
    } else if (words_per_row == 16u) {
        launch_game_of_life<16>(input, output, dim);
    } else {
        launch_game_of_life<32>(input, output, dim);
    }
}

#include <cstddef>
#include <cstdint>
#include <cuda_runtime.h>

// Optimized Conway's Game of Life step for bit-packed rows.
// - One CUDA thread owns one 64-bit word, i.e. 64 cells.
// - No shared memory is used: for this stencil on modern A100/H100-class GPUs,
//   warp shuffles are enough to eliminate most redundant left/right loads while
//   vertical reuse is handled well by the hardware caches.
// - A per-cell implementation with tiny masks and __popc is still much slower
//   than summing all 64 lanes in parallel with bit-sliced logic.

namespace {

using word_t = unsigned long long;

constexpr unsigned int kFullWarpMask = 0xFFFFFFFFu;
constexpr unsigned int kRowsPerBlock = 8u;  // 32x8 -> 256 threads, 16x8 -> 128 threads.
static_assert((kRowsPerBlock & (kRowsPerBlock - 1u)) == 0u,
              "kRowsPerBlock must remain a power of two.");

// Host-side integer log2 for a known power-of-two value.
// Host overhead is not performance-critical here; keep it simple and portable.
static inline unsigned int ilog2_pow2(unsigned int v) {
    unsigned int r = 0u;
    while (v > 1u) {
        v >>= 1u;
        ++r;
    }
    return r;
}

// Bitwise majority of three 64-bit masks.
// The compiler maps this form efficiently to ternary logic (LOP3) on Ampere/Hopper.
__device__ __forceinline__ word_t majority3(word_t a, word_t b, word_t c) {
    return (a & b) | (c & (a ^ b));
}

template <int TILE_W>
__global__ void game_of_life_kernel(
    const std::uint64_t* __restrict__ input,
    std::uint64_t* __restrict__ output,
    unsigned int words_per_row,
    unsigned int last_row,
    unsigned int row_tiles_log2,
    unsigned int row_tiles_mask,
    unsigned int block_x_last)
{
    static_assert(TILE_W == 16 || TILE_W == 32,
                  "The launch helper only instantiates 16-wide or 32-wide tiles.");

    // grid_dimensions and words_per_row are powers of two.
    // We linearize the logical 2D block grid into grid.x because grid.y is too small
    // for the largest legal inputs. row tiles are made the fast-varying dimension so
    // consecutive block indices tend to walk vertically, which improves cache reuse
    // because adjacent row tiles share input rows.
    const unsigned int block_linear = blockIdx.x;
    const unsigned int block_y = block_linear & row_tiles_mask;
    const unsigned int block_x = block_linear >> row_tiles_log2;

    const unsigned int row = block_y * kRowsPerBlock + threadIdx.y;
    const unsigned int word = block_x * TILE_W + threadIdx.x;

    const std::size_t idx = static_cast<std::size_t>(row) * words_per_row + word;

    const bool has_up = (row != 0u);
    const bool has_down = (row != last_row);

    // Arithmetic on size_t is well-defined even when the result is not used because
    // unsigned wrap-around is defined. Loads remain predicated by has_up/has_down.
    const std::size_t up_idx = idx - words_per_row;
    const std::size_t down_idx = idx + words_per_row;

    // Center words from the row above, current row, and row below.
    const word_t mc = static_cast<word_t>(input[idx]);
    const word_t tc = has_up ? static_cast<word_t>(input[up_idx]) : 0ull;
    const word_t bc = has_down ? static_cast<word_t>(input[down_idx]) : 0ull;

    // Horizontal neighbors are obtained from warp shuffles whenever possible.
    // For TILE_W == 32, one warp == one row chunk.
    // For TILE_W == 16, the shuffle width partitions each warp into two independent
    // 16-lane sub-warps, which exactly matches the only legal narrow-row case.
    word_t ml = __shfl_up_sync(kFullWarpMask, mc, 1, TILE_W);
    word_t mr = __shfl_down_sync(kFullWarpMask, mc, 1, TILE_W);
    word_t tl = __shfl_up_sync(kFullWarpMask, tc, 1, TILE_W);
    word_t tr = __shfl_down_sync(kFullWarpMask, tc, 1, TILE_W);
    word_t bl = __shfl_up_sync(kFullWarpMask, bc, 1, TILE_W);
    word_t br = __shfl_down_sync(kFullWarpMask, bc, 1, TILE_W);

    // Threads at the sub-warp boundaries need cross-chunk loads (or zero at the true
    // grid boundary). Only two lanes per sub-warp take these paths.
    const bool has_left_chunk = (block_x != 0u);
    const bool has_right_chunk = (block_x != block_x_last);

    if (threadIdx.x == 0u) {
        ml = has_left_chunk ? static_cast<word_t>(input[idx - 1]) : 0ull;
        tl = (has_left_chunk && has_up) ? static_cast<word_t>(input[up_idx - 1]) : 0ull;
        bl = (has_left_chunk && has_down) ? static_cast<word_t>(input[down_idx - 1]) : 0ull;
    }

    if (threadIdx.x == static_cast<unsigned int>(TILE_W - 1)) {
        mr = has_right_chunk ? static_cast<word_t>(input[idx + 1]) : 0ull;
        tr = (has_right_chunk && has_up) ? static_cast<word_t>(input[up_idx + 1]) : 0ull;
        br = (has_right_chunk && has_down) ? static_cast<word_t>(input[down_idx + 1]) : 0ull;
    }

    // Bit layout convention:
    //   bit 0  = left-most cell inside this 64-cell word
    //   bit 63 = right-most cell inside this 64-cell word
    // This matches the user's boundary note that bit 0 reaches into the word to the
    // left and bit 63 reaches into the word to the right.
    //
    // Therefore:
    //   west-aligned  neighbors use << 1 and carry in bit 63 from the previous word
    //   east-aligned  neighbors use >> 1 and carry in bit 0  from the next word

    // Horizontal 3-cell / 2-cell row sums in bit-sliced form:
    // upper row: (u1:u0) = up_w + up_c + up_e   in [0,3]
    // middle row: (m1:m0) = mid_w + mid_e       in [0,2]
    // lower row: (d1:d0) = dn_w + dn_c + dn_e   in [0,3]
    word_t u0, u1;
    {
        const word_t up_w = (tc << 1) | (tl >> 63);
        const word_t up_e = (tc >> 1) | (tr << 63);
        u0 = up_w ^ tc ^ up_e;
        u1 = majority3(up_w, tc, up_e);
    }

    word_t m0, m1;
    {
        const word_t mid_w = (mc << 1) | (ml >> 63);
        const word_t mid_e = (mc >> 1) | (mr << 63);
        m0 = mid_w ^ mid_e;
        m1 = mid_w & mid_e;
    }

    word_t d0, d1;
    {
        const word_t dn_w = (bc << 1) | (bl >> 63);
        const word_t dn_e = (bc >> 1) | (br << 63);
        d0 = dn_w ^ bc ^ dn_e;
        d1 = majority3(dn_w, bc, dn_e);
    }

    // Add the three partial row counts.
    // We only materialize the low 3 bits of the 0..8 neighbor count:
    //   count = c0 + 2*c1 + 4*c2 (+ 8*c3, ignored)
    //
    // That is sufficient because the Life rule can be written as:
    //   next = (count == 3) | (alive & count == 2)
    //        = c1 & ~c2 & (alive | c0)
    //
    // The only missed case when c3 would matter is count == 8, but that already has
    // c1 == 0, so it is automatically rejected.
    const word_t t0 = u0 ^ m0;
    const word_t carry0 = u0 & m0;
    const word_t t1 = u1 ^ m1 ^ carry0;
    const word_t t2 = majority3(u1, m1, carry0);

    const word_t c0 = t0 ^ d0;
    const word_t carry1 = t0 & d0;
    const word_t c1 = t1 ^ d1 ^ carry1;
    const word_t c2 = t2 ^ majority3(t1, d1, carry1);

    const word_t next = c1 & ~c2 & (mc | c0);
    output[idx] = static_cast<std::uint64_t>(next);
}

template <int TILE_W>
inline void launch_game_of_life_kernel(
    const std::uint64_t* input,
    std::uint64_t* output,
    unsigned int grid_dim,
    unsigned int words_per_row)
{
    static_assert(TILE_W == 16 || TILE_W == 32, "Unsupported tile width.");

    const unsigned int blocks_x = words_per_row / TILE_W;
    const unsigned int row_tiles = grid_dim / kRowsPerBlock;

    // All of these are powers of two:
    //   grid_dim         by contract
    //   words_per_row    = grid_dim / 64
    //   TILE_W           = 16 or 32
    //   kRowsPerBlock    = 8
    //
    // So blocks_x and row_tiles are powers of two as well.
    const unsigned int row_tiles_log2 = ilog2_pow2(row_tiles);
    const unsigned int row_tiles_mask = row_tiles - 1u;
    const unsigned int block_x_last = blocks_x - 1u;
    const unsigned int total_blocks = blocks_x * row_tiles;

    const dim3 block(TILE_W, kRowsPerBlock, 1u);
    game_of_life_kernel<TILE_W><<<total_blocks, block>>>(
        input,
        output,
        words_per_row,
        grid_dim - 1u,
        row_tiles_log2,
        row_tiles_mask,
        block_x_last);
}

} // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions) {
    // The caller owns synchronization. Keep this function fully asynchronous:
    // no host/device sync and no error-querying here.
    const unsigned int grid_dim = static_cast<unsigned int>(grid_dimensions);
    const unsigned int words_per_row = grid_dim >> 6;

    // grid_dimensions is a power of two > 512, so words_per_row is a power of two.
    // The only legal case smaller than 32 words/row is exactly 16.
    if (words_per_row == 16u) {
        launch_game_of_life_kernel<16>(input, output, grid_dim, words_per_row);
    } else {
        launch_game_of_life_kernel<32>(input, output, grid_dim, words_per_row);
    }
}

#include <cstdint>
#include <cuda_runtime.h>

// Bit-packed Conway's Game of Life.
//
// Design choices driven purely by performance on modern data-center GPUs:
// - One CUDA thread owns one 64-bit output word (64 cells), so no atomics are needed.
// - Shared/texture memory are intentionally avoided.
// - A per-bit __popc baseline is reasonable, but a bit-sliced 64-lane counter is faster here:
//   all 64 cells in a word are updated in parallel with bitwise logic.
// - Warp shuffles provide left/right neighboring words inside a warp (or half warp for the
//   smallest legal grid), so only subgroup-edge lanes need explicit halo handling.
// - Cells outside the grid are dead: halos are zero-filled, i.e. no toroidal wrap-around.
//
// Bit numbering follows the problem statement's boundary description:
// bit 0 is the leftmost cell in a 64-cell word, and bit 63 is the rightmost.

namespace {

using u64 = std::uint64_t;
using u32 = std::uint32_t;

constexpr int kBlockSize = 256;          // 8 warps/block; good balance for A100/H100.
constexpr u32 kFullWarpMask = 0xFFFFFFFFu;

static_assert((kBlockSize & (kBlockSize - 1)) == 0, "Block size must be a power of two.");
static_assert((kBlockSize % 32) == 0, "Block size must be warp-aligned.");

// Add one 64-bit bitboard into a bit-sliced 3-bit counter.
// The counter is maintained modulo 8. That is sufficient because Game of Life only needs
// neighbor counts 2 and 3, and count 8 wraps to 0 modulo 8, which does not alias 2 or 3.
__device__ __forceinline__ void add_bitboard(u64 x, u64& ones, u64& twos, u64& fours) {
    u64 carry = ones & x;
    ones ^= x;
    x = carry;

    carry = twos & x;
    twos ^= x;
    x = carry;

    fours ^= x;
}

// 64-bit warp shuffle helpers built from native 32-bit shuffles.
template <int SUBGROUP_WIDTH>
__device__ __forceinline__ u64 shfl_up1_u64(u64 v) {
    u32 lo = static_cast<u32>(v);
    u32 hi = static_cast<u32>(v >> 32);
    lo = __shfl_up_sync(kFullWarpMask, lo, 1, SUBGROUP_WIDTH);
    hi = __shfl_up_sync(kFullWarpMask, hi, 1, SUBGROUP_WIDTH);
    return (static_cast<u64>(hi) << 32) | static_cast<u64>(lo);
}

template <int SUBGROUP_WIDTH>
__device__ __forceinline__ u64 shfl_down1_u64(u64 v) {
    u32 lo = static_cast<u32>(v);
    u32 hi = static_cast<u32>(v >> 32);
    lo = __shfl_down_sync(kFullWarpMask, lo, 1, SUBGROUP_WIDTH);
    hi = __shfl_down_sync(kFullWarpMask, hi, 1, SUBGROUP_WIDTH);
    return (static_cast<u64>(hi) << 32) | static_cast<u64>(lo);
}

// Fix subgroup-edge left/right words.
// SUBGROUP_WIDTH == 16:
//   The subgroup is exactly one full row (this only happens for 1024x1024 grids), so subgroup
//   edges are physical grid edges and the missing horizontal halos are always zero.
// SUBGROUP_WIDTH == 32:
//   A subgroup is one 32-word row segment. Interior subgroup edges fetch the missing halo words
//   from global memory; true row edges inject zeros.
template <int SUBGROUP_WIDTH>
__device__ __forceinline__ void apply_horizontal_halo(
    u64& left, u64& right,
    const u64* input,
    u64 base_index,
    bool load_left,
    bool load_right,
    u32 lane_in_group);

template <>
__device__ __forceinline__ void apply_horizontal_halo<16>(
    u64& left, u64& right,
    const u64* input,
    u64 base_index,
    bool load_left,
    bool load_right,
    u32 lane_in_group)
{
    (void)input;
    (void)base_index;
    (void)load_left;
    (void)load_right;

    if (lane_in_group == 0u) {
        left = 0ull;
    }
    if (lane_in_group == 15u) {
        right = 0ull;
    }
}

template <>
__device__ __forceinline__ void apply_horizontal_halo<32>(
    u64& left, u64& right,
    const u64* input,
    u64 base_index,
    bool load_left,
    bool load_right,
    u32 lane_in_group)
{
    if (lane_in_group == 0u) {
        left = load_left ? input[base_index - 1] : 0ull;
    }
    if (lane_in_group == 31u) {
        right = load_right ? input[base_index + 1] : 0ull;
    }
}

// Under the stated constraints:
// - grid_dimensions is a power of two and > 512
// - words_per_row = grid_dimensions / 64 is therefore either 16 or a multiple of 32
// - total_words = grid_dimensions * words_per_row is a power of two and divisible by kBlockSize
//
// The host launch therefore covers the grid exactly, and the kernel can omit a bounds check.
template <int SUBGROUP_WIDTH>
__global__ __launch_bounds__(kBlockSize)
void game_of_life_kernel(
    const u64* __restrict__ input,
    u64* __restrict__ output,
    u32 words_per_row,
    u32 words_per_row_log2,
    u32 last_row)
{
    static_assert(SUBGROUP_WIDTH == 16 || SUBGROUP_WIDTH == 32, "Unsupported subgroup width.");

    const u64 word_index =
        static_cast<u64>(blockIdx.x) * static_cast<u64>(kBlockSize) +
        static_cast<u64>(threadIdx.x);

    const u32 last_word     = words_per_row - 1u;
    const u32 wx            = static_cast<u32>(word_index) & last_word;
    const u32 row           = static_cast<u32>(word_index >> words_per_row_log2);
    const u32 lane_in_group = static_cast<u32>(threadIdx.x) & (SUBGROUP_WIDTH - 1);

    const bool has_up    = (row != 0u);
    const bool has_down  = (row != last_row);
    const bool has_left  = (wx  != 0u);
    const bool has_right = (wx  != last_word);

    const u64 row_stride = static_cast<u64>(words_per_row);
    const u64 up_index   = word_index - row_stride;
    const u64 down_index = word_index + row_stride;

    const u64 cC = input[word_index];

    u64 ones  = 0ull;
    u64 twos  = 0ull;
    u64 fours = 0ull;

    // North row: NW, N, NE
    {
        const u64 nC = has_up ? input[up_index] : 0ull;

        u64 nL = shfl_up1_u64<SUBGROUP_WIDTH>(nC);
        u64 nR = shfl_down1_u64<SUBGROUP_WIDTH>(nC);
        apply_horizontal_halo<SUBGROUP_WIDTH>(
            nL, nR, input, up_index,
            has_up && has_left,
            has_up && has_right,
            lane_in_group);

        add_bitboard((nC << 1) | (nL >> 63), ones, twos, fours);  // NW
        add_bitboard(nC,                         ones, twos, fours);  // N
        add_bitboard((nC >> 1) | (nR << 63), ones, twos, fours);  // NE
    }

    // Current row: W, E
    {
        u64 cL = shfl_up1_u64<SUBGROUP_WIDTH>(cC);
        u64 cR = shfl_down1_u64<SUBGROUP_WIDTH>(cC);
        apply_horizontal_halo<SUBGROUP_WIDTH>(
            cL, cR, input, word_index,
            has_left,
            has_right,
            lane_in_group);

        add_bitboard((cC << 1) | (cL >> 63), ones, twos, fours);  // W
        add_bitboard((cC >> 1) | (cR << 63), ones, twos, fours);  // E
    }

    // South row: SW, S, SE
    {
        const u64 sC = has_down ? input[down_index] : 0ull;

        u64 sL = shfl_up1_u64<SUBGROUP_WIDTH>(sC);
        u64 sR = shfl_down1_u64<SUBGROUP_WIDTH>(sC);
        apply_horizontal_halo<SUBGROUP_WIDTH>(
            sL, sR, input, down_index,
            has_down && has_left,
            has_down && has_right,
            lane_in_group);

        add_bitboard((sC << 1) | (sL >> 63), ones, twos, fours);  // SW
        add_bitboard(sC,                         ones, twos, fours);  // S
        add_bitboard((sC >> 1) | (sR << 63), ones, twos, fours);  // SE
    }

    // Classic Life rule from the bit-sliced counter:
    // - count == 2  -> twos=1, ones=0, fours=0  => cell survives iff it is already alive
    // - count == 3  -> twos=1, ones=1, fours=0  => cell is alive next generation
    //
    // This collapses to:
    //   next = twos & ~fours & (ones | alive)
    output[word_index] = twos & ~fours & (ones | cC);
}

}  // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions) {
    // Natural double-buffered usage is assumed: input and output are distinct device allocations.
    // No synchronization is performed here; the caller owns ordering and synchronization.

    const std::uint32_t n = static_cast<std::uint32_t>(grid_dimensions);
    const std::uint32_t words_per_row = n >> 6;  // 64 cells per 64-bit word.

    // words_per_row is a power of two by problem construction.
    std::uint32_t words_per_row_log2 = 0u;
    for (std::uint32_t t = words_per_row; t > 1u; t >>= 1u) {
        ++words_per_row_log2;
    }

    const std::uint64_t total_words =
        static_cast<std::uint64_t>(n) * static_cast<std::uint64_t>(words_per_row);

    // total_words is a power of two and divisible by kBlockSize under the given constraints.
    const std::uint32_t blocks =
        static_cast<std::uint32_t>(total_words / static_cast<std::uint64_t>(kBlockSize));

    // words_per_row is either:
    // - 16  (the smallest legal grid: 1024x1024), where each half warp is one full row, or
    // - a multiple of 32, where each warp stays entirely inside a row segment.
    if (words_per_row == 16u) {
        game_of_life_kernel<16><<<blocks, kBlockSize>>>(
            input, output, words_per_row, words_per_row_log2, n - 1u);
    } else {
        game_of_life_kernel<32><<<blocks, kBlockSize>>>(
            input, output, words_per_row, words_per_row_log2, n - 1u);
    }
}

#include <cstdint>
#include <cuda_runtime.h>

using u64 = std::uint64_t;
constexpr int kThreadsPerBlock = 256;

namespace {

// One thread owns one 64-bit word, exactly as requested.
// Layout is row-major: each row contains grid_dimensions / 64 words, and each word packs
// 64 consecutive cells from that row.
//
// A straightforward optimized baseline would iterate over the 64 bit positions in the word and
// use masked __popc/__popcll neighborhood counts. That is much better than scalar bit tests,
// but it still performs 64 neighborhood counts per thread. This kernel keeps the same
// thread-to-word mapping and instead uses bit-sliced boolean adders so that all 64 cells in
// the word are advanced in parallel.
//
// No shared memory or texture memory is used on purpose: the access pattern is regular,
// neighbor reuse is handled well by the hardware caches on modern GPUs, and avoiding explicit
// staging keeps the kernel lean. Every thread writes one unique output word, so no atomics
// are required.

// Majority bit for three 64-bit bitboards.
// On recent NVIDIA GPUs the compiler lowers this kind of boolean expression efficiently.
__device__ __forceinline__ u64 majority64(const u64 a, const u64 b, const u64 c) {
    return (a & b) | (a & c) | (b & c);
}

// Bit layout matches the prompt:
//   bit 0  is the left-most cell inside the 64-bit word,
//   bit 63 is the right-most cell.
//
// Therefore:
//   west-neighbor bits are aligned with (center << 1) | (left >> 63)
//   east-neighbor bits are aligned with (center >> 1) | (right << 63)
//
// This is the branch-free form of the special handling the prompt calls out for bit 0 and bit 63.
__device__ __forceinline__ u64 shift_west(const u64 center, const u64 left) {
    return (center << 1) | (left >> 63);
}

__device__ __forceinline__ u64 shift_east(const u64 center, const u64 right) {
    return (center >> 1) | (right << 63);
}

// Sum three 1-bit fields per lane.
// For each of the 64 bit lanes independently:
//   bit0 + 2*bit1 == a + b + c
__device__ __forceinline__ void count3(const u64 a, const u64 b, const u64 c,
                                       u64& bit0, u64& bit1) {
    bit0 = a ^ b ^ c;
    bit1 = majority64(a, b, c);
}

// Return a bitboard whose lane k is 1 iff exactly one of a/b/c/d has lane k set.
// We intentionally compute only this predicate rather than a full 4-input population count,
// because after splitting the 8-neighbor sum into low/high parts, Conway's rule only needs
// to know whether the "weight-2" part equals 1.
__device__ __forceinline__ u64 exactly_one_of_four(const u64 a, const u64 b,
                                                   const u64 c, const u64 d) {
    const u64 one01 = a ^ b;  // pair (a,b) has exactly one set
    const u64 two01 = a & b;  // pair (a,b) has exactly two set
    const u64 one23 = c ^ d;  // pair (c,d) has exactly one set
    const u64 two23 = c & d;  // pair (c,d) has exactly two set
    return (one01 ^ one23) & ~(two01 | two23);
}

// One Conway step on a bit-packed grid.
// Missing neighbors are injected as zero words, implementing the required
// "outside the grid is dead" boundary condition with no wrapping.
//
// For each 64-bit word, the 8-neighbor sum is decomposed into three strips:
//
//   top    = NW + N + NE  = top0 + 2*top1
//   middle = W  + E       = mid0 + 2*mid1
//   bottom = SW + S + SE  = bot0 + 2*bot1
//
// Then:
//
//   cnt0 + 2*carry1 = top0 + mid0 + bot0
//
// Let u = carry1 + top1 + mid1 + bot1.
// The full neighbor count is:
//
//   neighbor_count = cnt0 + 2*u
//
// Conway's rule only needs neighbor_count == 2 or neighbor_count == 3.
// That is equivalent to u == 1, with cnt0 selecting between 2 and 3:
//
//   next = (u == 1) & (cnt0 | center)
//
// - cnt0 == 0 => count 2, so the cell survives only if it is already alive.
// - cnt0 == 1 => count 3, so the cell is alive in the next generation regardless of current state.
__global__ __launch_bounds__(kThreadsPerBlock)
void game_of_life_step_kernel(const u64* __restrict__ input,
                              u64* __restrict__ output,
                              const u64 total_words,
                              const u64 row_stride,
                              const u64 col_mask,
                              const u64 last_row_start) {
    const u64 idx =
        static_cast<u64>(blockIdx.x) * static_cast<u64>(kThreadsPerBlock) + threadIdx.x;
    if (idx >= total_words) {
        return;
    }

    // Because the row length in words is a power of two, x-boundary detection is just a mask.
    const u64 col = idx & col_mask;
    const bool has_left = col != 0;
    const bool has_right = col != col_mask;

    // Top/bottom detection is just a range check on the linear word index.
    const bool has_up = idx >= row_stride;
    const bool has_down = idx < last_row_start;

    const u64 center = input[idx];
    const u64 left = has_left ? input[idx - 1] : 0ull;
    const u64 right = has_right ? input[idx + 1] : 0ull;

    const u64 west = shift_west(center, left);
    const u64 east = shift_east(center, right);
    const u64 mid0 = west ^ east;
    const u64 mid1 = west & east;

    u64 top0 = 0ull;
    u64 top1 = 0ull;
    if (has_up) {
        const u64 idx_up = idx - row_stride;
        const u64 up = input[idx_up];
        const u64 up_left = has_left ? input[idx_up - 1] : 0ull;
        const u64 up_right = has_right ? input[idx_up + 1] : 0ull;
        count3(shift_west(up, up_left), up, shift_east(up, up_right), top0, top1);
    }

    u64 bot0 = 0ull;
    u64 bot1 = 0ull;
    if (has_down) {
        const u64 idx_down = idx + row_stride;
        const u64 down = input[idx_down];
        const u64 down_left = has_left ? input[idx_down - 1] : 0ull;
        const u64 down_right = has_right ? input[idx_down + 1] : 0ull;
        count3(shift_west(down, down_left), down, shift_east(down, down_right), bot0, bot1);
    }

    u64 cnt0;
    u64 carry1;
    count3(top0, mid0, bot0, cnt0, carry1);

    const u64 u_eq_1 = exactly_one_of_four(carry1, top1, mid1, bot1);
    output[idx] = u_eq_1 & (cnt0 | center);
}

}  // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions) {
    // input and output are device pointers allocated by cudaMalloc.
    // The launch is asynchronous; the caller is responsible for synchronization and error handling.
    // input and output are assumed not to alias.
    const u64 row_stride = static_cast<u64>(grid_dimensions) >> 6;  // words per row
    const u64 total_words = row_stride * static_cast<u64>(grid_dimensions);
    if (total_words == 0) {
        return;
    }

    const u64 col_mask = row_stride - 1;         // row_stride is a power of two
    const u64 last_row_start = total_words - row_stride;
    const unsigned int blocks =
        static_cast<unsigned int>((total_words + kThreadsPerBlock - 1) / kThreadsPerBlock);

    game_of_life_step_kernel<<<blocks, kThreadsPerBlock>>>(
        input, output, total_words, row_stride, col_mask, last_row_start);
}

#include <cstdint>
#include <cuda_runtime.h>

using u64 = std::uint64_t;
using u32 = std::uint32_t;

constexpr int kBlockSize = 256;   // 8 warps per CTA.
constexpr u32 kWarpLastLane = 31u;

static_assert((kBlockSize & 31) == 0, "kBlockSize must be a multiple of the warp size (32).");

/*
  One-step Conway's Game of Life for a square, bit-packed board.

  Representation:
    - Row-major.
    - One 64-bit word stores 64 consecutive cells from the same row.
    - Bit 0 is the leftmost cell inside that 64-cell run; bit 63 is the rightmost.
    - All cells outside the board are dead.

  Performance-oriented choices:
    - One CUDA thread updates exactly one 64-bit word at a time, so there are no atomics
      and no write conflicts.
    - The row length in words is a power of two, so the column index is just a bit-mask.
    - Shared/texture memory is intentionally not used. The access pattern is regular, the
      hardware caches are effective, and warp shuffles are enough for the needed neighbor exchange.
    - A scalar rolling-window implementation using __popc/__popcll is a good baseline, but on
      modern data-center GPUs the fastest path for this packed representation is bit-sliced:
      the eight neighbor bitboards are summed with carry-save adders, so all 64 cells in the word
      are evaluated in parallel and the per-bit inner loop disappears entirely.
    - Each thread loads only three words unconditionally: center, north, south. Left/right and
      diagonal neighbor words are normally obtained from adjacent lanes via warp shuffles. Only
      warp-edge lanes fall back to explicit global loads.
*/

static __device__ __forceinline__ u64 shfl_up_u64(const unsigned int mask, const u64 value, const unsigned int delta) {
    return static_cast<u64>(__shfl_up_sync(mask, static_cast<unsigned long long>(value), static_cast<int>(delta)));
}

static __device__ __forceinline__ u64 shfl_down_u64(const unsigned int mask, const u64 value, const unsigned int delta) {
    return static_cast<u64>(__shfl_down_sync(mask, static_cast<unsigned long long>(value), static_cast<int>(delta)));
}

/*
  3:2 compressor (carry-save adder) on bit-planes.

  For every bit position independently:
      a + b + c = sum + 2 * carry

  "carry" here is the next count bit-plane, not a spatial carry to a neighboring cell.
*/
static __device__ __forceinline__ void csa3(const u64 a, const u64 b, const u64 c, u64& sum, u64& carry) {
    sum = a ^ b ^ c;
    carry = (a & b) | (c & (a | b));
}

static __global__ __launch_bounds__(kBlockSize)
void game_of_life_kernel(const u64* __restrict__ input,
                         u64* __restrict__ output,
                         const u64 total_words,
                         const u64 words_per_row,
                         const u64 last_row_start,
                         const u32 words_per_row_mask) {
    const u64 global_thread =
        static_cast<u64>(blockIdx.x) * static_cast<u64>(blockDim.x) +
        static_cast<u64>(threadIdx.x);
    const u64 stride =
        static_cast<u64>(gridDim.x) * static_cast<u64>(blockDim.x);

    const u32 lane = static_cast<u32>(threadIdx.x) & kWarpLastLane;

    for (u64 idx = global_thread; idx < total_words; idx += stride) {
        // Only the column needs a modulo, and because the row length in words is a power of two
        // that modulo is just a mask. Top/bottom checks use the linear index directly.
        const u32 col = static_cast<u32>(idx) & words_per_row_mask;

        const bool has_up    = idx >= words_per_row;
        const bool has_down  = idx < last_row_start;
        const bool has_left  = col != 0u;
        const bool has_right = col != words_per_row_mask;

        const u64 center = input[idx];
        const u64 north  = has_up   ? input[idx - words_per_row] : 0ull;
        const u64 south  = has_down ? input[idx + words_per_row] : 0ull;

        // Align the six neighbor directions to the current word. After a 1-bit shift, only one
        // carried-in boundary bit from the adjacent word matters.
        u64 w  = center << 1;
        u64 e  = center >> 1;
        u64 nw = north  << 1;
        u64 ne = north  >> 1;
        u64 sw = south  << 1;
        u64 se = south  >> 1;

        const unsigned int active = __activemask();

        {
            // Special handling for bit 0: after shifting left, inject bit 63 from the word on the
            // left for the current, north, and south rows.
            const u64 center_from_left = shfl_up_u64(active, center, 1);
            const u64 north_from_left  = shfl_up_u64(active, north,  1);
            const u64 south_from_left  = shfl_up_u64(active, south,  1);

            if (has_left) {
                w |= ((lane != 0u) ? center_from_left : input[idx - 1]) >> 63;

                if (has_up) {
                    nw |= ((lane != 0u) ? north_from_left : input[idx - words_per_row - 1]) >> 63;
                }
                if (has_down) {
                    sw |= ((lane != 0u) ? south_from_left : input[idx + words_per_row - 1]) >> 63;
                }
            }
        }

        {
            // Special handling for bit 63: after shifting right, inject bit 0 from the word on the
            // right for the current, north, and south rows.
            const u64 center_from_right = shfl_down_u64(active, center, 1);
            const u64 north_from_right  = shfl_down_u64(active, north,  1);
            const u64 south_from_right  = shfl_down_u64(active, south,  1);

            if (has_right) {
                e |= (((lane != kWarpLastLane) ? center_from_right : input[idx + 1]) & 1ull) << 63;

                if (has_up) {
                    ne |= (((lane != kWarpLastLane) ? north_from_right : input[idx - words_per_row + 1]) & 1ull) << 63;
                }
                if (has_down) {
                    se |= (((lane != kWarpLastLane) ? south_from_right : input[idx + words_per_row + 1]) & 1ull) << 63;
                }
            }
        }

        // Sum the eight aligned neighbor bitboards with carry-save adders.
        u64 s0, c0;
        u64 s1, c1;
        u64 s2, c2;
        u64 s3, carry4;

        csa3(nw,    north, ne, s0, c0);
        csa3(w,     e,     sw, s1, c1);
        csa3(south, se,    s0, s2, c2);
        csa3(c0,    c1,    c2, s3, carry4);

        // count_bit0 and count_bit1 are the low two bits of the final 0..8 neighbor count.
        // The outstanding weight-4 plane (carry4) distinguishes {2,3} from the higher counts.
        // Therefore:
        //   count_is_2_or_3 = (~carry4) & count_bit1
        //
        // Life's rule:
        //   next = (count == 3) | (center && count == 2)
        //        = count_is_2_or_3 & (count_bit0 | center)
        const u64 count_bit0      = s1 ^ s2;
        const u64 carry_to_bit1   = s1 & s2;
        const u64 count_bit1      = s3 ^ carry_to_bit1;
        const u64 count_is_2_or_3 = (~carry4) & count_bit1;

        output[idx] = count_is_2_or_3 & (count_bit0 | center);
    }
}

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions) {
    // The caller guarantees:
    //   - a valid power-of-two square board,
    //   - grid_dimensions > 512,
    //   - input/output are device pointers from cudaMalloc,
    //   - input and output are distinct buffers.
    //
    // No synchronization or launch-error polling is done here; the caller owns ordering and any
    // host-device synchronization. The kernel is grid-stride, so we launch only enough CTAs to
    // saturate the device according to the compiled kernel's actual residency.

    const u32 words_per_row_u32 = static_cast<u32>(grid_dimensions) >> 6;
    const u32 words_per_row_mask = words_per_row_u32 - 1u;
    const u64 words_per_row = static_cast<u64>(words_per_row_u32);

    const u64 total_words =
        static_cast<u64>(static_cast<u32>(grid_dimensions)) * words_per_row;
    const u64 last_row_start = total_words - words_per_row;

    int device = 0;
    cudaGetDevice(&device);

    int sm_count = 0;
    cudaDeviceGetAttribute(&sm_count, cudaDevAttrMultiProcessorCount, device);
    if (sm_count < 1) {
        sm_count = 1;
    }

    int active_blocks_per_sm = 0;
    cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &active_blocks_per_sm,
        game_of_life_kernel,
        kBlockSize,
        0);
    if (active_blocks_per_sm < 1) {
        active_blocks_per_sm = 1;
    }

    u64 grid_blocks =
        (total_words + static_cast<u64>(kBlockSize) - 1ull) / static_cast<u64>(kBlockSize);

    const u64 resident_blocks =
        static_cast<u64>(sm_count) * static_cast<u64>(active_blocks_per_sm);

    if (grid_blocks > resident_blocks) {
        grid_blocks = resident_blocks;
    }

    game_of_life_kernel<<<static_cast<unsigned int>(grid_blocks), kBlockSize>>>(
        input,
        output,
        total_words,
        words_per_row,
        last_row_start,
        words_per_row_mask);
}

#include <cstdint>
#include <cuda_runtime.h>

namespace {

// High-throughput Conway's Game of Life step for a square, bit-packed board.
//
// Performance-focused design:
// - One CUDA thread updates one 64-bit word = 64 cells, so no atomics are needed.
// - All 64 cells in that word are updated simultaneously with SWAR/bit-sliced integer logic.
// - Shared memory and textures are intentionally avoided; the board is already compact, and
//   warp shuffles are sufficient to reuse adjacent words without extra synchronization.
//
// The special handling for bit 0 and bit 63 requested by the problem is implemented by
// shift_west() / shift_east(): bit 0 pulls its west neighbor from the word on the left,
// bit 63 pulls its east neighbor from the word on the right, and the same is done for the
// row above, the current row, and the row below.

using u64 = std::uint64_t;
using u32 = std::uint32_t;

constexpr int kWarpSize = 32;
constexpr u32 kWarpLaneMask = kWarpSize - 1u;
constexpr unsigned int kFullWarpMask = 0xffffffffu;

// 256 threads = 8 warps per block. This is a strong fixed point for this kernel on
// recent NVIDIA data-center GPUs while keeping the launch geometry simple.
constexpr int kBlockShift = 8;
constexpr int kBlockSize = 1 << kBlockShift;

static_assert(kBlockSize == (1 << kBlockShift), "kBlockShift must match kBlockSize.");
static_assert((kBlockSize % kWarpSize) == 0, "kBlockSize must be a multiple of the warp size.");

// Read-only cached load. The input board is never modified by this kernel.
__device__ __forceinline__ u64 load_ro(const u64* ptr) {
#if __CUDA_ARCH__ >= 350
    return __ldg(ptr);
#else
    return *ptr;
#endif
}

// Align west/east neighbors to the current word's bit positions.
// For example, shift_west(center, left_word) returns a mask whose bit i is the cell immediately
// west of bit i in center. Bit 0 therefore comes from left_word bit 63; shift_east does the
// symmetric thing for bit 63 and the word on the right.
__device__ __forceinline__ u64 shift_west(u64 center, u64 left_word) {
    return (center << 1) | (left_word >> 63);
}

__device__ __forceinline__ u64 shift_east(u64 center, u64 right_word) {
    return (center >> 1) | (right_word << 63);
}

// Per-bit population count of two 1-bit masks. For every bit position i:
//   count_i = lo_i + 2 * hi_i
__device__ __forceinline__ void bitcount2(u64 a, u64 b, u64& lo, u64& hi) {
    lo = a ^ b;
    hi = a & b;
}

// Per-bit population count of three 1-bit masks. For every bit position i:
//   count_i = lo_i + 2 * hi_i
__device__ __forceinline__ void bitcount3(u64 a, u64 b, u64 c, u64& lo, u64& hi) {
    const u64 x = a ^ b;
    lo = x ^ c;
    hi = (a & b) | (x & c);
}

// Return a mask whose bit i is 1 iff exactly one of a_i, b_i, c_i, d_i is 1.
// This is cheaper than materializing the full 3-bit sum when all we need is the "sum == 1" test.
__device__ __forceinline__ u64 exactly_one_of_four(u64 a, u64 b, u64 c, u64 d) {
    const u64 u = a ^ b;
    const u64 v = c ^ d;
    const u64 bit0 = u ^ v;
    const u64 carries = (a & b) | (c & d) | (u & v);
    return bit0 & ~carries;
}

// Choose the adjacent 64-bit word for one row.
// The shuffle itself is executed unconditionally in the kernel so the *_sync mask is always valid.
// This helper only decides between:
//   - zero at the board edge,
//   - the shuffled word when the neighbor stays inside the same warp chunk of the row,
//   - one fallback global load when the row continues into the previous/next warp.
__device__ __forceinline__ u64 neighbor_left(u64 shuffled_left,
                                             const u64* row_center_ptr,
                                             bool has_neighbor_word,
                                             bool same_warp) {
    return !has_neighbor_word ? 0ULL : (same_warp ? shuffled_left : load_ro(row_center_ptr - 1));
}

__device__ __forceinline__ u64 neighbor_right(u64 shuffled_right,
                                              const u64* row_center_ptr,
                                              bool has_neighbor_word,
                                              bool same_warp) {
    return !has_neighbor_word ? 0ULL : (same_warp ? shuffled_right : load_ro(row_center_ptr + 1));
}

__global__ __launch_bounds__(kBlockSize)
void game_of_life_kernel(const u64* __restrict__ input,
                         u64* __restrict__ output,
                         u32 words_per_row,
                         u32 word_mask,
                         int log2_words_per_row,
                         u32 last_row) {
    // run_game_of_life launches exactly one thread per 64-bit word, and total_words is chosen
    // so every block and warp is full. Therefore there is no tail path and the full warp mask is valid.
    const u32 idx = (static_cast<u32>(blockIdx.x) << kBlockShift) + static_cast<u32>(threadIdx.x);

    // words_per_row is a power of two, so word-in-row and row index are obtained with a mask and shift.
    const u32 word = idx & word_mask;
    const u32 row = idx >> log2_words_per_row;

    const bool has_up = row != 0u;
    const bool has_down = row != last_row;
    const bool has_left = word != 0u;
    const bool has_right = word != word_mask;

    // Because words_per_row is itself a power of two, a row either evenly divides a warp
    // or spans an integer number of whole warps. Therefore word&31 is sufficient to know
    // whether the adjacent word is already owned by a neighboring lane in this warp.
    const u32 warp_word = word & kWarpLaneMask;
    const bool same_warp_left = warp_word != 0u;
    const bool same_warp_right = warp_word != kWarpLaneMask;

    const u64* const center_ptr = input + idx;
    const u64* const up_ptr = has_up ? (center_ptr - words_per_row) : center_ptr;
    const u64* const down_ptr = has_down ? (center_ptr + words_per_row) : center_ptr;

    const u64 cur_word = load_ro(center_ptr);
    const u64 up_word = has_up ? load_ro(up_ptr) : 0ULL;
    const u64 down_word = has_down ? load_ro(down_ptr) : 0ULL;

    u64 shuffled_left;
    u64 shuffled_right;
    u64 west;
    u64 east;

    // Top row contribution: up-left, up, up-right.
    shuffled_left = __shfl_up_sync(kFullWarpMask, up_word, 1);
    shuffled_right = __shfl_down_sync(kFullWarpMask, up_word, 1);
    west = shift_west(up_word, neighbor_left(shuffled_left, up_ptr, has_up && has_left, same_warp_left));
    east = shift_east(up_word, neighbor_right(shuffled_right, up_ptr, has_up && has_right, same_warp_right));
    u64 top_lo, top_hi;
    bitcount3(west, up_word, east, top_lo, top_hi);

    // Middle row contribution: only west and east; the current word itself is not a neighbor.
    shuffled_left = __shfl_up_sync(kFullWarpMask, cur_word, 1);
    shuffled_right = __shfl_down_sync(kFullWarpMask, cur_word, 1);
    west = shift_west(cur_word, neighbor_left(shuffled_left, center_ptr, has_left, same_warp_left));
    east = shift_east(cur_word, neighbor_right(shuffled_right, center_ptr, has_right, same_warp_right));
    u64 mid_lo, mid_hi;
    bitcount2(west, east, mid_lo, mid_hi);

    // Bottom row contribution: down-left, down, down-right.
    shuffled_left = __shfl_up_sync(kFullWarpMask, down_word, 1);
    shuffled_right = __shfl_down_sync(kFullWarpMask, down_word, 1);
    west = shift_west(down_word, neighbor_left(shuffled_left, down_ptr, has_down && has_left, same_warp_left));
    east = shift_east(down_word, neighbor_right(shuffled_right, down_ptr, has_down && has_right, same_warp_right));
    u64 bot_lo, bot_hi;
    bitcount3(west, down_word, east, bot_lo, bot_hi);

    // Add the low bits of the three row counts:
    //   (top_lo + mid_lo + bot_lo) = sum_lsb + 2 * carry_to_high
    u64 sum_lsb, carry_to_high;
    bitcount3(top_lo, mid_lo, bot_lo, sum_lsb, carry_to_high);

    // The total neighbor count is:
    //   total = sum_lsb + 2 * (top_hi + mid_hi + bot_hi + carry_to_high)
    //
    // A cell is alive in the next generation only for totals 2 and 3.
    // Those are exactly the cases where the parenthesized group equals 1:
    //   total == 2 -> sum_lsb = 0
    //   total == 3 -> sum_lsb = 1
    //
    // Therefore:
    //   next = (group == 1) & (sum_lsb | current_cell)
    // which implements:
    //   - birth on 3 neighbors,
    //   - survival on 2 neighbors.
    const u64 high_is_one = exactly_one_of_four(top_hi, mid_hi, bot_hi, carry_to_high);
    output[idx] = high_is_one & (sum_lsb | cur_word);
}

// words_per_row is guaranteed to be a power of two.
inline int ilog2_pow2_u32(u32 v) {
    int log2 = 0;
    while ((v >>= 1u) != 0u) {
        ++log2;
    }
    return log2;
}

}  // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions) {
    // The caller provides device pointers and owns all synchronization. This function only
    // computes launch parameters and submits one kernel for a single Conway step.
    //
    // Given the problem constraints:
    //   n = 2^k, k >= 10
    //   total_words = n * (n / 64) = n^2 / 64 = 2^(2k - 6)
    // so total_words is a power of two and therefore divisible by kBlockSize = 256.
    // That lets the kernel run with an exact one-thread-per-word launch and no tail handling.
    const u32 n = static_cast<u32>(grid_dimensions);
    const u32 words_per_row = n >> 6;
    const int log2_words_per_row = ilog2_pow2_u32(words_per_row);
    const std::uint64_t total_words = (static_cast<std::uint64_t>(n) * static_cast<std::uint64_t>(n)) >> 6;
    const u32 num_blocks = static_cast<u32>(total_words >> kBlockShift);

    // Double-buffering is assumed: input and output must refer to different device buffers.
    game_of_life_kernel<<<num_blocks, kBlockSize>>>(
        input,
        output,
        words_per_row,
        words_per_row - 1u,
        log2_words_per_row,
        n - 1u);
}

#include <cuda_runtime.h>

#include <cstddef>
#include <cstdint>

/*
Optimized single-step Conway's Game of Life for a square, bit-packed grid.

Key ideas used here for performance on modern datacenter GPUs:
  1. One CUDA thread updates one 64-bit word, i.e. 64 cells at once.
  2. Horizontal neighbor words are exchanged with warp/sub-warp shuffles instead of
     shared memory. Only the segment-edge lanes perform extra global halo loads.
  3. The eight neighbor counts are accumulated bit-slice-wise with carry-save adders,
     so all 64 cells in a word are updated in parallel with boolean operations.
  4. A flattened 1D grid of thread blocks is used to avoid gridDim.y limits on very
     large boards. Because the dimensions are powers of two, decoding the flattened
     block index is just a mask + shift.

Bit layout assumption (matches the prompt's "0th/63rd bit need special handling"):
  - Bit k in a word corresponds to column (word_index * 64 + k).
  - Therefore:
      west  neighbors = (word << 1) | (left_word  >> 63)
      east  neighbors = (word >> 1) | (right_word << 63)
  - Cells outside the board are treated as dead by zeroing missing rows/halos.
*/

namespace {

using u64 = std::uint64_t;

constexpr unsigned int kFullWarpMask   = 0xFFFFFFFFu;
constexpr int          kThreadsPerBlock = 256;

/* Build the "west" neighbor bitmask for the current 64-cell word. */
__device__ __forceinline__ u64 shift_left_with_carry(u64 word, u64 left_word) {
    return (word << 1) | (left_word >> 63);
}

/* Build the "east" neighbor bitmask for the current 64-cell word. */
__device__ __forceinline__ u64 shift_right_with_carry(u64 word, u64 right_word) {
    return (word >> 1) | (right_word << 63);
}

/*
Carry-save adder for three equally-weighted bitboards.
For every bit position independently:
  a + b + c = low + 2*high
where:
  low  = parity(a,b,c)
  high = majority(a,b,c)
*/
__device__ __forceinline__ void csa(u64& high, u64& low, u64 a, u64 b, u64 c) {
    low  = a ^ b ^ c;
    high = (a & b) | (a & c) | (b & c);
}

/*
Fetch the raw x-1 and x+1 words for one row.

`GROUP_WIDTH` is either 32 (one full row segment per warp) or 16 (two independent
row segments per warp). The shuffle width confines communication to that segment.
Only the first/last lane of each segment falls back to a global load that crosses
the segment boundary.
*/
template <int GROUP_WIDTH>
__device__ __forceinline__ void fetch_horizontal_neighbors(
    u64 word,
    const u64* __restrict__ cell_ptr,
    std::ptrdiff_t row_delta_words,
    bool row_exists,
    bool has_left_global,
    bool has_right_global,
    bool has_left_in_group,
    bool has_right_in_group,
    u64& left_word,
    u64& right_word)
{
    const u64 shfl_left  = __shfl_up_sync(kFullWarpMask,   word, 1, GROUP_WIDTH);
    const u64 shfl_right = __shfl_down_sync(kFullWarpMask, word, 1, GROUP_WIDTH);

    left_word =
        (row_exists && has_left_global)
            ? (has_left_in_group ? shfl_left : cell_ptr[row_delta_words - 1])
            : u64{0};

    right_word =
        (row_exists && has_right_global)
            ? (has_right_in_group ? shfl_right : cell_ptr[row_delta_words + 1])
            : u64{0};
}

template <int GROUP_WIDTH, int BLOCK_Y>
__global__ __launch_bounds__(kThreadsPerBlock)
void game_of_life_kernel(
    const u64* __restrict__ input,
    u64* __restrict__ output,
    int words_per_row,
    int grid_dimensions,
    unsigned int blocks_per_row_mask,
    unsigned int blocks_per_row_shift)
{
    static_assert(GROUP_WIDTH * BLOCK_Y == kThreadsPerBlock,
                  "The tuned launch shape is expected to keep 256 threads per block.");

    constexpr int kGroupShift  = (GROUP_WIDTH == 16 ? 4 : 5);
    constexpr int kBlockYShift = (BLOCK_Y    == 16 ? 4 : 3);

    /*
    Flattened block decode:
      block_x = blockIdx.x % blocks_per_row
      block_y = blockIdx.x / blocks_per_row

    Because blocks_per_row is a power of two, the host passes its mask and shift so
    this decode is just bit operations.
    */
    const unsigned int linear_block = blockIdx.x;
    const int bx = static_cast<int>(linear_block & blocks_per_row_mask);
    const int by = static_cast<int>(linear_block >> blocks_per_row_shift);

    const int tx = static_cast<int>(threadIdx.x);
    const int ty = static_cast<int>(threadIdx.y);

    const int x = (bx << kGroupShift)  | tx;
    const int y = (by << kBlockYShift) | ty;

    /*
    Exact tiling is guaranteed by the problem constraints:
      - grid_dimensions is a power of two,
      - words_per_row = grid_dimensions / 64 is a power of two,
      - launch shapes are chosen so block dimensions divide the board exactly.
    Hence no bounds checks are needed here, only physical board-edge checks.
    */
    const bool has_up            = (y != 0);
    const bool has_down          = (y != (grid_dimensions - 1));
    const bool has_left_global   = (x != 0);
    const bool has_right_global  = (x != (words_per_row - 1));
    const bool has_left_in_group = (tx != 0);
    const bool has_right_in_group= (tx != (GROUP_WIDTH - 1));

    const std::size_t idx =
        static_cast<std::size_t>(y) * static_cast<std::size_t>(words_per_row) +
        static_cast<std::size_t>(x);

    const u64* const cell = input + idx;
    const std::ptrdiff_t stride = static_cast<std::ptrdiff_t>(words_per_row);

    const u64 center = *cell;
    const u64 north  = has_up   ? cell[-stride] : u64{0};
    const u64 south  = has_down ? cell[ stride] : u64{0};

    u64 north_left_word, north_right_word;
    u64 center_left_word, center_right_word;
    u64 south_left_word, south_right_word;

    fetch_horizontal_neighbors<GROUP_WIDTH>(
        north, cell, -stride,
        has_up, has_left_global, has_right_global, has_left_in_group, has_right_in_group,
        north_left_word, north_right_word);

    fetch_horizontal_neighbors<GROUP_WIDTH>(
        center, cell, 0,
        true, has_left_global, has_right_global, has_left_in_group, has_right_in_group,
        center_left_word, center_right_word);

    fetch_horizontal_neighbors<GROUP_WIDTH>(
        south, cell, stride,
        has_down, has_left_global, has_right_global, has_left_in_group, has_right_in_group,
        south_left_word, south_right_word);

    /* The eight neighbor bitboards aligned to the current 64-cell lane group. */
    const u64 nw = shift_left_with_carry (north,  north_left_word);
    const u64 ne = shift_right_with_carry(north,  north_right_word);
    const u64 w  = shift_left_with_carry (center, center_left_word);
    const u64 e  = shift_right_with_carry(center, center_right_word);
    const u64 sw = shift_left_with_carry (south,  south_left_word);
    const u64 se = shift_right_with_carry(south,  south_right_word);

    /*
    Specialized 8-input bit-sliced adder tree.

    After this sequence:
      ones  = 1's bit of the neighbor count for each cell
      twos  = 2's bit
      fours = 4's bit

    We intentionally do NOT materialize the 8's bit, because Conway's rule only needs
    to know whether the neighbor count is 2 or 3:
      - For counts 0..8, (twos & ~fours) is true iff the count is 2 or 3.
      - Count 8 also has fours==0, but twos==0, so the missing 8's bit is irrelevant.
      - (ones | center) then maps {2,3} to the actual Life rule:
          count==2 -> survive only if center was already alive
          count==3 -> always alive
    */
    u64 ones  = nw ^ north;
    u64 twosA = nw & north;

    u64 twosB;
    csa(twosB, ones, ones, ne, w);

    u64 twos   = twosA ^ twosB;
    u64 foursA = twosA & twosB;

    u64 twosC;
    csa(twosC, ones, ones, e, sw);

    u64 twosD;
    csa(twosD, ones, ones, south, se);

    u64 foursB;
    csa(foursB, twos, twos, twosC, twosD);

    const u64 fours = foursA ^ foursB;
    output[idx] = twos & ~fours & (ones | center);
}

/* Host-side helper: blocks_per_row is guaranteed to be a power of two. */
inline unsigned int log2_power_of_two(unsigned int value) {
    unsigned int shift = 0;
    while (value > 1u) {
        value >>= 1;
        ++shift;
    }
    return shift;
}

template <int GROUP_WIDTH, int BLOCK_Y>
inline void launch_game_of_life_step(
    const u64* input,
    u64* output,
    int grid_dimensions,
    int words_per_row)
{
    static_assert(GROUP_WIDTH * BLOCK_Y == kThreadsPerBlock,
                  "The tuned launch shape is expected to keep 256 threads per block.");

    const int blocks_per_row = words_per_row / GROUP_WIDTH;
    const int block_rows     = grid_dimensions / BLOCK_Y;

    const unsigned int blocks_per_row_mask  = static_cast<unsigned int>(blocks_per_row - 1);
    const unsigned int blocks_per_row_shift = log2_power_of_two(static_cast<unsigned int>(blocks_per_row));

    /*
    A 1D grid is used deliberately:
      total_blocks = blocks_per_row * block_rows

    This avoids any possible gridDim.y limit for very large boards while keeping the
    kernel-side decode cheap.
    */
    const unsigned int total_blocks = static_cast<unsigned int>(
        static_cast<std::size_t>(blocks_per_row) * static_cast<std::size_t>(block_rows));

    const dim3 block_dim(GROUP_WIDTH, BLOCK_Y, 1);
    const dim3 grid_dim(total_blocks, 1, 1);

    game_of_life_kernel<GROUP_WIDTH, BLOCK_Y><<<grid_dim, block_dim>>>(
        input,
        output,
        words_per_row,
        grid_dimensions,
        blocks_per_row_mask,
        blocks_per_row_shift);
}

}  // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions) {
    /*
    The board size is guaranteed to be a power of two greater than 512.
    Therefore words_per_row = grid_dimensions / 64 is also a power of two.

    Tuning choice:
      - 1024x1024 boards have exactly 16 words per row, so a 16-lane shuffle width
        avoids wasting half of each warp. One warp then carries two independent rows.
      - All larger boards use a 32-lane shuffle width, one row segment per warp.
    */
    const int words_per_row = grid_dimensions >> 6;

    if (words_per_row == 16) {
        launch_game_of_life_step<16, 16>(input, output, grid_dimensions, words_per_row);
    } else {
        launch_game_of_life_step<32, 8>(input, output, grid_dimensions, words_per_row);
    }

    /* No synchronization here; the caller explicitly owns synchronization. */
}

#include <cuda_runtime.h>

#include <cstddef>
#include <cstdint>

namespace {

// Storage type mandated by the public interface.
using packed_t = std::uint64_t;

// Internal arithmetic/shuffle type. CUDA warp shuffle support is guaranteed for
// unsigned long long, and the conversion is a no-op on all supported platforms.
using word_t = unsigned long long;

static_assert(sizeof(packed_t) == sizeof(word_t), "Expected 64-bit packed words.");

// One warp in X is intentional: every warp owns 32 consecutive words from one row,
// so horizontal reuse can be handled with warp shuffles instead of shared memory.
constexpr int kBlockX = 32;
constexpr int kBlockY = 8;
constexpr int kBlockThreads = kBlockX * kBlockY;

static_assert(kBlockX == 32, "The shuffle path assumes exactly one warp along X.");

// Simple typed load/store helpers so the kernel can use the arithmetic/shuffle type
// without changing the externally visible API type.
__device__ __forceinline__ word_t load_word(const packed_t* ptr) {
    return static_cast<word_t>(*ptr);
}

__device__ __forceinline__ packed_t store_word(word_t v) {
    return static_cast<packed_t>(v);
}

// Bit i in the returned word becomes the western neighbor of bit i in `center`.
// This is exactly where the special handling for bit 0 happens: its west neighbor
// is imported from bit 63 of the word on the left.
__device__ __forceinline__ word_t align_west(word_t center, word_t left_word) {
    return (center << 1) | (left_word >> 63);
}

// Bit i in the returned word becomes the eastern neighbor of bit i in `center`.
// This is exactly where the special handling for bit 63 happens: its east neighbor
// is imported from bit 0 of the word on the right.
__device__ __forceinline__ word_t align_east(word_t center, word_t right_word) {
    return (center >> 1) | (right_word << 63);
}

// Bit-sliced carry for adding three 1-bit planes in parallel across all 64 cells.
__device__ __forceinline__ word_t majority3(word_t a, word_t b, word_t c) {
    return ((a ^ b) & c) | (a & b);
}

// Returns a 1-bit plane whose bit i is set iff exactly one of the four input
// bit-planes has bit i set.
__device__ __forceinline__ word_t exactly_one_of_four(word_t a, word_t b, word_t c, word_t d) {
    const word_t ab = a ^ b;
    const word_t cd = c ^ d;
    return (ab ^ cd) & ~((a & b) | (c & d) | (ab & cd));
}

// Compute the next generation for 64 cells at once.
//
// The 3x3 word neighborhood is supplied explicitly:
//
//   up_left   up_center   up_right
//   mid_left  mid_center  mid_right
//   dn_left   dn_center   dn_right
//
// The eight neighbor planes are first aligned so that bit i of each aligned word
// corresponds to the neighbor of cell i in `mid_center`.
//
// Then the 8-neighbor count is reduced with a tiny bit-sliced adder tree:
//
//   top    = NW + N + NE      -> (top1, top0)   in [0, 3]
//   middle = W + E            -> (mid1, mid0)   in [0, 2]
//   bottom = SW + S + SE      -> (bot1, bot0)   in [0, 3]
//
// Let:
//   low   = parity(top0, mid0, bot0)
//   carry = carry(top0, mid0, bot0)
//   H     = top1 + mid1 + bot1 + carry
//
// The Game of Life rule only needs to distinguish:
//   neighbors == 2  -> survive if currently alive
//   neighbors == 3  -> become/stay alive
//
// Because neighbors = low + 2*H, we only need H == 1.
// `low` then distinguishes 2 from 3.
// Therefore:
//
//   next = (H == 1) & (low | current)
//
// This updates all 64 cells with only Boolean logic, no per-cell loops, and no
// scalar popcount on individual bits.
__device__ __forceinline__ word_t life_step_word(
    word_t up_left,  word_t up_center,  word_t up_right,
    word_t mid_left, word_t mid_center, word_t mid_right,
    word_t dn_left,  word_t dn_center,  word_t dn_right) {

    const word_t nw = align_west(up_center, up_left);
    const word_t n  = up_center;
    const word_t ne = align_east(up_center, up_right);

    const word_t w  = align_west(mid_center, mid_left);
    const word_t e  = align_east(mid_center, mid_right);

    const word_t sw = align_west(dn_center, dn_left);
    const word_t s  = dn_center;
    const word_t se = align_east(dn_center, dn_right);

    const word_t top0 = nw ^ n ^ ne;
    const word_t top1 = majority3(nw, n, ne);

    const word_t mid0 = w ^ e;
    const word_t mid1 = w & e;

    const word_t bot0 = sw ^ s ^ se;
    const word_t bot1 = majority3(sw, s, se);

    const word_t low   = top0 ^ mid0 ^ bot0;
    const word_t carry = majority3(top0, mid0, bot0);

    const word_t high_eq_1 = exactly_one_of_four(top1, mid1, bot1, carry);

    return high_eq_1 & (low | mid_center);
}

// Kernel layout:
//   - blockDim.x == 32, so each warp covers 32 consecutive words from one row.
//   - blockDim.y > 1 to keep enough warps per block for occupancy.
//
// Main optimization:
//   Each thread loads only the three "center column" words:
//       row-1, row, row+1 at its own x position.
//   Left/right words are usually obtained from adjacent lanes via warp shuffles.
//   Only the two warp-edge lanes need cross-warp fallback loads.
//   This cuts the common-case global loads from 9 words/thread to 3 words/thread.
__global__ __launch_bounds__(kBlockThreads)
void game_of_life_kernel(const packed_t* __restrict__ input,
                         packed_t* __restrict__ output,
                         int words_per_row,
                         int grid_dimensions) {
    const int lane = static_cast<int>(threadIdx.x);
    const int col  = static_cast<int>(blockIdx.x) * kBlockX + lane;
    const int row  = static_cast<int>(blockIdx.y) * kBlockY + static_cast<int>(threadIdx.y);

    if (row >= grid_dimensions || col >= words_per_row) {
        return;
    }

    const int last_row = grid_dimensions - 1;
    const int last_col = words_per_row - 1;

    const bool has_up    = (row != 0);
    const bool has_down  = (row != last_row);
    const bool has_left  = (col != 0);
    const bool has_right = (col != last_col);

    const std::size_t idx =
        static_cast<std::size_t>(row) * static_cast<std::size_t>(words_per_row) +
        static_cast<std::size_t>(col);

    const std::ptrdiff_t stride = static_cast<std::ptrdiff_t>(words_per_row);
    const packed_t* const p = input + idx;

    word_t up_center = 0ull;
    word_t dn_center = 0ull;

    if (has_up) {
        up_center = load_word(p - stride);
    }

    const word_t mid_center = load_word(p);

    if (has_down) {
        dn_center = load_word(p + stride);
    }

    // The active mask is required because the last X block can be a partial warp
    // (for example, 16 words/row when grid_dimensions == 1024).
    const unsigned mask = __activemask();

    const word_t up_from_left  = __shfl_up_sync(mask,   up_center, 1);
    const word_t mid_from_left = __shfl_up_sync(mask,   mid_center, 1);
    const word_t dn_from_left  = __shfl_up_sync(mask,   dn_center, 1);

    const word_t up_from_right  = __shfl_down_sync(mask, up_center, 1);
    const word_t mid_from_right = __shfl_down_sync(mask, mid_center, 1);
    const word_t dn_from_right  = __shfl_down_sync(mask, dn_center, 1);

    // Default case: horizontal neighbors come from adjacent lanes.
    // Warp-edge lanes overwrite with direct cross-warp loads if those words exist.
    const bool left_in_warp  = (lane != 0);
    const bool right_in_warp = (lane != (kBlockX - 1)) && has_right;

    word_t up_left  = left_in_warp  ? up_from_left   : 0ull;
    word_t mid_left = left_in_warp  ? mid_from_left  : 0ull;
    word_t dn_left  = left_in_warp  ? dn_from_left   : 0ull;

    word_t up_right  = right_in_warp ? up_from_right  : 0ull;
    word_t mid_right = right_in_warp ? mid_from_right : 0ull;
    word_t dn_right  = right_in_warp ? dn_from_right  : 0ull;

    // Cross-warp fallback for the left word. Outside-grid cells stay zero.
    if (!left_in_warp && has_left) {
        mid_left = load_word(p - 1);
        if (has_up) {
            up_left = load_word(p - stride - 1);
        }
        if (has_down) {
            dn_left = load_word(p + stride - 1);
        }
    }

    // Cross-warp fallback for the right word. Outside-grid cells stay zero.
    if (!right_in_warp && has_right) {
        mid_right = load_word(p + 1);
        if (has_up) {
            up_right = load_word(p - stride + 1);
        }
        if (has_down) {
            dn_right = load_word(p + stride + 1);
        }
    }

    output[idx] = store_word(life_step_word(
        up_left,  up_center,  up_right,
        mid_left, mid_center, mid_right,
        dn_left,  dn_center,  dn_right));
}

}  // namespace

void run_game_of_life(const std::uint64_t* input,
                      std::uint64_t* output,
                      int grid_dimensions) {
    // The prompt guarantees a power-of-two square side length > 512, so the row
    // width in packed 64-bit words is always integral and at least 16.
    const int words_per_row = grid_dimensions >> 6;

    const dim3 block(kBlockX, kBlockY);
    const dim3 grid(
        static_cast<unsigned>((words_per_row   + kBlockX - 1) / kBlockX),
        static_cast<unsigned>((grid_dimensions + kBlockY - 1) / kBlockY));

    // Intentionally fire-and-forget: the caller owns synchronization and error
    // handling/timing policy.
    game_of_life_kernel<<<grid, block>>>(input, output, words_per_row, grid_dimensions);
}

#include <cuda_runtime.h>
#include <cstddef>
#include <cstdint>

// High-throughput one-step Conway's Game of Life for a square, bit-packed grid.
//
// Design choices driven purely by throughput:
//   * one thread updates one 64-bit word (64 cells), so no atomics are needed.
//   * the 64 cells in a word are updated simultaneously with bit-sliced boolean arithmetic;
//     there is no per-cell loop and no per-cell popcount.
//   * shared/texture memory are intentionally avoided. Horizontal reuse is captured with
//     warp shuffles, while the remaining vertical loads are cache-friendly on modern
//     datacenter GPUs.
//
// Outside-the-grid cells are dead, so missing rows/words are injected as zeros.

namespace
{
using u64 = unsigned long long;

constexpr int kThreadsPerBlock = 256;
constexpr int kCellsPerWordLog2 = 6;  // 64 packed cells per 64-bit word.
constexpr int kWordEdgeBit = 63;
constexpr unsigned int kFullWarpMask = 0xFFFFFFFFu;

static_assert(sizeof(u64) == sizeof(std::uint64_t), "Expected 64-bit words.");
static_assert((kThreadsPerBlock & (kThreadsPerBlock - 1)) == 0, "Block size must be a power of two.");
static_assert((kThreadsPerBlock % 32) == 0, "Block size must be warp aligned.");

__device__ __forceinline__ u64 load_word(const std::uint64_t* __restrict__ words, std::size_t idx)
{
    return static_cast<u64>(words[idx]);
}

__device__ __forceinline__ u64 align_west(const u64 center_word, const u64 left_word)
{
    // Bit i receives the state of cell i-1.
    // The only cross-word case is bit 0, which pulls bit 63 from the word to the left.
    return (center_word << 1) | (left_word >> kWordEdgeBit);
}

__device__ __forceinline__ u64 align_east(const u64 center_word, const u64 right_word)
{
    // Bit i receives the state of cell i+1.
    // The only cross-word case is bit 63, which pulls bit 0 from the word to the right.
    return (center_word >> 1) | (right_word << kWordEdgeBit);
}

__device__ __forceinline__ void csa3(const u64 a, const u64 b, const u64 c, u64& carry, u64& sum)
{
    // Carry-save adder on three 1-bit planes:
    //   a + b + c = sum + 2*carry
    // performed independently for all 64 bit positions.
    const u64 ab_xor = a ^ b;
    sum = ab_xor ^ c;
    carry = (a & b) | (ab_xor & c);
}

__device__ __forceinline__ void sum_three_adjacent(
    const u64 left_word,
    const u64 center_word,
    const u64 right_word,
    u64& high_bit,
    u64& low_bit)
{
    // Counts the three horizontally adjacent cells for every bit position in one row:
    //   [x-1, x, x+1] -> low_bit + 2*high_bit
    const u64 west = align_west(center_word, left_word);
    const u64 east = align_east(center_word, right_word);
    csa3(west, center_word, east, high_bit, low_bit);
}

__device__ __forceinline__ u64 one_of_four(const u64 a, const u64 b, const u64 c, const u64 d)
{
    // Exact-one detector for four 1-bit planes.
    // Used for H = carry0 + top_hi + mid_hi + bot_hi.
    const u64 ab_xor = a ^ b;
    const u64 ab_carry = a & b;
    const u64 cd_xor = c ^ d;
    const u64 cd_carry = c & d;
    return (ab_xor ^ cd_xor) & ~(ab_carry | cd_carry | (ab_xor & cd_xor));
}

__global__ __launch_bounds__(kThreadsPerBlock)
void game_of_life_kernel(
    const std::uint64_t* __restrict__ input,
    std::uint64_t* __restrict__ output,
    const std::size_t words_per_row,
    const std::size_t word_mask,
    const std::size_t last_row_base)
{
    // One thread updates one packed 64-cell word.
    //
    // Horizontal neighbor words are obtained from adjacent lanes via warp shuffles whenever
    // they live inside the same warp. Only warp-boundary lanes (0 and 31) need a global-load
    // fallback, and only when the neighboring word is still inside the same row.
    //
    // The problem constraints imply:
    //   grid_dimensions = 2^k, k >= 10
    //   words_per_row   = grid_dimensions / 64 = 2^(k-6)
    //   total_words     = grid_dimensions * words_per_row = 2^(2k-6)
    //
    // So total_words is a power of two and at least 2^14. With a power-of-two block size
    // (256), the launch covers the domain exactly: no tail threads and every warp is full.
    const std::size_t idx =
        static_cast<std::size_t>(blockIdx.x) * static_cast<std::size_t>(kThreadsPerBlock) +
        static_cast<std::size_t>(threadIdx.x);

    const std::size_t x = idx & word_mask;
    const bool has_left = x != 0;
    const bool has_right = x != word_mask;
    const bool has_up = idx >= words_per_row;
    const bool has_down = idx < last_row_base;

    // Missing rows are zero because cells outside the grid are dead.
    const u64 center = load_word(input, idx);
    const u64 above = has_up ? load_word(input, idx - words_per_row) : 0ull;
    const u64 below = has_down ? load_word(input, idx + words_per_row) : 0ull;

    // Warp-local horizontal reuse. For words_per_row == 16, a warp spans two rows, but the
    // has_left/has_right predicates prevent crossing the row boundary at lanes 15/16.
    const u64 center_prev = __shfl_up_sync(kFullWarpMask, center, 1);
    const u64 center_next = __shfl_down_sync(kFullWarpMask, center, 1);
    const u64 above_prev = __shfl_up_sync(kFullWarpMask, above, 1);
    const u64 above_next = __shfl_down_sync(kFullWarpMask, above, 1);
    const u64 below_prev = __shfl_up_sync(kFullWarpMask, below, 1);
    const u64 below_next = __shfl_down_sync(kFullWarpMask, below, 1);

    const unsigned int lane = threadIdx.x & 31u;

    const bool use_shfl_left = has_left && (lane != 0u);
    const bool use_shfl_right = has_right && (lane != 31u);
    const bool load_left = has_left && (lane == 0u);
    const bool load_right = has_right && (lane == 31u);

    // Missing left/right words are zero for the same "outside the grid is dead" reason.
    const u64 left_word = use_shfl_left
        ? center_prev
        : (load_left ? load_word(input, idx - 1) : 0ull);
    const u64 right_word = use_shfl_right
        ? center_next
        : (load_right ? load_word(input, idx + 1) : 0ull);

    const u64 above_left = use_shfl_left
        ? above_prev
        : ((load_left && has_up) ? load_word(input, idx - words_per_row - 1) : 0ull);
    const u64 above_right = use_shfl_right
        ? above_next
        : ((load_right && has_up) ? load_word(input, idx - words_per_row + 1) : 0ull);

    const u64 below_left = use_shfl_left
        ? below_prev
        : ((load_left && has_down) ? load_word(input, idx + words_per_row - 1) : 0ull);
    const u64 below_right = use_shfl_right
        ? below_next
        : ((load_right && has_down) ? load_word(input, idx + words_per_row + 1) : 0ull);

    // Row-wise neighbor counts:
    //   top    = above-left + above + above-right
    //   middle = left + right
    //   bottom = below-left + below + below-right
    u64 top_hi, top_lo;
    sum_three_adjacent(above_left, above, above_right, top_hi, top_lo);

    const u64 west = align_west(center, left_word);
    const u64 east = align_east(center, right_word);
    const u64 mid_lo = west ^ east;  // 0/1 count bit for the two same-row side neighbors.
    const u64 mid_hi = west & east;  // 2's bit for the two same-row side neighbors.

    u64 bot_hi, bot_lo;
    sum_three_adjacent(below_left, below, below_right, bot_hi, bot_lo);

    // Sum the low bits from the three row contributions:
    //   top_lo + mid_lo + bot_lo = count0 + 2*carry0
    u64 carry0, count0;
    csa3(top_lo, mid_lo, bot_lo, carry0, count0);

    // Total neighbor count can now be written as:
    //   neighbors = count0 + 2 * H
    // where
    //   H = carry0 + top_hi + mid_hi + bot_hi
    //
    // The only counts that matter are 2 and 3:
    //   2 -> H == 1 and count0 == 0
    //   3 -> H == 1 and count0 == 1
    //
    // So the final rule becomes:
    //   next = (H == 1) & (count0 | center)
    // which simultaneously implements:
    //   * birth on exactly 3 neighbors
    //   * survival on exactly 2 or 3 neighbors
    const u64 high_sum_eq_one = one_of_four(carry0, top_hi, mid_hi, bot_hi);
    const u64 next = high_sum_eq_one & (count0 | center);

    output[idx] = static_cast<std::uint64_t>(next);
}
}  // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions)
{
    // The caller guarantees:
    //   * grid_dimensions is a power of two
    //   * grid_dimensions > 512
    //   * input and output are device pointers allocated by cudaMalloc
    //
    // No synchronization or error checking is done here by design: the caller owns
    // synchronization, and raw step throughput is the only concern.
    const std::size_t words_per_row = static_cast<std::size_t>(grid_dimensions) >> kCellsPerWordLog2;
    const std::size_t word_mask = words_per_row - 1;
    const std::size_t total_words = static_cast<std::size_t>(grid_dimensions) * words_per_row;
    const std::size_t last_row_base = total_words - words_per_row;

    // Exact division under the stated constraints because total_words is a power of two
    // and kThreadsPerBlock is also a power of two.
    const unsigned int blocks = static_cast<unsigned int>(total_words / kThreadsPerBlock);

    game_of_life_kernel<<<blocks, kThreadsPerBlock>>>(
        input,
        output,
        words_per_row,
        word_mask,
        last_row_base);
}

#include <cstddef>
#include <cstdint>
#include <cuda_runtime.h>

// Optimized Conway's Game of Life for a bit-packed square grid.
//
// Key choices made for throughput on modern data-center GPUs:
// - The kernel operates directly on the packed representation; no unpacking pass.
// - One thread updates one 64-bit word, i.e. 64 cells, so writes are naturally race-free.
// - Shared memory is intentionally avoided. Left/right word exchange is done with warp
//   shuffles, which is cheaper than staging 3x3 neighborhoods in shared memory here.
// - Neighbor counts are accumulated bit-slice style with carry-save adders, so all 64
//   cells in a word are updated simultaneously with integer logic.

namespace detail {

using u64 = std::uint64_t;
using usize = std::size_t;

static_assert(sizeof(u64) == 8, "This implementation requires 64-bit words.");

constexpr int kCellsPerWordShift = 6;  // 2^6 = 64 cells per packed word.
constexpr int kBlockThreads = 256;
constexpr unsigned kFullWarpMask = 0xFFFFFFFFu;

// Host-side helper. The input is guaranteed to be a power of two.
inline int log2_pow2(int value) noexcept {
    int shift = 0;
    while (value > 1) {
        value >>= 1;
        ++shift;
    }
    return shift;
}

// Bit 0 is treated as the leftmost cell in the 64-cell span, matching the problem
// statement: bit 0 needs words to the left, bit 63 needs words to the right.
__device__ __forceinline__ u64 neighbor_from_left(u64 word, u64 left_word) {
    return (word << 1) | (left_word >> 63);
}

__device__ __forceinline__ u64 neighbor_from_right(u64 word, u64 right_word) {
    return (word >> 1) | (right_word << 63);
}

// Carry-save add of three 1-bit planes across all 64 bit positions in parallel.
// Written in canonical XOR/AND/OR form so NVCC can lower it efficiently on modern GPUs.
__device__ __forceinline__ void csa(u64& carry, u64& sum, u64 a, u64 b, u64 c) {
    const u64 ab_xor = a ^ b;
    sum = ab_xor ^ c;
    carry = (a & b) | (ab_xor & c);
}

// Sum the three neighbors contributed by a row above or below:
//   upper-left / upper / upper-right   or   lower-left / lower / lower-right
// The result is returned as two bit-planes: ones and twos.
__device__ __forceinline__ void row_sum3(
    u64 row_center_word,
    u64 row_left_word,
    u64 row_right_word,
    u64& ones,
    u64& twos) {
    const u64 left = neighbor_from_left(row_center_word, row_left_word);
    const u64 right = neighbor_from_right(row_center_word, row_right_word);
    csa(twos, ones, left, row_center_word, right);
}

// Sum the two horizontal neighbors in the current row. The center cell itself is
// intentionally excluded because Conway counts only neighbors.
__device__ __forceinline__ void row_sum2(
    u64 row_center_word,
    u64 row_left_word,
    u64 row_right_word,
    u64& ones,
    u64& twos) {
    const u64 left = neighbor_from_left(row_center_word, row_left_word);
    const u64 right = neighbor_from_right(row_center_word, row_right_word);
    ones = left ^ right;
    twos = left & right;
}

template <int SUBWARP_SHIFT>
__global__ __launch_bounds__(kBlockThreads)
void game_of_life_kernel(
    const u64* __restrict__ input,
    u64* __restrict__ output,
    int words_shift,
    int grid_dim) {
    constexpr int SUBWARP = 1 << SUBWARP_SHIFT;
    constexpr int GROUPS_PER_BLOCK = kBlockThreads / SUBWARP;

    const int lane = threadIdx.x & (SUBWARP - 1);
    const int subgroup = threadIdx.x >> SUBWARP_SHIFT;

    // The launch is linearized over contiguous row-segments instead of using grid.y.
    // This avoids the 65535 grid.y limit for very large boards while preserving
    // contiguous memory access within each subgroup.
    const usize segment =
        static_cast<usize>(blockIdx.x) * GROUPS_PER_BLOCK + static_cast<usize>(subgroup);

    const int words_per_row = 1 << words_shift;
    const int segment_row_shift = words_shift - SUBWARP_SHIFT;
    const usize segment_row_mask = static_cast<usize>((words_per_row >> SUBWARP_SHIFT) - 1);

    const usize y = segment >> segment_row_shift;
    const int x = static_cast<int>((segment & segment_row_mask) << SUBWARP_SHIFT) | lane;

    const int last_word = words_per_row - 1;
    const usize last_row = static_cast<usize>(grid_dim - 1);

    const bool has_left = (x != 0);
    const bool has_right = (x != last_word);
    const bool has_up = (y != 0);
    const bool has_down = (y != last_row);

    const usize row_base = y << words_shift;
    const usize idx = row_base | static_cast<usize>(x);
    const u64* p = input + idx;

    // Common-case traffic is just three coalesced loads per thread: above/current/below.
    // Interior left/right words are supplied via shuffles; only subgroup boundary lanes
    // perform extra global loads to cross subgroup boundaries or handle true edges.
    const u64 center = p[0];
    const u64 above = has_up ? p[-words_per_row] : 0ULL;
    const u64 below = has_down ? p[words_per_row] : 0ULL;

    // Exact power-of-two launch geometry means every subgroup is full, so a constant
    // full-warp mask is valid here. width=16/32 partitions the warp into subgroups.
    u64 above_left = __shfl_up_sync(kFullWarpMask, above, 1, SUBWARP);
    u64 above_right = __shfl_down_sync(kFullWarpMask, above, 1, SUBWARP);
    u64 center_left = __shfl_up_sync(kFullWarpMask, center, 1, SUBWARP);
    u64 center_right = __shfl_down_sync(kFullWarpMask, center, 1, SUBWARP);
    u64 below_left = __shfl_up_sync(kFullWarpMask, below, 1, SUBWARP);
    u64 below_right = __shfl_down_sync(kFullWarpMask, below, 1, SUBWARP);

    // Handle the special cases called out in the prompt:
    // - bit 0 needs the three words to the left (above-left / left / below-left)
    // - bit 63 needs the three words to the right (above-right / right / below-right)
    if (lane == 0) {
        above_left = (has_up && has_left) ? p[-words_per_row - 1] : 0ULL;
        center_left = has_left ? p[-1] : 0ULL;
        below_left = (has_down && has_left) ? p[words_per_row - 1] : 0ULL;
    }

    if (lane == SUBWARP - 1) {
        above_right = (has_up && has_right) ? p[-words_per_row + 1] : 0ULL;
        center_right = has_right ? p[1] : 0ULL;
        below_right = (has_down && has_right) ? p[words_per_row + 1] : 0ULL;
    }

    u64 top_ones, top_twos;
    row_sum3(above, above_left, above_right, top_ones, top_twos);

    u64 mid_ones, mid_twos;
    row_sum2(center, center_left, center_right, mid_ones, mid_twos);

    u64 bot_ones, bot_twos;
    row_sum3(below, below_left, below_right, bot_ones, bot_twos);

    // Add the three row-contribution bit-planes.
    //
    // After these two CSA stages:
    // - count_bit0 is the low bit of the 8-neighbor count.
    // - count_bit1 is 1 for counts 2,3,6,7.
    // - carry_to_fours is 1 for counts 5,6,7,8.
    //
    // Therefore:
    //   count_bit1 & ~carry_to_fours   <=>   neighbor count is exactly 2 or 3.
    u64 carry_to_twos, count_bit0;
    csa(carry_to_twos, count_bit0, top_ones, mid_ones, bot_ones);

    u64 carry_to_fours, twos_sum_lsb;
    csa(carry_to_fours, twos_sum_lsb, top_twos, mid_twos, bot_twos);

    const u64 count_bit1 = twos_sum_lsb ^ carry_to_twos;
    const u64 two_or_three = count_bit1 & ~carry_to_fours;

    // Game of Life rule:
    // - count == 3: born regardless of current state  -> count_bit0 == 1
    // - count == 2: survive only if already alive     -> count_bit0 == 0
    output[idx] = two_or_three & (count_bit0 | center);
}

}  // namespace detail

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions) {
    // grid_dimensions is guaranteed to be a power of two, so words_per_row and the
    // number of row-segments are also powers of two. That lets the kernel recover
    // x/y entirely with shifts and masks and lets the launch cover the board exactly
    // with no tail handling.
    const int words_shift = detail::log2_pow2(grid_dimensions) - detail::kCellsPerWordShift;
    const dim3 block(detail::kBlockThreads);

    // Prefer full 32-lane subgroups whenever a row has at least 32 words.
    // The only smaller valid case under the stated constraints is 16 words/row
    // (a 1024x1024 grid), where 16-lane subgroups avoid wasting half a warp.
    if (words_shift >= 5) {
        constexpr int kSubwarpShift = 5;
        constexpr int kGroupsPerBlock = detail::kBlockThreads >> kSubwarpShift;

        const std::size_t total_segments =
            static_cast<std::size_t>(grid_dimensions) << (words_shift - kSubwarpShift);
        const dim3 grid(static_cast<unsigned int>(total_segments / kGroupsPerBlock));

        // As required, synchronization is left entirely to the caller.
        detail::game_of_life_kernel<kSubwarpShift><<<grid, block>>>(
            input, output, words_shift, grid_dimensions);
    } else {
        constexpr int kSubwarpShift = 4;
        constexpr int kGroupsPerBlock = detail::kBlockThreads >> kSubwarpShift;

        const std::size_t total_segments =
            static_cast<std::size_t>(grid_dimensions) << (words_shift - kSubwarpShift);
        const dim3 grid(static_cast<unsigned int>(total_segments / kGroupsPerBlock));

        detail::game_of_life_kernel<kSubwarpShift><<<grid, block>>>(
            input, output, words_shift, grid_dimensions);
    }
}

#include <cstddef>
#include <cstdint>
#include <cuda_runtime.h>

// High-performance, bit-parallel Conway's Game of Life.
//
// Design choices tuned for modern NVIDIA data-center GPUs:
//   - One CUDA thread updates one packed 64-bit word (64 cells), so no atomics are needed.
//   - No shared memory: the only horizontal cross-word dependency is one bit wide after a 1-bit shift,
//     so shuffles are cheaper and simpler.
//   - Eight neighbor masks are counted with a bit-sliced carry-save adder tree, processing all
//     64 cells in parallel instead of iterating cell-by-cell.
//   - A 1D grid avoids the 65535 limit on grid.y for very large boards that still fit in memory.

namespace {

using word_t = std::uint64_t;

constexpr unsigned int kFullMask = 0xffffffffu;
constexpr int kBlockY = 8;

static_assert(sizeof(word_t) == 8, "Expected 64-bit packed words.");

struct SumCarry {
    word_t sum;
    word_t carry;
};

__device__ __forceinline__ SumCarry csa3(const word_t a, const word_t b, const word_t c) {
    // Bit-sliced carry-save adder:
    //   a + b + c = sum + 2 * carry
    // independently for all 64 bit positions.
    const word_t ab_xor = a ^ b;
    return {ab_xor ^ c, (a & b) | (ab_xor & c)};
}

__device__ __forceinline__ word_t exactly_one_of_four(
    const word_t a, const word_t b, const word_t c, const word_t d) {
    // True per bit position iff exactly one of {a,b,c,d} is set there.
    const word_t p0 = a ^ b;
    const word_t p1 = c ^ d;
    return (p0 ^ p1) & ~((a & b) | (c & d) | (p0 & p1));
}

template <int TILE_X>
__device__ __forceinline__ void shifted_row_neighbors(
    const word_t row,
    const word_t* __restrict__ input,
    const std::size_t row_idx,
    const bool has_left_word,
    const bool has_right_word,
    const unsigned int lane,
    word_t& west,
    word_t& east) {
    static_assert(TILE_X == 16 || TILE_X == 32, "Unsupported tile width.");

    // Bit i represents the i-th cell inside this 64-cell word span.
    // To align the west neighbor (x-1) with x, the row shifts left.
    // To align the east neighbor (x+1) with x, the row shifts right.
    //
    // After the shift, only one cross-word bit is missing:
    //   west: bit 63 from the word to the left -> injected into bit 0
    //   east: bit 0  from the word to the right -> injected into bit 63
    //
    // Most threads obtain that bit from the adjacent thread via a 16- or 32-lane shuffle.
    // Only subgroup-edge threads fall back to one global load.
    unsigned int left_msb =
        __shfl_up_sync(kFullMask, static_cast<unsigned int>(row >> 63), 1, TILE_X);
    unsigned int right_lsb =
        __shfl_down_sync(kFullMask, static_cast<unsigned int>(row & word_t{1}), 1, TILE_X);

    if (lane == 0u) {
        left_msb = has_left_word ? static_cast<unsigned int>(input[row_idx - 1] >> 63) : 0u;
    }
    if (lane == static_cast<unsigned int>(TILE_X - 1)) {
        right_lsb = has_right_word ? static_cast<unsigned int>(input[row_idx + 1] & word_t{1}) : 0u;
    }

    west = (row << 1) | static_cast<word_t>(left_msb);
    east = (row >> 1) | (static_cast<word_t>(right_lsb) << 63);
}

template <int TILE_X>
__global__ __launch_bounds__(TILE_X * kBlockY)
void game_of_life_kernel(
    const word_t* __restrict__ input,
    word_t* __restrict__ output,
    const int words_per_row,
    const int grid_dimensions,
    const unsigned int tiles_per_row_mask,
    const int tiles_per_row_shift) {
    static_assert(TILE_X == 16 || TILE_X == 32, "Unsupported tile width.");

    const unsigned int words = static_cast<unsigned int>(words_per_row);
    const unsigned int board_dim = static_cast<unsigned int>(grid_dimensions);

    // The board width in packed words is a power of two, so the number of row tiles is also
    // a power of two. That lets us recover (tile_x, tile_y) from a single linear block index
    // using a cheap mask+shift instead of division/modulo.
    const unsigned int linear_block = blockIdx.x;
    const unsigned int tile_x = linear_block & tiles_per_row_mask;
    const unsigned int tile_y = linear_block >> tiles_per_row_shift;

    // blockDim.x == TILE_X, so threadIdx.x is already the lane inside the 16- or 32-thread row subgroup.
    const unsigned int x = tile_x * TILE_X + threadIdx.x;
    const unsigned int y = tile_y * kBlockY + threadIdx.y;
    const unsigned int lane = threadIdx.x;

    const std::size_t stride = static_cast<std::size_t>(words);
    const std::size_t idx = static_cast<std::size_t>(y) * stride + static_cast<std::size_t>(x);

    // Exact tiling is possible because the problem guarantees power-of-two dimensions.
    const bool has_n = (y != 0u);
    const bool has_s = (y + 1u != board_dim);
    const bool has_l = (x != 0u);
    const bool has_r = (x + 1u != words);

    const word_t center = input[idx];
    const word_t north_row = has_n ? input[idx - stride] : word_t{0};
    const word_t south_row = has_s ? input[idx + stride] : word_t{0};

    const std::size_t north_idx = has_n ? (idx - stride) : idx;
    const std::size_t south_idx = has_s ? (idx + stride) : idx;

    word_t west_c, east_c;
    word_t west_n, east_n;
    word_t west_s, east_s;

    // Build aligned neighbor masks for the three relevant rows:
    //   north: NW, N, NE
    //   center: W, E
    //   south: SW, S, SE
    shifted_row_neighbors<TILE_X>(center,    input, idx,       has_l,           has_r,           lane, west_c, east_c);
    shifted_row_neighbors<TILE_X>(north_row, input, north_idx, has_n && has_l,  has_n && has_r,  lane, west_n, east_n);
    shifted_row_neighbors<TILE_X>(south_row, input, south_idx, has_s && has_l,  has_s && has_r,  lane, west_s, east_s);

    // Carry-save reduction of the eight 1-bit neighbor masks.
    //
    // The arrangement below produces:
    //   neighbor_count = b0 + 2*q
    // where q is the population count of four carry masks.
    //
    // Conway's rule needs only count == 2 or count == 3, so we never materialize the full 0..8 count.
    // We only test q == 1:
    //   q == 1 and b0 == 0  -> exactly 2 neighbors
    //   q == 1 and b0 == 1  -> exactly 3 neighbors
    const SumCarry north_acc  = csa3(west_n, north_row, east_n);     // NW + N + NE
    const SumCarry south_acc  = csa3(west_s, south_row, east_s);     // SW + S + SE
    const SumCarry middle_acc = csa3(west_c, east_c, north_acc.sum); // W + E + north_sum

    const word_t b0 = middle_acc.sum ^ south_acc.sum;
    const word_t d1 = middle_acc.sum & south_acc.sum;
    const word_t q_eq_1 =
        exactly_one_of_four(north_acc.carry, middle_acc.carry, south_acc.carry, d1);

    // If q == 1 then neighbor_count == 2 + b0:
    //   b0 == 0 -> survive only if currently alive
    //   b0 == 1 -> birth/survival unconditionally
    output[idx] = q_eq_1 & (b0 | center);
}

inline int log2_pow2(unsigned int v) {
    // v is guaranteed to be a power of two.
    int shift = 0;
    while (v > 1u) {
        v >>= 1u;
        ++shift;
    }
    return shift;
}

template <int TILE_X>
inline void launch_game_of_life_kernel(
    const word_t* input,
    word_t* output,
    const int words_per_row,
    const int grid_dimensions) {
    static_assert(TILE_X == 16 || TILE_X == 32, "Unsupported tile width.");

    const unsigned int tiles_per_row = static_cast<unsigned int>(words_per_row / TILE_X);
    const unsigned int blocks_y = static_cast<unsigned int>(grid_dimensions / kBlockY);
    const unsigned int total_blocks = tiles_per_row * blocks_y;

    // Row-major layout in tile space.
    const unsigned int tiles_per_row_mask = tiles_per_row - 1u;
    const int tiles_per_row_shift = log2_pow2(tiles_per_row);

    const dim3 block(TILE_X, kBlockY);
    const dim3 grid(total_blocks);

    // input/output are assumed to be distinct device buffers (double buffering),
    // and synchronization is intentionally left to the caller.
    game_of_life_kernel<TILE_X><<<grid, block>>>(
        input,
        output,
        words_per_row,
        grid_dimensions,
        tiles_per_row_mask,
        tiles_per_row_shift);
}

} // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions) {
    const int words_per_row = grid_dimensions >> 6;

    // The only legal board with fewer than 32 packed words per row is 1024x1024,
    // which has exactly 16 packed words per row. Specializing that case avoids
    // half-empty warp rows and keeps shuffle subgroups full.
    if (words_per_row == 16) {
        launch_game_of_life_kernel<16>(input, output, words_per_row, grid_dimensions);
    } else {
        launch_game_of_life_kernel<32>(input, output, words_per_row, grid_dimensions);
    }
}

#include <cuda_runtime.h>
#include <cstdint>

namespace {

// 64-bit packed cell word. Bit i corresponds to cell x = word_x * 64 + i in a row.
// With that convention:
//   left-neighbor-aligned  mask = (word << 1) | (left_word  >> 63)
//   right-neighbor-aligned mask = (word >> 1) | (right_word << 63)
// This is exactly the required special handling for bit 0 and bit 63.
using u64 = std::uint64_t;

// Fixed launch shape.
// For valid inputs:
//   grid_dimensions = 2^n, n >= 10
//   words_per_row   = grid_dimensions / 64 = 2^(n-6) >= 16
//   total_words     = grid_dimensions * words_per_row = 2^(2n-6)
// so total_words is always a multiple of 256, which lets the kernel avoid an
// idx < total_words guard in the hot path.
constexpr int kThreadsPerBlockLog2 = 8;
constexpr int kThreadsPerBlock = 1 << kThreadsPerBlockLog2;
constexpr unsigned kFullWarpMask = 0xFFFFFFFFu;

static_assert(sizeof(u64) == 8, "Expected 64-bit words.");
static_assert(sizeof(unsigned long long) == 8, "Expected 64-bit unsigned long long.");
static_assert(kThreadsPerBlock == 256, "Index computation below assumes 256 threads per block.");

// Bit-sliced half/full adders.
// Every bit position is an independent 1-bit lane, so one instruction sequence
// updates 64 cells at once. On modern NVIDIA GPUs these boolean forms map well
// to LOP3-heavy code.
__device__ __forceinline__ void half_adder(const u64 a, const u64 b, u64& sum, u64& carry) {
    sum = a ^ b;
    carry = a & b;
}

__device__ __forceinline__ void full_adder(const u64 a, const u64 b, const u64 c,
                                           u64& sum, u64& carry) {
    sum = a ^ b ^ c;
    carry = (a & b) | (a & c) | (b & c);
}

// 64-bit shuffle helpers. Shared memory is intentionally avoided; horizontal
// neighbor words are exchanged with warp shuffles instead. Only subgroup-edge
// lanes need extra global loads for cross-subgroup words.
template<int WIDTH>
__device__ __forceinline__ u64 subgroup_shfl_up_1(const u64 v) {
    return static_cast<u64>(
        __shfl_up_sync(kFullWarpMask, static_cast<unsigned long long>(v), 1, WIDTH));
}

template<int WIDTH>
__device__ __forceinline__ u64 subgroup_shfl_down_1(const u64 v) {
    return static_cast<u64>(
        __shfl_down_sync(kFullWarpMask, static_cast<unsigned long long>(v), 1, WIDTH));
}

// Current row contribution: only left/right neighbors count; the center bit does not.
__device__ __forceinline__ void horizontal_pair_count(
    const u64 row, const u64 left_word, const u64 right_word, u64& sum, u64& carry) {
    const u64 left_neighbors  = (row << 1) | (left_word >> 63);
    const u64 right_neighbors = (row >> 1) | (right_word << 63);
    half_adder(left_neighbors, right_neighbors, sum, carry);
}

// Top/bottom row contribution: left/center/right are all neighbors.
__device__ __forceinline__ void horizontal_triplet_count(
    const u64 row, const u64 left_word, const u64 right_word, u64& sum, u64& carry) {
    const u64 left_neighbors  = (row << 1) | (left_word >> 63);
    const u64 right_neighbors = (row >> 1) | (right_word << 63);
    full_adder(left_neighbors, row, right_neighbors, sum, carry);
}

// SUBGROUP_WIDTH is 16 only for a 1024x1024 grid (16 packed words per row).
// For all larger valid grids it is 32, so each warp processes a 32-word segment
// of a row. In both cases the subgroup width matches the natural horizontal
// shuffle domain, which keeps cross-lane neighbor exchange cheap and correct.
template<int SUBGROUP_WIDTH>
__global__ __launch_bounds__(kThreadsPerBlock, 2)
void game_of_life_kernel(const u64* __restrict__ input,
                         u64* __restrict__ output,
                         const unsigned int words_per_row,
                         const u64 total_words) {
    static_assert(SUBGROUP_WIDTH == 16 || SUBGROUP_WIDTH == 32,
                  "Only 16- and 32-lane shuffle subgroups are supported.");

    // Exact 1-D mapping: one thread owns one 64-cell word.
    const u64 idx = (static_cast<u64>(blockIdx.x) << kThreadsPerBlockLog2) +
                    static_cast<u64>(threadIdx.x);

    // Because words_per_row is a power of two, x-within-row is a simple mask.
    const u64 stride   = static_cast<u64>(words_per_row);
    const u64 row_mask = stride - 1ULL;
    const u64 x        = idx & row_mask;

    const bool has_left   = x != 0ULL;
    const bool has_right  = x != row_mask;
    const bool has_top    = idx >= stride;
    const bool has_bottom = idx + stride < total_words;

    // Common-case global loads: only the vertically aligned words.
    // Relative to a naive 9-load stencil, the hot path is reduced to 3 loads/thread.
    const u64 center = input[idx];

    u64 top = 0ULL;
    u64 bottom = 0ULL;
    u64 top_idx = 0ULL;
    u64 bottom_idx = 0ULL;

    if (has_top) {
        top_idx = idx - stride;
        top = input[top_idx];
    }
    if (has_bottom) {
        bottom_idx = idx + stride;
        bottom = input[bottom_idx];
    }

    // Determine whether this lane sits at a shuffle subgroup boundary.
    // Only those lanes need the extra global loads for cross-subgroup words.
    const unsigned int lane = threadIdx.x & 31U;
    const unsigned int subgroup_mask = static_cast<unsigned int>(SUBGROUP_WIDTH - 1);
    const unsigned int lane_in_group = lane & subgroup_mask;
    const bool first_in_group = lane_in_group == 0U;
    const bool last_in_group  = lane_in_group == subgroup_mask;

    // Current row: get the word to the left/right.
    u64 left_word = subgroup_shfl_up_1<SUBGROUP_WIDTH>(center);
    u64 right_word = subgroup_shfl_down_1<SUBGROUP_WIDTH>(center);

    if (first_in_group) {
        left_word = has_left ? input[idx - 1ULL] : 0ULL;
    }
    if (last_in_group) {
        right_word = has_right ? input[idx + 1ULL] : 0ULL;
    }

    u64 mid_sum;
    u64 mid_carry;
    horizontal_pair_count(center, left_word, right_word, mid_sum, mid_carry);

    // Top row: same shuffle pattern, but boundary loads come from the row above.
    left_word = subgroup_shfl_up_1<SUBGROUP_WIDTH>(top);
    right_word = subgroup_shfl_down_1<SUBGROUP_WIDTH>(top);

    if (first_in_group) {
        left_word = (has_top && has_left) ? input[top_idx - 1ULL] : 0ULL;
    }
    if (last_in_group) {
        right_word = (has_top && has_right) ? input[top_idx + 1ULL] : 0ULL;
    }

    u64 top_sum;
    u64 top_carry;
    horizontal_triplet_count(top, left_word, right_word, top_sum, top_carry);

    // Bottom row: same again for the row below.
    left_word = subgroup_shfl_up_1<SUBGROUP_WIDTH>(bottom);
    right_word = subgroup_shfl_down_1<SUBGROUP_WIDTH>(bottom);

    if (first_in_group) {
        left_word = (has_bottom && has_left) ? input[bottom_idx - 1ULL] : 0ULL;
    }
    if (last_in_group) {
        right_word = (has_bottom && has_right) ? input[bottom_idx + 1ULL] : 0ULL;
    }

    u64 bottom_sum;
    u64 bottom_carry;
    horizontal_triplet_count(bottom, left_word, right_word, bottom_sum, bottom_carry);

    // Each row count is encoded as:
    //   row_count = row_sum + 2 * row_carry
    //
    // Add the three row counts in bit-sliced form:
    //   total_count = ones + 2 * twos + 4 * high
    // where `high` is intentionally saturated to "count >= 4", because the Life
    // rule only needs exact counts 2 and 3.
    u64 ones;
    u64 twos_from_row_lsb;
    full_adder(top_sum, mid_sum, bottom_sum, ones, twos_from_row_lsb);

    u64 twos_from_row_msb;
    u64 high_from_row_msb;
    full_adder(top_carry, mid_carry, bottom_carry,
               twos_from_row_msb, high_from_row_msb);

    u64 twos;
    u64 overflow_to_four_or_more;
    half_adder(twos_from_row_lsb, twos_from_row_msb, twos, overflow_to_four_or_more);

    const u64 high = high_from_row_msb | overflow_to_four_or_more;

    // Conway rule in bit-sliced form:
    //   count == 2 -> survive iff currently alive
    //   count == 3 -> always alive
    //
    // `twos & ~high` selects counts {2, 3}; `(ones | center)` turns:
    //   count 2 -> center
    //   count 3 -> 1
    output[idx] = twos & ~high & (ones | center);
}

} // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions) {
    // Contract assumptions from the problem statement are taken as given:
    // - square grid
    // - grid_dimensions is a power of two and > 512
    // - input/output are device pointers from cudaMalloc
    // - input/output fit in device memory
    //
    // No host/device synchronization or launch error checking is done here;
    // the caller explicitly owns synchronization, and only steady-state speed matters.
    const unsigned int words_per_row = static_cast<unsigned int>(grid_dimensions >> 6);
    const u64 total_words =
        static_cast<u64>(grid_dimensions) * static_cast<u64>(words_per_row);

    // Exact launch: total_words is always a multiple of 256 for valid inputs.
    const unsigned int blocks =
        static_cast<unsigned int>(total_words >> kThreadsPerBlockLog2);

    // 1024x1024 -> 16 packed words per row, so half-warps are the natural shuffle domain.
    // Larger grids have at least 32 packed words per row, so full-warps are used.
    if (words_per_row == 16U) {
        game_of_life_kernel<16><<<blocks, kThreadsPerBlock>>>(
            input, output, words_per_row, total_words);
    } else {
        game_of_life_kernel<32><<<blocks, kThreadsPerBlock>>>(
            input, output, words_per_row, total_words);
    }
}

#include <cuda_runtime.h>

#include <cstddef>
#include <cstdint>

namespace detail {

// Broadword / SWAR implementation for Conway's Game of Life.
//
// - One CUDA thread owns one 64-bit packed word, so no atomics are needed.
// - Each thread advances 64 cells at once with bitwise logic.
// - The 0th and 63rd bits are handled by injecting edge bits from the adjacent
//   left/right words, so there is no per-bit scalar slow path.
// - A tiny boundary kernel peels the outer perimeter away from the hot interior
//   kernel. This keeps the interior loads branch-free while still honoring the
//   "outside the grid is dead" rule.
// - Shared/texture memory are intentionally not used here; for this access
//   pattern, the hardware caches on modern A100/H100-class GPUs are sufficient.

using u64   = std::uint64_t;
using usize = std::size_t;

constexpr int kThreadsPerBlock = 256;
constexpr int kWordShift       = 6;   // 64 cells per packed word.
constexpr int kEdgeBit         = 63;  // Cross-word injection bit for left/right shifts.

// 3:2 compressor / carry-save adder.
// For three 1-bit planes a,b,c it produces:
//   value = sum + 2 * carry
// lane-wise and independently for all 64 bits.
// This boolean pattern maps well to modern NVIDIA ternary-logic hardware.
__device__ __forceinline__ void csa3(u64 a, u64 b, u64 c, u64& sum, u64& carry) {
    const u64 axb = a ^ b;
    sum   = axb ^ c;
    carry = (a & b) | (c & axb);
}

// Build the "left-neighbor" bitboard for the 64 cells stored in center_word.
// Bit i of the result becomes cell (i-1) from center_word, except result bit 0,
// which receives bit 63 from left_word. This is exactly the special handling
// needed for the 0th bit across the three words to the left (upper/current/lower).
__device__ __forceinline__ u64 align_left_neighbors(u64 left_word, u64 center_word) {
    return (center_word << 1) | (left_word >> kEdgeBit);
}

// Symmetric operation for the right neighbors: result bit 63 receives bit 0
// from right_word, which handles the 63rd-bit cross-word case.
__device__ __forceinline__ u64 align_right_neighbors(u64 center_word, u64 right_word) {
    return (center_word >> 1) | (right_word << kEdgeBit);
}

// Advance one 64-cell word.
// uL/uC/uR = words from the row above
// mL/mC/mR = words from the current row
// bL/bC/bR = words from the row below
//
// The eight neighbor planes are reduced with a carry-save tree into:
//   ones = neighbor_count bit 0
//   twos = neighbor_count bit 1
//   ge4  = neighbor_count >= 4
//
// The Game-of-Life rule
//   next = (count == 3) | (alive & count == 2)
// simplifies to
//   next = twos & !ge4 & (ones | alive)
__device__ __forceinline__ u64 evolve_word(
    u64 uL, u64 uC, u64 uR,
    u64 mL, u64 mC, u64 mR,
    u64 bL, u64 bC, u64 bR) {

    u64 s1, c1;
    {
        const u64 top_left  = align_left_neighbors(uL, uC);
        const u64 top       = uC;
        const u64 top_right = align_right_neighbors(uC, uR);
        csa3(top_left, top, top_right, s1, c1);
    }

    u64 s2, c2;
    {
        const u64 left        = align_left_neighbors(mL, mC);
        const u64 right       = align_right_neighbors(mC, mR);
        const u64 bottom_left = align_left_neighbors(bL, bC);
        csa3(left, right, bottom_left, s2, c2);
    }

    u64 s3, c3;
    csa3(s1, s2, bC, s3, c3);

    const u64 bottom_right = align_right_neighbors(bC, bR);
    const u64 ones         = s3 ^ bottom_right;
    const u64 c4           = s3 & bottom_right;

    u64 s4, c5;
    csa3(c1, c2, c3, s4, c5);

    const u64 twos = s4 ^ c4;
    const u64 ge4  = c5 | (s4 & c4);

    return twos & ~ge4 & (ones | mC);
}

// Exact tiling of the full word lattice with a 1D block grid.
// We keep a 2D thread block so warps still traverse contiguous words within a row,
// but flatten the grid to 1D to avoid CUDA's 65535 limit on grid.y.
// Because both the board dimensions and the block geometry are powers of two,
// blockIdx.x can be split back into (tile_x, tile_y) with a mask and a shift.
template <int BLOCK_X_SHIFT, int BLOCK_Y_SHIFT>
__global__ __launch_bounds__(kThreadsPerBlock)
void game_of_life_interior_kernel(
    const u64* __restrict__ input,
    u64* __restrict__ output,
    int words_per_row,
    int row_shift,
    int grid_dimensions,
    int tiles_x_mask,
    int tiles_x_shift) {

    constexpr int BLOCK_X = 1 << BLOCK_X_SHIFT;
    constexpr int BLOCK_Y = 1 << BLOCK_Y_SHIFT;
    (void)BLOCK_X;
    (void)BLOCK_Y;

    const int tile   = static_cast<int>(blockIdx.x);
    const int tile_x = tile & tiles_x_mask;
    const int tile_y = tile >> tiles_x_shift;

    const int x = (tile_x << BLOCK_X_SHIFT) + static_cast<int>(threadIdx.x);
    const int y = (tile_y << BLOCK_Y_SHIFT) + static_cast<int>(threadIdx.y);

    const int last_word = words_per_row - 1;
    const int last_row  = grid_dimensions - 1;

    // The boundary is handled by a tiny second kernel so the hot path below can
    // assume that all eight neighboring words exist.
    if (x == 0 || x == last_word || y == 0 || y == last_row) {
        return;
    }

    const usize pitch = static_cast<usize>(words_per_row);
    const usize base  = (static_cast<usize>(y) << row_shift) + static_cast<usize>(x);

    const u64* mid  = input + base;
    const u64* up   = mid - pitch;
    const u64* down = mid + pitch;

    const u64 uL = up[-1];
    const u64 uC = up[0];
    const u64 uR = up[1];

    const u64 mL = mid[-1];
    const u64 mC = mid[0];
    const u64 mR = mid[1];

    const u64 bL = down[-1];
    const u64 bC = down[0];
    const u64 bR = down[1];

    output[base] = evolve_word(uL, uC, uR, mL, mC, mR, bL, bC, bR);
}

// Separate boundary pass.
// Grouping boundary words as top, bottom, left, right keeps most warps within a
// single boundary class, which minimizes divergence inside this already-small kernel.
__global__ __launch_bounds__(kThreadsPerBlock)
void game_of_life_boundary_kernel(
    const u64* __restrict__ input,
    u64* __restrict__ output,
    int words_per_row,
    int row_shift,
    int grid_dimensions) {

    const int tid = static_cast<int>(blockIdx.x) * kThreadsPerBlock + static_cast<int>(threadIdx.x);

    const int side_rows      = grid_dimensions - 2;
    const int top_end        = words_per_row;
    const int bottom_end     = top_end + words_per_row;
    const int left_end       = bottom_end + side_rows;
    const int boundary_words = left_end + side_rows;

    if (tid >= boundary_words) {
        return;
    }

    const int last_word = words_per_row - 1;
    const int last_row  = grid_dimensions - 1;

    int x;
    int y;

    if (tid < top_end) {
        y = 0;
        x = tid;
    } else if (tid < bottom_end) {
        y = last_row;
        x = tid - top_end;
    } else if (tid < left_end) {
        y = 1 + (tid - bottom_end);
        x = 0;
    } else {
        y = 1 + (tid - left_end);
        x = last_word;
    }

    const bool has_up    = (y != 0);
    const bool has_down  = (y != last_row);
    const bool has_left  = (x != 0);
    const bool has_right = (x != last_word);

    const usize pitch = static_cast<usize>(words_per_row);
    const usize base  = (static_cast<usize>(y) << row_shift) + static_cast<usize>(x);

    const u64* mid = input + base;

    u64 uL = 0, uC = 0, uR = 0;
    u64 mL = 0, mC = mid[0], mR = 0;
    u64 bL = 0, bC = 0, bR = 0;

    if (has_up) {
        const u64* up = mid - pitch;
        uC = up[0];
        if (has_left)  uL = up[-1];
        if (has_right) uR = up[1];
    }

    if (has_left)  mL = mid[-1];
    if (has_right) mR = mid[1];

    if (has_down) {
        const u64* down = mid + pitch;
        bC = down[0];
        if (has_left)  bL = down[-1];
        if (has_right) bR = down[1];
    }

    output[base] = evolve_word(uL, uC, uR, mL, mC, mR, bL, bC, bR);
}

// Host-side helper: input is guaranteed to be a power of two.
inline int log2_power_of_two(unsigned value) {
    int shift = 0;
    while ((1u << shift) < value) {
        ++shift;
    }
    return shift;
}

template <int BLOCK_X_SHIFT, int BLOCK_Y_SHIFT>
inline void launch_interior_kernel(
    const u64* input,
    u64* output,
    int words_per_row,
    int row_shift,
    int grid_dimensions) {

    constexpr int BLOCK_X = 1 << BLOCK_X_SHIFT;
    constexpr int BLOCK_Y = 1 << BLOCK_Y_SHIFT;
    static_assert(BLOCK_X * BLOCK_Y == kThreadsPerBlock, "interior block must have 256 threads");

    const int tiles_x       = words_per_row >> BLOCK_X_SHIFT;
    const int tiles_y       = grid_dimensions >> BLOCK_Y_SHIFT;
    const int tiles_x_mask  = tiles_x - 1;
    const int tiles_x_shift = log2_power_of_two(static_cast<unsigned>(tiles_x));

    const unsigned int blocks = static_cast<unsigned int>(tiles_x) * static_cast<unsigned int>(tiles_y);
    const dim3 grid(blocks, 1, 1);
    const dim3 block(BLOCK_X, BLOCK_Y, 1);

    game_of_life_interior_kernel<BLOCK_X_SHIFT, BLOCK_Y_SHIFT>
        <<<grid, block>>>(input, output, words_per_row, row_shift, grid_dimensions, tiles_x_mask, tiles_x_shift);
}

}  // namespace detail

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions) {
    // Out-of-place update: input and output are assumed to be different device buffers.
    // The caller is responsible for any synchronization/error handling around this launch.
    const int words_per_row = grid_dimensions >> detail::kWordShift;
    const int row_shift     = detail::log2_power_of_two(static_cast<unsigned>(words_per_row));

    // Keep 256 threads/block but adapt the x dimension to the row width so that,
    // whenever possible, each warp owns a contiguous run of words within a row:
    //   16 words/row  -> 16x16
    //   32 words/row  -> 32x8
    //   64+ words/row -> 64x4
    if (words_per_row >= 64) {
        detail::launch_interior_kernel<6, 2>(input, output, words_per_row, row_shift, grid_dimensions);
    } else if (words_per_row >= 32) {
        detail::launch_interior_kernel<5, 3>(input, output, words_per_row, row_shift, grid_dimensions);
    } else {
        detail::launch_interior_kernel<4, 4>(input, output, words_per_row, row_shift, grid_dimensions);
    }

    // Perimeter in words, with corners counted only once:
    //   top row + bottom row + left side (without corners) + right side (without corners)
    const int boundary_words = 2 * (words_per_row + grid_dimensions - 2);
    if (boundary_words > 0) {
        const unsigned int boundary_blocks =
            static_cast<unsigned int>((boundary_words + detail::kThreadsPerBlock - 1) / detail::kThreadsPerBlock);
        detail::game_of_life_boundary_kernel
            <<<boundary_blocks, detail::kThreadsPerBlock>>>(input, output, words_per_row, row_shift, grid_dimensions);
    }
}

#include <cstddef>
#include <cstdint>
#include <cuda_runtime.h>

// Fast bit-parallel Conway's Game of Life for a square bit-packed grid.
//
// Encoding assumption used by this kernel:
//   * within each 64-bit word, bit 0 is the leftmost cell in that 64-cell span
//   * bit 63 is the rightmost cell in that 64-cell span
//
// That matches the required special handling:
//   * bit 0 needs the three words to the left  (upper/current/lower rows)
//   * bit 63 needs the three words to the right (upper/current/lower rows)
//
// Performance notes:
//   * one CUDA thread updates one 64-bit word => 64 cells/thread, no atomics
//   * horizontal neighbor reuse is handled with warp/subwarp shuffles
//   * only the first/last lane of each row segment performs extra global loads
//   * the 8 neighbor bitboards are reduced with carry-save adders, so all
//     64 neighbor counts are computed simultaneously with bitwise logic
//   * shared memory is intentionally not used; shuffles cover horizontal reuse
//     and the hardware caches are sufficient for vertical reuse on A100/H100

namespace {

using u64 = std::uint64_t;
using usize = std::size_t;

constexpr unsigned int FULL_MASK = 0xFFFFFFFFu;

// Both launch configurations keep the block size at 256 threads.
// BLOCK_X also defines the logical shuffle width.
constexpr int BLOCK_X_32 = 32;
constexpr int BLOCK_Y_32 = 8;

constexpr int BLOCK_X_16 = 16;
constexpr int BLOCK_Y_16 = 16;

constexpr int TUNED_BLOCK_THREADS = 256;
constexpr int MIN_BLOCKS_PER_SM = 2;

// Host-side helper: input is guaranteed to be a power of two by the problem.
inline unsigned int log2_pow2_host(unsigned int value) {
    unsigned int shift = 0;
    while (value > 1u) {
        value >>= 1u;
        ++shift;
    }
    return shift;
}

// 0x96 = XOR3(a,b,c)
// 0xE8 = MAJORITY(a,b,c) = carry bit of a 3-input full adder
__device__ __forceinline__ u64 xor3_u64(u64 a, u64 b, u64 c) {
#if defined(__CUDA_ARCH__)
    u64 r;
    asm("lop3.b64 %0, %1, %2, %3, 0x96;" : "=l"(r) : "l"(a), "l"(b), "l"(c));
    return r;
#else
    return a ^ b ^ c;
#endif
}

__device__ __forceinline__ u64 maj3_u64(u64 a, u64 b, u64 c) {
#if defined(__CUDA_ARCH__)
    u64 r;
    asm("lop3.b64 %0, %1, %2, %3, 0xE8;" : "=l"(r) : "l"(a), "l"(b), "l"(c));
    return r;
#else
    return (a & b) | (a & c) | (b & c);
#endif
}

__device__ __forceinline__ void csa(u64 a, u64 b, u64 c, u64& sum, u64& carry) {
    sum = xor3_u64(a, b, c);
    carry = maj3_u64(a, b, c);
}

__device__ __forceinline__ void ha(u64 a, u64 b, u64& sum, u64& carry) {
    sum = a ^ b;
    carry = a & b;
}

template <int BLOCK_X, int BLOCK_Y>
__global__ __launch_bounds__(TUNED_BLOCK_THREADS, MIN_BLOCKS_PER_SM)
void game_of_life_kernel(const u64* __restrict__ input,
                         u64* __restrict__ output,
                         int words_per_row,
                         int rows,
                         unsigned int tile_x_mask,
                         unsigned int tile_x_shift) {
    static_assert(BLOCK_X == 16 || BLOCK_X == 32, "BLOCK_X must be 16 or 32.");
    static_assert(BLOCK_X * BLOCK_Y == TUNED_BLOCK_THREADS,
                  "Kernel tuning assumes 256-thread blocks.");

    // The block grid is intentionally 1D to avoid the 65535 limit on grid.y.
    // Because the number of x-tiles per row is always a power of two, we can
    // decode blockIdx.x into (tile_x, block_row) with a mask and a shift.
    const unsigned int linear_block = blockIdx.x;
    const int tile_x = static_cast<int>(linear_block & tile_x_mask);
    const int block_row = static_cast<int>(linear_block >> tile_x_shift);

    // BLOCK_X is also the shuffle width:
    //   * BLOCK_X == 32: one warp == one row segment
    //   * BLOCK_X == 16: one warp == two independent 16-lane row segments
    //                    and the width parameter keeps them isolated
    const int lane = static_cast<int>(threadIdx.x);
    const int x = tile_x * BLOCK_X + lane;
    const int y = block_row * BLOCK_Y + static_cast<int>(threadIdx.y);

    // Exact tiling is guaranteed by the problem constraints and the launch
    // configuration chosen in run_game_of_life, so no x/y bounds checks are
    // needed inside the hot kernel.
    const bool has_left  = (x != 0);
    const bool has_right = (x != (words_per_row - 1));
    const bool has_up    = (y != 0);
    const bool has_down  = (y != (rows - 1));

    const usize row_stride = static_cast<usize>(words_per_row);
    const usize base = static_cast<usize>(y) * row_stride + static_cast<usize>(x);
    const usize up_base = base - row_stride;
    const usize down_base = base + row_stride;

    // Current word and vertical neighbors. Off-grid rows are injected as zero.
    const u64 mid  = input[base];
    const u64 up   = has_up   ? input[up_base]   : 0ull;
    const u64 down = has_down ? input[down_base] : 0ull;

    // Horizontal neighbors normally come from shuffles inside the row segment.
    // The first/last lane of the segment handles cross-segment / row-edge
    // cases with explicit loads. These are exactly the "three words to the
    // left" / "three words to the right" mentioned in the prompt.
    u64 up_left   = __shfl_up_sync(FULL_MASK, up,   1, BLOCK_X);
    u64 mid_left  = __shfl_up_sync(FULL_MASK, mid,  1, BLOCK_X);
    u64 down_left = __shfl_up_sync(FULL_MASK, down, 1, BLOCK_X);
    if (lane == 0) {
        mid_left  = has_left ? input[base - 1] : 0ull;
        up_left   = (has_left && has_up)   ? input[up_base - 1]   : 0ull;
        down_left = (has_left && has_down) ? input[down_base - 1] : 0ull;
    }

    u64 up_right   = __shfl_down_sync(FULL_MASK, up,   1, BLOCK_X);
    u64 mid_right  = __shfl_down_sync(FULL_MASK, mid,  1, BLOCK_X);
    u64 down_right = __shfl_down_sync(FULL_MASK, down, 1, BLOCK_X);
    if (lane == BLOCK_X - 1) {
        mid_right  = has_right ? input[base + 1] : 0ull;
        up_right   = (has_right && has_up)   ? input[up_base + 1]   : 0ull;
        down_right = (has_right && has_down) ? input[down_base + 1] : 0ull;
    }

    // Build aligned neighbor bitboards.
    // For example, bit k of "west" contains the state of the cell immediately
    // left of the current cell at bit k.
    //
    // The eight neighbors are grouped as:
    //   top row    : NW, N, NE
    //   middle row : W, E
    //   bottom row : SW, S, SE
    //
    // Then we use a carry-save adder tree to compute the 4 bitplanes of the
    // neighbor count (0..8) for all 64 cells in parallel.
    u64 s_top, c_top;
    {
        const u64 nw = (up << 1) | (up_left >> 63);
        const u64 ne = (up >> 1) | (up_right << 63);
        csa(nw, up, ne, s_top, c_top);
    }

    u64 s_mid, c_mid;
    {
        const u64 w = (mid << 1) | (mid_left >> 63);
        const u64 e = (mid >> 1) | (mid_right << 63);
        ha(w, e, s_mid, c_mid);
    }

    u64 s_bot, c_bot;
    {
        const u64 sw = (down << 1) | (down_left >> 63);
        const u64 se = (down >> 1) | (down_right << 63);
        csa(sw, down, se, s_bot, c_bot);
    }

    u64 bit0, carry_ones;
    csa(s_top, s_mid, s_bot, bit0, carry_ones);

    u64 twos_sum, fours_carry;
    csa(c_top, c_mid, c_bot, twos_sum, fours_carry);

    u64 bit1, carry_twos;
    ha(twos_sum, carry_ones, bit1, carry_twos);

    u64 bit2, bit3;
    ha(fours_carry, carry_twos, bit2, bit3);

    // count == 2 or 3  <=>  bit1 == 1 and bit2 == bit3 == 0
    // next = (count == 3) | (alive & count == 2)
    //      = live23 & (bit0 | alive)
    const u64 live23 = bit1 & ~(bit2 | bit3);
    output[base] = live23 & (bit0 | mid);
}

template <int BLOCK_X, int BLOCK_Y>
inline void launch_game_of_life_kernel(const u64* input,
                                       u64* output,
                                       int words_per_row,
                                       int rows) {
    static_assert(BLOCK_X == 16 || BLOCK_X == 32, "BLOCK_X must be 16 or 32.");
    static_assert(BLOCK_X * BLOCK_Y == TUNED_BLOCK_THREADS,
                  "Kernel tuning assumes 256-thread blocks.");

    // Exact tiling guaranteed by the problem:
    //   * words_per_row is a power of two
    //   * rows is a power of two
    //   * BLOCK_X and BLOCK_Y are powers of two that exactly divide the chosen
    //     valid cases
    const unsigned int tiles_x =
        static_cast<unsigned int>(words_per_row / BLOCK_X);
    const unsigned int block_rows =
        static_cast<unsigned int>(rows / BLOCK_Y);

    // tiles_x is a power of two, so we can decode linear block indices with
    // a mask and a shift instead of division/modulo inside the kernel.
    const unsigned int tile_x_mask = tiles_x - 1u;
    const unsigned int tile_x_shift = log2_pow2_host(tiles_x);

    // Row-major block order: x-tiles vary fastest.
    const unsigned int total_blocks = tiles_x * block_rows;

    const dim3 block(BLOCK_X, BLOCK_Y, 1);
    const dim3 grid(total_blocks, 1, 1);

    game_of_life_kernel<BLOCK_X, BLOCK_Y>
        <<<grid, block>>>(input, output, words_per_row, rows,
                          tile_x_mask, tile_x_shift);
}

}  // namespace

void run_game_of_life(const std::uint64_t* input,
                      std::uint64_t* output,
                      int grid_dimensions) {
    // The caller is responsible for synchronization and for ping-ponging
    // input/output buffers across steps. No host-device sync is performed here.
    if (grid_dimensions <= 0) {
        return;
    }

    // Direct packed-word processing is already the fast path, so no unpack /
    // repack transformation is needed.
    const int words_per_row = grid_dimensions >> 6;

    // Problem constraints:
    //   * grid_dimensions is a power of two
    //   * grid_dimensions > 512
    //
    // Therefore:
    //   * words_per_row is also a power of two
    //   * the only valid case with fewer than 32 words per row is 1024x1024,
    //     which has exactly 16 words per row
    //
    // We use a 16-lane subwarp specialization for that case so no lanes are
    // wasted. All larger valid cases use full 32-lane row segments.
    if (words_per_row == BLOCK_X_16) {
        launch_game_of_life_kernel<BLOCK_X_16, BLOCK_Y_16>(
            input, output, words_per_row, grid_dimensions);
    } else {
        launch_game_of_life_kernel<BLOCK_X_32, BLOCK_Y_32>(
            input, output, words_per_row, grid_dimensions);
    }
}

#include <cstddef>
#include <cstdint>
#include <cuda_runtime.h>

/*
  High-throughput Conway's Game of Life for a square, bit-packed grid.

  Layout:
    - Row-major.
    - Each 64-bit word stores 64 consecutive cells from one row.
    - Bit 0 is the leftmost cell in that 64-cell run; bit 63 is the rightmost.

  Performance strategy:
    - One thread updates one 64-cell word.
    - The hot kernel covers only interior rows. blockDim.x is fixed to 32 so one warp spans
      32 consecutive words from a single row.
    - Each lane loads only the center word from the row above/current/below.
      Horizontal neighbor words are obtained with warp shuffles; only the first and last
      active lanes fetch a halo word from global memory.
    - The 64 cells inside a word are updated simultaneously with bit-sliced logic. We never
      iterate over cells and we never need atomics.
    - A tiny second kernel handles the first and last rows, keeping the main kernel free of
      top/bottom boundary checks.

  Boundary rule:
    - Cells outside the grid are dead. Missing rows/columns are therefore represented by zero words.
*/

namespace {

using u64 = std::uint64_t;

constexpr int kInteriorBlockX = 32;   // One warp spans one horizontal run of words.
constexpr int kInteriorBlockY = 8;    // 8 warps/block -> 256 threads/block.
constexpr int kBoundaryBlock  = 256;
constexpr int kMaxGridY       = 65535;  // Architectural limit for 2D CUDA launches.

static_assert(kInteriorBlockX == 32, "The interior kernel relies on one warp spanning one row segment.");
static_assert(sizeof(u64) == 8, "This implementation requires 64-bit words.");

// CUDA shuffle intrinsics have guaranteed overloads for unsigned long long.
// Casting keeps this helper portable even if std::uint64_t is typedef'd to another 64-bit unsigned type.
__device__ __forceinline__ u64 shfl_up_u64(unsigned mask, u64 value, unsigned delta) {
    return static_cast<u64>(__shfl_up_sync(mask, static_cast<unsigned long long>(value), delta));
}

__device__ __forceinline__ u64 shfl_down_u64(unsigned mask, u64 value, unsigned delta) {
    return static_cast<u64>(__shfl_down_sync(mask, static_cast<unsigned long long>(value), delta));
}

// Align the x-1 neighbors of all 64 cells in one operation.
// For bit i>0 the source is bit i-1 of center_word.
// For bit 0 the source is bit 63 of left_word.
// If the current word is on the global left edge, the caller passes left_word = 0.
__device__ __forceinline__ u64 neighbors_from_left(u64 center_word, u64 left_word) {
    return (center_word << 1) | (left_word >> 63);
}

// Align the x+1 neighbors of all 64 cells in one operation.
// For bit i<63 the source is bit i+1 of center_word.
// For bit 63 the source is bit 0 of right_word.
// If the current word is on the global right edge, the caller passes right_word = 0.
__device__ __forceinline__ u64 neighbors_from_right(u64 center_word, u64 right_word) {
    return (center_word >> 1) | (right_word << 63);
}

// Compute the next-state word for 64 cells at once from the surrounding 3x3 block of words.
// The current-center word (mc) is *not* included in the neighbor count; it is only used in the final rule.
__device__ __forceinline__ u64 life_word(
    u64 ul, u64 uc, u64 ur,
    u64 ml, u64 mc, u64 mr,
    u64 dl, u64 dc, u64 dr)
{
    // Align all eight neighbor directions to the bit positions of the current word.
    const u64 up_left    = neighbors_from_left (uc, ul);
    const u64 up_center  = uc;
    const u64 up_right   = neighbors_from_right(uc, ur);

    const u64 mid_left   = neighbors_from_left (mc, ml);
    const u64 mid_right  = neighbors_from_right(mc, mr);

    const u64 dn_left    = neighbors_from_left (dc, dl);
    const u64 dn_center  = dc;
    const u64 dn_right   = neighbors_from_right(dc, dr);

    // Horizontal row sums, computed bit-sliced:
    //   top_count    = top_lo + 2*top_hi    for (up_left + up_center + up_right), range 0..3
    //   middle_count = mid_lo + 2*mid_hi    for (mid_left + mid_right),            range 0..2
    //   bottom_count = bot_lo + 2*bot_hi    for (dn_left + dn_center + dn_right),  range 0..3
    u64 x = up_left ^ up_center;
    const u64 top_lo = x ^ up_right;
    const u64 top_hi = (up_left & up_center) | (up_right & x);

    const u64 mid_lo = mid_left ^ mid_right;
    const u64 mid_hi = mid_left & mid_right;

    x = dn_left ^ dn_center;
    const u64 bot_lo = x ^ dn_right;
    const u64 bot_hi = (dn_left & dn_center) | (dn_right & x);

    // Add the three row-sum low bits:
    //   total_neighbors = count_bit0 + 2*(top_hi + mid_hi + bot_hi + carry_2)
    x = top_lo ^ mid_lo;
    const u64 count_bit0 = x ^ bot_lo;
    const u64 carry_2    = (top_lo & mid_lo) | (bot_lo & x);

    // We do not need the full 4-bit neighbor count.
    // The Life rule only cares about counts 2 and 3, which means:
    //   top_hi + mid_hi + bot_hi + carry_2 must equal exactly 1.
    //
    // Pairwise reduction of those four "2's-place" bits:
    //   pair_a_lo/pair_a_hi encode top_hi + mid_hi
    //   pair_b_lo/pair_b_hi encode bot_hi + carry_2
    //
    // count_bit1 is the low bit of that 4-way sum.
    // ge4 is true when that 4-way sum is >= 2, which means the full neighbor count is >= 4.
    const u64 pair_a_lo = top_hi ^ mid_hi;
    const u64 pair_a_hi = top_hi & mid_hi;
    const u64 pair_b_lo = bot_hi ^ carry_2;
    const u64 pair_b_hi = bot_hi & carry_2;

    const u64 count_bit1 = pair_a_lo ^ pair_b_lo;
    const u64 ge4        = pair_a_hi | pair_b_hi | (pair_a_lo & pair_b_lo);

    // count == 2 or 3  <=>  count_bit1 == 1 and ge4 == 0
    const u64 count_is_2_or_3 = count_bit1 & ~ge4;

    // Final Life rule:
    //   next = (count == 3) | (alive & (count == 2))
    //
    // For counts 2/3, count_bit0 distinguishes them:
    //   count == 2 -> count_bit0 = 0, so survival requires mc = 1
    //   count == 3 -> count_bit0 = 1, so birth/survival is unconditional
    return count_is_2_or_3 & (count_bit0 | mc);
}

// Hot path: rows 1..N-2 only.
// The top and bottom neighbor rows always exist here, so the kernel has no row-boundary checks.
// Horizontal boundary columns are still handled by zero halo words on the first/last word of each row.
__global__ __launch_bounds__(kInteriorBlockX * kInteriorBlockY)
void game_of_life_interior_rows_kernel(
    const u64* __restrict__ input,
    u64* __restrict__ output,
    int grid_dimensions,
    int words_per_row)
{
    const int last_row = grid_dimensions - 1;
    const int row_start = blockIdx.y * blockDim.y + threadIdx.y + 1;
    if (row_start >= last_row) {
        return;
    }

    // blockDim.x is exactly one warp, so threadIdx.x is also the lane id.
    const int lane = threadIdx.x;
    const int col  = blockIdx.x * blockDim.x + lane;
    if (col >= words_per_row) {
        return;
    }

    // Only the high lanes of the final x-block can be inactive, so the active mask is always
    // a contiguous prefix. Therefore only lane 0 and the last active lane need explicit halo loads.
    const unsigned active_mask   = __activemask();
    const int last_active_lane   = 31 - __clz(active_mask);
    const bool fetch_left_halo   = (lane == 0);
    const bool fetch_right_halo  = (lane == last_active_lane);

    const int last_col           = words_per_row - 1;
    const bool has_left_col      = (col != 0);
    const bool has_right_col     = (col != last_col);

    const std::size_t stride_words = static_cast<std::size_t>(words_per_row);
    const int row_step             = blockDim.y * gridDim.y;
    const std::size_t base_step    = static_cast<std::size_t>(row_step) * stride_words;

    std::size_t base =
        static_cast<std::size_t>(row_start) * stride_words +
        static_cast<std::size_t>(col);

    for (int row = row_start; row < last_row; row += row_step, base += base_step) {
        const u64* above = input + (base - stride_words);
        const u64* mid   = input +  base;
        const u64* below = input + (base + stride_words);

        // Center-column words for the three relevant rows.
        const u64 uc = above[0];
        const u64 mc = mid[0];
        const u64 dc = below[0];

        // Most horizontal neighbors come from adjacent lanes instead of global memory.
        u64 ul = shfl_up_u64  (active_mask, uc, 1);
        u64 ml = shfl_up_u64  (active_mask, mc, 1);
        u64 dl = shfl_up_u64  (active_mask, dc, 1);

        u64 ur = shfl_down_u64(active_mask, uc, 1);
        u64 mr = shfl_down_u64(active_mask, mc, 1);
        u64 dr = shfl_down_u64(active_mask, dc, 1);

        // Only the warp-edge lanes need explicit horizontal halo loads.
        if (fetch_left_halo) {
            ul = 0;
            ml = 0;
            dl = 0;
            if (has_left_col) {
                ul = above[-1];
                ml = mid[-1];
                dl = below[-1];
            }
        }

        if (fetch_right_halo) {
            ur = 0;
            mr = 0;
            dr = 0;
            if (has_right_col) {
                ur = above[1];
                mr = mid[1];
                dr = below[1];
            }
        }

        output[base] = life_word(ul, uc, ur, ml, mc, mr, dl, dc, dr);
    }
}

// Tiny boundary-only kernel for row 0 and row N-1.
// These rows are a negligible fraction of the work, so simple direct global loads are preferable
// to complicating the main interior kernel.
__global__ __launch_bounds__(kBoundaryBlock)
void game_of_life_boundary_rows_kernel(
    const u64* __restrict__ input,
    u64* __restrict__ output,
    int grid_dimensions,
    int words_per_row)
{
    const int col = blockIdx.x * blockDim.x + threadIdx.x;
    if (col >= words_per_row) {
        return;
    }

    const int last_col = words_per_row - 1;
    const bool has_left_col  = (col != 0);
    const bool has_right_col = (col != last_col);

    const std::size_t stride_words = static_cast<std::size_t>(words_per_row);
    const int last_row             = grid_dimensions - 1;
    const std::size_t bottom_base  = static_cast<std::size_t>(last_row) * stride_words;

    const u64* top    = input;
    const u64* second = input + stride_words;
    const u64* penult = input + (bottom_base - stride_words);
    const u64* bottom = input + bottom_base;

    // Top row: above-grid words are dead (zero).
    u64 top_ml = 0;
    u64 top_mr = 0;
    u64 top_dl = 0;
    u64 top_dr = 0;

    if (has_left_col) {
        top_ml = top[col - 1];
        top_dl = second[col - 1];
    }
    if (has_right_col) {
        top_mr = top[col + 1];
        top_dr = second[col + 1];
    }

    output[col] = life_word(
        0, 0, 0,
        top_ml, top[col], top_mr,
        top_dl, second[col], top_dr);

    // Bottom row: below-grid words are dead (zero).
    u64 bot_ul = 0;
    u64 bot_ur = 0;
    u64 bot_ml = 0;
    u64 bot_mr = 0;

    if (has_left_col) {
        bot_ul = penult[col - 1];
        bot_ml = bottom[col - 1];
    }
    if (has_right_col) {
        bot_ur = penult[col + 1];
        bot_mr = bottom[col + 1];
    }

    output[bottom_base + static_cast<std::size_t>(col)] = life_word(
        bot_ul, penult[col], bot_ur,
        bot_ml, bottom[col], bot_mr,
        0, 0, 0);
}

} // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions) {
    // The caller manages synchronization; this function only enqueues kernels.
    // The usual double-buffered usage is assumed: input and output should not alias.

    const int words_per_row = grid_dimensions >> 6;  // grid_dimensions is a power of two, so this is exact.
    const int interior_rows = grid_dimensions - 2;

    const dim3 interior_block(kInteriorBlockX, kInteriorBlockY);
    const int interior_grid_x = (words_per_row + kInteriorBlockX - 1) / kInteriorBlockX;
    const int raw_grid_y      = (interior_rows + kInteriorBlockY - 1) / kInteriorBlockY;
    const int interior_grid_y = (raw_grid_y < kMaxGridY) ? raw_grid_y : kMaxGridY;

    game_of_life_interior_rows_kernel<<<dim3(interior_grid_x, interior_grid_y), interior_block>>>(
        input, output, grid_dimensions, words_per_row);

    const int boundary_grid_x = (words_per_row + kBoundaryBlock - 1) / kBoundaryBlock;
    game_of_life_boundary_rows_kernel<<<boundary_grid_x, kBoundaryBlock>>>(
        input, output, grid_dimensions, words_per_row);
}

#include <cuda_runtime.h>
#include <cstddef>
#include <cstdint>

/*
  Bit-sliced Conway's Game of Life for a square, bit-packed board.

  Layout assumed by the prompt:
    - The board is row-major.
    - One 64-bit word stores 64 consecutive x positions from one row.
    - Bit j of word (row, word_col) is cell x = 64 * word_col + j.
    - Cells outside the board are dead.

  The kernel processes 64 cells at once per thread by treating each bit position as an independent
  1-bit lane. Neighbor counts are accumulated with carry-save adder logic:
      sum   = a ^ b ^ c
      carry = majority(a,b,c) = (a & b) | ((a ^ b) & c)
  applied bitwise across the full 64-bit word.

  The "special handling" for bit 0 and bit 63 is exactly the cross-word splice done by align_west()
  and align_east():
    - west neighbor of bit 0 comes from bit 63 of the word on the left
    - east neighbor of bit 63 comes from bit 0 of the word on the right

  This implementation intentionally stays with plain global memory; for this access pattern on modern
  A100/H100-class GPUs, regular coalesced loads plus cheap bitwise ALU is the fast path, and shared
  or texture memory only adds complexity.
*/

namespace {

using u64 = std::uint64_t;

constexpr int kBlockSize = 256;

// Power-of-two CTA cap.
// Boards up to 16384x16384 cells launch literally one thread per 64-bit word.
// Larger boards keep the same per-word ownership but use a grid-stride loop to avoid launching
// millions of CTAs. Keeping the cap as a power of two also makes the capped grid-stride a power
// of two, which matches the power-of-two row pitch nicely.
constexpr unsigned int kMaxBlocks = 1u << 14;  // 16384

static_assert((kBlockSize & (kBlockSize - 1)) == 0, "kBlockSize must be a power of two.");
static_assert((kMaxBlocks & (kMaxBlocks - 1u)) == 0u, "kMaxBlocks must be a power of two.");
static_assert(sizeof(u64) == 8, "u64 must be 64 bits.");

// 3:2 carry-save adder applied bitwise to all 64 lanes at once.
// For each bit position this is a full adder:
//   sum   = a ^ b ^ c
//   carry = majority(a, b, c)
// The carry represents the next higher count bit.
static __device__ __forceinline__
void csa3(const u64 a, const u64 b, const u64 c, u64& sum, u64& carry) {
    const u64 ab_xor = a ^ b;
    sum   = ab_xor ^ c;
    carry = (a & b) | (ab_xor & c);
}

// Align the west neighbors of the 64 cells owned by the current word.
// Bit 0 pulls in bit 63 from the word on the left; all other bits come from a 1-bit left shift.
static __device__ __forceinline__
u64 align_west(const u64 center, const u64 left) {
    return (center << 1) | (left >> 63);
}

// Align the east neighbors of the 64 cells owned by the current word.
// Bit 63 pulls in bit 0 from the word on the right; all other bits come from a 1-bit right shift.
static __device__ __forceinline__
u64 align_east(const u64 center, const u64 right) {
    return (center >> 1) | (right << 63);
}

__global__ __launch_bounds__(kBlockSize)
void game_of_life_kernel(const u64* __restrict__ input,
                         u64* __restrict__ output,
                         std::size_t total_words,
                         unsigned int words_per_row) {
    // words_per_row is guaranteed to be a power of two, so words_per_row - 1 is both:
    //   - the last valid word index within a row
    //   - the bitmask that extracts the intra-row word coordinate from a flattened index
    const std::size_t row_stride = static_cast<std::size_t>(words_per_row);
    const std::size_t bottom_limit = total_words - row_stride;
    const unsigned int last_col = words_per_row - 1u;

    const std::size_t thread_index =
        static_cast<std::size_t>(blockIdx.x) * static_cast<std::size_t>(blockDim.x) +
        static_cast<std::size_t>(threadIdx.x);
    const std::size_t thread_stride =
        static_cast<std::size_t>(blockDim.x) * static_cast<std::size_t>(gridDim.x);

    // Each loop iteration still updates exactly one 64-bit word, and each output word is written
    // by exactly one thread. The loop only amortizes launch/scheduling overhead on very large boards.
    for (std::size_t idx = thread_index; idx < total_words; idx += thread_stride) {
        const unsigned int col = static_cast<unsigned int>(idx) & last_col;
        const bool has_left  = (col != 0u);
        const bool has_right = (col != last_col);
        const bool has_up    = (idx >= row_stride);
        const bool has_down  = (idx < bottom_limit);

        // Current word: also serves as the "alive" mask for the final rule application.
        const u64 center = input[idx];

        // Missing neighbor words beyond the border are treated as zero, which exactly implements
        // "cells outside the grid are dead".
        u64 left = 0;
        u64 right = 0;
        if (has_left)  left  = input[idx - 1];
        if (has_right) right = input[idx + 1];

        // Same-row horizontal neighbors (W, E): 0..2 neighbors, encoded as two bit-planes.
        const u64 west  = align_west(center, left);
        const u64 east  = align_east(center, right);
        const u64 side0 = west ^ east;   // bit 0 of the 0..2 count
        const u64 side1 = west & east;   // bit 1 of the 0..2 count

        // North row (NW, N, NE): 0..3 neighbors, encoded as two bit-planes.
        u64 top0 = 0;
        u64 top1 = 0;
        if (has_up) {
            const std::size_t up_idx = idx - row_stride;
            const u64 up = input[up_idx];

            u64 up_left = 0;
            u64 up_right = 0;
            if (has_left)  up_left  = input[up_idx - 1];
            if (has_right) up_right = input[up_idx + 1];

            csa3(align_west(up, up_left), up, align_east(up, up_right), top0, top1);
        }

        // South row (SW, S, SE): 0..3 neighbors, encoded as two bit-planes.
        u64 bottom0 = 0;
        u64 bottom1 = 0;
        if (has_down) {
            const std::size_t down_idx = idx + row_stride;
            const u64 down = input[down_idx];

            u64 down_left = 0;
            u64 down_right = 0;
            if (has_left)  down_left  = input[down_idx - 1];
            if (has_right) down_right = input[down_idx + 1];

            csa3(align_west(down, down_left), down, align_east(down, down_right), bottom0, bottom1);
        }

        // Combine the three groups:
        //   top    : 0..3  -> (top1 top0)
        //   sides  : 0..2  -> (side1 side0)
        //   bottom : 0..3  -> (bottom1 bottom0)
        //
        // First combine the low bits of the three groups; this yields the full count LSB (count0)
        // plus a carry plane (carry0).
        u64 count0;
        u64 carry0;
        csa3(top0, bottom0, side0, count0, carry0);

        // Then combine the remaining carry planes. carry1 is the next count bit, carry2 is the bit
        // above that. We do not need the count bit for value 8 explicitly: counts 2 and 3 are
        // identified entirely by the low three bits, and count 8 has low three bits 000 so it
        // cannot alias either case.
        u64 carry1;
        u64 carry2;
        csa3(carry0, top1, bottom1, carry1, carry2);

        const u64 count1 = carry1 ^ side1;
        const u64 count2 = carry2 ^ (carry1 & side1);

        // Counts 2 and 3 are exactly the cases:
        //   count2 count1 = 0 1
        const u64 count_is_2_or_3 = count1 & ~count2;

        // Game of Life rule in factorized bit-sliced form:
        //   next = (count == 3) | (alive & (count == 2))
        //        = (count is 2 or 3) & (alive | count0)
        // because count0 distinguishes 2 (count0=0) from 3 (count0=1).
        output[idx] = count_is_2_or_3 & (center | count0);
    }
}

}  // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions) {
    // The prompt guarantees valid power-of-two dimensions > 512, but these guards keep the function
    // well-defined for accidental misuse without adding any measurable cost.
    if (grid_dimensions <= 0) {
        return;
    }

    const unsigned int words_per_row = static_cast<unsigned int>(grid_dimensions) >> 6;
    if (words_per_row == 0u) {
        return;
    }

    const std::size_t total_words =
        static_cast<std::size_t>(grid_dimensions) * static_cast<std::size_t>(words_per_row);

    // Launch literally one thread per word when the board is small enough.
    // Once the board is larger, cap the grid and let the kernel's grid-stride loop carry the rest.
    // The caller handles synchronization; this function only launches the kernel.
    const std::size_t required_blocks =
        (total_words + static_cast<std::size_t>(kBlockSize) - 1u) /
        static_cast<std::size_t>(kBlockSize);

    const unsigned int blocks = static_cast<unsigned int>(
        required_blocks < static_cast<std::size_t>(kMaxBlocks)
            ? required_blocks
            : static_cast<std::size_t>(kMaxBlocks));

    game_of_life_kernel<<<blocks, kBlockSize>>>(input, output, total_words, words_per_row);
}

#include <cstddef>
#include <cstdint>
#include <cuda_runtime.h>

/*
  One-step Conway's Game of Life on a square, bit-packed grid.

  Performance-oriented design:
  - One CUDA thread updates exactly one 64-bit word, i.e. 64 cells at once.
    That makes the update naturally race-free and eliminates atomics.
  - The grid is row-major and each row contains grid_dimensions / 64 words.
  - Outside-the-grid cells are treated as dead by substituting zero for missing
    neighbor words/rows.
  - Most horizontal/diagonal neighbor words are obtained with warp shuffles from
    threads that already loaded them as their own center/north/south words.
    Only lanes on warp/subwarp boundaries fall back to extra global loads.
  - Eight 1-bit neighbor bitboards are summed with a carry-save adder tree.
    This computes the neighbor counts for all 64 cells in parallel using simple
    bitwise logic.
*/

namespace {

using word_t = std::uint64_t;

constexpr int kBlockSize  = 256;
constexpr int kBlockShift = 8;

static_assert((kBlockSize & (kBlockSize - 1)) == 0, "kBlockSize must be a power of two.");
static_assert((1 << kBlockShift) == kBlockSize,     "kBlockShift must match kBlockSize.");
static_assert((kBlockSize % 32) == 0,               "kBlockSize must be warp-aligned.");

/*
  Carry-save adder for three 1-bit bitboards a, b, c.

  For each bit position independently:
    sum_bit   = a ^ b ^ c
    carry_bit = majority(a, b, c)

  Interpreted numerically, that is:
    a + b + c = sum + 2 * carry
*/
__device__ __forceinline__ void csa(word_t a, word_t b, word_t c, word_t& sum, word_t& carry) {
    const word_t u = a ^ b;
    sum   = u ^ c;
    carry = (a & b) | (u & c);
}

/*
  kShuffleWidth is 16 only for the 1024x1024 case (16 packed words per row),
  otherwise it is 32.

  Why two specializations are enough:
  - grid_dimensions is a power of two > 512
  - words_per_row = grid_dimensions / 64 is also a power of two
  - therefore words_per_row is either 16 or a multiple of 32
  - when words_per_row == 16, each warp covers two rows in word-space, so shuffles
    must be restricted to 16-lane subwarps
  - otherwise, rows are 32-word aligned and full-warp shuffles never cross rows
*/
template <int kShuffleWidth>
__global__ __launch_bounds__(kBlockSize)
void game_of_life_kernel(
    const word_t* __restrict__ input,
    word_t* __restrict__ output,
    std::size_t words_per_row,
    std::size_t last_row_start,
    unsigned int word_mask)
{
    static_assert(kShuffleWidth == 16 || kShuffleWidth == 32, "Unexpected shuffle width.");

    constexpr unsigned int kFullMask    = 0xFFFFFFFFu;
    constexpr unsigned int kSegmentMask = static_cast<unsigned int>(kShuffleWidth - 1);

    // Because the launch uses exactly total_words / kBlockSize blocks and
    // total_words is a power of two >= 2^14, every block and every warp is full.
    // That lets us use full-mask shuffles without an in-kernel bounds check.
    const std::size_t idx =
        (static_cast<std::size_t>(blockIdx.x) << kBlockShift) +
        static_cast<std::size_t>(threadIdx.x);

    // x-coordinate in word-space. This is just a bitmask because words_per_row is a power of two.
    const unsigned int xw = static_cast<unsigned int>(idx) & word_mask;

    const bool has_left  = (xw != 0u);
    const bool has_right = (xw != word_mask);
    const bool has_up    = (idx >= words_per_row);
    const bool has_down  = (idx < last_row_start);

    // The three words every thread always needs for itself.
    const word_t current = input[idx];

    word_t north = 0;
    if (has_up) {
        north = input[idx - words_per_row];
    }

    word_t south = 0;
    if (has_down) {
        south = input[idx + words_per_row];
    }

    // Use shuffles to obtain left/right words for current, north, and south rows.
    // Only lanes on the edge of a warp/subwarp segment need to fall back to global loads.
    word_t current_left  = __shfl_up_sync  (kFullMask, current, 1, kShuffleWidth);
    word_t current_right = __shfl_down_sync(kFullMask, current, 1, kShuffleWidth);
    word_t north_left    = __shfl_up_sync  (kFullMask, north,   1, kShuffleWidth);
    word_t north_right   = __shfl_down_sync(kFullMask, north,   1, kShuffleWidth);
    word_t south_left    = __shfl_up_sync  (kFullMask, south,   1, kShuffleWidth);
    word_t south_right   = __shfl_down_sync(kFullMask, south,   1, kShuffleWidth);

    const unsigned int lane_in_segment = static_cast<unsigned int>(threadIdx.x) & kSegmentMask;

    if (lane_in_segment == 0u) {
        current_left = 0;
        north_left   = 0;
        south_left   = 0;

        if (has_left) {
            current_left = input[idx - 1];
            if (has_up) {
                north_left = input[idx - words_per_row - 1];
            }
            if (has_down) {
                south_left = input[idx + words_per_row - 1];
            }
        }
    } else if (lane_in_segment == kSegmentMask) {
        current_right = 0;
        north_right   = 0;
        south_right   = 0;

        if (has_right) {
            current_right = input[idx + 1];
            if (has_up) {
                north_right = input[idx - words_per_row + 1];
            }
            if (has_down) {
                south_right = input[idx + words_per_row + 1];
            }
        }
    }

    /*
      Align each neighbor direction so that bit i in the resulting word is the
      state of the corresponding neighbor of cell i.

      Example:
        west = (current << 1) | (current_left >> 63)

      That means:
        - target bit i gets source bit i-1 from the current word
        - target bit 0 gets source bit 63 from the word to the left

      This is exactly the required special handling for bit 0 / bit 63.
    */
    const word_t west      = (current << 1) | (current_left >> 63);
    const word_t east      = (current >> 1) | (current_right << 63);
    const word_t northwest = (north   << 1) | (north_left   >> 63);
    const word_t northeast = (north   >> 1) | (north_right  << 63);
    const word_t southwest = (south   << 1) | (south_left   >> 63);
    const word_t southeast = (south   >> 1) | (south_right  << 63);

    /*
      Sum the eight 1-bit neighbor bitboards with a CSA tree:

        group 0: northwest + north + northeast -> ones0 + 2*twos0
        group 1: west + east + southwest       -> ones1 + 2*twos1
        group 2: south + southeast             -> ones2 + 2*twos2

      Then combine the low and high bits of those partial sums:
        (ones0, ones1, ones2) -> count_bit0 + 2*carry2_from_ones
        (twos0, twos1, twos2) -> extra_twos + 2*extra_fours

      Finally:
        count = count_bit0
              + 2*(carry2_from_ones + extra_twos)
              + 4*extra_fours

      So:
        count_bit1 = carry2_from_ones ^ extra_twos
        count_bit2 = extra_fours ^ (carry2_from_ones & extra_twos)

      count_bit3 is not needed:
        - counts 4..7 already have count_bit2 = 1
        - count 8 has count_bit1 = 0
        Therefore the Life rule can be evaluated using only count_bit0/1/2.
    */
    word_t ones0, twos0;
    word_t ones1, twos1;
    csa(northwest, north, northeast, ones0, twos0);
    csa(west, east, southwest,        ones1, twos1);

    const word_t ones2 = south ^ southeast;
    const word_t twos2 = south & southeast;

    word_t count_bit0, carry2_from_ones;
    word_t extra_twos, extra_fours;
    csa(ones0, ones1, ones2, count_bit0,        carry2_from_ones);
    csa(twos0, twos1, twos2, extra_twos,        extra_fours);

    const word_t count_bit1 = carry2_from_ones ^ extra_twos;
    const word_t count_bit2 = extra_fours ^ (carry2_from_ones & extra_twos);

    // Game of Life rule in bit-sliced form:
    //   next = (count == 3) | (current & (count == 2))
    //
    // With the bitboards above:
    //   count == 2 or 3  <=>  count_bit1 & ~count_bit2
    //   count == 3        <=>  count_bit0 == 1
    //
    // Therefore:
    //   next = (count_bit1 & ~count_bit2) & (count_bit0 | current)
    output[idx] = (count_bit1 & ~count_bit2) & (count_bit0 | current);
}

}  // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions) {
    /*
      The problem guarantees:
      - grid_dimensions is a power of two
      - grid_dimensions > 512

      Therefore:
      - words_per_row = grid_dimensions / 64 is also a power of two
      - total_words   = grid_dimensions * words_per_row is a power of two
      - with grid_dimensions >= 1024, total_words >= 2^14 and is divisible by 2^8 = 256

      So the kernel launch can cover the grid exactly with 256-thread blocks and
      does not need an in-kernel bounds guard.
    */
    const std::size_t words_per_row =
        static_cast<std::size_t>(grid_dimensions) >> 6;
    const std::size_t total_words =
        words_per_row * static_cast<std::size_t>(grid_dimensions);
    const std::size_t last_row_start = total_words - words_per_row;
    const unsigned int word_mask =
        static_cast<unsigned int>(words_per_row - 1);
    const unsigned int blocks =
        static_cast<unsigned int>(total_words >> kBlockShift);

    // The caller manages synchronization; this function intentionally only enqueues the kernel.
    if (words_per_row == 16u) {
        game_of_life_kernel<16><<<blocks, kBlockSize>>>(
            input, output, words_per_row, last_row_start, word_mask);
    } else {
        game_of_life_kernel<32><<<blocks, kBlockSize>>>(
            input, output, words_per_row, last_row_start, word_mask);
    }
}

#include <cuda_runtime.h>
#include <cstddef>
#include <cstdint>

// One-step Conway's Game of Life on a square, bit-packed grid.
//
// Storage layout:
//   - Each std::uint64_t stores 64 consecutive cells from one row.
//   - Bit 0 is the left edge of the packed 64-cell run.
//   - Bit 63 is the right edge of the packed 64-cell run.
//
// Performance strategy:
//   - One CUDA thread updates one 64-bit word, so 64 cells are processed at once.
//   - blockDim.x is fixed to one warp (32 threads). Each warp therefore covers 32 adjacent
//     packed words in x and can exchange x-neighbor words through warp shuffles instead of
//     reloading them from memory.
//   - Neighbor counts are computed with a bit-sliced full-adder tree. This adds the eight
//     per-cell neighbor bits for all 64 cells in parallel using only bitwise operations.
//   - No shared memory, no textures, and no atomics are needed.

namespace {

using u32 = unsigned int;

// CUDA shuffle intrinsics have native 64-bit overloads for unsigned long long on all supported
// host ABIs, so we use that as the working word type even though the external storage type is
// std::uint64_t.
using u64 = unsigned long long;

static_assert(sizeof(u64) == sizeof(std::uint64_t), "Expected a 64-bit word type.");

constexpr int kWordBits       = 64;
constexpr int kWordBitShift   = 6;                 // log2(64)
constexpr int kWordMsbShift   = kWordBits - 1;     // 63

constexpr int kWarpWords      = 32;                // one warp spans 32 packed words in x
constexpr int kWarpWordShift  = 5;                 // log2(32)

constexpr int kBlockRows      = 4;                 // 4 warps per block is a good occupancy balance
constexpr int kBlockRowsShift = 2;                 // log2(4)
constexpr int kBlockThreads   = kWarpWords * kBlockRows;

static_assert(kWordBits  == (1 << kWordBitShift),   "Word geometry must stay power-of-two.");
static_assert(kWarpWords == (1 << kWarpWordShift),  "Warp geometry must stay power-of-two.");
static_assert(kBlockRows == (1 << kBlockRowsShift), "Block geometry must stay power-of-two.");

// Portable host-side log2 for guaranteed power-of-two inputs.
inline int log2_pow2(u32 x) {
    int shift = 0;
    while (x > 1u) {
        x >>= 1u;
        ++shift;
    }
    return shift;
}

__device__ __forceinline__ u64 majority(u64 a, u64 b, u64 c) {
    // Per-bit majority; on modern NVIDIA GPUs this maps well to LOP3.
    return (a & b) | (c & (a | b));
}

__device__ __forceinline__ void full_adder(u64 a, u64 b, u64 c, u64& sum, u64& carry) {
    // 3:2 compressor:
    //   sum   = low bit of a+b+c
    //   carry = high bit of a+b+c (weight 2)
    sum   = a ^ b ^ c;
    carry = majority(a, b, c);
}

__device__ __forceinline__ void half_adder(u64 a, u64 b, u64& sum, u64& carry) {
    // 2:2 compressor:
    //   sum   = low bit of a+b
    //   carry = high bit of a+b (weight 2)
    sum   = a ^ b;
    carry = a & b;
}

__device__ __forceinline__ u64 evolve_packed_word(
    u64 nw, u64 n,  u64 ne,
    u64 w,  u64 self, u64 e,
    u64 sw, u64 s,  u64 se)
{
    // The 3x3 neighborhood of 64-bit words around the current word:
    //
    //   nw |  n | ne
    //   w  |self| e
    //   sw |  s | se
    //
    // Each bit position corresponds to one cell. The update below computes the next state for all
    // 64 cells in "self" simultaneously.
    //
    // Full-adder idea:
    //   For any three 64-bit inputs, xor gives the 1's bit of the per-bit sum and majority gives
    //   the 2's bit. We first compress the three *raw word columns*:
    //
    //     left  column: (nw, w,  sw)
    //     mid   column: (n,  self, s)
    //     right column: (ne, e,  se)
    //
    // The actual left/right neighbor columns seen by the target cells are then formed by shifting
    // the compressed middle column and injecting the edge bit from the compressed left/right raw
    // columns:
    //
    //   left  bits 1..63 <- mid bits 0..62
    //   left  bit 0      <- raw-left bit 63
    //
    //   right bits 0..62 <- mid bits 1..63
    //   right bit 63     <- raw-right bit 0
    //
    // This is exactly the required special handling for bit 0 / bit 63. The center neighbor
    // column is only (n, s); "self" must not count itself.

    u64 raw_left_sum,  raw_left_carry;
    u64 raw_mid_sum,   raw_mid_carry;
    u64 raw_right_sum, raw_right_carry;

    full_adder(nw, w,  sw, raw_left_sum,  raw_left_carry);
    full_adder(n,  self, s, raw_mid_sum,   raw_mid_carry);
    full_adder(ne, e,  se, raw_right_sum, raw_right_carry);

    const u64 left_sum   = (raw_mid_sum   << 1) | (raw_left_sum   >> kWordMsbShift);
    const u64 left_carry = (raw_mid_carry << 1) | (raw_left_carry >> kWordMsbShift);

    const u64 right_sum   = (raw_mid_sum   >> 1) | (raw_right_sum   << kWordMsbShift);
    const u64 right_carry = (raw_mid_carry >> 1) | (raw_right_carry << kWordMsbShift);

    u64 center_sum, center_carry;
    half_adder(n, s, center_sum, center_carry);

    // Combine the three neighbor columns into a 4-bit bit-sliced count:
    //   ones   = bit 0 of neighbor count
    //   twos   = bit 1 of neighbor count
    //   fours  = bit 2 of neighbor count
    //   eights = bit 3 of neighbor count
    u64 ones, twos_from_low_planes;
    u64 twos_from_high_planes, fours_from_high_planes;
    u64 twos, fours_from_cross;
    u64 fours, eights;

    full_adder(left_sum,   center_sum,   right_sum,   ones,                  twos_from_low_planes);
    full_adder(left_carry, center_carry, right_carry, twos_from_high_planes, fours_from_high_planes);
    half_adder(twos_from_low_planes,  twos_from_high_planes, twos,  fours_from_cross);
    half_adder(fours_from_high_planes, fours_from_cross,     fours, eights);

    // Conway rule:
    //   next = (count == 3) | (self & (count == 2))
    //
    // In the bit-sliced count:
    //   count is 2 or 3  <=> twos=1 and fours=eights=0
    //   among those, count is 3 OR the cell is already alive <=> (ones | self)
    const u64 count_is_2_or_3 = twos & ~(fours | eights);
    return count_is_2_or_3 & (ones | self);
}

__global__ __launch_bounds__(kBlockThreads)
void game_of_life_step_kernel(
    const std::uint64_t* __restrict__ input,
    std::uint64_t* __restrict__ output,
    u32 grid_dimensions,
    int words_per_row_shift,
    int tiles_x_shift)
{
    // Block layout:
    //   - blockDim.x == 32, so each warp is one horizontal tile of 32 packed words.
    //   - blockDim.y == kBlockRows, so a block processes kBlockRows independent rows of tiles.
    //
    // Grid layout:
    //   We flatten the logical 2D launch grid into grid.x so we are not limited by grid.y for
    //   very large boards. Because the board size is a power of two, the inverse mapping from
    //   blockIdx.x to (row_tile, x_tile) uses only shifts and masks.

    const u32 words_per_row = 1u << words_per_row_shift;
    const u32 x_tile_mask   = (1u << tiles_x_shift) - 1u;

    const u32 block_linear = static_cast<u32>(blockIdx.x);
    const u32 x_tile       = block_linear & x_tile_mask;
    const u32 row_tile     = block_linear >> tiles_x_shift;

    const u32 word_x = (x_tile << kWarpWordShift) | static_cast<u32>(threadIdx.x);
    const u32 row    = (row_tile << kBlockRowsShift) | static_cast<u32>(threadIdx.y);

    const bool active = (row < grid_dimensions) && (word_x < words_per_row);

    // All lanes in the warp execute the ballot before any early return, so the resulting mask is
    // valid for subsequent shuffle operations even when only part of the warp is active (the only
    // practical partial case here is 16 words/row, i.e. grid_dimensions == 1024).
    const unsigned int active_mask = __ballot_sync(0xFFFFFFFFu, active);
    if (!active) {
        return;
    }

    // Because words_per_row is a power of two and word_x < words_per_row, index computation can
    // use a shift/or instead of a multiply/add.
    const u32 index = (row << words_per_row_shift) | word_x;

    const bool has_top    = (row != 0u);
    const bool has_bottom = (row + 1u < grid_dimensions);
    const bool has_left   = (word_x != 0u);
    const bool has_right  = (word_x + 1u < words_per_row);

    // Every active thread loads only its own three center words.
    const u64 self  = input[index];
    const u64 north = has_top    ? input[index - words_per_row] : 0ull;
    const u64 south = has_bottom ? input[index + words_per_row] : 0ull;

    // Horizontal neighbors are exchanged within the warp. Only the two warp-edge lanes fall back
    // to one extra global load for x-1 / x+1 (or to zero at the grid boundary).
    const u64 sh_w  = __shfl_up_sync(active_mask,   self,  1);
    const u64 sh_nw = __shfl_up_sync(active_mask,   north, 1);
    const u64 sh_sw = __shfl_up_sync(active_mask,   south, 1);

    const u64 sh_e  = __shfl_down_sync(active_mask, self,  1);
    const u64 sh_ne = __shfl_down_sync(active_mask, north, 1);
    const u64 sh_se = __shfl_down_sync(active_mask, south, 1);

    const bool use_shuffle_left  = (static_cast<u32>(threadIdx.x) != 0u);
    const bool use_shuffle_right = (static_cast<u32>(threadIdx.x) + 1u < kWarpWords) && has_right;

    const u64 west =
        use_shuffle_left ? sh_w : (has_left ? input[index - 1u] : 0ull);
    const u64 north_west =
        use_shuffle_left ? sh_nw : ((has_top && has_left) ? input[index - words_per_row - 1u] : 0ull);
    const u64 south_west =
        use_shuffle_left ? sh_sw : ((has_bottom && has_left) ? input[index + words_per_row - 1u] : 0ull);

    const u64 east =
        use_shuffle_right ? sh_e : (has_right ? input[index + 1u] : 0ull);
    const u64 north_east =
        use_shuffle_right ? sh_ne : ((has_top && has_right) ? input[index - words_per_row + 1u] : 0ull);
    const u64 south_east =
        use_shuffle_right ? sh_se : ((has_bottom && has_right) ? input[index + words_per_row + 1u] : 0ull);

    output[index] = static_cast<std::uint64_t>(evolve_packed_word(
        north_west, north, north_east,
        west,       self,  east,
        south_west, south, south_east));
}

} // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions)
{
    // The problem guarantees:
    //   - square dimensions
    //   - power-of-two size
    //   - input/output already allocated on the device
    //   - caller handles synchronization
    //
    // So the host side does only the minimal launch preparation needed for the optimized kernel.

    const u32 n = static_cast<u32>(grid_dimensions);

    // Because n is a power of two:
    //   words_per_row       = n / 64  = 2^(log2(n) - 6)
    //   x_tiles_per_row     = max(1, words_per_row / 32)
    // Both are therefore powers of two as well, so the kernel can recover row/column tile IDs
    // with shifts and masks only.
    const int grid_shift          = log2_pow2(n);
    const int words_per_row_shift = grid_shift - kWordBitShift;
    const int tiles_x_shift =
        (words_per_row_shift > kWarpWordShift) ? (words_per_row_shift - kWarpWordShift) : 0;

    // kBlockRows is also a power of two and n is guaranteed to be divisible by it.
    const std::size_t row_tiles  = static_cast<std::size_t>(n) >> kBlockRowsShift;
    const std::size_t block_count = row_tiles << tiles_x_shift;

    const dim3 block(kWarpWords, kBlockRows, 1);
    const dim3 grid(static_cast<u32>(block_count), 1, 1);

    // Intentionally no host-device synchronization and no error checking in this hot path.
    game_of_life_step_kernel<<<grid, block>>>(input, output, n, words_per_row_shift, tiles_x_shift);
}

#include <cuda_runtime.h>
#include <cstddef>
#include <cstdint>

namespace {

// CUDA implementation of one Conway's Game of Life step on a bit-packed grid.
//
// Design choices for performance on modern data-center GPUs:
// - One thread owns one packed 64-bit output word, so stores are conflict-free and
//   no atomics are needed.
// - The grid stays in its packed representation end-to-end; no unpacking is done.
// - Shared / texture memory are intentionally avoided. Instead, each warp (or
//   half-warp for the 1024x1024 case) covers a contiguous row segment and exchanges
//   left/right center/north/south words via warp shuffles.
// - Neighbor counting uses carry-save / half-adder logic on 64-bit bit-planes, so
//   each thread updates 64 cells in parallel with pure bitwise operations.
// - Standard double buffering is assumed: input and output point to different device
//   allocations.

using u64 = std::uint64_t;

constexpr int kWordBits = 64;
constexpr int kWordBitShift = 6;       // log2(64)
constexpr int kBlockY8Log2 = 3;        // block.y = 8
constexpr int kBlockY16Log2 = 4;       // block.y = 16
constexpr unsigned kBlockY8 = 1u << kBlockY8Log2;
constexpr unsigned kBlockY16 = 1u << kBlockY16Log2;
constexpr unsigned kGridYLimit = 65535u;
constexpr unsigned kFullWarpMask = 0xFFFFFFFFu;

static_assert(sizeof(u64) * 8 == kWordBits, "Expected 64-bit words");

// Bit i in a packed word represents the cell at x = word_base + i.
// Bit 0 and bit 63 therefore need cross-word handling:
//   west  = (self << 1) | (left_word  >> 63)
//   east  = (self >> 1) | (right_word << 63)
// so the missing neighbor bit is pulled from the adjacent packed word.
static __device__ __forceinline__ u64 align_left(u64 word, u64 left_word) {
    return (word << 1) | (left_word >> (kWordBits - 1));
}

static __device__ __forceinline__ u64 align_right(u64 word, u64 right_word) {
    return (word >> 1) | (right_word << (kWordBits - 1));
}

// Carry-save adder for 64 independent bit positions at once:
//   a + b + c = sum + 2 * carry
// with:
//   sum   = a ^ b ^ c
//   carry = majority(a, b, c)
static __device__ __forceinline__ void csa(u64 a, u64 b, u64 c, u64& sum, u64& carry) {
    const u64 ab_xor = a ^ b;
    sum = ab_xor ^ c;
    carry = (a & b) | (c & ab_xor);
}

static __device__ __forceinline__ void ha(u64 a, u64 b, u64& sum, u64& carry) {
    sum = a ^ b;
    carry = a & b;
}

// Consume the 3x3 packed-word neighborhood around the current word and compute the
// next 64-cell packed word.
static __device__ __forceinline__ u64 step_word(
    u64 north_left, u64 north, u64 north_right,
    u64 left,       u64 center, u64 right,
    u64 south_left, u64 south,  u64 south_right)
{
    // Compress the top and bottom neighbor triplets independently:
    //   row_sum + 2*row_carry = diag_left + vertical + diag_right
    u64 top_sum, top_carry;
    csa(align_left(north, north_left), north, align_right(north, north_right),
        top_sum, top_carry);

    u64 bottom_sum, bottom_carry;
    csa(align_left(south, south_left), south, align_right(south, south_right),
        bottom_sum, bottom_carry);

    // Left/right neighbors from the current row.
    u64 side_sum, side_carry;
    ha(align_left(center, left), align_right(center, right), side_sum, side_carry);

    // Combine the 1s planes.
    u64 b0, c01;
    csa(top_sum, bottom_sum, side_sum, b0, c01);

    // Combine the 2s planes from top/bottom and the carry generated above.
    u64 s2, c2;
    csa(c01, top_carry, bottom_carry, s2, c2);

    // Add the remaining 2s plane from left/right.
    u64 b1, c3;
    ha(s2, side_carry, b1, c3);

    // Final 4s / 8s planes.
    u64 b2, b3;
    ha(c2, c3, b2, b3);

    // Neighbor count per bit position:
    //   count = b0 + 2*b1 + 4*b2 + 8*b3
    //
    // Conway rule:
    //   next = (count == 3) | (center & (count == 2))
    //
    // This simplifies to:
    //   next = (b1 & ~(b2 | b3)) & (b0 | center)
    // because b1=1 and b2=b3=0 selects {2,3}, while b0 distinguishes 3 from 2.
    return (b1 & ~(b2 | b3)) & (b0 | center);
}

template <int TILE_WIDTH, int BLOCK_Y_LOG2>
static __device__ __forceinline__ void game_of_life_kernel_body(
    const u64* __restrict__ input,
    u64* __restrict__ output,
    unsigned grid_dim,
    unsigned row_shift)
{
    static_assert(TILE_WIDTH == 16 || TILE_WIDTH == 32, "Unsupported tile width");
    static_assert(BLOCK_Y_LOG2 == 3 || BLOCK_Y_LOG2 == 4, "Unsupported block height");
    constexpr unsigned kTileLog2 = (TILE_WIDTH == 16 ? 4u : 5u);
    constexpr unsigned kLastLane = TILE_WIDTH - 1u;

    // Exact launch geometry:
    // - grid_dim is a power of two > 512, so it is divisible by both 8 and 16.
    // - words_per_row = grid_dim / 64 is also a power of two.
    // - For the 1024x1024 case, words_per_row == 16, so a 16-wide tile covers the
    //   entire packed row and width=16 shuffles partition each warp into two
    //   independent half-warps.
    // - For all larger valid grids, words_per_row is a multiple of 32, so a 32-wide
    //   tile maps exactly to one contiguous warp-sized row segment.
    //
    // The launch therefore covers only valid output words; there are no bounds
    // checks in the hot path.
    const unsigned y = (static_cast<unsigned>(blockIdx.y) << BLOCK_Y_LOG2) + threadIdx.y;
    const std::size_t row_stride = std::size_t{1} << row_shift;
    const std::size_t idx =
        (static_cast<std::size_t>(y) << row_shift) +
        (static_cast<std::size_t>(blockIdx.x) << kTileLog2) +
        static_cast<std::size_t>(threadIdx.x);

    const bool has_up = (y != 0u);
    const bool has_down = ((y + 1u) != grid_dim);
    const bool first_tile = (blockIdx.x == 0u);
    const bool last_tile = ((blockIdx.x + 1u) == gridDim.x);

    // Load the vertically aligned words. Outside the grid is treated as dead, so
    // missing top/bottom rows are represented by zero.
    const u64 center = input[idx];
    const u64 north = has_up ? input[idx - row_stride] : 0ull;
    const u64 south = has_down ? input[idx + row_stride] : 0ull;

    // Exchange horizontally adjacent center/north/south words within the warp.
    // width=TILE_WIDTH prevents the shuffle from crossing row boundaries.
    const u64 sh_left_center  = __shfl_up_sync  (kFullWarpMask, center, 1, TILE_WIDTH);
    const u64 sh_right_center = __shfl_down_sync(kFullWarpMask, center, 1, TILE_WIDTH);
    const u64 sh_left_north   = __shfl_up_sync  (kFullWarpMask, north,  1, TILE_WIDTH);
    const u64 sh_right_north  = __shfl_down_sync(kFullWarpMask, north,  1, TILE_WIDTH);
    const u64 sh_left_south   = __shfl_up_sync  (kFullWarpMask, south,  1, TILE_WIDTH);
    const u64 sh_right_south  = __shfl_down_sync(kFullWarpMask, south,  1, TILE_WIDTH);

    // Most lanes get left/right halo words from shuffles. Only the tile boundary
    // lanes need extra global loads. Missing left/right words at the outer grid
    // border are zero to honor the "outside is dead" rule.
    u64 left = sh_left_center;
    u64 north_left = sh_left_north;
    u64 south_left = sh_left_south;
    if (threadIdx.x == 0u) {
        left = first_tile ? 0ull : input[idx - 1];
        north_left = (has_up && !first_tile) ? input[idx - row_stride - 1] : 0ull;
        south_left = (has_down && !first_tile) ? input[idx + row_stride - 1] : 0ull;
    }

    u64 right = sh_right_center;
    u64 north_right = sh_right_north;
    u64 south_right = sh_right_south;
    if (threadIdx.x == kLastLane) {
        right = last_tile ? 0ull : input[idx + 1];
        north_right = (has_up && !last_tile) ? input[idx - row_stride + 1] : 0ull;
        south_right = (has_down && !last_tile) ? input[idx + row_stride + 1] : 0ull;
    }

    output[idx] = step_word(
        north_left, north, north_right,
        left, center, right,
        south_left, south, south_right);
}

__global__ __launch_bounds__(256)
void game_of_life_kernel32x8(
    const u64* __restrict__ input,
    u64* __restrict__ output,
    unsigned grid_dim,
    unsigned row_shift)
{
    game_of_life_kernel_body<32, kBlockY8Log2>(input, output, grid_dim, row_shift);
}

__global__ __launch_bounds__(512)
void game_of_life_kernel32x16(
    const u64* __restrict__ input,
    u64* __restrict__ output,
    unsigned grid_dim,
    unsigned row_shift)
{
    game_of_life_kernel_body<32, kBlockY16Log2>(input, output, grid_dim, row_shift);
}

__global__ __launch_bounds__(256)
void game_of_life_kernel16x16(
    const u64* __restrict__ input,
    u64* __restrict__ output,
    unsigned grid_dim,
    unsigned row_shift)
{
    game_of_life_kernel_body<16, kBlockY16Log2>(input, output, grid_dim, row_shift);
}

// Host-side cold-path helper; a tiny loop is fine here.
inline unsigned log2_pow2(unsigned x) {
    unsigned s = 0;
    while (x > 1u) {
        x >>= 1;
        ++s;
    }
    return s;
}

} // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions)
{
    // The caller provides device pointers and handles synchronization. This function
    // intentionally performs only the launch, with no host-side synchronization or
    // launch-time error querying in the hot path.
    const unsigned grid_dim = static_cast<unsigned>(grid_dimensions);
    const unsigned words_per_row = grid_dim >> kWordBitShift;
    const unsigned row_shift = log2_pow2(words_per_row);

    if (words_per_row == 16u) {
        // 1024x1024 grid: exactly 16 packed words per row. A 16x16 launch keeps all
        // lanes productive and uses width=16 shuffles so each half-warp is isolated.
        const dim3 block(16u, kBlockY16, 1u);
        const dim3 grid(1u, grid_dim >> kBlockY16Log2, 1u);
        game_of_life_kernel16x16<<<grid, block>>>(input, output, grid_dim, row_shift);
    } else if ((grid_dim >> kBlockY8Log2) <= kGridYLimit) {
        // Preferred large-grid shape: one full warp per row segment, 256 threads/block.
        const dim3 block(32u, kBlockY8, 1u);
        const dim3 grid(words_per_row >> 5, grid_dim >> kBlockY8Log2, 1u);
        game_of_life_kernel32x8<<<grid, block>>>(input, output, grid_dim, row_shift);
    } else {
        // Very large grids that still fit on current H100/A100-class hardware can
        // exceed CUDA's 2D grid.y limit with 8 rows/block. Fall back to 16 rows/block
        // while preserving the same one-warp-per-row-segment mapping.
        const dim3 block(32u, kBlockY16, 1u);
        const dim3 grid(words_per_row >> 5, grid_dim >> kBlockY16Log2, 1u);
        game_of_life_kernel32x16<<<grid, block>>>(input, output, grid_dim, row_shift);
    }
}

#include <cuda_runtime.h>
#include <cstdint>

namespace {

// One-step Conway's Game of Life on a bit-packed square grid.
//
// Design points chosen strictly for throughput on modern NVIDIA data-center GPUs:
//   - One thread updates one 64-bit packed word = 64 cells.
//   - No shared/texture memory: horizontal reuse is captured with warp shuffles instead.
//   - Neighbor counts are accumulated with carry-save full/half adders so all 64 cells in a
//     word are processed in parallel with simple bitwise logic.
//
// Bit convention inside each 64-bit word:
//   - bit 0  = leftmost cell of the 64-cell run
//   - bit 63 = rightmost cell of the 64-cell run
//
// This matches the prompt's requirement that bit 0 depends on words to the left and bit 63 on
// words to the right.

using u64 = std::uint64_t;

constexpr int BLOCK_THREADS = 256;
constexpr int BLOCK_SHIFT   = 8;
constexpr unsigned int FULL_MASK = 0xFFFFFFFFu;

static_assert(BLOCK_THREADS == (1 << BLOCK_SHIFT),
              "BLOCK_THREADS and BLOCK_SHIFT must remain consistent.");
static_assert((BLOCK_THREADS % 32) == 0,
              "BLOCK_THREADS must be a whole number of warps.");
static_assert(sizeof(u64) == 8, "Expected 64-bit packed words.");

// 2-input bit-sliced adder.
// For every bit position independently:
//   sum   = a xor b
//   carry = a & b
// carry has twice the weight of sum in the population-count reduction.
__device__ __forceinline__ void half_adder(const u64 a, const u64 b,
                                           u64& sum, u64& carry) {
    sum   = a ^ b;
    carry = a & b;
}

// 3-input bit-sliced full adder.
// For every bit position independently:
//   sum   = a xor b xor c
//   carry = majority(a, b, c)
// carry again has twice the weight of sum.
__device__ __forceinline__ void full_adder(const u64 a, const u64 b, const u64 c,
                                           u64& sum, u64& carry) {
    const u64 axb = a ^ b;
    sum   = axb ^ c;
    carry = (a & b) | (axb & c);
}

template <int SHUFFLE_WIDTH>
__global__ __launch_bounds__(BLOCK_THREADS)
void game_of_life_kernel(const u64* __restrict__ input,
                         u64* __restrict__ output,
                         const unsigned int words_per_row,
                         const unsigned int word_mask,
                         const unsigned int last_row_start) {
    // One thread per packed 64-cell word.
    //
    // The problem constraints guarantee:
    //   grid_dimensions = 2^k, k >= 10
    //   words_per_row   = grid_dimensions / 64 = 2^(k-6)
    //   total_words     = grid_dimensions * words_per_row = 2^(2k-6)
    //
    // Therefore total_words is always a multiple of 256, so this launch has no tail block and
    // needs no bounds check.
    //
    // Under the stated A100/H100-class memory envelope, even the largest admissible power-of-two
    // grid still has valid packed-word indices in [0, 2^32 - 1], so 32-bit index arithmetic is
    // sufficient and cheaper than 64-bit indexing here.
    const unsigned int idx = blockIdx.x * BLOCK_THREADS + threadIdx.x;

    // words_per_row is a power of two, so x = idx mod words_per_row is just a mask.
    const unsigned int x = idx & word_mask;

    const bool has_left  = (x != 0u);
    const bool has_right = (x != word_mask);
    const bool has_up    = (idx >= words_per_row);
    const bool has_down  = (idx < last_row_start);

    const unsigned int up_idx   = idx - words_per_row;   // Wrap on top row is harmless; guarded by has_up.
    const unsigned int down_idx = idx + words_per_row;   // Wrap on bottom row is harmless; guarded by has_down.

    // Mandatory global loads: the current word plus the vertically adjacent words.
    const u64 current = input[idx];

    u64 north = 0ULL;
    if (has_up) {
        north = input[up_idx];
    }

    u64 south = 0ULL;
    if (has_down) {
        south = input[down_idx];
    }

    // Horizontal neighboring words are usually obtained with warp shuffles instead of extra
    // global loads. Only lanes at the edge of a shuffle segment fall back to global memory.
    //
    // Two segment widths are enough:
    //   SHUFFLE_WIDTH == 16 : only for the smallest legal grid (1024x1024 => 16 words/row),
    //                         so each half warp corresponds to one complete row.
    //   SHUFFLE_WIDTH == 32 : all larger grids; each warp is a 32-word row segment.
    //
    // For rows wider than one segment, segment-edge lanes load the missing left/right words from
    // global memory. This avoids shared memory while preserving correctness across warp and block
    // boundaries.
    const unsigned int lane         = threadIdx.x & 31u;
    constexpr unsigned int SEG_MASK = static_cast<unsigned int>(SHUFFLE_WIDTH - 1);
    const unsigned int segment_lane = lane & SEG_MASK;

    u64 left_current  = __shfl_up_sync(FULL_MASK, current, 1, SHUFFLE_WIDTH);
    u64 right_current = __shfl_down_sync(FULL_MASK, current, 1, SHUFFLE_WIDTH);
    u64 left_north    = __shfl_up_sync(FULL_MASK, north,   1, SHUFFLE_WIDTH);
    u64 right_north   = __shfl_down_sync(FULL_MASK, north, 1, SHUFFLE_WIDTH);
    u64 left_south    = __shfl_up_sync(FULL_MASK, south,   1, SHUFFLE_WIDTH);
    u64 right_south   = __shfl_down_sync(FULL_MASK, south, 1, SHUFFLE_WIDTH);

    if (segment_lane == 0u) {
        if (has_left) {
            left_current = input[idx - 1u];
            left_north   = has_up   ? input[up_idx   - 1u] : 0ULL;
            left_south   = has_down ? input[down_idx - 1u] : 0ULL;
        } else {
            left_current = 0ULL;
            left_north   = 0ULL;
            left_south   = 0ULL;
        }
    }

    if (segment_lane == SEG_MASK) {
        if (has_right) {
            right_current = input[idx + 1u];
            right_north   = has_up   ? input[up_idx   + 1u] : 0ULL;
            right_south   = has_down ? input[down_idx + 1u] : 0ULL;
        } else {
            right_current = 0ULL;
            right_north   = 0ULL;
            right_south   = 0ULL;
        }
    }

    // Align each neighbor direction to the destination bit position.
    //
    // Example for the west neighbor:
    //   aligned_west[i] = current[i-1] for i > 0
    //   aligned_west[0] = left_current[63]
    //
    // This is exactly the special handling required for bits 0 and 63 at word boundaries.
    //
    // We then reduce the 8 aligned neighbor bitplanes with a carry-save adder tree:
    //   top row    : NW + N + NE  -> top_ones,    top_twos
    //   bottom row : SW + S + SE  -> bottom_ones, bottom_twos
    //   same row   : W  + E       -> horiz_ones,  horiz_twos
    //
    // Finally:
    //   count_bit0    = bit 0 of the neighbor count
    //   count_bit1    = bit 1 of the neighbor count, provided count < 4
    //   at_least_four = count in [4, 8]
    //
    // Game of Life then becomes:
    //   next = (count == 3) | (current & (count == 2))
    //        = count_bit1 & ~at_least_four & (count_bit0 | current)
    u64 top_ones, top_twos;
    full_adder((north << 1) | (left_north >> 63),    // NW
               north,                                // N
               (north >> 1) | (right_north << 63),   // NE
               top_ones, top_twos);

    u64 bottom_ones, bottom_twos;
    full_adder((south << 1) | (left_south >> 63),    // SW
               south,                                // S
               (south >> 1) | (right_south << 63),   // SE
               bottom_ones, bottom_twos);

    u64 horiz_ones, horiz_twos;
    half_adder((current << 1) | (left_current >> 63),    // W
               (current >> 1) | (right_current << 63),   // E
               horiz_ones, horiz_twos);

    u64 count_bit0, twos_from_ones;
    full_adder(top_ones, bottom_ones, horiz_ones, count_bit0, twos_from_ones);

    u64 twos_lsb, fours_from_twos;
    full_adder(top_twos, bottom_twos, horiz_twos, twos_lsb, fours_from_twos);

    u64 count_bit1, fours_from_merge;
    half_adder(twos_lsb, twos_from_ones, count_bit1, fours_from_merge);

    const u64 at_least_four = fours_from_twos | fours_from_merge;
    output[idx] = count_bit1 & ~at_least_four & (count_bit0 | current);
}

}  // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions) {
    // The caller guarantees:
    //   - grid_dimensions is a power of two
    //   - grid_dimensions > 512
    //   - input/output are device pointers from cudaMalloc
    //   - input and output are distinct ping-pong buffers
    //
    // Therefore:
    //   words_per_row = grid_dimensions / 64 is a power of two and at least 16
    //   total_words   = grid_dimensions * words_per_row is an exact multiple of 256
    //
    // No host-side synchronization or error checking is performed here because the prompt states
    // that synchronization is handled by the caller and only performance matters.

    const unsigned int n = static_cast<unsigned int>(grid_dimensions);
    const unsigned int words_per_row = n >> 6;

    const std::uint64_t total_words =
        static_cast<std::uint64_t>(n) * static_cast<std::uint64_t>(words_per_row);

    const unsigned int word_mask      = words_per_row - 1u;
    const unsigned int last_row_start = static_cast<unsigned int>(total_words - words_per_row);
    const unsigned int grid_blocks    = static_cast<unsigned int>(total_words >> BLOCK_SHIFT);

    if (words_per_row == 16u) {
        game_of_life_kernel<16><<<grid_blocks, BLOCK_THREADS>>>(
            input, output, words_per_row, word_mask, last_row_start);
    } else {
        game_of_life_kernel<32><<<grid_blocks, BLOCK_THREADS>>>(
            input, output, words_per_row, word_mask, last_row_start);
    }
}

#include <cstddef>
#include <cstdint>
#include <cuda_runtime.h>

/*
 * High-throughput bit-packed Conway step.
 *
 * Key choices:
 * - One thread updates exactly one 64-bit word = 64 cells.
 * - Horizontal reuse is handled with warp shuffles instead of shared memory.
 * - Vertical reuse is left to the hardware caches; no shared/texture memory is used.
 * - Neighbor counts are computed with bit-sliced full-adder logic, so each 64-bit
 *   operation updates 64 independent cells in parallel.
 *
 * The implementation intentionally exploits the stated constraints:
 * - grid_dimensions is a power of two and > 512
 * - therefore words_per_row = grid_dimensions / 64 is either 16 (the 1024x1024 case)
 *   or a multiple of 32
 *
 * Two exact kernels are used:
 * - 32x8 tiles for all boards with at least 32 words/row: one warp == one row tile
 * - 16x16 tiles for the 1024x1024 board: width-16 shuffles split each warp into
 *   two independent 16-lane row tiles
 *
 * This removes hot-path bounds checks entirely.
 */

namespace {

using u64 = unsigned long long;

static_assert(sizeof(u64) == sizeof(std::uint64_t), "Expected 64-bit words.");

constexpr unsigned int kFullMask      = 0xFFFFFFFFu;
constexpr unsigned int kMaxExactGridY = 1u << 15;  // Largest power of two <= 65535.

constexpr int kSmallTileX = 16;
constexpr int kSmallTileY = 16;
constexpr int kLargeTileX = 32;
constexpr int kLargeTileY = 8;

static_assert(kSmallTileX * kSmallTileY == 256, "Small kernel must use 256 threads/block.");
static_assert(kLargeTileX * kLargeTileY == 256, "Large kernel must use 256 threads/block.");

// Per-bit full adder for three 64-bit bitmasks:
//   a + b + c = sum + 2*carry
// Every bit position is an independent 1-bit addition, so this computes 64
// cell-neighbor additions in parallel.
__device__ __forceinline__ void full_adder(u64 a, u64 b, u64 c, u64& sum, u64& carry) {
    const u64 axb = a ^ b;
    sum   = axb ^ c;
    carry = (a & b) | (axb & c);  // majority(a, b, c)
}

// Builds the contribution of one board row to the 8-neighbor count.
//
// INCLUDE_CENTER == true:
//   count west + center + east
//   used for the north and south rows
//
// INCLUDE_CENTER == false:
//   count west + east only
//   used for the current row because the cell itself is not its own neighbor
//
// The helper is called unconditionally by every thread. A ballot computes the
// exact participating lane mask for this invocation; this is required for the
// 16-word kernel, where a warp contains two independent 16-lane row tiles and
// only one of them may exist at the top/bottom edge.
template <int TileX, bool INCLUDE_CENTER>
__device__ __forceinline__ void accumulate_row(
    const std::uint64_t* __restrict__ input,
    std::size_t center_idx,
    u64 center_word,
    int lane_in_tile,
    bool row_exists,
    bool has_left,
    bool has_right,
    u64& sum,
    u64& carry)
{
    const unsigned int active_mask = __ballot_sync(kFullMask, row_exists);

    if (!row_exists) {
        sum = 0ULL;
        carry = 0ULL;
        return;
    }

    // Shuffles are issued unconditionally for the participating lanes.
    // Boundary lanes may receive undefined shuffle results when the source lane
    // would be outside the tile; those lanes never use that value and instead
    // fall back to a global load (or zero at the global board edge).
    const u64 left_from_lane  = __shfl_up_sync(active_mask, center_word, 1, TileX);
    const u64 right_from_lane = __shfl_down_sync(active_mask, center_word, 1, TileX);

    u64 left_word = 0ULL;
    u64 right_word = 0ULL;

    if (has_left) {
        left_word = (lane_in_tile > 0)
            ? left_from_lane
            : static_cast<u64>(input[center_idx - 1]);
    }

    if (has_right) {
        right_word = (lane_in_tile + 1 < TileX)
            ? right_from_lane
            : static_cast<u64>(input[center_idx + 1]);
    }

    // Bit 0 and bit 63 need cross-word handling:
    // - west neighbor of bit 0 comes from bit 63 of the word on the left
    // - east neighbor of bit 63 comes from bit 0 of the word on the right
    const u64 west = (center_word << 1) | (left_word >> 63);
    const u64 east = (center_word >> 1) | (right_word << 63);

    if (INCLUDE_CENTER) {
        full_adder(west, center_word, east, sum, carry);
    } else {
        sum   = west ^ east;
        carry = west & east;
    }
}

template <int TileX, int TileY>
__global__ __launch_bounds__(256)
void game_of_life_kernel(
    const std::uint64_t* __restrict__ input,
    std::uint64_t* __restrict__ output,
    unsigned int grid_dimensions)
{
    static_assert((TileX & (TileX - 1)) == 0, "TileX must be a power of two.");
    static_assert((TileY & (TileY - 1)) == 0, "TileY must be a power of two.");
    static_assert(TileX * TileY == 256, "Kernel launch configuration must use 256 threads/block.");

    const unsigned int words_per_row = grid_dimensions >> 6;

    // Launch geometry is exact for the stated constraints:
    // - x tiles exactly cover the row
    // - y tiles exactly cover the board height
    // Thus no bounds checks are needed in the hot path.
    const unsigned int x = blockIdx.x * TileX + threadIdx.x;
    const unsigned int tile_y = blockIdx.y + blockIdx.z * gridDim.y;
    const unsigned int y = tile_y * TileY + threadIdx.y;

    const bool has_left  = (x != 0u);
    const bool has_right = (x + 1u < words_per_row);
    const bool has_north = (y != 0u);
    const bool has_south = (y + 1u < grid_dimensions);

    const int lane_in_tile = static_cast<int>(threadIdx.x);

    const std::size_t stride = static_cast<std::size_t>(words_per_row);
    const std::size_t idx = static_cast<std::size_t>(y) * stride + static_cast<std::size_t>(x);
    const std::size_t north_idx = idx - stride;
    const std::size_t south_idx = idx + stride;

    u64 north = 0ULL;
    if (has_north) {
        north = static_cast<u64>(input[north_idx]);
    }

    const u64 cur = static_cast<u64>(input[idx]);

    u64 south = 0ULL;
    if (has_south) {
        south = static_cast<u64>(input[south_idx]);
    }

    u64 top_sum, top_carry;
    accumulate_row<TileX, true>(
        input, north_idx, north, lane_in_tile, has_north, has_left, has_right, top_sum, top_carry);

    u64 mid_sum, mid_carry;
    accumulate_row<TileX, false>(
        input, idx, cur, lane_in_tile, true, has_left, has_right, mid_sum, mid_carry);

    u64 bot_sum, bot_carry;
    accumulate_row<TileX, true>(
        input, south_idx, south, lane_in_tile, has_south, has_left, has_right, bot_sum, bot_carry);

    // Bit-sliced count tree:
    //
    //   top    = NW + N + NE     = top_sum + 2*top_carry
    //   middle = W + E           = mid_sum + 2*mid_carry
    //   bottom = SW + S + SE     = bot_sum + 2*bot_carry
    //
    // Combine low bits and high bits separately:
    //   low  = top_sum   + mid_sum   + bot_sum
    //   high = top_carry + mid_carry + bot_carry
    //
    // We only need:
    //   s0  = count bit 0
    //   q0  = count bit 1
    //   ge4 = (count >= 4)
    //
    // Then the Game of Life rule is:
    //   next = (count == 3) | (current & count == 2)
    //        = q0 & ~ge4 & (s0 | current)
    u64 s0, c0;
    full_adder(top_sum, mid_sum, bot_sum, s0, c0);

    u64 s1, c1;
    full_adder(top_carry, mid_carry, bot_carry, s1, c1);

    const u64 q0  = c0 ^ s1;
    const u64 ge4 = (c0 & s1) | c1;
    const u64 next = q0 & (s0 | cur) & ~ge4;

    output[idx] = static_cast<std::uint64_t>(next);
}

template <int TileX, int TileY>
inline void launch_exact_tiled_kernel(
    const std::uint64_t* input,
    std::uint64_t* output,
    unsigned int grid_dimensions)
{
    static_assert((TileX & (TileX - 1)) == 0, "TileX must be a power of two.");
    static_assert((TileY & (TileY - 1)) == 0, "TileY must be a power of two.");
    static_assert(TileX * TileY == 256, "Launch configuration must use 256 threads/block.");

    const unsigned int words_per_row = grid_dimensions >> 6;
    const unsigned int tiles_x = words_per_row / TileX;
    const unsigned int row_tiles = grid_dimensions / TileY;

    // row_tiles is a power of two. Choosing grid.y as either row_tiles itself or
    // 32768 (also a power of two) keeps grid_z integral, so the Y decomposition
    // is exact and the kernel needs no Y bounds checks.
    const unsigned int grid_y = (row_tiles > kMaxExactGridY) ? kMaxExactGridY : row_tiles;
    const unsigned int grid_z = row_tiles / grid_y;

    const dim3 block(TileX, TileY, 1);
    const dim3 grid(tiles_x, grid_y, grid_z);

    game_of_life_kernel<TileX, TileY><<<grid, block>>>(input, output, grid_dimensions);
}

} // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions) {
    if (grid_dimensions <= 0) {
        return;
    }

    const unsigned int n = static_cast<unsigned int>(grid_dimensions);
    const unsigned int words_per_row = n >> 6;

    // The constraints guarantee:
    // - words_per_row == 16 for the smallest legal board (1024x1024)
    // - otherwise words_per_row is a multiple of 32
    //
    // The 16x16 kernel avoids half-empty 32-lane row tiles on the 1024x1024 case.
    if (words_per_row == 16u) {
        launch_exact_tiled_kernel<kSmallTileX, kSmallTileY>(input, output, n);
    } else {
        launch_exact_tiled_kernel<kLargeTileX, kLargeTileY>(input, output, n);
    }

    // Deliberately no synchronization or error-query call here.
    // The caller owns synchronization/error handling, and only step throughput
    // matters for this function.
}

#include <cuda_runtime.h>

#include <cstddef>
#include <cstdint>

namespace {

// CUDA's shuffle intrinsics are guaranteed to support unsigned long long as a 64-bit lane value.
// std::uint64_t may alias either unsigned long or unsigned long long depending on platform, so we
// use unsigned long long internally and convert at the load/store boundaries.
using word_t = unsigned long long;

constexpr unsigned int kWarpSize   = 32u;
constexpr unsigned int kBlockShift = 8u;          // 2^8 = 256 threads/block
constexpr unsigned int kBlockSize  = 1u << kBlockShift;
constexpr unsigned int kFullMask   = 0xFFFFFFFFu;

static_assert(sizeof(word_t) == 8, "word_t must be 64-bit");
static_assert(sizeof(std::uint64_t) == 8, "std::uint64_t must be 64-bit");
static_assert(kBlockSize % kWarpSize == 0u, "Block size must be warp-aligned");

// Simple typed load helper. Kept separate only because the kernel uses word_t internally.
__device__ __forceinline__ word_t load_word(const std::uint64_t* ptr) {
    return static_cast<word_t>(*ptr);
}

// Bit-sliced 3:2 compressor / full adder.
// For every bit position independently:
//   a + b + c = sum + 2 * carry
// with:
//   sum   = a ^ b ^ c
//   carry = majority(a, b, c)
__device__ __forceinline__ void csa3(
    const word_t a,
    const word_t b,
    const word_t c,
    word_t& sum,
    word_t& carry)
{
    const word_t ab = a ^ b;
    sum   = ab ^ c;
    carry = (a & b) | (c & ab);
}

// Compute one output 64-cell word from the 3x3 word neighborhood around it.
//
// Bit layout assumption (matching the prompt's "0th" and "63rd" bit wording):
// - bit 0  = leftmost cell of the 64-cell chunk
// - bit 63 = rightmost cell of the 64-cell chunk
//
// Therefore:
// - shifting a word left aligns west-neighbor bits to the destination cells
// - shifting a word right aligns east-neighbor bits to the destination cells
// - the carry-in for bit 0 comes from bit 63 of the word to the left
// - the carry-in for bit 63 comes from bit 0 of the word to the right
__device__ __forceinline__ word_t evolve_word(
    const word_t center,
    const word_t left,
    const word_t right,
    const word_t up_left,
    const word_t up,
    const word_t up_right,
    const word_t down_left,
    const word_t down,
    const word_t down_right)
{
    // Align horizontal neighbors to the destination bit positions.
    const word_t west       = (center << 1) | (left >> 63);
    const word_t east       = (center >> 1) | (right << 63);
    const word_t north_west = (up << 1) | (up_left >> 63);
    const word_t north_east = (up >> 1) | (up_right << 63);
    const word_t south_west = (down << 1) | (down_left >> 63);
    const word_t south_east = (down >> 1) | (down_right << 63);

    // Compress each neighbor row horizontally:
    //   top = top0 + 2*top1   for {NW, N, NE}
    //   mid = mid0 + 2*mid1   for {W, E}
    //   bot = bot0 + 2*bot1   for {SW, S, SE}
    word_t top0, top1;
    csa3(north_west, up, north_east, top0, top1);

    const word_t mid0 = west ^ east;
    const word_t mid1 = west & east;

    word_t bot0, bot1;
    csa3(south_west, down, south_east, bot0, bot1);

    // Add the three 2-bit row counts in bit-sliced form.
    // Result is encoded as bit0/bit1/bit2/bit3 = 1/2/4/8 place of the neighbor count.
    word_t bit0, carry0;
    csa3(top0, mid0, bot0, bit0, carry0);

    word_t twos0, twos1;
    csa3(top1, mid1, bot1, twos0, twos1);

    const word_t bit1   = twos0 ^ carry0;
    const word_t carry1 = twos0 & carry0;
    const word_t bit2   = twos1 ^ carry1;
    const word_t bit3   = twos1 & carry1;

    // Conway update:
    // - survive on exactly 2 neighbors
    // - born on exactly 3 neighbors
    //
    // Using the bit-sliced count:
    //   count == 2 -> bit1=1, bit0=0, bit2=0, bit3=0
    //   count == 3 -> bit1=1, bit0=1, bit2=0, bit3=0
    //
    // This simplifies to:
    //   next = (center | bit0) & bit1 & ~(bit2 | bit3)
    return (center | bit0) & bit1 & ~(bit2 | bit3);
}

// Power-of-two integer log2 used on the host. The input is guaranteed to be a power of two.
inline unsigned int ilog2_pow2(unsigned int v) {
    unsigned int r = 0;
    while (v > 1u) {
        v >>= 1u;
        ++r;
    }
    return r;
}

// A 1D launch is deliberate:
// - it avoids the 2D grid.y <= 65535 limit for very large boards
// - words_per_row is a power of two, so x/y decode is just mask + shift
// - with a warp-aligned block size, warps naturally cover contiguous row segments
//
// Each thread owns exactly one 64-bit packed word, so no atomics are needed.
__global__ __launch_bounds__(256) void game_of_life_kernel(
    const std::uint64_t* __restrict__ input,
    std::uint64_t* __restrict__ output,
    const unsigned int words_per_row,
    const unsigned int row_mask,
    const unsigned int last_row,
    const int row_shift)
{
    // Under the stated constraints:
    //   N = 2^m, words_per_row = N / 64 = 2^(m-6), total_words = 2^(2m-6)
    // and N > 512 => total_words is divisible by 256.
    //
    // So the host launches an exact multiple of kBlockSize threads and there is no tail block.
    const std::size_t idx = (static_cast<std::size_t>(blockIdx.x) << kBlockShift) + threadIdx.x;

    // Recover word coordinates with bit ops instead of integer div/mod.
    const unsigned int x = static_cast<unsigned int>(idx & row_mask);
    const unsigned int y = static_cast<unsigned int>(idx >> row_shift);

    const bool has_left  = (x != 0u);
    const bool has_right = (x != row_mask);
    const bool has_up    = (y != 0u);
    const bool has_down  = (y != last_row);

    // Precompute indices used by the boundary-path fallback loads.
    const std::size_t idx_left  = idx - 1u;
    const std::size_t idx_right = idx + 1u;
    const std::size_t idx_up    = idx - words_per_row;
    const std::size_t idx_down  = idx + words_per_row;

    // Load only the three vertically aligned words directly.
    // Horizontal neighbors are usually supplied by adjacent lanes via warp shuffles.
    const word_t center = load_word(input + idx);

    word_t up = 0ull;
    if (has_up) {
        up = load_word(input + idx_up);
    }

    word_t down = 0ull;
    if (has_down) {
        down = load_word(input + idx_down);
    }

    // Warp-local reuse of adjacent words is cheaper than shared memory here.
    //
    // For words_per_row >= 32, each warp covers one contiguous 32-word row segment.
    // For the only smaller legal case (words_per_row == 16), a warp spans two rows, but
    // the x-boundary predicates below ensure that the cross-row values at the 16-lane seam
    // are never consumed.
    const unsigned int lane          = threadIdx.x & (kWarpSize - 1u);
    const bool left_in_warp_segment  = (lane != 0u);
    const bool right_in_warp_segment = (lane != (kWarpSize - 1u));

    const word_t center_prev = __shfl_up_sync(kFullMask, center, 1);
    const word_t center_next = __shfl_down_sync(kFullMask, center, 1);
    const word_t up_prev     = __shfl_up_sync(kFullMask, up, 1);
    const word_t up_next     = __shfl_down_sync(kFullMask, up, 1);
    const word_t down_prev   = __shfl_up_sync(kFullMask, down, 1);
    const word_t down_next   = __shfl_down_sync(kFullMask, down, 1);

    // Outside-grid words are treated as zero. Only true row boundaries or warp-edge lanes need
    // fallback global loads; all other left/right words come from neighboring lanes.
    word_t left = 0ull;
    if (has_left) {
        left = left_in_warp_segment ? center_prev : load_word(input + idx_left);
    }

    word_t right = 0ull;
    if (has_right) {
        right = right_in_warp_segment ? center_next : load_word(input + idx_right);
    }

    word_t up_left = 0ull;
    if (has_up && has_left) {
        up_left = left_in_warp_segment ? up_prev : load_word(input + idx_up - 1u);
    }

    word_t up_right = 0ull;
    if (has_up && has_right) {
        up_right = right_in_warp_segment ? up_next : load_word(input + idx_up + 1u);
    }

    word_t down_left = 0ull;
    if (has_down && has_left) {
        down_left = left_in_warp_segment ? down_prev : load_word(input + idx_down - 1u);
    }

    word_t down_right = 0ull;
    if (has_down && has_right) {
        down_right = right_in_warp_segment ? down_next : load_word(input + idx_down + 1u);
    }

    const word_t next = evolve_word(
        center,
        left,
        right,
        up_left,
        up,
        up_right,
        down_left,
        down,
        down_right);

    output[idx] = static_cast<std::uint64_t>(next);
}

} // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions) {
    // The problem statement guarantees:
    // - square board
    // - power-of-two dimension
    // - dimension > 512
    // - input/output are device pointers allocated with cudaMalloc
    //
    // Those assumptions are used directly for speed:
    // - no runtime validation
    // - no tail handling in the kernel
    // - no host-side synchronization or error polling here
    //
    // input and output are assumed to be distinct ping-pong buffers.
    const unsigned int dim           = static_cast<unsigned int>(grid_dimensions);
    const unsigned int words_per_row = dim >> 6;                 // 64 cells per packed word
    const unsigned int row_shift     = ilog2_pow2(words_per_row);
    const std::size_t total_words    = static_cast<std::size_t>(dim) * static_cast<std::size_t>(words_per_row);

    // Exact launch: total_words is always divisible by 256 under the stated constraints.
    const dim3 block(kBlockSize, 1u, 1u);
    const dim3 grid(static_cast<unsigned int>(total_words >> kBlockShift), 1u, 1u);

    game_of_life_kernel<<<grid, block>>>(
        input,
        output,
        words_per_row,
        words_per_row - 1u,
        dim - 1u,
        static_cast<int>(row_shift));
}

#include <cuda_runtime.h>
#include <cstddef>
#include <cstdint>

namespace {

// Bit-packed board word: one thread updates one 64-bit word = 64 cells.
using word_t = std::uint64_t;

// Bit layout convention used throughout this implementation:
//   bit k of a word stores the cell at x = word_base_x + k
// Therefore:
//   - the west neighbor of bit k is bit k-1
//   - the east neighbor of bit k is bit k+1
//
// To align neighbors with the current cell position, we shift the current row word and
// import one crossing bit from the adjacent word. This is exactly the "special handling"
// required for bit 0 / bit 63 at word boundaries.
__device__ __forceinline__ word_t align_west(word_t row_word, word_t left_word) {
    return (row_word << 1) | (left_word >> 63);
}

__device__ __forceinline__ word_t align_east(word_t row_word, word_t right_word) {
    return (row_word >> 1) | (right_word << 63);
}

// Bit-sliced full adder over 64 independent cell positions.
// For every bit position i:
//   a_i + b_i + c_i = sum_i + 2 * carry_i
//
// The expression is written in a form that modern NVIDIA compilers typically lower
// efficiently (often to LOP3-based logic on Ampere/Hopper).
__device__ __forceinline__ void add3(word_t a, word_t b, word_t c,
                                     word_t& sum, word_t& carry) {
    const word_t ab_xor = a ^ b;
    sum   = ab_xor ^ c;
    carry = (a & b) | (ab_xor & c);
}

// kSubgroupWidth:
//   * 16 when a row contains only 16 packed words (the smallest legal board: 1024x1024)
//   * 32 for all larger legal boards
//
// Left/right neighbor words are exchanged with warp shuffles inside that subgroup.
// Only subgroup-edge lanes need fallback global loads, which removes most redundant
// left/right memory traffic without using shared memory.
template <int kSubgroupWidth>
__launch_bounds__(256, 2)
__global__ void game_of_life_kernel(const word_t* __restrict__ input,
                                    word_t* __restrict__ output,
                                    std::size_t words_per_row,
                                    std::size_t total_words) {
    static_assert(kSubgroupWidth == 16 || kSubgroupWidth == 32,
                  "Unsupported shuffle subgroup width.");
    static_assert((256 % kSubgroupWidth) == 0,
                  "Block size must be a multiple of the shuffle subgroup width.");

    const std::size_t x_mask        = words_per_row - 1;          // words_per_row is a power of two
    const std::size_t last_row_base = total_words - words_per_row;
    const std::size_t stride        = static_cast<std::size_t>(blockDim.x) * gridDim.x;

    const unsigned subgroup_lane = static_cast<unsigned>(threadIdx.x) & (kSubgroupWidth - 1);
    const unsigned subgroup_last = kSubgroupWidth - 1;

    for (std::size_t idx = static_cast<std::size_t>(blockIdx.x) * blockDim.x + threadIdx.x;
         idx < total_words;
         idx += stride) {
        // Because the row width in packed words is a power of two, x can be extracted with
        // a mask instead of division/modulo. This is one of the key constraints we exploit.
        const std::size_t x        = idx & x_mask;
        const std::size_t row_base = idx - x;

        const bool has_left   = (x != 0);
        const bool has_right  = (x != x_mask);
        const bool has_top    = (row_base != 0);
        const bool has_bottom = (row_base != last_row_base);

        // These indices are only dereferenced when the corresponding has_* predicate is true.
        const std::size_t north_idx = has_top    ? idx - words_per_row : 0;
        const std::size_t south_idx = has_bottom ? idx + words_per_row : 0;

        // Core loads:
        //   center word for the current row
        //   matching word from the row above
        //   matching word from the row below
        //
        // Left/right words are obtained from shuffles whenever possible.
        const word_t center = input[idx];
        const word_t north  = has_top    ? input[north_idx] : 0ull;
        const word_t south  = has_bottom ? input[south_idx] : 0ull;

        // __activemask() keeps the code safe even if this kernel is later reused with a
        // different launch geometry or weaker input constraints.
        const unsigned shuffle_mask = __activemask();

        // Top-row contribution: NW + N + NE
        word_t top_lo, top_hi;
        {
            word_t north_left  = __shfl_up_sync  (shuffle_mask, north, 1, kSubgroupWidth);
            word_t north_right = __shfl_down_sync(shuffle_mask, north, 1, kSubgroupWidth);

            // Only subgroup-edge lanes need cross-subgroup or boundary fallback loads.
            if (subgroup_lane == 0) {
                north_left = (has_top && has_left) ? input[north_idx - 1] : 0ull;
            }
            if (subgroup_lane == subgroup_last) {
                north_right = (has_top && has_right) ? input[north_idx + 1] : 0ull;
            }

            const word_t nw = align_west(north, north_left);
            const word_t ne = align_east(north, north_right);
            add3(nw, north, ne, top_lo, top_hi);
        }

        // Middle-row contribution: W + E
        // The center cell itself is NOT part of the neighbor count.
        word_t mid_lo, mid_hi;
        {
            word_t left_word  = __shfl_up_sync  (shuffle_mask, center, 1, kSubgroupWidth);
            word_t right_word = __shfl_down_sync(shuffle_mask, center, 1, kSubgroupWidth);

            if (subgroup_lane == 0) {
                left_word = has_left ? input[idx - 1] : 0ull;
            }
            if (subgroup_lane == subgroup_last) {
                right_word = has_right ? input[idx + 1] : 0ull;
            }

            const word_t west = align_west(center, left_word);
            const word_t east = align_east(center, right_word);

            // Half-adder for two inputs:
            //   west + east = mid_lo + 2 * mid_hi
            mid_lo = west ^ east;
            mid_hi = west & east;
        }

        // Bottom-row contribution: SW + S + SE
        word_t bot_lo, bot_hi;
        {
            word_t south_left  = __shfl_up_sync  (shuffle_mask, south, 1, kSubgroupWidth);
            word_t south_right = __shfl_down_sync(shuffle_mask, south, 1, kSubgroupWidth);

            if (subgroup_lane == 0) {
                south_left = (has_bottom && has_left) ? input[south_idx - 1] : 0ull;
            }
            if (subgroup_lane == subgroup_last) {
                south_right = (has_bottom && has_right) ? input[south_idx + 1] : 0ull;
            }

            const word_t sw = align_west(south, south_left);
            const word_t se = align_east(south, south_right);
            add3(sw, south, se, bot_lo, bot_hi);
        }

        // Each row partial is encoded as:
        //   row_sum = row_lo + 2 * row_hi
        //
        // Combine the three row partials into a full 4-bit neighbor count:
        //   count = count0 + 2*count1 + 4*count2 + 8*count3
        //
        // This is still fully bit-sliced: each bit position represents one cell.
        word_t count0, carry2_from_low_bits;
        add3(top_lo, mid_lo, bot_lo, count0, carry2_from_low_bits);

        word_t tmp_count1, carry4_a;
        add3(carry2_from_low_bits, top_hi, mid_hi, tmp_count1, carry4_a);

        const word_t count1   = tmp_count1 ^ bot_hi;
        const word_t carry4_b = tmp_count1 & bot_hi;
        const word_t count2   = carry4_a ^ carry4_b;
        const word_t count3   = carry4_a & carry4_b;

        // Conway rule in terms of the bit-sliced count:
        //   birth/survival on exactly 3 neighbors
        //   survival only on exactly 2 neighbors
        //
        // count in {2,3} iff:
        //   count1 == 1 and count2 == 0 and count3 == 0
        //
        // Then:
        //   next = (count == 3) || (alive && count == 2)
        //        = (count1 & ~(count2 | count3)) & (count0 | alive)
        const word_t two_or_three = count1 & ~(count2 | count3);
        output[idx] = two_or_three & (center | count0);
    }
}

__host__ inline int get_current_device_sm_count() {
    // Cached per host thread to avoid repeated runtime queries when stepping many generations.
    thread_local int cached_device   = -1;
    thread_local int cached_sm_count = 0;

    int device = 0;
    cudaGetDevice(&device);

    if (device != cached_device) {
        cudaDeviceGetAttribute(&cached_sm_count, cudaDevAttrMultiProcessorCount, device);
        cached_device = device;
    }

    return cached_sm_count;
}

} // anonymous namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions) {
    // The caller guarantees:
    //   * square board
    //   * power-of-two dimension
    //   * dimension > 512
    //   * input/output are device buffers allocated by cudaMalloc
    //   * synchronization/error handling are managed externally
    //
    // This implementation directly consumes the provided bit-packed layout, so no host-side
    // or device-side format conversion is needed.

    constexpr int kBlockSize   = 256;
    constexpr int kBlocksPerSM = 8;

    const std::size_t words_per_row = static_cast<std::size_t>(grid_dimensions) >> 6;
    const std::size_t total_words   = words_per_row * static_cast<std::size_t>(grid_dimensions);

    if (total_words == 0) {
        return;
    }

    // Persistent-grid style launch:
    //   * enough blocks to fill the GPU well
    //   * grid-stride loop covers arbitrarily large boards
    //   * avoids 2D grid dimension limits on very large inputs
    const int sm_count = get_current_device_sm_count();
    const std::size_t desired_blocks =
        static_cast<std::size_t>((sm_count > 0) ? sm_count : 1) * kBlocksPerSM;
    const std::size_t max_blocks = (total_words + kBlockSize - 1) / kBlockSize;
    const int blocks = static_cast<int>(max_blocks < desired_blocks ? max_blocks : desired_blocks);

    if (words_per_row == 16) {
        // 1024x1024 cells => exactly 16 packed words per row.
        // Half-warps line up perfectly with rows, so use 16-lane shuffle subgroups.
        game_of_life_kernel<16><<<blocks, kBlockSize>>>(input, output, words_per_row, total_words);
    } else {
        // All larger legal boards have at least 32 packed words per row, and still a power-of-two
        // width, so full warps map cleanly to contiguous row segments.
        game_of_life_kernel<32><<<blocks, kBlockSize>>>(input, output, words_per_row, total_words);
    }

    // Intentionally no synchronization and no launch-error polling here:
    // the caller explicitly owns those responsibilities.
}

#include <cstdint>
#include <cuda_runtime.h>

namespace {

using u64 = std::uint64_t;

// The problem guarantees power-of-two grids > 512, so:
//   words_per_row = grid_dimensions / 64 is either 16 (only for 1024x1024)
//   or a multiple of 32.
// We exploit that with exact x-dimensions and no partial-warps in x.
//
// A fixed, power-of-two y-cap keeps the row-stride loop regular without paying
// host-side occupancy-query overhead on every call.
constexpr unsigned kSmallBlockX = 16u;
constexpr unsigned kLargeBlockX = 32u;
constexpr unsigned kBlockY      = 8u;
constexpr unsigned kMaxGridY    = 1024u;
constexpr unsigned kFullWarpMask = 0xFFFFFFFFu;

static_assert((kBlockY & (kBlockY - 1u)) == 0u, "kBlockY must stay a power of two.");
static_assert((kMaxGridY & (kMaxGridY - 1u)) == 0u, "kMaxGridY must stay a power of two.");

// Majority for three 1-bit inputs, applied bit-slice-wise across 64 cells.
// On modern NVIDIA GPUs this maps efficiently to a single LOP3.
static __device__ __forceinline__ u64 majority3(const u64 a, const u64 b, const u64 c) {
    return (a & b) | (a & c) | (b & c);
}

// Bit packing convention used here:
//   bit k in a word is cell x = word_base + k.
// Therefore:
//   left neighbor  -> shift left, borrowing bit 63 from the word to the left
//   right neighbor -> shift right, borrowing bit 0  from the word to the right
static __device__ __forceinline__ u64 align_left(const u64 center, const u64 left_word) {
    return (center << 1) | (left_word >> 63);
}

static __device__ __forceinline__ u64 align_right(const u64 center, const u64 right_word) {
    return (center >> 1) | (right_word << 63);
}

// Compute one Game-of-Life step for 64 cells packed in one word.
// Inputs are the raw neighbor words around the current word.
// Missing words outside the grid are passed in as zero, matching the required
// dead-outside boundary condition.
static __device__ __forceinline__ u64 next_word(
    const u64 current_word,
    const u64 left_word,  const u64 right_word,
    const u64 above_word, const u64 above_left_word, const u64 above_right_word,
    const u64 below_word, const u64 below_left_word, const u64 below_right_word)
{
    // Align all eight neighbors to the current bit positions.
    const u64 tl = align_left(above_word, above_left_word);
    const u64 tc = above_word;
    const u64 tr = align_right(above_word, above_right_word);

    const u64 ml = align_left(current_word, left_word);
    const u64 mr = align_right(current_word, right_word);

    const u64 bl = align_left(below_word, below_left_word);
    const u64 bc = below_word;
    const u64 br = align_right(below_word, below_right_word);

    // Bit-sliced carry-save addition:
    //
    // Top row count    = t0 + 2*t1, where
    //   t0 = tl ^ tc ^ tr
    //   t1 = majority(tl, tc, tr)
    //
    // Middle row count = m0 + 2*m1, where
    //   m0 = ml ^ mr
    //   m1 = ml & mr
    //
    // Bottom row count = b0 + 2*b1, where
    //   b0 = bl ^ bc ^ br
    //   b1 = majority(bl, bc, br)
    //
    // This processes all 64 cell positions in parallel with plain bitwise ops.
    const u64 t0 = tl ^ tc ^ tr;
    const u64 t1 = majority3(tl, tc, tr);

    const u64 m0 = ml ^ mr;
    const u64 m1 = ml & mr;

    const u64 b0 = bl ^ bc ^ br;
    const u64 b1 = majority3(bl, bc, br);

    // Combine the three group-counts. The full 4-bit count would be:
    //   bit0 = bit0
    //   bit1 = c0 ^ s1
    //   bit2 = c1 ^ (c0 & s1)
    //   bit3 = c1 & (c0 & s1)
    //
    // Conway's rule only needs to distinguish counts {2, 3} from everything
    // else, so we materialize:
    //   bit0  = count bit 0
    //   bit1  = count bit 1
    //   ge4   = (count >= 4)
    const u64 bit0 = t0 ^ m0 ^ b0;
    const u64 c0   = majority3(t0, m0, b0);

    const u64 s1   = t1 ^ m1 ^ b1;
    const u64 c1   = majority3(t1, m1, b1);

    const u64 bit1 = c0 ^ s1;
    const u64 ge4  = c1 | (c0 & s1);

    // Game of Life:
    //   next = (count == 3) | (alive && count == 2)
    //        = (~ge4) & bit1 & (bit0 | alive)
    return (~ge4) & bit1 & (bit0 | current_word);
}

// Kernel body shared by the 16-wide and 32-wide specializations.
// kBlockX is both the block width and the horizontal shuffle width:
//
//   kBlockX == 32:
//     one warp = one 32-word horizontal segment
//
//   kBlockX == 16:
//     one warp = two independent 16-lane segments
//     (used only for the smallest legal grid: 1024x1024 -> 16 words/row)
//
// Horizontal neighbor words within a segment are exchanged with warp shuffles;
// only the segment-edge lanes issue extra global loads across segment boundaries.
// Vertical reuse is left to the hardware caches; shared memory adds overhead for
// this access pattern and is unnecessary here.
template <unsigned kBlockX>
static __device__ __forceinline__ void game_of_life_kernel_body(
    const u64* __restrict__ input,
    u64* __restrict__ output,
    const unsigned grid_dimensions)
{
    static_assert(kBlockX == kSmallBlockX || kBlockX == kLargeBlockX,
                  "Unsupported horizontal tile width.");

    const u64 row_words  = static_cast<u64>(grid_dimensions >> 6);
    const u64 total_rows = static_cast<u64>(grid_dimensions);

    const bool first_segment = (blockIdx.x == 0);
    const bool last_segment  = (blockIdx.x + 1 == gridDim.x);

    const bool at_segment_left  = (threadIdx.x == 0);
    const bool at_segment_right = (threadIdx.x == (kBlockX - 1u));

    const bool has_left         = !first_segment || !at_segment_left;
    const bool has_right        = !last_segment  || !at_segment_right;
    const bool use_left_global  = !first_segment && at_segment_left;
    const bool use_right_global = !last_segment  && at_segment_right;

    const u64 col = static_cast<u64>(blockIdx.x) * kBlockX + threadIdx.x;

    // Because grid_dimensions, kBlockY, and kMaxGridY are powers of two, this
    // row-stride is also a power of two. Combined with the problem's power-of-two
    // grid size, that keeps loop trip counts uniform.
    u64 row = static_cast<u64>(blockIdx.y) * kBlockY + threadIdx.y;
    const u64 row_step = static_cast<u64>(gridDim.y) * kBlockY;

    u64 idx = row * row_words + col;
    const u64 idx_step = row_step * row_words;

    for (; row < total_rows; row += row_step, idx += idx_step) {
        const bool has_top    = (row != 0);
        const bool has_bottom = (row + 1u < total_rows);

        const u64 idx_above = idx - row_words;
        const u64 idx_below = idx + row_words;

        const u64 current_word = input[idx];
        const u64 above_word   = has_top    ? input[idx_above] : u64{0};
        const u64 below_word   = has_bottom ? input[idx_below] : u64{0};

        // Shuffles are exact and always safe here because the launch geometry is
        // chosen so that x is exact (no partial x-blocks), and kBlockX matches the
        // logical horizontal segment width.
        const u64 current_left_shfl = __shfl_up_sync  (kFullWarpMask, current_word, 1, kBlockX);
        const u64 current_right_shfl= __shfl_down_sync(kFullWarpMask, current_word, 1, kBlockX);
        const u64 above_left_shfl   = __shfl_up_sync  (kFullWarpMask, above_word,   1, kBlockX);
        const u64 above_right_shfl  = __shfl_down_sync(kFullWarpMask, above_word,   1, kBlockX);
        const u64 below_left_shfl   = __shfl_up_sync  (kFullWarpMask, below_word,   1, kBlockX);
        const u64 below_right_shfl  = __shfl_down_sync(kFullWarpMask, below_word,   1, kBlockX);

        u64 left_word = 0;
        u64 right_word = 0;
        if (has_left) {
            left_word = use_left_global ? input[idx - 1] : current_left_shfl;
        }
        if (has_right) {
            right_word = use_right_global ? input[idx + 1] : current_right_shfl;
        }

        u64 above_left_word = 0;
        u64 above_right_word = 0;
        if (has_top) {
            if (has_left) {
                above_left_word = use_left_global ? input[idx_above - 1] : above_left_shfl;
            }
            if (has_right) {
                above_right_word = use_right_global ? input[idx_above + 1] : above_right_shfl;
            }
        }

        u64 below_left_word = 0;
        u64 below_right_word = 0;
        if (has_bottom) {
            if (has_left) {
                below_left_word = use_left_global ? input[idx_below - 1] : below_left_shfl;
            }
            if (has_right) {
                below_right_word = use_right_global ? input[idx_below + 1] : below_right_shfl;
            }
        }

        output[idx] = next_word(
            current_word,
            left_word, right_word,
            above_word, above_left_word, above_right_word,
            below_word, below_left_word, below_right_word);
    }
}

// Thin wrappers provide exact launch bounds for the two only useful x-widths.
__launch_bounds__(128)
__global__ void game_of_life_kernel_16(
    const u64* __restrict__ input,
    u64* __restrict__ output,
    const unsigned grid_dimensions)
{
    game_of_life_kernel_body<kSmallBlockX>(input, output, grid_dimensions);
}

__launch_bounds__(256)
__global__ void game_of_life_kernel_32(
    const u64* __restrict__ input,
    u64* __restrict__ output,
    const unsigned grid_dimensions)
{
    game_of_life_kernel_body<kLargeBlockX>(input, output, grid_dimensions);
}

} // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions)
{
    // The caller handles synchronization. For performance, this function only
    // enqueues the kernel and does not add host-side synchronization or extra
    // runtime tuning overhead.

    const unsigned dim = static_cast<unsigned>(grid_dimensions);
    const unsigned words_per_row = dim >> 6;
    const unsigned row_tiles = dim >> 3;  // exact because kBlockY == 8 and dim is a power of two
    const unsigned grid_y = (row_tiles < kMaxGridY) ? row_tiles : kMaxGridY;

    // Exact x launch geometry:
    //   1024x1024 -> 16 words/row -> 16-wide specialization
    //   larger    -> multiple of 32 words/row -> 32-wide specialization
    if (words_per_row == kSmallBlockX) {
        game_of_life_kernel_16<<<dim3(1u, grid_y), dim3(kSmallBlockX, kBlockY)>>>(
            input, output, dim);
    } else {
        game_of_life_kernel_32<<<dim3(words_per_row >> 5, grid_y), dim3(kLargeBlockX, kBlockY)>>>(
            input, output, dim);
    }
}

#include <cuda_runtime.h>
#include <cstddef>
#include <cstdint>

namespace {

// Bit-packed Conway step for modern NVIDIA GPUs.
//
// Design choices:
// - One CUDA thread updates one 64-bit word, i.e. 64 cells at once.
// - Horizontal neighbor words are exchanged with warp shuffles instead of reloading
//   them from global memory. Only subgroup-edge lanes do extra global loads.
// - Per-cell neighbor counts are accumulated with a carry-save / full-adder tree:
//       top    = NW + N + NE
//       middle = W  + E
//       bottom = SW + S + SE
//   All of this happens bitwise across 64 cells in parallel.
// - Because the board dimensions are powers of two, the row width in words is also
//   a power of two. We therefore use two exact x-tilings:
//       * 32x4 blocks for rows with >= 32 words
//       * 16x8 blocks for the smallest legal case (16 words/row)
//   Both specializations are 128-thread CTAs, which is a good scheduling granularity
//   on A100/H100-class GPUs.
// - The kernel grid-strides in Y so the host can cap grid.y to an occupancy-shaped
//   value instead of launching one CTA per row-tile on extremely large boards.

using u64 = std::uint64_t;

constexpr int kThreadsPerBlock = 128;
constexpr int kBlockX32 = 32;
constexpr int kBlockY32 = 4;
constexpr int kBlockX16 = 16;
constexpr int kBlockY16 = 8;
constexpr int kMaxGridY = 65535;
constexpr int kResidentWaves = 2;

static_assert(kBlockX32 * kBlockY32 == kThreadsPerBlock,
              "32-wide specialization must remain a 128-thread CTA.");
static_assert(kBlockX16 * kBlockY16 == kThreadsPerBlock,
              "16-wide specialization must remain a 128-thread CTA.");

// Bit 0 is the first cell in the 64-cell run, so shifting left aligns the x-1
// neighbor with the current bit position, while shifting right aligns x+1.
__device__ __forceinline__ u64 align_west_neighbor(u64 center, u64 left_word) {
    return (center << 1) | (left_word >> 63);
}

__device__ __forceinline__ u64 align_east_neighbor(u64 center, u64 right_word) {
    return (center >> 1) | (right_word << 63);
}

// 3:2 compressor / full adder on 64 independent bit lanes.
// For three one-bit inputs a,b,c at every bit position:
//   sum   = a xor b xor c
//   carry = majority(a,b,c)
// so a + b + c = sum + 2*carry.
__device__ __forceinline__ void full_adder(u64 a, u64 b, u64 c, u64& sum, u64& carry) {
    const u64 ab_xor = a ^ b;
    sum   = ab_xor ^ c;
    carry = (a & b) | (ab_xor & c);
}

template <int BLOCK_X, int BLOCK_Y>
__launch_bounds__(kThreadsPerBlock)
__global__ void game_of_life_kernel(const u64* __restrict__ input,
                                    u64* __restrict__ output,
                                    int words_per_row,
                                    int rows) {
    static_assert(BLOCK_X == 16 || BLOCK_X == 32,
                  "BLOCK_X must match the shuffle subgroup width.");
    static_assert(BLOCK_X * BLOCK_Y == kThreadsPerBlock,
                  "This kernel is tuned for 128-thread CTAs.");

    constexpr unsigned int kFullMask = 0xFFFFFFFFu;
    constexpr int kShuffleWidth = BLOCK_X;

    // X is always valid because run_game_of_life only launches exact x-tilings:
    // words_per_row is a power of two, and we choose BLOCK_X that divides it.
    const int x = static_cast<int>(blockIdx.x) * BLOCK_X + static_cast<int>(threadIdx.x);
    const bool first_word = (x == 0);
    const bool last_word  = (x == words_per_row - 1);

    // BLOCK_X is also the shuffle width:
    //   - BLOCK_X == 32: one row-segment per warp
    //   - BLOCK_X == 16: two independent row-segments per warp
    int y = static_cast<int>(blockIdx.y) * BLOCK_Y + static_cast<int>(threadIdx.y);
    const int y_stride = static_cast<int>(gridDim.y) * BLOCK_Y;

    const std::size_t stride = static_cast<std::size_t>(words_per_row);
    const std::size_t x_index = static_cast<std::size_t>(x);
    std::size_t row_base = static_cast<std::size_t>(y) * stride;
    const std::size_t row_base_stride = static_cast<std::size_t>(y_stride) * stride;

    for (;;) {
        const bool row_valid = (y < rows);

        // For the 16-wide specialization a warp contains two independent row-segments,
        // so we keep the whole warp alive until every subgroup has exhausted its rows.
        if (!__any_sync(kFullMask, row_valid)) {
            break;
        }

        const bool north_row_valid = row_valid && (y > 0);
        const bool south_row_valid = row_valid && ((y + 1) < rows);
        const std::size_t idx = row_base + x_index;

        // Load the three vertically aligned words (north/current/south).
        u64 north = 0ull;
        u64 center = 0ull;
        u64 south = 0ull;

        if (row_valid) {
            center = input[idx];
            if (north_row_valid) north = input[idx - stride];
            if (south_row_valid) south = input[idx + stride];
        }

        // Interior left/right words come from warp shuffles. Only subgroup-edge lanes
        // need one extra global load to cross a 16- or 32-word segment boundary.
        u64 north_left  = __shfl_up_sync(kFullMask, north, 1, kShuffleWidth);
        u64 center_left = __shfl_up_sync(kFullMask, center, 1, kShuffleWidth);
        u64 south_left  = __shfl_up_sync(kFullMask, south, 1, kShuffleWidth);

        u64 north_right  = __shfl_down_sync(kFullMask, north, 1, kShuffleWidth);
        u64 center_right = __shfl_down_sync(kFullMask, center, 1, kShuffleWidth);
        u64 south_right  = __shfl_down_sync(kFullMask, south, 1, kShuffleWidth);

        if (threadIdx.x == 0u) {
            if (row_valid && !first_word) {
                const std::size_t left_idx = idx - 1u;
                center_left = input[left_idx];
                north_left  = north_row_valid ? input[left_idx - stride] : 0ull;
                south_left  = south_row_valid ? input[left_idx + stride] : 0ull;
            } else {
                north_left = center_left = south_left = 0ull;
            }
        }

        if (threadIdx.x == static_cast<unsigned int>(BLOCK_X - 1)) {
            if (row_valid && !last_word) {
                const std::size_t right_idx = idx + 1u;
                center_right = input[right_idx];
                north_right  = north_row_valid ? input[right_idx - stride] : 0ull;
                south_right  = south_row_valid ? input[right_idx + stride] : 0ull;
            } else {
                north_right = center_right = south_right = 0ull;
            }
        }

        // Align horizontal neighbors for the current word's 64 cells.
        const u64 west = align_west_neighbor(center, center_left);
        const u64 east = align_east_neighbor(center, center_right);

        // Add north triplet, south triplet, and middle pair with full-adder logic.
        u64 top_sum, top_carry;
        full_adder(align_west_neighbor(north, north_left),
                   north,
                   align_east_neighbor(north, north_right),
                   top_sum,
                   top_carry);

        u64 bottom_sum, bottom_carry;
        full_adder(align_west_neighbor(south, south_left),
                   south,
                   align_east_neighbor(south, south_right),
                   bottom_sum,
                   bottom_carry);

        const u64 middle_sum   = west ^ east;
        const u64 middle_carry = west & east;

        // Count bit-planes:
        //   count = bit0 + 2*bit1 + 4*bit2 + 8*bit3
        // We only need bit0/bit1/bit2. bit3 can be ignored because count==8 also has
        // bit1==0, so it can never satisfy the Life predicates for 2 or 3 neighbors.
        u64 bit0, ones_carry;
        full_adder(top_sum, bottom_sum, middle_sum, bit0, ones_carry);

        u64 twos_sum, twos_carry;
        full_adder(top_carry, bottom_carry, middle_carry, twos_sum, twos_carry);

        const u64 bit1 = twos_sum ^ ones_carry;
        const u64 bit2 = twos_carry ^ (twos_sum & ones_carry);

        // Game of Life rule:
        //   next = (count == 3) | (alive & (count == 2))
        //        = bit1 & ~bit2 & (bit0 | alive)
        const u64 next = (bit1 & ~bit2) & (bit0 | center);

        if (row_valid) {
            output[idx] = next;
        }

        y += y_stride;
        row_base += row_base_stride;
    }
}

// Host-side launch shaping is not measured, so we use occupancy to cap grid.y.
// This keeps enough CTAs in flight while avoiding a pathological number of tiny
// CTAs for very tall boards. The kernel itself grid-strides over the remaining rows.
template <int BLOCK_X, int BLOCK_Y>
inline int choose_launch_grid_y(int grid_x, int total_tile_rows) {
    int device = 0;
    int sm_count = 1;
    int blocks_per_sm = 1;

    (void)cudaGetDevice(&device);
    (void)cudaDeviceGetAttribute(&sm_count, cudaDevAttrMultiProcessorCount, device);
    (void)cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &blocks_per_sm,
        game_of_life_kernel<BLOCK_X, BLOCK_Y>,
        kThreadsPerBlock,
        0);

    if (sm_count < 1) sm_count = 1;
    if (blocks_per_sm < 1) blocks_per_sm = 1;

    int grid_y = (sm_count * blocks_per_sm * kResidentWaves + grid_x - 1) / grid_x;
    if (grid_y < 1) grid_y = 1;
    if (grid_y > total_tile_rows) grid_y = total_tile_rows;
    if (grid_y > kMaxGridY) grid_y = kMaxGridY;

    return grid_y;
}

}  // namespace

void run_game_of_life(const std::uint64_t* input, std::uint64_t* output, int grid_dimensions) {
    // input/output are assumed to be distinct device buffers (double buffering),
    // which allows the kernel to use __restrict__ safely.
    const int words_per_row = grid_dimensions >> 6;

    // Smallest legal board: 1024x1024 -> 16 words per row.
    // Use 16-wide row segments so no half-warps are wasted.
    if (words_per_row == kBlockX16) {
        const int grid_x = 1;
        const int total_tile_rows = grid_dimensions >> 3;  // exact: BLOCK_Y == 8
        const int grid_y = choose_launch_grid_y<kBlockX16, kBlockY16>(grid_x, total_tile_rows);

        game_of_life_kernel<kBlockX16, kBlockY16>
            <<<dim3(static_cast<unsigned int>(grid_x),
                    static_cast<unsigned int>(grid_y),
                    1u),
               dim3(static_cast<unsigned int>(kBlockX16),
                    static_cast<unsigned int>(kBlockY16),
                    1u)>>>(input, output, words_per_row, grid_dimensions);
        return;
    }

    // All larger legal boards have at least 32 words per row, and because the width
    // is a power of two the row width is an exact multiple of 32.
    const int grid_x = words_per_row >> 5;        // exact: BLOCK_X == 32
    const int total_tile_rows = grid_dimensions >> 2;  // exact: BLOCK_Y == 4
    const int grid_y = choose_launch_grid_y<kBlockX32, kBlockY32>(grid_x, total_tile_rows);

    game_of_life_kernel<kBlockX32, kBlockY32>
        <<<dim3(static_cast<unsigned int>(grid_x),
                static_cast<unsigned int>(grid_y),
                1u),
           dim3(static_cast<unsigned int>(kBlockX32),
                static_cast<unsigned int>(kBlockY32),
                1u)>>>(input, output, words_per_row, grid_dimensions);
}
